const ENABLE_SHARED_SYSTEM_ACCOUNTS = false;

function isLocalDevelopmentHost() {
  const hostname = String(window.location.hostname || "").toLowerCase();
  return window.location.protocol === "file:"
    || ["localhost", "127.0.0.1", "::1"].includes(hostname);
}

function readDeveloperSession() {
  try {
    const session = JSON.parse(sessionStorage.getItem(DEV_MOD_SESSION_KEY) || "null");
    if (!session?.authorized || Number(session.expiresAt || 0) <= Date.now()) {
      sessionStorage.removeItem(DEV_MOD_SESSION_KEY);
      return null;
    }
    return session;
  } catch {
    sessionStorage.removeItem(DEV_MOD_SESSION_KEY);
    return null;
  }
}

function isDeveloperModeEnabled() {
  return isLocalDevelopmentHost() && !!readDeveloperSession();
}

