function simTariffItem(tariff) {
  return {
    name: tariff.name,
    price: tariff.price,
    item: tariff.name,
    repeatable: true,
    text: tariff.unlimited
      ? "Telefon und SMS ohne Guthabenkosten. Jeder Anruf kommt sicher durch."
      : `SMS und Anruf kosten je ${euro.format(tariff.smsCost)}. Anrufchance ${Math.round(tariff.callChance * 100)} Prozent.`
  };
}

function phoneCreditCardItem(card) {
  return {
    name: card.name,
    price: card.price,
    item: card.name,
    repeatable: true,
    phoneCredit: card.credit,
    text: `Lädt nach dem Einlösen ${euro.format(card.credit)} Handy-Guthaben auf.`
  };
}

