clothingModelDefinitions.forEach((model) => {
  model.colors.forEach((color) => {
    const itemName = `${model.name} ${color}`;
    if (shopMarketCatalog.clothing.some((item) => item.item === itemName)) return;
    shopMarketCatalog.clothing.push({
      name: itemName,
      item: itemName,
      price: model.price + (color === "Gold" ? 90 : color === "Silber" ? 35 : 0),
      wear: { [model.slot]: itemName },
      clothingCategory: model.category,
      clothingModel: model.name,
      clothingColor: color,
      clothingColorHex: clothingColors[color],
      text: `${model.name} in ${color}. Farbe wird direkt am Charakter dargestellt.`
    });
  });
});

// Headwear, bandanas and masks can be combined. Older catalog entries used
// the generic hat/accessory slots, so normalize them before saves are loaded.
shopMarketCatalog.clothing.forEach((item) => {
  const name = String(item.name || item.item || "").toLowerCase();
  if (name.includes("bandana")) {
    const value = item.wear?.bandana || item.wear?.hat || item.item || item.name;
    item.wear = { ...(item.wear || {}), bandana: value };
    delete item.wear.hat;
  }
  if (name.includes("maske")) {
    const value = item.wear?.mask || item.wear?.accessory || item.item || item.name;
    item.wear = { ...(item.wear || {}), mask: value };
    delete item.wear.accessory;
  }
});

