function createGeneratedRealEstateItems() {
  const markets = [
    { city: "Cottbus", currency: "EUR", rate: 1, base: 1450 },
    { city: "Leipzig", currency: "EUR", rate: 1, base: 2800 },
    { city: "Berlin", currency: "EUR", rate: 1, base: 6100 },
    { city: "München", currency: "EUR", rate: 1, base: 9200 },
    { city: "Paris", currency: "EUR", rate: 1, base: 10400 },
    { city: "Mallorca", currency: "EUR", rate: 1, base: 5200 },
    { city: "London", currency: "GBP", rate: 1.18, base: 12200 },
    { city: "New York", currency: "USD", rate: 0.92, base: 13800 },
    { city: "Miami", currency: "USD", rate: 0.92, base: 9800 },
    { city: "Dubai", currency: "AED", rate: 0.25, base: 7400 },
    { city: "Shanghai", currency: "CNY", rate: 0.12, base: 8400 },
    { city: "Tokio", currency: "JPY", rate: 0.006, base: 11200 },
    { city: "Sydney", currency: "AUD", rate: 0.61, base: 9100 },
    { city: "Zürich", currency: "CHF", rate: 1.03, base: 15100 }
  ];
  const types = [
    { name: "Mikro-Apartment", sqm: 24, factor: 0.72 },
    { name: "2-Zimmer-Wohnung", sqm: 55, factor: 1 },
    { name: "Familienwohnung", sqm: 92, factor: 1.12 },
    { name: "Reihenhaus", sqm: 118, factor: 1.2 },
    { name: "Stadthaus", sqm: 165, factor: 1.38 },
    { name: "Penthouse", sqm: 140, factor: 2.15 },
    { name: "Villa", sqm: 260, factor: 2.8 }
  ];
  const generated = [];
  for (let i = 0; i < 30; i += 1) {
    const discount = 5000 + (i % 7) * 1000;
    const eur = Math.max(5000, 14000 + (i % 9) * 1750 - discount);
    generated.push({
      id: `garage-${i + 1}`,
      name: `Garage Angebot ${i + 1}`,
      city: markets[i % markets.length].city,
      price: eur,
      currency: "EUR",
      eur,
      garageSlots: 2,
      discount,
      text: `Garage mit 2 Stellplätzen. Rabatt heute: ${euro.format(discount)}.`
    });
  }
  for (let i = 0; i < 360; i += 1) {
    const market = markets[i % markets.length];
    const type = types[i % types.length];
    const variant = 0.82 + ((i * 37) % 45) / 100;
    const eur = Math.round(type.sqm * market.base * type.factor * variant / 1000) * 1000;
    const price = Math.round(eur / market.rate / 1000) * 1000;
    generated.push({
      id: `estate-${i + 1}`,
      name: `${type.name} ${market.city} ${i + 1}`,
      city: market.city,
      price,
      currency: market.currency,
      eur,
      bidOnly: i % 5 === 0,
      text: `${type.sqm} m², Lagefaktor ${variant.toFixed(2)}.${i % 5 === 0 ? " Nur per Gebot, KI bietet mit." : ""}`
    });
  }
  generated.push(
    { id: "mega-mall", name: "Einkaufszentrum International", city: "Dubai", price: 4800000000, currency: "AED", eur: 1200000000, bidOnly: true, text: "Großes Gewerbeobjekt, nur über Auktion." },
    { id: "city-tower", name: "City Tower New York", city: "New York", price: 3200000000, currency: "USD", eur: 2944000000, bidOnly: true, text: "Milliarden-Gewerbeimmobilie mit KI-Bietern." }
  );
  return generated;
}

