function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function defaultSkillValues(path) {
  const values = Object.fromEntries(skills.map(([name]) => [name, 1]));
  const boosts = {
    balanced: ["Gesundheit", "Kommunikation", "Finanzen"],
    career: ["Disziplin", "Bildung", "Kommunikation"],
    business: ["Finanzen", "Verhandlung", "Unternehmertum"],
    street: ["Stresskontrolle", "Straßenwissen", "Charisma"],
    craft: ["Handwerk", "Kraft", "Fahren"],
    tech: ["Technik", "Intelligenz", "Finanzen"],
    creative: ["Kreativität", "Charisma", "Kommunikation"],
    social: ["Soziales", "Kommunikation", "Verhandlung"],
    finance: ["Finanzen", "Organisation", "Verhandlung"],
    sport: ["Ausdauer", "Kraft", "Disziplin"]
  }[path] || ["Gesundheit", "Kommunikation", "Finanzen"];
  boosts.forEach((name) => values[name] = 3);
  return values;
}

