function render() {
  const preservePagePosition = window.matchMedia?.("(max-width: 600px)")?.matches;
  const savedPageScrollX = preservePagePosition ? window.scrollX : 0;
  const savedPageScrollY = preservePagePosition ? window.scrollY : 0;
  const restorePagePosition = () => {
    if (!preservePagePosition) return;
    requestAnimationFrame(() => window.scrollTo(savedPageScrollX, savedPageScrollY));
  };
  applyRealtimeNeedsHealth();
  completeQuickHomeTravelIfReady();
  completeWorldTravelIfReady();
  completeLocalTravelIfReady();
  if (isLoadingGame) {
    els.setup.classList.remove("hidden");
    els.game.classList.add("hidden");
    setSetupView("loading");
    restorePagePosition();
    return;
  }
  if (!state) {
    els.setup.classList.remove("hidden");
    els.game.classList.add("hidden");
    setSetupView("start");
    restorePagePosition();
    return;
  }

  if (els.setup.classList.contains("settings-overlay")) {
    els.setup.classList.remove("hidden");
  } else {
    els.setup.classList.add("hidden");
  }
  initSharedSystemAccountsSync();
  els.game.classList.remove("hidden");
  checkAnnualBirthdayGift();
  updateHeaderStatusUi(true);
  setTextIfChanged(els.bankName, state.bankName);
  setTextIfChanged(els.accountIban, fakeIban());
  setTextIfChanged(els.creditInfo, `Kreditrahmen: ${euro.format(creditLimit())}`);
  if (!basePanelsInitialized) {
    renderCharacter();
    basePanelsInitialized = true;
  }
  const renderedTab = activeTabId() || "overview";
  renderActiveTabContent(renderedTab);
  lastLiveTabName = renderedTab;
  lastLiveTabRefreshAt = Date.now();
  document.dispatchEvent(new CustomEvent("lifebuilder:rendered", { detail: { tab: renderedTab } }));
  if (!state.introDone && !els.dialog.open && !els.setup.classList.contains("settings-overlay")) {
    setTimeout(() => showIntroStep(0), 80);
  }
  restorePagePosition();
}

let lastPortraitHeaderHtml = "";
let lastDashboardVisibility = null;
let lastDashboardLevel = null;

function compactDashboardMoney(value) {
  const amount = Number(value || 0);
  const absolute = Math.abs(amount);
  if (absolute < 10000) return euro.format(amount);
  const units = [
    [1_000_000_000_000, "Bio."],
    [1_000_000_000, "Mrd."],
    [1_000_000, "M"],
    [1_000, "K"]
  ];
  const [unit, suffix] = units.find(([threshold]) => absolute >= threshold) || [1, ""];
  const scaled = amount / unit;
  const digits = Math.abs(scaled) >= 100 ? 0 : Math.abs(scaled) >= 10 ? 1 : 1;
  return `${scaled.toLocaleString("de-DE", { minimumFractionDigits: 0, maximumFractionDigits: digits })}${suffix} €`;
}

function updateHeaderStatusUi(force = false) {
  if (!state) return;
  setTextIfChanged(els.playerName, `${state.firstName} ${state.lastName}`);
  setTextIfChanged(els.dayLabel, `Tag ${state.day}`);
  const portrait = document.querySelector(".portrait");
  const portraitHtml = portraitHeaderHtml();
  if (portrait && (force || portraitHtml !== lastPortraitHeaderHtml)) {
    setHtmlIfChanged(portrait, portraitHtml);
    lastPortraitHeaderHtml = portraitHtml;
    els.ageBadge = document.getElementById("ageBadge");
  }
  setTextIfChanged(els.cash, compactDashboardMoney(state.cash));
  setTextIfChanged(els.bank, compactDashboardMoney(state.bank));
  if (els.cash) els.cash.title = `Bargeld: ${euro.format(state.cash)}`;
  if (els.bank) els.bank.title = `Kontostand: ${euro.format(state.bank)}`;
  setTextIfChanged(els.debt, euro.format(state.debt));
  setTextIfChanged(els.job, state.job);
  setValueIfChanged(els.hunger, state.hunger);
  setValueIfChanged(els.thirst, state.thirst);
  setValueIfChanged(els.energy, state.energy);
  setValueIfChanged(els.mood, state.mood);
  updatePhoneShortcut();
  if (force || lastDashboardLevel !== state.level) {
    updateDashboardLevelLocks();
    lastDashboardLevel = state.level;
  }
  const dashboardVisible = isDailyDashboardAvailable();
  if (force || lastDashboardVisibility !== dashboardVisible) {
    updateHomeDashboardVisibility();
    lastDashboardVisibility = dashboardVisible;
  }
}

