function ownedPhoneItem() {
  if (!state?.items) return "";
  return (state.items || [])
    .filter((item) => /phone|smartphone/i.test(item))
    .sort((a, b) => deviceTier(b) - deviceTier(a))[0] || "";
}

const purchaseChains = {
  smartphone: ["Basic Phone KL-1", "Smartphone", "Mittelklasse Smartphone", "Pro Smartphone", "Ultra Smartphone"],
  computer: ["Laptop gebraucht", "Office Laptop", "Creator Laptop", "Gaming-PC", "High-End Gaming-PC"],
  backpacks: ["Kleiner Rucksack", "Alltagsrucksack", "Reiserucksack", "Profi-Rucksack", "Expeditionsrucksack", "Mega-Transportrucksack"]
};

function normalizeOwnedName(value) {
  return String(value || "").toLowerCase().replace(/[\s_-]+/g, "");
}

function itemMatchesName(item, name) {
  const itemKey = normalizeOwnedName(item);
  const nameKey = normalizeOwnedName(name);
  if (itemKey === nameKey) return true;
  const aliases = {
    smartphone: ["smartphone", "einsteigersmartphone"],
    mittelklassesmartphone: ["mittelklassesmartphone", "mittelklassesmartphone"],
    prosmartphone: ["prosmartphone"],
    ultrasmartphone: ["ultrasmartphone"],
    basicphonekl1: ["basicphonekl1", "basicphone"],
    gamingpc: ["gamingpc"],
    highendgamingpc: ["highendgamingpc"]
  };
  return (aliases[nameKey] || []).includes(itemKey) || (aliases[itemKey] || []).includes(nameKey);
}

function stateHasItemNamed(name) {
  return (state.items || []).some((item) => itemMatchesName(item, name));
}

function purchaseChainKeyForItem(item) {
  const name = item?.item || item?.name || "";
  if (purchaseChains.smartphone.some((entry) => itemMatchesName(name, entry))) return "smartphone";
  if (purchaseChains.computer.some((entry) => itemMatchesName(name, entry))) return "computer";
  if (purchaseChains.backpacks.some((entry) => itemMatchesName(name, entry))) return "backpacks";
  return "";
}

function purchaseChainIndex(chainKey, name) {
  return (purchaseChains[chainKey] || []).findIndex((entry) => itemMatchesName(name, entry));
}

function ownedPurchaseChainItems(chainKey, excludeName = "") {
  const chain = purchaseChains[chainKey] || [];
  return (state.items || []).filter((owned) => chain.some((entry) => itemMatchesName(owned, entry)) && !itemMatchesName(owned, excludeName));
}

function bestOwnedPurchaseChainIndex(chainKey) {
  return ownedPurchaseChainItems(chainKey).reduce((best, owned) => Math.max(best, purchaseChainIndex(chainKey, owned)), -1);
}

function removeOwnedItemEverywhere(name) {
  let removed = 0;
  state.items = (state.items || []).filter((entry) => {
    if (itemMatchesName(entry, name)) { removed += 1; return false; }
    return true;
  });
  if (state.inventorySlots) {
    state.inventorySlots = state.inventorySlots.map((entry) => itemMatchesName(entry, name) ? null : entry);
  }
  return removed;
}

function currentShopScrollContext(marketKey = activeShopMarketKey) {
  if (!els.dialog?.open) return null;
  const list = els.dialog.querySelector('.clothing-variant-list, .clothing-model-list, .market-list');
  return {
    marketKey: marketKey || "",
    categoryId: activeClothingCategory || "",
    modelName: activeClothingModelName || "",
    dialogScroll: Number(els.dialog.scrollTop || 0),
    listScroll: Number(list?.scrollTop || 0)
  };
}

function restoreShopScrollContext(context) {
  if (!context) return;
  requestAnimationFrame(() => requestAnimationFrame(() => {
    const list = els.dialog?.querySelector('.clothing-variant-list, .clothing-model-list, .market-list');
    if (els.dialog) els.dialog.scrollTop = Number(context.dialogScroll || 0);
    if (list) list.scrollTop = Number(context.listScroll || 0);
  }));
}

function reopenShopContext(context = activePurchaseReturnContext) {
  if (!context?.marketKey) {
    els.dialog?.close();
    return;
  }
  const marketItem = shopItems.find((entry) => entry.market === context.marketKey)
    || { name: "Markt", text: "Weitere Angebote.", market: context.marketKey };
  if (context.marketKey === "clothing" && context.categoryId && context.modelName) {
    const variants = shopMarketCatalog.clothing.filter((entry) => clothingCategoryForItem(entry) === context.categoryId && clothingModelName(entry) === context.modelName);
    openClothingVariantPicker(marketItem, context.categoryId, context.modelName, variants);
  } else if (context.marketKey === "clothing" && context.categoryId) {
    openClothingCategory(marketItem, context.categoryId);
  } else {
    openShopMarket(marketItem);
  }
  restoreShopScrollContext(context);
}

function deviceReplacementCandidates(item) {
  const chainKey = purchaseChainKeyForItem(item);
  if (!['smartphone', 'computer'].includes(chainKey)) return [];
  const targetName = item.item || item.name;
  const targetIndex = purchaseChainIndex(chainKey, targetName);
  return [...new Set(ownedPurchaseChainItems(chainKey, targetName).filter((owned) => purchaseChainIndex(chainKey, owned) < targetIndex))];
}

function openDeviceReplacementDialog(item, oldItems, returnContext) {
  if (!oldItems?.length) return reopenShopContext(returnContext);
  clearDialogDynamic();
  els.dialog.classList.add('purchase-dialog', 'device-replacement-dialog');
  const total = oldItems.reduce((sum, name) => sum + Math.max(1, inventorySellValue(name)), 0);
  els.dialogTitle.textContent = "Altes Gerät ersetzen?";
  els.dialogText.textContent = `${item.name} ist jetzt dein neues Hauptgerät. Möchtest du ${oldItems.join(', ')} direkt verkaufen?`;
  const box = document.createElement('div');
  box.className = 'replacement-device-card';
  box.innerHTML = `<strong>${oldItems.length} altes Gerät${oldItems.length === 1 ? '' : 'e'}</strong><span>Verkaufserlös: ${euro.format(total)}</span>`;
  const sell = document.createElement('button');
  sell.className = 'primary-button';
  sell.textContent = `Verkaufen ${euro.format(total)}`;
  sell.onclick = () => {
    oldItems.forEach(removeOwnedItemEverywhere);
    payoutFromTreasury(total);
    recordIncome('sales', total);
    addFeed(`${oldItems.join(', ')} automatisch verkauft. ${euro.format(total)} erhalten.`);
    save();
    render();
    reopenShopContext(returnContext);
  };
  const keep = document.createElement('button');
  keep.className = 'mini-button';
  keep.textContent = 'Behalten';
  keep.onclick = () => reopenShopContext(returnContext);
  els.dialog.append(box, sell, keep);
  if (!els.dialog.open) els.dialog.showModal();
}

let itemRegistryCache = null;

const ITEM_ID_DISPLAY_KEY = "lifebuilder-2026-item-id-display";
const ITEM_ID_MOD_SESSION_KEY = "lifebuilder-2026-mod-session";

function hasActiveItemIdModSession() {
  try {
    const localSession = JSON.parse(sessionStorage.getItem(ITEM_ID_MOD_SESSION_KEY) || "null");
    const onlineSession = JSON.parse(sessionStorage.getItem("lifebuilder-2026-online-mod-session") || "null");
    const localPermissions = Array.isArray(localSession?.permissions) ? localSession.permissions : [];
    const onlinePermissions = Array.isArray(onlineSession?.permissions) ? onlineSession.permissions : [];
    const localAllowed = isLocalDevelopmentHost()
      && !!localSession?.authorized
      && (localPermissions.includes("*") || localPermissions.includes("ids.read"))
      && Number(localSession.expiresAt || 0) > Date.now();
    const onlineAllowed = !!onlineSession?.authorized
      && !!onlineSession?.online
      && (onlinePermissions.includes("*") || onlinePermissions.includes("ids.read"))
      && Number(onlineSession.expiresAt || 0) > Date.now();
    return localAllowed || onlineAllowed;
  } catch {
    return false;
  }
}

function itemIdDisplayEnabled() {
  return hasActiveItemIdModSession() && sessionStorage.getItem(ITEM_ID_DISPLAY_KEY) === "on";
}

function syncItemIdDisplayMode() {
  const hasSession = hasActiveItemIdModSession();
  if (!hasSession) sessionStorage.removeItem(ITEM_ID_DISPLAY_KEY);
  const enabled = hasSession && sessionStorage.getItem(ITEM_ID_DISPLAY_KEY) === "on";
  document.body?.classList.toggle("mod-item-ids-visible", enabled);
  return enabled;
}

function setItemIdDisplayEnabled(enabled) {
  if (!hasActiveItemIdModSession()) {
    sessionStorage.removeItem(ITEM_ID_DISPLAY_KEY);
    document.body?.classList.remove("mod-item-ids-visible");
    return false;
  }
  sessionStorage.setItem(ITEM_ID_DISPLAY_KEY, enabled ? "on" : "off");
  syncItemIdDisplayMode();
  return true;
}

window.KLItemIds = {
  isEnabled: itemIdDisplayEnabled,
  setEnabled: setItemIdDisplayEnabled,
  sync: syncItemIdDisplayMode
};

let itemIdSessionWatcher = null;

function startItemIdSessionWatcher() {
  if (itemIdSessionWatcher) clearInterval(itemIdSessionWatcher);
  itemIdSessionWatcher = setInterval(() => {
    if (!document.hidden) syncItemIdDisplayMode();
  }, 15000);
}

document.addEventListener("DOMContentLoaded", () => {
  syncItemIdDisplayMode();
  startItemIdSessionWatcher();
});
document.addEventListener("visibilitychange", () => {
  if (!document.hidden) syncItemIdDisplayMode();
});

function itemIdHash(value) {
  let hash = 2166136261;
  for (const char of String(value || "")) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36).slice(0, 5).padStart(5, "0");
}

function itemIdSlug(value) {
  return String(value || "item")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/ß/g, "ss")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 34) || "item";
}

function makeItemId(name, prefix = "itm") {
  const canonical = String(name || "Unbekannt").trim();
  return `${prefix}-${itemIdSlug(canonical)}-${itemIdHash(`${prefix}:${canonical}`)}`;
}

function catalogEntryName(entry) {
  return String(entry?.item || entry?.name || entry?.property?.name || "Unbekannt");
}

function registerCatalogEntries(target, entries, source, prefix = "itm") {
  (entries || []).forEach((entry) => {
    if (!entry || typeof entry !== "object") return;
    const name = catalogEntryName(entry);
    if (!name) return;
    const stableId = entry.itemId
      || (source === "weapon" && entry.id ? `weapon-${entry.id}` : "")
      || (source === "property" && (entry.property?.id || entry.id) ? `property-${entry.property?.id || entry.id}` : "")
      || makeItemId(name, prefix);
    entry.itemId = stableId;
    if (!target.has(stableId.toLowerCase())) target.set(stableId.toLowerCase(), { id: stableId, name, entry, source });
  });
}

function runtimeInventoryNames() {
  if (!state) return [];
  const names = new Set();
  (state.items || []).forEach((name) => name && names.add(String(name)));
  (state.wardrobe || []).forEach((name) => name && names.add(String(name)));
  Object.keys(state.consumables || {}).forEach((name) => name && names.add(String(name)));
  (state.blackBusiness?.weapons || []).forEach((weapon) => {
    const name = weapon?.name || weapon?.item;
    if (name) names.add(String(name));
  });
  (state.properties || []).forEach((id) => {
    const property = typeof findProperty === "function" ? findProperty(id) : null;
    if (property?.name) names.add(String(property.name));
  });
  return [...names];
}

function registerRuntimeInventoryEntries(registry) {
  runtimeInventoryNames().forEach((name) => {
    const stableId = makeItemId(name, "itm");
    const key = stableId.toLowerCase();
    if (registry.has(key)) return;
    const entry = {
      name,
      item: name,
      itemId: stableId,
      price: typeof itemBasePrice === "function" ? itemBasePrice(name) : 0,
      runtimeInventoryItem: true
    };
    registry.set(key, { id: stableId, name, entry, source: "inventory" });
  });
}

function buildItemRegistry(force = false) {
  if (itemRegistryCache && !force) {
    registerRuntimeInventoryEntries(itemRegistryCache);
    return itemRegistryCache;
  }
  const registry = new Map();
  registerCatalogEntries(registry, shopItems, "shop", "itm");
  Object.entries(shopMarketCatalog || {}).forEach(([market, entries]) => registerCatalogEntries(registry, entries, `shop:${market}`, "itm"));
  registerCatalogEntries(registry, typeof stationBlackMarketOffers !== "undefined" ? stationBlackMarketOffers : [], "blackmarket", "contraband");
  registerCatalogEntries(registry, typeof blackWeaponCatalog !== "undefined" ? blackWeaponCatalog : [], "weapon", "weapon");
  registerCatalogEntries(registry, typeof realEstateItems !== "undefined" ? realEstateItems : [], "property", "property");
  registerCatalogEntries(registry, typeof furnitureCatalog !== "undefined" ? furnitureCatalog : [], "furniture", "furn");
  registerRuntimeInventoryEntries(registry);
  itemRegistryCache = registry;
  return registry;
}

function ensureAllItemIds() {
  buildItemRegistry(true);
}

function findCatalogItemById(id) {
  const key = String(id || "").trim().toLowerCase();
  return key ? buildItemRegistry().get(key) || null : null;
}

function findCatalogItemByName(name) {
  const query = String(name || "").trim();
  if (!query) return null;
  for (const record of buildItemRegistry().values()) {
    if (record.name === query || record.entry?.name === query || record.entry?.item === query) return record;
    if (itemMatchesName(record.name, query) || itemMatchesName(record.entry?.name, query) || itemMatchesName(record.entry?.item, query)) return record;
  }
  return null;
}

function catalogItemIdByName(name) {
  return findCatalogItemByName(name)?.id || makeItemId(name, "itm");
}

function itemIdBadge(name) {
  const canonical = String(name || "").trim();
  if (!canonical) return "";
  let record = findCatalogItemByName(canonical);
  if (!record) {
    const registry = buildItemRegistry();
    const stableId = makeItemId(canonical, "itm");
    const entry = { name: canonical, item: canonical, itemId: stableId, price: itemBasePrice(canonical), runtimeInventoryItem: true };
    record = { id: stableId, name: canonical, entry, source: "inventory" };
    registry.set(stableId.toLowerCase(), record);
  }
  return `<small class="item-id">ID: ${record.id}</small>`;
}

function giveInventoryItemById(id, amount = 1) {
  const record = findCatalogItemById(id);
  if (!record || !state) return { ok: false, message: `Keine Item-ID „${id}“ gefunden.` };
  const entry = record.entry || {};
  const count = Math.max(1, Math.min(99, Math.floor(Number(amount) || 1)));
  state.items ||= [];
  state.wardrobe ||= [];
  state.blackBusiness ||= {};
  state.blackBusiness.weapons ||= [];
  state.properties ||= [];
  state.customProperties ||= [];
  state.propertyMeta ||= {};

  if (record.source === "weapon") {
    for (let index = 0; index < count; index += 1) {
      state.blackBusiness.weapons.push({ ...entry, uid: `weapon-${Date.now()}-${index}-${Math.round(Math.random() * 9999)}`, mods: [] });
    }
  } else if (record.source === "property" || entry.property) {
    const property = entry.property ? { ...entry.property } : { ...entry };
    const propertyId = property.id || entry.id;
    if (!propertyId) return { ok: false, message: "Diese Immobilien-ID ist unvollständig." };
    if (!state.properties.includes(propertyId)) state.properties.push(propertyId);
    if (!findProperty(propertyId)) state.customProperties.push({ ...property, id: propertyId, eur: property.eur || property.price || entry.price || 50000 });
    state.propertyMeta[propertyId] ||= { boughtAt: Date.now(), purchasePrice: property.eur || property.price || entry.price || 0 };
  } else if (entry.wear) {
    const itemName = entry.item || entry.name;
    if (!state.wardrobe.includes(itemName)) state.wardrobe.push(itemName);
  } else if (entry.backpackSlots) {
    const itemName = entry.item || entry.name;
    if (!state.items.some((owned) => itemMatchesName(owned, itemName))) state.items.push(itemName);
    state.backpackSlots = Math.max(state.backpackSlots || 0, entry.backpackSlots || 0);
  } else if (entry.effect) {
    addConsumable({ ...entry, name: entry.name || record.name }, count);
  } else {
    const itemName = entry.item || entry.name || record.name;
    const repeatable = !!entry.repeatable || count > 1;
    if (repeatable) {
      for (let index = 0; index < count; index += 1) state.items.push(itemName);
    } else if (!state.items.some((owned) => itemMatchesName(owned, itemName))) {
      state.items.push(itemName);
    }
    if (entry.vehicle) ensureVehicleMeta(itemName);
    if (itemName === "Reisepass") state.passportTrips = Math.max(state.passportTrips || 0, 5);
  }
  save();
  render();
  return { ok: true, id: record.id, name: record.name, amount: count, message: `${record.name}${count > 1 ? ` (${count}x)` : ""} hinzugefügt.` };
}

function ownsAnyComputerAtLeast(itemName) {
  const chain = purchaseChains.computer;
  const index = chain.findIndex((entry) => itemMatchesName(entry, itemName));
  if (index < 0) return stateHasItemNamed(itemName);
  const ownedIndexes = (state.items || [])
    .map((item) => chain.findIndex((entry) => itemMatchesName(item, entry)))
    .filter((ownedIndex) => ownedIndex >= 0);
  return ownedIndexes.some((ownedIndex) => ownedIndex >= index);
}

function ownsAnyPhoneAtLeast(itemName) {
  const chain = purchaseChains.smartphone;
  const index = chain.findIndex((entry) => itemMatchesName(entry, itemName));
  if (index < 0) return stateHasItemNamed(itemName);
  const ownedIndexes = (state.items || [])
    .map((item) => chain.findIndex((entry) => itemMatchesName(item, entry)))
    .filter((ownedIndex) => ownedIndex >= 0);
  return ownedIndexes.some((ownedIndex) => ownedIndex >= index);
}

function shopProgressionStatus(item, marketKey = activeShopMarketKey) {
  if (!item?.item || item.item === "Powerbank") return { locked: false, owned: false, text: "" };
  const chain = purchaseChains[marketKey];
  if (!chain) return { locked: false, owned: false, text: "" };
  const index = chain.findIndex((entry) => itemMatchesName(entry, item.item));
  if (index < 0) return { locked: false, owned: false, text: "" };
  const chainOwned = marketKey === "computer"
    ? ownsAnyComputerAtLeast(item.item)
    : marketKey === "smartphone"
      ? ownsAnyPhoneAtLeast(item.item)
      : false;
  const owned = stateHasItemNamed(item.item) || (!!item.backpackSlots && (state.backpackSlots || 0) >= item.backpackSlots) || chainOwned;
  if (owned) return { locked: true, owned: true, text: "Besitzt du bereits." };
  const previousOwned = marketKey === "computer"
    ? ownsAnyComputerAtLeast(chain[index - 1])
    : marketKey === "smartphone"
      ? ownsAnyPhoneAtLeast(chain[index - 1])
      : stateHasItemNamed(chain[index - 1]);
  if (index > 0 && !previousOwned) {
    return { locked: true, owned: false, text: `Vorher kaufen: ${chain[index - 1]}.` };
  }
  return { locked: false, owned: false, text: "" };
}

function updatePhoneShortcut() {
  const shortcut = document.querySelector("[data-phone-shortcut]");
  if (!shortcut) return;
  const phone = ownedPhoneItem();
  if (phone) updatePhoneBattery(false);
  const tier = phone ? String(deviceTier(phone)) : "-1";
  if (shortcut.dataset.phoneTier !== tier) shortcut.dataset.phoneTier = tier;
  shortcut.disabled = !phone;
  const html = phone
    ? `<span>Info ${phoneInfoCount()}</span><b>${phone.replace(" Smartphone", "").replace("Basic Phone ", "Basic ")}</b><small>Akku ${Math.round(state.phoneBattery ?? 100)}% · ${euro.format(phoneCreditAmount())}</small>`
    : `<span>Handy</span><b>Keins</b>`;
  setHtmlIfChanged(shortcut, html);
  updateHomeShortcut();
}

function phoneInfoCount() {
  if (!state) return 0;
  const buckets = [
    phoneNotesArray().length,
    state.phoneIncomingCalls?.length,
    Object.values(state.phoneMessages || {}).some((messages) => messages?.length),
    state.pendingBankLoan || state.taxLiability || state.debt,
    state.feed?.some((entry) => /sms|anruf|telefon/i.test(entry)),
    state.feed?.some((entry) => /shop|gekauft|inventar/i.test(entry)),
    state.worldTravel || state.localTravel || state.quickHomeTravel,
    state.feed?.some((entry) => /game|snake|racer|casino|börse|trading/i.test(entry))
  ];
  return buckets.filter(Boolean).length;
}

function updateHomeShortcut() {
  const shortcut = document.querySelector("[data-home-shortcut]");
  if (!shortcut) return;
  const active = state?.quickHomeTravel;
  if (active) {
    const seconds = Math.max(0, Math.ceil((active.arrivesAt - Date.now()) / 1000));
    shortcut.disabled = true;
    setHtmlIfChanged(shortcut, `<span>Zuhause</span><b>${seconds}s</b>`);
    return;
  }
  shortcut.disabled = false;
  const html = isHotelDashboardAvailable()
    ? `<span>Hotelzimmer</span><b>H</b>`
    : isHomeDashboardAvailable()
      ? usesEmergencyShelter()
        ? `<span class="home-shortcut-label"><span class="desktop-label">Notunterkunft</span><span class="mobile-label">Notunt.</span></span><b>⌂</b>`
        : `<span>Zuhause</span><b>⌂</b>`
      : `<span>Haus</span><b>⌂</b>`;
  setHtmlIfChanged(shortcut, html);
}

function updateHomeDashboardVisibility() {
  if (!state) return;
  const visible = isDailyDashboardAvailable();
  const tabs = document.querySelector(".tabs");
  // Heute und Arbeit sind zuhause, in der Notunterkunft oder nach einer Hotelbuchung sichtbar.
  // Welt, Games, Casino usw. bleiben weiterhin erreichbar.
  tabs?.querySelectorAll('[data-tab="overview"], [data-tab="work"]').forEach((button) => {
    button.hidden = !visible;
    button.disabled = !visible;
    button.tabIndex = visible ? 0 : -1;
    button.setAttribute("aria-hidden", visible ? "false" : "true");
  });
  if (!visible && ["overview", "work"].includes(activeTabId())) switchMainTab("world");
}

function activeTabId() {
  return document.querySelector(".tab-panel.active")?.id || "";
}

function activeCharacterSection() {
  return els.dialog?.querySelector(".character-hub [data-character-section].gold")?.dataset.characterSection || "";
}

let liveUiTickBusy = false;
let lastLiveTabRefreshAt = 0;
let lastLiveTabName = "";
let lastCharacterBankRefreshAt = 0;
let lastUiInteractionAt = 0;
["scroll", "touchstart", "touchmove", "pointerdown", "wheel"].forEach((type) => {
  window.addEventListener(type, () => { lastUiInteractionAt = Date.now(); }, { passive: true, capture: true });
});

function liveUiRefreshInterval(tab) {
  if (tab === "overview" || tab === "work") return 2000;
  if (tab === "world" || tab === "bank" || tab === "games") return 5000;
  return 0;
}

function liveUiTick() {
  if (!state || isLoadingGame || document.hidden || liveUiTickBusy) return;
  liveUiTickBusy = true;
  try {
    applyRealtimeNeedsHealth();
    checkAnnualBirthdayGift();
    const completedSales = completeBlackBusinessTimers();
    completeQuickHomeTravelIfReady();
    completeWorldTravelIfReady();
    completeLocalTravelIfReady();
    resetPhoneChargeTimerIfAway();
    tickPhoneCharging();
    updateHeaderStatusUi();
    updateStationContactCountdown();
    const tab = activeTabId();
    if (els.dialog?.open && els.dialog.querySelector("[data-business-offer-cooldown]")) {
      const businessStatus = normalizeBusinessOfferLimit();
      const cooldownNode = els.dialog.querySelector("[data-business-offer-cooldown]");
      const attemptsNode = els.dialog.querySelector("[data-business-offer-attempts]");
      const runButton = els.dialog.querySelector("[data-run-business-offers]");
      setTextIfChanged(cooldownNode, "Nach Schlafen");
      setTextIfChanged(attemptsNode, `${businessStatus.remaining}/${BUSINESS_OFFER_LIMIT}`);
      if (runButton) {
        const locked = businessStatus.remaining <= 0;
        runButton.disabled = locked || !canAfford(BUSINESS_OFFER_COST);
        setTextIfChanged(runButton, locked
          ? "Heute ausgeschöpft"
          : `5 Angebote senden (${euro.format(BUSINESS_OFFER_COST)})`);
      }
    }
    const now = Date.now();
    const refreshEvery = liveUiRefreshInterval(tab);
    if (refreshEvery && (tab !== lastLiveTabName || now - lastLiveTabRefreshAt >= refreshEvery)) {
      // Hintergrundbereiche werden bei geöffneten Fenstern überhaupt nicht neu aufgebaut.
      // Beim normalen Scrollen wird die exakte Position vor und nach dem Check bewahrt.
      if (!els.dialog?.open && now - lastUiInteractionAt > 900) {
        const pageX = window.scrollX;
        const pageY = window.scrollY;
        renderActiveTabContent(tab);
        requestAnimationFrame(() => window.scrollTo(pageX, pageY));
      }
      lastLiveTabName = tab;
      lastLiveTabRefreshAt = now;
    }
    if (activeCharacterSection() === "bank" && now - lastCharacterBankRefreshAt >= 5000) {
      refreshOpenCharacterHub("bank");
      lastCharacterBankRefreshAt = now;
    }
    if (completedSales > 0 && tab === "overview") renderFeed();
  } finally {
    liveUiTickBusy = false;
  }
}

function completeQuickHomeTravelIfReady() {
  if (!state?.quickHomeTravel || Date.now() < state.quickHomeTravel.arrivesAt) return;
  state.quickHomeTravel = null;
  state.worldTravel = null;
  state.localTravel = null;
  state.worldLocation = state.homeCity || state.worldLocation;
  state.location = "home";
  state.hotelStay = null;
  state.homeDashboardActive = true;
  addFeed(usesEmergencyShelter()
    ? `Du bist zurück in ${state.homeCity} und in der Notunterkunft angekommen.`
    : `Du bist zurück in ${state.homeCity} und in deiner freien Wohnung angekommen.`);
  save();
  switchMainTab("overview");
  render();
  openHomePropertyDialog();
}

function updateStationContactCountdown() {
  const nodes = document.querySelectorAll("[data-station-contact-countdown]");
  if (!nodes.length) return;
  const left = Math.max(0, (state.stationContactCooldownUntil || 0) - Date.now());
  nodes.forEach((node) => {
    node.textContent = left > 0 ? formatRemainingMs(left) : "bereit";
  });
}

function completeLocalTravelIfReady() {
  if (!state?.localTravel || Date.now() < state.localTravel.arrivesAt) return;
  const place = mapPlaces.find((entry) => entry.id === state.localTravel.placeId);
  if (place) {
    state.location = place.id;
    if (place.id !== "hotel") state.hotelStay = null;
    state.homeDashboardActive = place.id === "home" && (state.worldLocation || state.homeCity) === state.homeCity;
    addFeed(`Du bist bei ${place.name} angekommen.`);
  }
  state.localTravel = null;
  save();
}

function completeWorldTravelIfReady() {
  if (!state?.worldTravel || Date.now() < state.worldTravel.arrivesAt) return;
  const destination = state.worldTravel.place;
  state.worldLocation = destination.name;
  state.location = "airport";
  state.hotelStay = null;
  state.homeDashboardActive = false;
  state.worldTravel = null;
  state.localTravel = null;
  addFeed(`Du bist in ${destination.name} am Flughafen angekommen.`);
  save();
}

function showIntroStep(index) {
  if (!state || state.introDone) return;
  clearDialogDynamic();
  els.dialog.classList.add("intro-dialog");
  const step = introSteps[index];
  if (!step) {
    state.introDone = true;
    save();
    return;
  }
  [...els.dialog.querySelectorAll(".primary-button, .mini-button")].forEach((button) => button.remove());
  els.dialogTitle.textContent = step[0];
  els.dialogText.textContent = step[1];
  const ok = document.createElement("button");
  ok.className = "primary-button";
  ok.textContent = index >= introSteps.length - 1 ? "Loslegen" : "OK";
  ok.onclick = () => {
    if (index >= introSteps.length - 1) {
      state.introDone = true;
      save();
      els.dialog.close();
      return;
    }
    showIntroStep(index + 1);
  };
  const skip = document.createElement("button");
  skip.className = "mini-button";
  skip.textContent = "Überspringen";
  skip.onclick = () => {
    state.introDone = true;
    save();
    els.dialog.close();
  };
  els.dialog.append(ok, skip);
  if (!els.dialog.open) els.dialog.showModal();
}

function fakeIban() {
  const seed = `${state.firstName}${state.lastName}${state.bankName}`.split("").reduce((sum, char) => sum + char.charCodeAt(0), 0);
  return `DE${String(seed % 89 + 10)} 5001 ${String(seed * 97).slice(0, 4)} ${String(seed * 131).slice(0, 4)} ${String(seed * 173).slice(0, 4)}`;
}

function creditLimit() {
  if (state.credit < 35) return 2000;
  if (state.credit < 55) return 10000;
  if (state.credit < 75) return 50000;
  if (state.credit < 90) return 180000;
  return 500000;
}

function creditRatingLabel(credit = state?.credit || 0) {
  if (credit < 25) return "Sehr schwach";
  if (credit < 35) return "Schwach";
  if (credit < 55) return "Ausreichend";
  if (credit < 75) return "Gut";
  if (credit < 90) return "Sehr gut";
  return "Ausgezeichnet";
}

function freeCreditLimit() {
  return Math.max(0, creditLimit() - Math.max(0, state?.debt || 0));
}

function branchCreditAvailable() {
  return Math.min(8000, freeCreditLimit());
}

function loanInterestRate() {
  const credit = state?.credit || 0;
  if (credit < 25) return 18.9;
  if (credit < 40) return 13.5;
  if (credit < 60) return 8.9;
  if (credit < 80) return 5.6;
  return 3.4;
}

function formatRemainingMs(ms) {
  const total = Math.max(0, Math.ceil(ms / 1000));
  const minutesLeft = Math.floor(total / 60);
  const seconds = total % 60;
  return `${minutesLeft}:${String(seconds).padStart(2, "0")} Min.`;
}

function bankAppointmentReady() {
  return !!state?.pendingBankLoan?.readyAt && Date.now() >= state.pendingBankLoan.readyAt;
}

function improveCredit(amount = 1, reason = "") {
  if (amount <= 0.5) {
    state.credit = clamp((state.credit || 0) + amount);
    return true;
  }
  const chance = amount >= 3 ? 0.65 : amount >= 2 ? 0.42 : 0.24;
  if (Math.random() > chance) {
    if (reason) addFeed(`Bonität bleibt stabil: ${reason}.`);
    return false;
  }
  const gain = amount >= 3 ? 1.5 : 1;
  state.credit = clamp(state.credit + gain);
  return true;
}

function renderDailyActions() {
  const actions = [
    ["Lernen", "Ein Abendkurs bringt 1 freien Skillpunkt, kostet Energie.", () => {
      if (!isReady("learn")) return addFeed(`Lernen ist erst in ${waitText("learn")} wieder möglich.`);
      if (state.energy < 22) return addFeed("Du bist zu müde zum Lernen.");
      state.energy -= 22;
      state.skillPoints += 1;
      improveMood(1, "du hast etwas Neues gelernt", { feed: false });
      addXp(30, "Lernen");
      setCooldown("learn");
      addFeed("Du hast 2 Spielstunden gelernt, 1 Skillpunkt und 30 EP verdient.");
      save();
      render();
    }],
    ["Schlafen", "Überspringt den Tag. In Echtzeit alle 5 Minuten möglich und setzt Tagesaktionen zurück.", () => {
      if (!isReady("sleep")) return addFeed(`Schlafen und Tag überspringen geht erst in ${waitText("sleep")} wieder.`);
      if (isAtOwnHome()) {
        const reason = usesEmergencyShelter()
          ? "Du hast in der Notunterkunft geschlafen und bist erholt."
          : "Du hast in deiner Wohnung geschlafen und bist erholt.";
        return sleepAndAdvanceDay(reason);
      }
      if (state.location === "hotel") return openHotelOffersDialog();
      return openSleepRouteChoice();
    }],
    ["Training", "Verbessert Kraft, Ausdauer oder Gesundheit zufällig.", () => {
      if (!isReady("train")) return addFeed(`Training ist erst in ${waitText("train")} wieder möglich.`);
      if (state.energy < 18) return addFeed("Für Training brauchst du mehr Energie.");
      const pick = ["Kraft", "Ausdauer", "Gesundheit"][Math.floor(Math.random() * 3)];
      state.energy -= 18;
      improveMood(1, "das Training hat gutgetan", { feed: false });
      addXp(50, "Training");
      setCooldown("train");
      improveSkill(pick);
      addFeed(`Training erledigt: ${pick} ist gestiegen. +50 EP.`);
      save();
      render();
    }]
  ];
  els.dailyActions.innerHTML = dailyMeta() + actions.map(([name], index) => {
    const action = ["learn", "sleep", "train"][index];
    const disabled = !isReady(action);
    return card(name, `Status: ${waitText(action)}`, disabled ? "Warten" : "Start", index, disabled);
  }).join("");
  els.dailyActions.querySelectorAll("button").forEach((button, index) => button.addEventListener("click", actions[index][2]));
}

