function openLevelInfoDialog() {
  if (!state) return;
  clearDialogDynamic();
  const need = xpNeeded(state.level || 0);
  const current = Math.max(0, Number(state.xp || 0));
  const remaining = Math.max(0, need - current);
  const percent = Math.max(0, Math.min(100, Math.round(current / Math.max(1, need) * 100)));
  els.dialogTitle.textContent = `Level ${state.level || 0}`;
  els.dialogText.textContent = `${current.toLocaleString("de-DE")} von ${need.toLocaleString("de-DE")} EP gesammelt.`;
  const panel = document.createElement("div");
  panel.className = "profile-info-scroll level-info-panel";
  panel.innerHTML = `<section class="profile-info-card"><small>FORTSCHRITT ZUM NÄCHSTEN LEVEL</small><strong>${percent}%</strong><div class="profile-info-bar"><i style="width:${percent}%"></i></div><p>Noch <b>${remaining.toLocaleString("de-DE")} EP</b> bis Level ${(state.level || 0) + 1}.</p></section><section class="profile-tip-list"><h3>So erhältst du EP</h3><article>✓ Arbeiten, Lernen und Training abschließen</article><article>✓ Games spielen und Erfolge abholen</article><article>✓ Tägliche Quests und Events erledigen</article></section>`;
  els.dialog.append(panel);
  if (!els.dialog.open) els.dialog.showModal();
}

function openAgeInfoDialog() {
  if (!state) return;
  clearDialogDynamic();
  const info = nextBirthdayInfo();
  const birthdayText = info.days === 0 ? "Heute ist dein Geburtstag." : `Noch ${info.days.toLocaleString("de-DE")} Tag${info.days === 1 ? "" : "e"} bis zum nächsten Geburtstag.`;
  const alreadyClaimed = state.birthdayGiftYears?.includes(info.now.getFullYear());
  els.dialogTitle.textContent = `Alter · ${age()} Jahre`;
  els.dialogText.textContent = birthdayText;
  const panel = document.createElement("div");
  panel.className = "profile-info-scroll age-info-panel";
  panel.innerHTML = `<section class="profile-info-card birthday"><span>🎂</span><div><small>GEBURTSDATUM</small><strong>${info.dateText}</strong><p>Nächster Geburtstag: ${info.nextText}</p></div></section><section class="profile-info-card"><small>JÄHRLICHES GESCHENK</small><strong>${info.days === 0 ? (alreadyClaimed ? "Heute bereits erhalten" : "Heute verfügbar") : "Einmal pro Spieljahr"}</strong><p>Das Geburtstagsgeschenk wird automatisch am Geburtstag vergeben und richtet sich nach deinem aktuellen Level.</p></section>`;
  els.dialog.append(panel);
  if (!els.dialog.open) els.dialog.showModal();
}

