  els.dialogTitle.textContent = `Leben · ${health}%`;
  els.dialogText.textContent = `${status}. Dein Leben wird von Versorgung, Schlaf, Stimmung, Krankheit und bestimmten Aktivitäten beeinflusst.`;
  const panel = document.createElement("div");
