  els.dialogTitle.textContent = `Stimmung · ${mood}%`;
  els.dialogText.textContent = `${moodStatusLabel(mood)}. Die Stimmung sinkt nur langsam. Niedrige Werte erhöhen den Verbrauch von Hunger, Durst und Energie und können zusätzlich die Gesundheit belasten.`;
  const panel = document.createElement("div");
