function characterHubNavHtml(section) {
  const achievementCount = pendingAchievementCount();
  return ["overview:Charakter", "inventory:Inventar", "skills:Skills", "achievements:Erfolge", "barber:Friseur", "tattoo:Tätowierer", "worldinfo:Weltinfo", "record:Führungsz."].map((entry) => {
    const [id, label] = entry.split(":");
    const fullLabel = id === "record" ? "Führungszeugnis" : label;
    const achievementBadge = id === "achievements" && achievementCount ? `<span class="nav-alert-badge">${achievementCount}</span>` : "";
    return `<button class="mini-button ${section === id ? "gold" : ""}" data-character-section="${id}" title="${fullLabel}" aria-label="${fullLabel}">${label}${achievementBadge}</button>`;
  }).join("");
}

function healthBarHtml(size = "") {
  const health = Math.round(state.health ?? 100);
  const status = state.illness === "severe" ? "Schwer krank" : state.illness === "sick" ? "Krank" : "Gesund";
  return `
    <div class="health-panel ${size} ${state.illness || "healthy"}" data-open-life-info role="button" tabindex="0" title="Leben und Gesundheit anzeigen">
      <div class="health-label"><span>Leben</span><b>${health}% · ${status}</b></div>
      <div class="health-bar"><i style="width:${health}%"></i></div>
    </div>
  `;
}

function openCharacterHub(section = "overview") {
  clearDialogDynamic();
  els.dialog.classList.add("character-dialog");
  els.dialog.classList.toggle("inventory-dialog", section === "inventory");
  els.dialog.classList.toggle("character-overview-mode", section === "overview");
  els.dialogTitle.textContent = section === "inventory" ? "Charakter & Inventar" : "Charakter anpassen";
  els.dialogText.textContent = "";
  els.dialog.querySelectorAll("[data-character-floating-info]").forEach((button) => button.remove());
  const floatingInfo = document.createElement("button");
  floatingInfo.className = "modal-icon-button character-floating-info";
  floatingInfo.dataset.characterFloatingInfo = "1";
  floatingInfo.type = "button";
  floatingInfo.textContent = "i";
  floatingInfo.title = "Charakter-Info";
  floatingInfo.addEventListener("click", openCharacterInfoDialog);
  els.dialog.append(floatingInfo);
  const hub = document.createElement("div");
  hub.className = "character-hub market-list";
  hub.innerHTML = `
    ${section === "overview" ? "" : `<div class="character-hub-nav">${characterHubNavHtml(section)}</div>`}
    <div class="character-hub-content">${characterHubContent(section)}</div>
  `;
  els.dialog.append(hub);
  hub.querySelectorAll("[data-character-section]").forEach((button) => {
    button.addEventListener("click", () => openCharacterHub(button.dataset.characterSection));
  });
  bindCharacterHubContent(hub, section);
  stabilizeMobileCharacterScroll(section);
  if (!els.dialog.open) els.dialog.showModal();
}

function characterHubContent(section) {
  if (section === "inventory") return inventorySummaryHtml();
  if (section === "skills") return skillTreeHtml();
  if (section === "achievements") return achievementsHtml();
  if (section === "barber") return `<div class="barber-service-list-clean">${barberServices.map((service, index) => `
    <article class="barber-service-card-clean">
      <div><h3>${escapeHtml(service.name)}</h3><p>Kosten: ${euro.format(service.price)}.</p></div>
      <button type="button" data-kind="barber" data-index="${index}">Buchen</button>
    </article>`).join("")}</div>`;
  if (section === "tattoo") return tattooStudioHtml();
  if (section === "worldinfo") return worldInfoHtml();
  if (section === "record") return criminalRecordHtml();
  return characterOverviewHtml();
}

function worldInfoHtml() {
  const players = (saveSlots || [])
    .filter(Boolean)
    .map((slot, index) => {
      const propertyValue = (slot.properties || []).reduce((sum, id) => {
        const property = findProperty(id) || realEstateItems.find((entry) => entry.id === id);
        return sum + (property?.eur || 0);
      }, 0);
      const cash = (slot.cash || 0) + (slot.bank || 0) + propertyValue - (slot.debt || 0);
      return {
        name: `${slot.firstName || "Spieler"} ${slot.lastName || ""}`.trim(),
        city: slot.worldLocation || slot.homeCity || "Unbekannt",
        level: slot.level || 0,
        cash,
        properties: (slot.properties || []).length,
        tag: slot === state || index === selectedSlot ? "Du" : `Slot ${index + 1}`
      };
    })
    .sort((a, b) => b.cash - a.cash);
  return `
    <div class="world-info-panel">
      <article class="item-card">
        <div>
          <h3>Weltinfo</h3>
          <p>Aktuell werden nur echte lokale Charaktere aus deinen Spielständen gezählt, kein Gesamtvermögen aus allen Slots und keine Platzhalter.</p>
        </div>
        <button disabled>Online</button>
      </article>
      ${players.length ? players.map((player) => `
        <article class="item-card">
          <div>
            <h3>${player.name}</h3>
            <p>${player.city} · Level ${player.level} · Vermögen ${euro.format(player.cash)} · Immobilien ${player.properties}</p>
          </div>
          <button disabled>${player.tag}</button>
        </article>
      `).join("") : `<article class="item-card"><div><h3>Keine weiteren Charaktere</h3><p>Sobald weitere Charaktere erstellt oder später echte Online-Spieler verbunden sind, erscheinen sie hier.</p></div><button disabled>Leer</button></article>`}
    </div>
  `;
}

function criminalRecordHtml() {
  const records = state.criminalRecord || [];
  const fineOpen = state.unpaidFines || 0;
  const finePaid = state.paidFines || 0;
  return `
    <div class="world-info-panel">
      <article class="item-card">
        <div>
          <h3>Führungszeugnis</h3>
          <p>Einträge aus riskanten Aktionen. Offene Bußgelder: ${euro.format(fineOpen)} · Bereits bezahlt: ${euro.format(finePaid)}.</p>
        </div>
        <button disabled>${records.length} Einträge</button>
      </article>
      ${records.length ? records.map((record) => `
        <article class="item-card">
          <div>
            <h3>${record.title}</h3>
            <p>Tag ${record.day || state.day} · ${record.text} · Bußgeld ${euro.format(record.fine || 0)}${record.banUntil && Date.now() < record.banUntil ? ` · Bahnhofssperre noch ${formatRemainingMs(record.banUntil - Date.now())}` : ""}</p>
          </div>
          <button disabled>Akteneintrag</button>
        </article>
      `).join("") : `<article class="item-card"><div><h3>Keine Einträge</h3><p>Dein Führungszeugnis ist aktuell leer.</p></div><button disabled>Sauber</button></article>`}
    </div>
  `;
}

function bindCharacterHubContent(root, section) {
  root.querySelector('button[data-kind="wardrobe-open"]')?.addEventListener("click", openWardrobeDialog);
  root.querySelector("[data-wardrobe-open]")?.addEventListener("click", openWardrobeDialog);
  root.querySelector("[data-character-info]")?.addEventListener("click", openCharacterInfoDialog);
  root.querySelector("[data-partner-open]")?.addEventListener("click", openPartnerCareDialog);
  root.querySelectorAll('button[data-kind="barber"]').forEach((button) => {
    button.addEventListener("click", () => buyBarberService(barberServices[Number(button.dataset.index)]));
  });
  root.querySelectorAll('button[data-kind="tattoo-area"]').forEach((button) => {
    button.addEventListener("click", () => openTattooMotifs(button.dataset.index));
  });
  root.querySelectorAll("[data-skill-node]").forEach((button) => {
    button.addEventListener("click", () => upgradeSkillFromTree(button.dataset.skillNode));
  });
  root.querySelector("[data-skill-tree-expand]")?.addEventListener("click", expandSkillTree);
  root.querySelectorAll("[data-advanced-skill-node]").forEach((button) => {
    button.addEventListener("click", () => upgradeAdvancedSkill(button.dataset.advancedSkillNode));
  });
  root.querySelectorAll('button[data-kind="achievement"]:not(:disabled)').forEach((button) => {
    const achievements = achievementDefinitions();
    button.addEventListener("click", () => claimAchievement(achievements[Number(button.dataset.index)]));
  });
  if (section === "inventory") bindInventoryActions(root);
  root.querySelector("[data-bank-withdraw]")?.addEventListener("click", () => playerBankAmountAction("withdraw"));
  root.querySelector("[data-bank-deposit]")?.addEventListener("click", () => playerBankAmountAction("deposit"));
  root.querySelector("[data-bank-loan-request]")?.addEventListener("click", requestPlayerLoan);
  root.querySelector("[data-bank-appointment]")?.addEventListener("click", openBankAppointment);
  root.querySelector("[data-bank-repay]")?.addEventListener("click", repayCustom);
  root.querySelector("[data-bank-tax-pay]")?.addEventListener("click", () => payDueTaxes(calculateTaxDue()));
  root.querySelector("[data-bank-transfer]")?.addEventListener("click", openPlayerTransferDialog);
}

function refreshOpenCharacterHub(fallbackSection = "overview") {
  if (!els.dialog?.open || !els.dialog.querySelector(".character-hub")) return false;
  const active = els.dialog.querySelector("[data-character-section].gold")?.dataset.characterSection || fallbackSection;
  openCharacterHub(active);
  return true;
}

function captureDialogScrollState() {
  if (!els.dialog?.open) return null;
  const hub = els.dialog.querySelector(".character-hub");
  const content = els.dialog.querySelector(".character-hub-content");
  const inventoryGrid = els.dialog.querySelector("[data-inventory-slot-grid]");
  const deviceScreen = els.dialog.querySelector(".device-screen");
  return {
    dialog: els.dialog.scrollTop || 0,
    hub: hub?.scrollTop || 0,
    content: content?.scrollTop || 0,
    inventoryGrid: inventoryGrid?.scrollTop || 0,
    deviceScreen: deviceScreen?.scrollTop || 0
  };
}

function restoreDialogScrollState(snapshot) {
  if (!snapshot || !els.dialog?.open) return;
  requestAnimationFrame(() => {
    const hub = els.dialog.querySelector(".character-hub");
    const content = els.dialog.querySelector(".character-hub-content");
    const inventoryGrid = els.dialog.querySelector("[data-inventory-slot-grid]");
    const deviceScreen = els.dialog.querySelector(".device-screen");
    els.dialog.scrollTop = snapshot.dialog || 0;
    if (hub) hub.scrollTop = snapshot.hub || 0;
    if (content) content.scrollTop = snapshot.content || 0;
    if (inventoryGrid) inventoryGrid.scrollTop = snapshot.inventoryGrid || 0;
    if (deviceScreen) deviceScreen.scrollTop = snapshot.deviceScreen || 0;
  });
}

function refreshAfterStateChange(fallbackSection = "") {
  const scrollSnapshot = captureDialogScrollState();
  render();
  if (fallbackSection) refreshOpenCharacterHub(fallbackSection);
  restoreDialogScrollState(scrollSnapshot);
}

