  const appearance = state?.appearance || defaultAppearance(gender);
  const outfit = { ...defaultAppearance(gender).outfit, ...(appearance.outfit || {}), ...(previewOutfit || {}) };
  const skin = appearance.skin || "#c9875f";
  const hair = appearance.hairColor || "#2c1b13";
  const top = outfitTone(outfit.top, "#f3f5ed");
  const pants = outfitTone(outfit.pants, "#244e82");
  const underwear = outfitTone(outfit.underwear, "#355c8c");
  const socks = outfitTone(outfit.socks, "#f2f0e8");
  const shoes = outfitTone(outfit.shoes, "#f1efe4");
  const jacket = outfitTone(outfit.jacket, "#2c3847");
  const hat = outfitTone(outfit.hat, "#244e82");
  const bandana = outfitTone(outfit.bandana, "#151719");
  const mask = outfitTone(outfit.mask, "#151719");
  const accessory = outfitTone(outfit.accessory, "#a92f38");
  const avatarUid = String(`${gender}-${size}-${appearance.skin}-${appearance.hairColor}-${JSON.stringify(outfit)}`).replace(/[^a-z0-9]/gi, "").slice(0, 28) || "default";
  const topText = String(outfit.top || "").toLowerCase();
  const pantsText = String(outfit.pants || "").toLowerCase();
  const jacketText = String(outfit.jacket || "").toLowerCase();
  const hatText = String(outfit.hat || "").toLowerCase();
