function tattooMarksHtml(tattoos = []) {
  const slots = {
    leftArm: [{ x: 55, y: 145, r: -18 }, { x: 50, y: 176, r: -12 }, { x: 57, y: 203, r: -8 }],
    rightArm: [{ x: 165, y: 145, r: 18 }, { x: 170, y: 176, r: 12 }, { x: 163, y: 203, r: 8 }],
    leftLeg: [{ x: 94, y: 238, r: -4 }, { x: 91, y: 276, r: -3 }],
    rightLeg: [{ x: 126, y: 238, r: 4 }, { x: 129, y: 276, r: 3 }],
    neck: [{ x: 110, y: 96, r: 0 }, { x: 102, y: 91, r: -8 }],
    shoulder: [{ x: 82, y: 112, r: -14 }, { x: 138, y: 112, r: 14 }, { x: 110, y: 117, r: 0 }],
    face: [{ x: 92, y: 66, r: -10 }, { x: 132, y: 66, r: 10 }, { x: 112, y: 77, r: 0 }]
  };
  const used = {};
  return (tattoos || []).slice(-18).map((tattoo, index) => {
    const area = tattoo.area || "shoulder";
    const list = slots[area] || slots.shoulder;
    const slotIndex = used[area] || 0;
    used[area] = slotIndex + 1;
    const pos = list[slotIndex % list.length];
    const font = String(tattoo.icon || "").length > 1 ? 8 : 13;
    return `<text x="${pos.x}" y="${pos.y}" transform="rotate(${pos.r} ${pos.x} ${pos.y})" class="avatar-tattoo tattoo-${area}" style="font-size:${font}px">${tattoo.icon || "•"}</text>`;
  }).join("");
}

function wearClothing(itemName) {
  const item = shopMarketCatalog.clothing.find((entry) => entry.item === itemName || entry.name === itemName);
  if (!item?.wear) return addFeed("Dieses Kleidungsstück ist noch nicht zugeordnet.");
  state.appearance ||= defaultAppearance();
  state.appearance.outfit = { ...defaultAppearance().outfit, ...(state.appearance.outfit || {}), ...item.wear };
  addFeed(`${item.name} angezogen.`);
  save();
  render();
}

function isClothingEquipped(item) {
  const entries = Object.entries(item?.wear || {});
  return entries.length > 0 && entries.every(([slot, value]) => (state.appearance?.outfit?.[slot] || "") === value);
}

function toggleWearClothing(itemName) {
  const item = shopMarketCatalog.clothing.find((entry) => entry.item === itemName || entry.name === itemName);
  const wearEntries = Object.entries(item?.wear || {});
  if (!wearEntries.length) return addFeed("Dieses Kleidungsstück ist noch nicht zugeordnet.");
  state.appearance ||= defaultAppearance();
  state.appearance.outfit = { ...defaultAppearance().outfit, ...(state.appearance.outfit || {}) };
  const wasEquipped = wearEntries.every(([slot, value]) => state.appearance.outfit[slot] === value);
  if (wasEquipped) {
    wearEntries.forEach(([slot, value]) => {
      if (state.appearance.outfit[slot] === value) state.appearance.outfit[slot] = "";
    });
    addFeed(`${item.name} ausgezogen.`);
  } else {
    wearEntries.forEach(([slot, value]) => { state.appearance.outfit[slot] = value; });
    addFeed(`${item.name} angezogen.`);
  }
  save();
  openWardrobeDialog(wasEquipped ? "" : (item.item || item.name));
  render();
}

function sellWardrobeItem(itemName) {
  const wardrobe = state.wardrobe || [];
  const index = wardrobe.indexOf(itemName);
  if (index < 0) return addFeed("Dieses Kleidungsstück ist nicht mehr im Kleiderschrank.");
  const item = shopMarketCatalog.clothing.find((entry) => entry.item === itemName || entry.name === itemName);
  const value = inventorySellValue(itemName);
  if (!value) return addFeed("Dieses Basis-Kleidungsstück kann nicht verkauft werden.");
  Object.entries(item?.wear || {}).forEach(([slot, equippedValue]) => {
    if (state.appearance?.outfit?.[slot] === equippedValue) state.appearance.outfit[slot] = "";
  });
  wardrobe.splice(index, 1);
  payoutFromTreasury(value);
  recordIncome("sales", value);
  addFeed(`${item?.name || itemName} verkauft: ${euro.format(value)} erhalten.`);
  save();
  openWardrobeDialog();
  render();
}

function openWardrobeDialog(previewItemName = "") {
  const previewItem = shopMarketCatalog.clothing.find((entry) => entry.item === previewItemName || entry.name === previewItemName);
  const previewOutfit = previewItem?.wear || null;
  clearDialogDynamic();
  els.dialog.classList.add("wardrobe-dialog");
  els.dialogTitle.textContent = "Kleiderschrank";
  els.dialogText.textContent = "Beobachten zeigt Kleidung nur als Vorschau. AN/AUS zieht das Kleidungsstück wirklich an oder aus.";
  const closet = document.createElement("div");
  closet.className = "wardrobe-closet";
  const wardrobe = state.wardrobe || [];
  closet.innerHTML = `
    <div class="wardrobe-preview">
      ${avatarHtml("large", previewOutfit)}
      <div class="meta-strip">
        <span>Vorschau: ${previewItem?.name || "Aktueller Look"}</span>
        <span>Kleidung: ${wardrobe.length}</span>
      </div>
    </div>
    <div class="wardrobe-list">
      ${wardrobe.map((itemName, index) => {
        const item = shopMarketCatalog.clothing.find((entry) => entry.item === itemName || entry.name === itemName);
        const equipped = item && isClothingEquipped(item);
        return `
          <article class="item-card wardrobe-card ${equipped ? "equipped" : ""}">
            <div>
              <h3>${item?.name || itemName}</h3>
              <p>${item?.text || "Kleidung aus deiner Garderobe."}${itemIdBadge(itemName)}</p>
            </div>
            <div class="wardrobe-actions">
              <button data-wardrobe-preview="${index}">Beobachten</button>
              <button class="${equipped ? "danger" : ""}" data-wardrobe-toggle="${index}">${equipped ? "AUS" : "AN"}</button>
              <button class="mini-button" data-wardrobe-sell="${index}" title="Verkaufen für ${euro.format(inventorySellValue(itemName))}" ${inventorySellValue(itemName) <= 0 ? "disabled" : ""}>Verkaufen</button>
            </div>
          </article>
        `;
      }).join("") || `<article class="item-card"><div><h3>Leer</h3><p>Kaufe Kleidung im Kleidungsmarkt.</p></div><button disabled>Leer</button></article>`}
    </div>
  `;
  setDialogBack(() => openCharacterHub("overview"));
  els.dialog.append(closet);
  closet.querySelectorAll("[data-wardrobe-preview]").forEach((button) => {
    button.addEventListener("click", () => openWardrobeDialog(wardrobe[Number(button.dataset.wardrobePreview)]));
  });
  closet.querySelectorAll("[data-wardrobe-toggle]").forEach((button) => {
    button.addEventListener("click", () => toggleWearClothing(wardrobe[Number(button.dataset.wardrobeToggle)]));
  });
  closet.querySelectorAll("[data-wardrobe-sell]").forEach((button) => {
    button.addEventListener("click", () => sellWardrobeItem(wardrobe[Number(button.dataset.wardrobeSell)]));
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function openCharacterInfoDialog() {
  clearDialogDynamic();
  els.dialogTitle.textContent = "Charakter-Info";
  els.dialogText.textContent = "Übersicht darüber, womit dein Charakter Geld erwirtschaftet hat.";
  const box = document.createElement("div");
  box.className = "character-info-stats";
  box.innerHTML = earningsInfoHtml();
  setDialogBack(() => openCharacterHub("overview"));
  els.dialog.append(box);
  if (!els.dialog.open) els.dialog.showModal();
}

function earningsInfoHtml() {
  const e = state.earnings || {};
  const rows = [
    ["Lohn", e.salary || 0],
    ["Verkauf allgemein", e.sales || 0],
    ["Vermietung", e.rent || 0],
    ["Autos/Boote/Yachten", e.vehicles || 0],
    ["Gewerbe", e.business || 0],
    ["Börse", (e.exchange || 0) + (e.investments || 0)],
    ["Trading", e.trading || 0],
    ["Casino-Auszahlungen", e.casino || 0],
    ["Illegales Business", state.illegalEarnings || 0],
    ["Schwarzgeld offen", state.dirtyMoney || 0],
    ["Sonstiges", e.other || 0]
  ];
  const total = rows.reduce((sum, [, value]) => sum + value, 0);
  return `
    <div class="meta-strip"><span>Gesamt erwirtschaftet: ${euro.format(total)}</span><span>Level ${state.level || 0}</span></div>
    ${rows.map(([label, value]) => `<article class="item-card"><div><h3>${label}</h3><p>${euro.format(value)}</p></div><button disabled>Info</button></article>`).join("")}
  `;
}

function renderBarber() {
  if (!els.barberPanel || !state) return;
  els.barberPanel.innerHTML = `
    <div class="character-studio">${avatarHtml()}<div><h3>Friseur</h3><p>Haare und Bart anpassen. Preise sind typische 2026-Spielwerte nach Aufwand.</p></div></div>
    ${barberServices.map((service, index) => card(service.name, `Kosten: ${euro.format(service.price)}.`, "Buchen", index, false, "barber")).join("")}
  `;
  els.barberPanel.querySelectorAll('button[data-kind="barber"]').forEach((button) => {
    button.addEventListener("click", () => buyBarberService(barberServices[Number(button.dataset.index)]));
  });
}

function buyBarberService(service) {
  if (!pay(service.price)) return addFeed(`Für ${service.name} brauchst du ${euro.format(service.price)}.`);
  state.appearance ||= defaultAppearance();
  Object.assign(state.appearance, service.patch);
  addFeed(`${service.name} erledigt.`, { purchase: { kind: "booking", name: service.name, total: service.price, method: "auto" } });
  save();
  render();
}

function renderTattoo() {
  if (!els.tattooPanel || !state) return;
  els.tattooPanel.innerHTML = `
    ${tattooStudioHtml()}
  `;
  els.tattooPanel.querySelectorAll('button[data-kind="tattoo-area"]').forEach((button) => {
    button.addEventListener("click", () => openTattooMotifs(button.dataset.index));
  });
}

function openTattooMotifs(areaId) {
  const area = tattooAreas.find((entry) => entry.id === areaId);
  if (!area) return addFeed("Diese Körperstelle gibt es nicht.");
  clearDialogDynamic();
  els.dialogTitle.textContent = `${area.name} · Motive`;
  els.dialogText.textContent = "Wähle ein Tattoo-Motiv. Nach dem Stechen wird es sichtbar auf deiner Figur angezeigt.";
  const list = document.createElement("div");
  list.className = "market-list tattoo-motif-list";
  list.innerHTML = tattooMotifs.map((motif, index) => `
    <article class="item-card tattoo-motif-card">
      <div class="tattoo-preview">${motif.icon}</div>
      <div>
        <h3>${motif.name}</h3>
        <p>${motif.text} Kosten: ${euro.format(tattooPriceForArea(motif, area))}.</p>
      </div>
      <button data-kind="tattoo-motif" data-index="${index}">Stechen</button>
    </article>
  `).join("");
  setDialogBack(() => openCharacterHub("tattoo"));
  els.dialog.append(list);
  list.querySelectorAll('button[data-kind="tattoo-motif"]').forEach((button) => {
    button.addEventListener("click", () => buyTattoo(area, tattooMotifs[Number(button.dataset.index)]));
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function tattooPriceForArea(motif, area) {
  const areaFactor = { face: 1.45, neck: 1.25, shoulder: 1.18, leftArm: 1, rightArm: 1, leftLeg: 1.08, rightLeg: 1.08 }[area.id] || 1;
  return Math.round(motif.price * areaFactor);
}

function buyTattoo(area, motif) {
  const price = tattooPriceForArea(motif, area);
  if (!pay(price)) return addFeed(`Für ${motif.name} brauchst du ${euro.format(price)}.`);
  state.appearance ||= defaultAppearance();
  state.appearance.tattoos ||= [];
  state.appearance.tattoos.push({ name: motif.name, icon: motif.icon, motif: motif.id, area: area.id, areaName: area.name, day: state.day, price });
  addFeed(`${motif.name} auf ${area.name} gestochen.`, { purchase: { kind: "booking", name: `${motif.name} · ${area.name}`, total: price, method: "auto" } });
  save();
  render();
  openTattooMotifs(area.id);
}

function renderSkills() {
  if (!els.skillGrid) return;
  els.skillGrid.innerHTML = skillTreeHtml();
  els.skillGrid.querySelectorAll("[data-skill-node]").forEach((button) => button.addEventListener("click", () => upgradeSkillFromTree(button.dataset.skillNode)));
}

function openSkill(name) {
  const entry = skills.find(([skill]) => skill === name);
  els.dialogTitle.textContent = `${name} (${state.skills[name]}/10)`;
  const cost = skillUpgradeCost(name);
  els.dialogText.textContent = `${entry[1]} Freie Skillpunkte: ${state.skillPoints}. Nächste Stufe kostet ${cost} Punkt${cost === 1 ? "" : "e"}.`;
  els.dialog.showModal();
  if (state.skillPoints >= cost && state.skills[name] < 10) {
    const button = document.createElement("button");
    button.className = "primary-button";
    button.textContent = `Verbessern (${cost})`;
    button.onclick = () => {
      state.skillPoints -= cost;
      improveSkill(name);
      els.dialog.close();
      addFeed(`${name} wurde verbessert.`);
      save();
      render();
    };
    els.dialog.appendChild(button);
  }
}

function skillUpgradeCost(name) {
  const level = state.skills?.[name] || 1;
  if (level >= 9) return 5;
  if (level >= 7) return 4;
  if (level >= 5) return 3;
  if (level >= 3) return 2;
  return 1;
}

function baseSkillTreeComplete() {
  return skills.every(([name]) => (state.skills?.[name] || 1) >= 10);
}

function advancedSkillNames() {
  return ["Kraft", "Fahren", "Finanzen", "Verhandlung", "Ausdauer"];
}

function skillTreeHtml() {
  state.skillTreeTier ||= 1;
  state.advancedSkills ||= {};
  const rows = [
    ["Kraft", "Ausdauer", "Gesundheit", "Disziplin"],
    ["Kommunikation", "Charisma", "Soziales", "Stresskontrolle"],
    ["Bildung", "Intelligenz", "Technik", "Kreativität"],
    ["Finanzen", "Organisation", "Verhandlung", "Recht"],
    ["Handwerk", "Fahren", "Unternehmertum", "Straßenwissen"]
  ];
  return `
    <div class="skill-tree">
      <div class="skill-tree-head">
        <h3>Skillbaum</h3>
        <span>Freie Punkte: ${state.skillPoints || 0}</span>
      </div>
      ${rows.map((row, rowIndex) => `
        <div class="skill-tree-row" style="--row:${rowIndex}">
          ${row.map((name) => {
            const level = state.skills?.[name] || 1;
            const cost = skillUpgradeCost(name);
            const locked = state.skillPoints < cost || level >= 10;
            return `<button class="skill-node ${level >= 10 ? "maxed" : ""}" data-skill-node="${name}" ${locked ? "disabled" : ""}>
              <strong>${level}/10</strong><span title="${name}">${skillLabel(name)}</span><small>${level >= 10 ? "Max" : `${cost} Pkt.`}</small>
            </button>`;
          }).join("")}
        </div>
      `).join("")}
      ${baseSkillTreeComplete() && state.skillTreeTier < 2 ? `
        <button class="primary-button" data-skill-tree-expand>Neuer Skillbaum verfügbar</button>
      ` : ""}
      ${state.skillTreeTier >= 2 ? `
        <div class="skill-tree-head advanced">
          <h3>Skillbaum II</h3>
          <span>10 freie Punkte pro Stufe</span>
        </div>
        <div class="skill-tree-row advanced">
          ${advancedSkillNames().map((name) => {
            const level = state.advancedSkills?.[name] || 0;
            const locked = (state.skillPoints || 0) < 10 || level >= 10;
            return `<button class="skill-node advanced ${level >= 10 ? "maxed" : ""}" data-advanced-skill-node="${name}" ${locked ? "disabled" : ""}>
              <strong>${level}/10</strong><span>${skillLabel(name)}</span><small>${level >= 10 ? "Max" : "10 Pkt."}</small>
            </button>`;
          }).join("")}
        </div>
      ` : ""}
    </div>
  `;
}

function skillLabel(name) {
  return {
    Kommunikation: "Kommu...",
    Stresskontrolle: "Stress",
    Unternehmertum: "Unternehm.",
    Straßenwissen: "Straße",
    Organisation: "Organis.",
    Verhandlung: "Verhandl.",
    Intelligenz: "Intell.",
    Kreativität: "Kreativ."
  }[name] || name;
}

function upgradeSkillFromTree(name) {
  const cost = skillUpgradeCost(name);
  if ((state.skills?.[name] || 1) >= 10) return addFeed(`${name} ist bereits maximal.`);
  if ((state.skillPoints || 0) < cost) return addFeed(`${name} braucht ${cost} Skillpunkte.`);
  state.skillPoints -= cost;
  improveSkill(name);
  addFeed(`${name} im Skillbaum verbessert.`);
  save();
  render();
  if (els.dialog.open) openCharacterHub("skills");
}

function expandSkillTree() {
  if (!baseSkillTreeComplete()) return addFeed("Dafür müssen alle normalen Skills auf 10 sein.");
  state.skillTreeTier = 2;
  state.advancedSkills ||= {};
  advancedSkillNames().forEach((name) => state.advancedSkills[name] ||= 0);
  addFeed("Skillbaum II freigeschaltet.");
  save();
  if (els.dialog.open) openCharacterHub("skills");
  else render();
}

function upgradeAdvancedSkill(name) {
  state.advancedSkills ||= {};
  const level = state.advancedSkills[name] || 0;
  if (level >= 10) return addFeed(`${name} II ist bereits maximal.`);
  if ((state.skillPoints || 0) < 10) return addFeed(`${name} II braucht 10 freie Skillpunkte.`);
  state.skillPoints -= 10;
  state.advancedSkills[name] = level + 1;
  addFeed(`${name} II verbessert. 10 freie Skillpunkte verbraucht.`);
  save();
  if (els.dialog.open) openCharacterHub("skills");
  else render();
}



function createLogisticsBusinessState() {
  return {
    employees: 2,
    skillPoints: 0,
    skills: { procurement: 0, inspection: 0, conveyor: 0, dispatch: 0 },
    stage: "idle",
    stageEndsAt: 0,
    shipment: null,
    stats: { cycles: 0, packagesBought: 0, packagesSold: 0, revenue: 0, costs: 0, profit: 0, bestOrder: 0 },
    message: "Zwei kostenlose Mitarbeiter warten auf den ersten Auftrag.",
    log: []
  };
}

function normalizeLogisticsBusinessState(value) {
  const base = createLogisticsBusinessState();
  const raw = value && typeof value === "object" ? value : {};
  const next = { ...base, ...raw };
  next.employees = clamp(Math.round(Number(next.employees || 2)), 2, LOGISTICS_EMPLOYEE_MAX);
  next.skillPoints = Math.max(0, Math.round(Number(next.skillPoints || 0)));
  next.skills = { ...base.skills, ...(raw.skills || {}) };
  Object.keys(base.skills).forEach((branch) => next.skills[branch] = clamp(Math.round(Number(next.skills[branch] || 0)), 0, LOGISTICS_SKILL_BRANCH_MAX));
  next.stats = { ...base.stats, ...(raw.stats || {}) };
  Object.keys(base.stats).forEach((key) => next.stats[key] = Math.max(0, Number(next.stats[key] || 0)));
  next.log = Array.isArray(raw.log) ? raw.log.slice(0, 18) : [];
  const allowed = ["idle", "incoming", "delivery-ready", "receiving", "inspection-ready", "inspecting", "storage-ready", "storing", "packing-ready", "packing", "shipping-ready", "shipping", "payment"];
  if (!allowed.includes(next.stage)) next.stage = "idle";
  if (next.stage !== "idle" && !next.shipment) next.stage = "idle";
  next.stageEndsAt = Math.max(0, Number(next.stageEndsAt || 0));
  return next;
}

function logisticsState() {
  const current = state.logisticsBusiness;
  const normalized = normalizeLogisticsBusinessState(current);
  if (current && typeof current === "object") {
    Object.keys(current).forEach((key) => delete current[key]);
    Object.assign(current, normalized);
    state.logisticsBusiness = current;
    return current;
  }
  state.logisticsBusiness = normalized;
  return state.logisticsBusiness;
}

function logisticsInvestedSkills(data = logisticsState()) {
  return Object.values(data.skills || {}).reduce((sum, value) => sum + Number(value || 0), 0);
}

function logisticsEmployeeCost(data = logisticsState()) {
  return Math.round(2400 * Math.pow(1.42, Math.max(0, data.employees - 2)));
}

function logisticsStageInfo(stage = logisticsState().stage) {
  return {
    idle: { label: "Bereit", action: "Neue Ware kaufen", icon: "📦", progress: 0 },
    incoming: { label: "Lkw fährt an", action: "Warten", icon: "🚚", progress: 12 },
    "delivery-ready": { label: "Lieferung angekommen", action: "Ware annehmen", icon: "📥", progress: 22 },
    receiving: { label: "Ware wird angenommen", action: "Warten", icon: "🧾", progress: 32 },
    "inspection-ready": { label: "Prüfung bereit", action: "Ware durchsuchen", icon: "🔍", progress: 40 },
    inspecting: { label: "Ware wird geprüft", action: "Warten", icon: "🔎", progress: 50 },
    "storage-ready": { label: "Einlagerung bereit", action: "Ware verräumen", icon: "🏷️", progress: 58 },
    storing: { label: "Ware läuft ins Lager", action: "Warten", icon: "🏭", progress: 67 },
    "packing-ready": { label: "Verpackung bereit", action: "Ware verpacken", icon: "📦", progress: 72 },
    packing: { label: "Pakete werden verpackt", action: "Warten", icon: "🧰", progress: 80 },
    "shipping-ready": { label: "Versand bereit", action: "Ware verschicken", icon: "🚛", progress: 86 },
    shipping: { label: "Auslieferung läuft", action: "Warten", icon: "🚚", progress: 93 },
    payment: { label: "Zahlung wird verarbeitet", action: "Warten", icon: "💶", progress: 98 }
  }[stage] || { label: "Bereit", action: "Neue Ware kaufen", icon: "📦", progress: 0 };
}

function logisticsStageSkill(stage, data = logisticsState()) {
  if (["incoming", "receiving"].includes(stage)) return data.skills.procurement;
  if (stage === "inspecting") return data.skills.inspection;
  if (["storing", "packing"].includes(stage)) return data.skills.conveyor;
  return data.skills.dispatch;
}

function logisticsEmployeeProgress(data = logisticsState()) {
  const employees = clamp(Math.round(Number(data.employees || 2)), 2, LOGISTICS_EMPLOYEE_MAX);
  return clamp((employees - 2) / Math.max(1, LOGISTICS_EMPLOYEE_MAX - 2), 0, 1);
}

function logisticsStageDurationMs(stage, data = logisticsState()) {
  const base = { incoming: 9000, receiving: 6500, inspecting: 8000, storing: 7000, packing: 7500, shipping: 9000, payment: 6000 }[stage] || 5000;
  const employeeProgress = logisticsEmployeeProgress(data);
  const skillReduction = Math.min(.35, logisticsStageSkill(stage, data) * .0125);
  const skilledBase = Math.max(1000, Math.round(base * (1 - skillReduction)));
  if (Number(data.employees || 2) >= LOGISTICS_EMPLOYEE_MAX) return 1000;
  return Math.max(1000, Math.round(skilledBase - (skilledBase - 1000) * employeeProgress));
}

function logisticsTeamSpeedInfo(data = logisticsState()) {
  const employees = clamp(Math.round(Number(data.employees || 2)), 2, LOGISTICS_EMPLOYEE_MAX);
  const progress = logisticsEmployeeProgress(data);
  const packingDuration = logisticsStageDurationMs("packing", data);
  return {
    employees,
    progress,
    percent: Math.round(progress * 100),
    packingDuration,
    durationLabel: `${(packingDuration / 1000).toLocaleString("de-DE", { minimumFractionDigits: packingDuration % 1000 ? 1 : 0, maximumFractionDigits: 1 })} Sek.`,
    maxed: employees >= LOGISTICS_EMPLOYEE_MAX
  };
}

function logisticsProcurementCost(units, data = logisticsState()) {
  const raw = Array.from({ length: units }, () => randomInt(48, 118)).reduce((sum, value) => sum + value, 0);
  return Math.max(units * 28, Math.round(raw * (1 - data.skills.procurement * .008)));
}

function logisticsExpectedRevenue(shipment, data = logisticsState()) {
  const values = Array.isArray(shipment?.packageValues) ? shipment.packageValues : [];
  const quality = 1 + data.skills.inspection * .006;
  const dispatch = 1 + data.skills.dispatch * .008;
  return Math.round(values.reduce((sum, value) => sum + Number(value || 0), 0) * quality * dispatch);
}

function pushLogisticsLog(text) {
  const data = logisticsState();
  data.log.unshift({ at: Date.now(), text: String(text || "") });
  data.log = data.log.slice(0, 18);
}

function beginLogisticsTimedStage(stage, message) {
  const data = logisticsState();
  data.stage = stage;
  data.stageEndsAt = Date.now() + logisticsStageDurationMs(stage, data);
  data.message = message;
  pushLogisticsLog(message);
  save();
  refreshLogisticsDialog(true);
  ensureLogisticsWorkTimer();
}

function buyLogisticsShipment(units = 1) {
  const data = logisticsState();
  normalizeLogisticsProgress();
  if (data.stage !== "idle") return addFeed("Im Logistikzentrum läuft bereits ein Auftrag.");
  const quantity = clamp(Math.round(Number(units || 1)), 1, 5);
  const cost = logisticsProcurementCost(quantity, data);
  if (!pay(cost, false, { target: "treasury", taxRate: .19 })) return addFeed(`Für diese Warenlieferung brauchst du ${euro.format(cost)}.`);
  const packageValues = Array.from({ length: quantity }, () => randomInt(100, 300));
  data.shipment = { units: quantity, cost, packageValues, boughtAt: Date.now(), revenue: 0 };
  data.stats.packagesBought += quantity;
  data.stats.costs += cost;
  data.stage = "incoming";
  data.stageEndsAt = Date.now() + logisticsStageDurationMs("incoming", data);
  data.message = `${quantity} Paket${quantity === 1 ? "" : "e"} bestellt. Der Liefer-Lkw ist unterwegs.`;
  pushLogisticsLog(`${quantity} Paket${quantity === 1 ? "" : "e"} für ${euro.format(cost)} eingekauft.`);
  addFeed(`Logistikzentrum: ${quantity} Paket${quantity === 1 ? "" : "e"} für ${euro.format(cost)} bestellt.`);
  save();
  refreshLogisticsDialog(true);
  ensureLogisticsWorkTimer();
}

function logisticsReadyAction() {
  const data = logisticsState();
  const next = {
    "delivery-ready": ["receiving", "Die Mitarbeiter nehmen die Lieferung an und erfassen die Ware."],
    "inspection-ready": ["inspecting", "Die Ware wird geöffnet, geprüft und mit dem Auftrag abgeglichen."],
    "storage-ready": ["storing", "Die geprüfte Ware läuft über das Förderband in das Lager."],
    "packing-ready": ["packing", "Die Ware wird kommissioniert, verpackt und beschriftet."],
    "shipping-ready": ["shipping", "Der Ausgangs-Lkw übernimmt die fertigen Pakete."]
  }[data.stage];
  if (!next) return;
  beginLogisticsTimedStage(next[0], next[1]);
}

function completeLogisticsOrder() {
  const data = logisticsState();
  const shipment = data.shipment;
  if (!shipment) {
    data.stage = "idle";
    data.stageEndsAt = 0;
    return;
  }
  const revenue = logisticsExpectedRevenue(shipment, data);
  const profit = revenue - Number(shipment.cost || 0);
  payoutFromTreasury(revenue);
  recordIncome("business", revenue);
  data.stats.cycles += 1;
  data.stats.packagesSold += Number(shipment.units || 0);
  data.stats.revenue += revenue;
  data.stats.profit += profit;
  data.stats.bestOrder = Math.max(data.stats.bestOrder, revenue);
  data.skillPoints += 1;
  data.message = `${shipment.units} Paket${shipment.units === 1 ? "" : "e"} verkauft: ${euro.format(revenue)} Umsatz, ${euro.format(profit)} Gewinn. +1 Logistik-Skillpunkt.`;
  pushLogisticsLog(data.message);
  data.shipment = null;
  data.stage = "idle";
  data.stageEndsAt = 0;
  addXp(20, "Logistikauftrag");
  addFeed(`Logistikzentrum abgeschlossen: ${euro.format(revenue)} erhalten, Gewinn ${euro.format(profit)}. +1 Logistik-Skillpunkt.`, { purchase: { kind: "sell", title: "Logistikauftrag abgeschlossen", name: `${data.stats.packagesSold} Pakete gesamt verkauft`, total: revenue, method: "Geschäftskonto", icon: "🚚" } });
}

function normalizeLogisticsProgress() {
  const data = logisticsState();
  let changed = false;
  const now = Date.now();
  while (data.stageEndsAt > 0 && now >= data.stageEndsAt) {
    changed = true;
    data.stageEndsAt = 0;
    if (data.stage === "incoming") { data.stage = "delivery-ready"; data.message = "Der Liefer-Lkw steht am Tor. Nimm die Ware an."; }
    else if (data.stage === "receiving") { data.stage = "inspection-ready"; data.message = "Die Ware ist erfasst. Starte jetzt die Warenprüfung."; }
    else if (data.stage === "inspecting") { data.stage = "storage-ready"; data.message = "Prüfung bestanden. Die Ware kann verräumt werden."; }
    else if (data.stage === "storing") { data.stage = "packing-ready"; data.message = "Ware eingelagert. Kommissioniere und verpacke den Auftrag."; }
    else if (data.stage === "packing") { data.stage = "shipping-ready"; data.message = "Pakete fertig. Übergib sie an den Versand-Lkw."; }
    else if (data.stage === "shipping") {
      data.stage = "payment";
      data.stageEndsAt = now + logisticsStageDurationMs("payment", data);
      data.message = "Lieferung ist unterwegs. Die Zahlung wird nach Zustellung freigegeben.";
      continue;
    } else if (data.stage === "payment") {
      completeLogisticsOrder();
    } else break;
  }
  if (changed) save();
  return changed;
}

function logisticsSkillInfo(branch, data = logisticsState()) {
  const points = Number(data.skills[branch] || 0);
  return {
    procurement: { icon: "🛒", name: "Einkauf", text: "Senkt Einkaufskosten und beschleunigt Lieferungen.", detail: `-${Math.round(points * .8)} % Einkauf` },
    inspection: { icon: "🔎", name: "Prüfung", text: "Prüft schneller und steigert den Warenwert.", detail: `+${Math.round(points * .6)} % Warenwert` },
    conveyor: { icon: "⚙️", name: "Fördertechnik", text: "Beschleunigt Einlagerung und Verpackung.", detail: `Stufe ${points}/${LOGISTICS_SKILL_BRANCH_MAX}` },
    dispatch: { icon: "🚛", name: "Versand", text: "Beschleunigt Versand und erhöht den Verkaufspreis.", detail: `+${Math.round(points * .8)} % Verkauf` }
  }[branch];
}

function logisticsStageActionHtml(data) {
  const stage = data.stage;
  if (stage === "idle") return `<div class="logistics-buy-panel"><label>Pakete pro Lieferung<select data-logistics-units><option value="1">1 Paket</option><option value="2">2 Pakete</option><option value="3">3 Pakete</option><option value="4">4 Pakete</option><option value="5">5 Pakete</option></select></label><button class="primary-button" data-logistics-buy>Ware einkaufen</button></div>`;
  if (["delivery-ready", "inspection-ready", "storage-ready", "packing-ready", "shipping-ready"].includes(stage)) return `<button class="primary-button logistics-stage-action" data-logistics-action>${logisticsStageInfo(stage).action}</button>`;
  return `<button class="mini-button" disabled>${logisticsStageInfo(stage).label} · <span data-logistics-countdown>${formatRemainingMs(Math.max(0, data.stageEndsAt - Date.now()))}</span></button>`;
}

function logisticsWarehouseVisualHtml(data) {
  const stage = data.stage;
  const shipmentUnits = Number(data.shipment?.units || 0);
  const packageIcons = Array.from({ length: Math.max(1, shipmentUnits) }, (_, index) => `<span class="logistics-package p${index + 1}">📦</span>`).join("");
  return `<div class="logistics-warehouse stage-${stage}" data-logistics-visual>
    <div class="logistics-map-grid" aria-hidden="true"></div>
    <div class="logistics-building-label">LB LOGISTIKZENTRUM</div>
    <div class="logistics-flow-label flow-in"><span>01</span><b>Wareneingang</b></div>
    <div class="logistics-flow-label flow-out"><span>05</span><b>Warenausgang</b></div>
    <div class="logistics-truck inbound"><span>🚚</span><small>ANLIEFERUNG</small></div>
    <div class="logistics-belt belt-a">${packageIcons}</div>
    <div class="logistics-station inspect"><em>02</em><span>🔍</span><small>PRÜFUNG</small></div>
    <div class="logistics-belt belt-b">${packageIcons}</div>
    <div class="logistics-station storage"><em>03</em><span>🏷️</span><small>LAGER</small></div>
    <div class="logistics-belt belt-c">${packageIcons}</div>
    <div class="logistics-station packing"><em>04</em><span>🧰</span><small>VERPACKUNG</small></div>
    <div class="logistics-truck outbound"><span>🚛</span><small>VERSAND</small></div>
    <div class="logistics-workers">${Array.from({ length: Math.min(10, data.employees) }, () => "<i>👷</i>").join("")}<b>${data.employees} Mitarbeiter</b></div>
  </div>`;
}

function logisticsDialogHtml() {
  const data = logisticsState();
  normalizeLogisticsProgress();
  const stageInfo = logisticsStageInfo(data.stage);
  const speedInfo = logisticsTeamSpeedInfo(data);
  const invested = logisticsInvestedSkills(data);
  const shipmentRevenue = data.shipment ? logisticsExpectedRevenue(data.shipment, data) : 0;
  const stageProgress = data.stageEndsAt > 0 ? Math.max(stageInfo.progress, Math.min(99, stageInfo.progress + (1 - Math.max(0, data.stageEndsAt - Date.now()) / logisticsStageDurationMs(data.stage, data)) * 8)) : stageInfo.progress;
  return `<section class="logistics-game" data-logistics-root data-logistics-stage="${data.stage}">
    <div class="logistics-topbar">
      <article><small>VERFÜGBARES GELD</small><b>${formatCompactEuro((state.cash || 0) + (state.bank || 0))}</b></article>
      <article><small>AKTUELLE WARE</small><b>${data.shipment ? `${data.shipment.units} Paket${data.shipment.units === 1 ? "" : "e"}` : "Keine"}</b></article>
      <article><small>ERWARTETER UMSATZ</small><b>${shipmentRevenue ? euro.format(shipmentRevenue) : "–"}</b></article>
      <article><small>FIRMENSTATUS</small><b>${data.stats.cycles >= 25 ? "Profi" : data.stats.cycles >= 10 ? "Wachsend" : data.stats.cycles >= 3 ? "Stabil" : "Aufbau"}</b></article>
    </div>
    <div class="logistics-main-grid">
      <section class="logistics-map-panel">
        <div class="logistics-map-head"><div><small>BETRIEBSKARTE</small><h3>Warenfluss im Logistikzentrum</h3></div><span class="logistics-speed-badge">${speedInfo.employees}/20 Mitarbeiter · Verpacken ${speedInfo.durationLabel}</span></div>
        ${logisticsWarehouseVisualHtml(data)}
      </section>
      <div class="logistics-stage-card"><div><span>${stageInfo.icon}</span><div><small>AKTUELLER SCHRITT</small><h3>${stageInfo.label}</h3><p>${escapeHtml(data.message || "Bereit für den nächsten Auftrag.")}</p></div></div><div class="logistics-order-progress"><i data-logistics-progress style="width:${stageProgress}%"></i></div>${logisticsStageActionHtml(data)}</div>
      <aside class="logistics-inventory-panel">
        <div class="logistics-inventory-title"><div><small>UNTER DER BETRIEBSKARTE</small><h3>Firmeninventar</h3></div><b>${speedInfo.maxed ? "MAXIMALES TEMPO" : `TEAMTEMPO ${speedInfo.percent}%`}</b></div>
        <div class="logistics-inventory-stats">
          <span><small>Eingekauft</small><b>${Math.round(data.stats.packagesBought)}</b></span>
          <span><small>Verkauft</small><b>${Math.round(data.stats.packagesSold)}</b></span>
          <span><small>Umsatz</small><b>${formatCompactEuro(data.stats.revenue)}</b></span>
          <span><small>Gewinn</small><b>${formatCompactEuro(data.stats.profit)}</b></span>
          <span><small>Aufträge</small><b>${Math.round(data.stats.cycles)}</b></span>
          <span><small>Bester Auftrag</small><b>${formatCompactEuro(data.stats.bestOrder)}</b></span>
        </div>
        <div class="logistics-staff-card">
          <div class="logistics-team-summary"><div><small>TEAM</small><b>${data.employees}/${LOGISTICS_EMPLOYEE_MAX} Mitarbeiter</b></div><strong>${speedInfo.durationLabel} pro Verpackung</strong></div>
          <div class="logistics-team-progress"><i style="width:${Math.max(4, speedInfo.percent)}%"></i></div>
          <p>Jeder zusätzliche Mitarbeiter macht Anlieferung, Annahme, Prüfung, Einlagerung, Verpackung, Versand und Zahlung schneller. Bei 20/20 dauert jeder zeitgesteuerte Arbeitsschritt exakt 1 Sekunde.</p>
          <button class="mini-button gold" data-logistics-hire ${data.employees >= LOGISTICS_EMPLOYEE_MAX ? "disabled" : ""}>${data.employees >= LOGISTICS_EMPLOYEE_MAX ? "Team vollständig ausgebaut" : `Mitarbeiter einstellen · ${euro.format(logisticsEmployeeCost(data))}`}</button>
        </div>
      </aside>
    </div>
    <div class="logistics-skill-head"><div><small>EIGENER LOGISTIK-SKILLBAUM</small><h3>${invested}/100 investiert · ${data.skillPoints} freie Punkte</h3></div><p>Dieser Skillbaum gilt nur für das Logistikzentrum.</p></div>
    <div class="logistics-skill-grid">${Object.keys(data.skills).map((branch) => { const info = logisticsSkillInfo(branch, data); const points = data.skills[branch]; return `<article><span>${info.icon}</span><h4>${info.name}</h4><b>${points}/${LOGISTICS_SKILL_BRANCH_MAX}</b><div><i style="width:${points / LOGISTICS_SKILL_BRANCH_MAX * 100}%"></i></div><p>${info.text}</p><small>${info.detail}</small><button class="mini-button" data-logistics-upgrade="${branch}" ${data.skillPoints <= 0 || points >= LOGISTICS_SKILL_BRANCH_MAX ? "disabled" : ""}>1 Punkt investieren</button></article>`; }).join("")}</div>
    <details class="logistics-log"><summary>Betriebsprotokoll anzeigen</summary>${data.log.length ? data.log.map((entry) => `<p><span>${new Date(entry.at).toLocaleTimeString("de-DE", { hour: "2-digit", minute: "2-digit", second: "2-digit" })}</span>${escapeHtml(entry.text)}</p>`).join("") : "<p>Noch keine Vorgänge.</p>"}</details>
  </section>`;
}

function openLogisticsCenterDialog() {
  normalizeLogisticsProgress();
  clearDialogDynamic();
  els.dialog.classList.add("logistics-dialog");
  els.dialogTitle.textContent = "Logistikzentrum";
  els.dialogText.textContent = "Kaufe Ware, nimm die Lieferung an, prüfe, lagere, verpacke und verschicke sie. Jede abgeschlossene Lieferung gibt einen eigenen Logistik-Skillpunkt. Mit 20 Mitarbeitern dauert jeder Arbeitsschritt nur 1 Sekunde.";
  const wrap = document.createElement("div");
  wrap.innerHTML = logisticsDialogHtml();
  setDialogBack(openWorkHubDialog, "Arbeitszentrale");
  els.dialog.append(...wrap.children);
  bindLogisticsEvents();
  if (!els.dialog.open) els.dialog.showModal();
  ensureLogisticsWorkTimer();
}

function bindLogisticsEvents() {
  els.dialog.querySelector("[data-logistics-buy]")?.addEventListener("click", () => buyLogisticsShipment(els.dialog.querySelector("[data-logistics-units]")?.value || 1));
  els.dialog.querySelector("[data-logistics-action]")?.addEventListener("click", logisticsReadyAction);
  els.dialog.querySelector("[data-logistics-hire]")?.addEventListener("click", hireLogisticsEmployee);
  els.dialog.querySelectorAll("[data-logistics-upgrade]").forEach((button) => button.addEventListener("click", () => upgradeLogisticsSkill(button.dataset.logisticsUpgrade)));
}

function hireLogisticsEmployee() {
  const data = logisticsState();
  if (data.employees >= LOGISTICS_EMPLOYEE_MAX) return addFeed("Dein Logistikteam ist bereits vollständig ausgebaut.");
  const cost = logisticsEmployeeCost(data);
  if (!pay(cost, false, { target: "treasury", taxRate: .19 })) return addFeed(`Ein weiterer Logistik-Mitarbeiter kostet ${euro.format(cost)}.`);
  const timedStageActive = data.stageEndsAt > Date.now() && !["idle", "delivery-ready", "inspection-ready", "storage-ready", "packing-ready", "shipping-ready"].includes(data.stage);
  const oldDuration = timedStageActive ? logisticsStageDurationMs(data.stage, data) : 0;
  const remainingBeforeHire = timedStageActive ? Math.max(0, data.stageEndsAt - Date.now()) : 0;
  const completedRatio = oldDuration > 0 ? clamp(1 - remainingBeforeHire / oldDuration, 0, 1) : 0;
  data.employees += 1;
  if (timedStageActive) {
    const newDuration = logisticsStageDurationMs(data.stage, data);
    data.stageEndsAt = Date.now() + Math.max(0, Math.round(newDuration * (1 - completedRatio)));
  }
  const speedInfo = logisticsTeamSpeedInfo(data);
  data.message = `Neuer Mitarbeiter eingestellt. ${data.employees}/${LOGISTICS_EMPLOYEE_MAX} Personen arbeiten jetzt im Team. Verpacken dauert aktuell ${speedInfo.durationLabel}`;
  pushLogisticsLog(data.message);
  addFeed(`Logistikzentrum: Mitarbeiter für ${euro.format(cost)} eingestellt. Neues Verpackungstempo: ${speedInfo.durationLabel}`);
  save();
  refreshLogisticsDialog(true);
}

function upgradeLogisticsSkill(branch) {
  const data = logisticsState();
  if (!(branch in data.skills) || data.skillPoints <= 0 || data.skills[branch] >= LOGISTICS_SKILL_BRANCH_MAX) return;
  data.skillPoints -= 1;
  data.skills[branch] += 1;
  data.message = `${logisticsSkillInfo(branch, data).name} auf ${data.skills[branch]}/${LOGISTICS_SKILL_BRANCH_MAX} verbessert.`;
  pushLogisticsLog(data.message);
  save();
  refreshLogisticsDialog(true);
}

function refreshLogisticsDialog(force = false) {
  const root = els.dialog?.querySelector("[data-logistics-root]");
  if (!els.dialog?.open || !root) return false;
  const data = logisticsState();
  const changed = normalizeLogisticsProgress();
  if (force || changed || root.dataset.logisticsStage !== data.stage) {
    const scrollTop = els.dialog.scrollTop;
    openLogisticsCenterDialog();
    els.dialog.scrollTop = scrollTop;
    return true;
  }
  const remaining = Math.max(0, data.stageEndsAt - Date.now());
  root.querySelectorAll("[data-logistics-countdown]").forEach((node) => node.textContent = formatRemainingMs(remaining));
  const info = logisticsStageInfo(data.stage);
  const duration = logisticsStageDurationMs(data.stage, data);
  const progress = data.stageEndsAt > 0 ? Math.max(info.progress, Math.min(99, info.progress + (1 - remaining / duration) * 8)) : info.progress;
  const bar = root.querySelector("[data-logistics-progress]");
  if (bar) bar.style.width = `${progress}%`;
  return false;
}

function ensureLogisticsWorkTimer() {
  if (logisticsWorkTimer) return;
  logisticsWorkTimer = setInterval(() => {
    if (!state) return;
    if (!els.dialog?.open || !els.dialog.querySelector("[data-logistics-root]")) {
      clearInterval(logisticsWorkTimer);
      logisticsWorkTimer = null;
      return;
    }
    refreshLogisticsDialog(false);
  }, 500);
}

function workHubManualStatus() {
  normalizeManualWorkState();
  const session = state.manualWorkSession;
  const cooldown = manualWorkCooldownRemaining();
  if (session?.finished) return `${manualWorkDefinitions[session.type]?.name || "Manuelle Arbeit"}: Ergebnis abholen.`;
  if (session) return `${manualWorkDefinitions[session.type]?.name || "Manuelle Arbeit"}: noch ${formatRemainingMs(Math.max(0, session.endsAt - Date.now()))}.`;
  if (cooldown > 0) return `Manuelle Arbeit noch ${formatRemainingMs(cooldown)} gesperrt.`;
  return "Mine, Elektro und Bau sind bereit.";
}

function openWorkHubDialog() {
  clearDialogDynamic();
  els.dialogTitle.textContent = "Ihr persönlicher Arbeitshelfer";
  els.dialogText.textContent = "Hier findest du Arbeitsstatistik, Skillbaum, automatische Berufe, manuelle Arbeiten und dein Logistikzentrum an einem Ort.";
  const logistics = logisticsState();
  normalizeLogisticsProgress();
  const logisticsStage = logisticsStageInfo(logistics.stage);
  const logisticsText = logistics.stage === "idle"
    ? `${logistics.employees}/20 Mitarbeiter · ${logistics.skillPoints} freie Logistik-Skillpunkte · bereit.`
    : `${logisticsStage.label}: ${logistics.message}`;
  const list = document.createElement("div");
  list.className = "work-helper-hub";
  list.innerHTML = `
    <article><span>📊</span><div><h3>Arbeitsinfo & Skillbaum</h3><p>${state.workSkillPoints || 0} freie Arbeits-Skillpunkte. Statistiken und drei Verbesserungswege.</p></div><button class="mini-button gold" data-work-helper="info">Öffnen</button></article>
    <article><span>💼</span><div><h3>Arbeit automatisch</h3><p>Beruf auswählen, Schicht direkt abschließen und Lohn erhalten.</p></div><button class="mini-button gold" data-work-helper="automatic">Öffnen</button></article>
    <article><span>🧰</span><div><h3>Arbeit manuell</h3><p>${workHubManualStatus()}</p></div><button class="mini-button blue" data-work-helper="manual">Öffnen</button></article>
    <article><span>🚚</span><div><h3>Logistikzentrum</h3><p>${escapeHtml(logisticsText)}</p></div><button class="mini-button blue" data-work-helper="logistics">${logistics.stage === "idle" ? "Starten" : "Öffnen"}</button></article>`;
  setDialogBack(() => { clearDialogDynamic(); els.dialog.close(); }, "Arbeit");
  els.dialog.append(list);
  list.querySelector('[data-work-helper="info"]')?.addEventListener("click", openWorkInfoDialog);
  list.querySelector('[data-work-helper="automatic"]')?.addEventListener("click", openAutomaticWorkDialog);
  list.querySelector('[data-work-helper="manual"]')?.addEventListener("click", openManualWorkDialog);
  list.querySelector('[data-work-helper="logistics"]')?.addEventListener("click", openLogisticsCenterDialog);
  if (!els.dialog.open) els.dialog.showModal();
}

function ensureWorkProgressState() {
  state.workStats ||= { automatic: 0, manual: 0, manualByType: { mine: 0, electrical: 0, construction: 0 } };
  state.workStats.manualByType ||= { mine: 0, electrical: 0, construction: 0 };
  state.workSkillPoints = Math.max(0, Number(state.workSkillPoints || 0));
  state.workSkillTree ||= { time: 0, automatic: 0, manual: 0 };
  ["time", "automatic", "manual"].forEach((branch) => state.workSkillTree[branch] = clamp(Number(state.workSkillTree[branch] || 0), 0, 100));
  return state.workSkillTree;
}

function manualWorkDurationMs() {
  const tree = ensureWorkProgressState();
  return MANUAL_WORK_BASE_DURATION + Math.round(tree.time) * 1000;
}

function automaticWorkBonusPercent() {
  const points = Math.round(ensureWorkProgressState().automatic || 0);
  return points * points;
}

function automaticWorkPay(job) {
  const base = Math.max(0, Number(job?.pay || 0));
  return Math.round(base * (1 + automaticWorkBonusPercent() / 100));
}

function manualWorkYieldMultiplier() {
  const points = Math.round(ensureWorkProgressState().manual || 0);
  return 1 + points * 0.02;
}

function grantWorkSkillPoint(mode, type = "") {
  ensureWorkProgressState();
  state.workSkillPoints += 1;
  if (mode === "automatic") state.workStats.automatic += 1;
  if (mode === "manual") {
    state.workStats.manual += 1;
    if (type && type in state.workStats.manualByType) state.workStats.manualByType[type] += 1;
  }
}

function workSkillBranchInfo(branch) {
  const tree = ensureWorkProgressState();
  const points = Math.round(tree[branch] || 0);
  if (branch === "time") return { title: "Mehr Arbeitszeit", icon: "⏱", detail: `${60 + points} Sekunden manuelle Arbeitszeit`, benefit: `+${points} Sekunden`, text: "Jeder Punkt verlängert jede manuelle Schicht um genau eine Sekunde." };
  if (branch === "automatic") return { title: "Automatischer Lohn", icon: "💼", detail: `+${automaticWorkBonusPercent().toLocaleString("de-DE")}% auf jeden Grundlohn`, benefit: `Stufe ${points}/100`, text: "Der Bonus wächst mit der Ausbildung. Bei 100 Punkten beträgt er +10.000 %." };
  return { title: "Manuelle Ausbeute", icon: "🧰", detail: `${manualWorkYieldMultiplier().toFixed(2).replace(".", ",")}× Material pro Aktion`, benefit: `+${points * 2}%`, text: "Jeder Punkt erhöht Kohle, Auftragswert und Baumaterial um 2 %." };
}

function workInfoHtml() {
  ensureWorkProgressState();
  const stats = state.workStats;
  return `
    <section class="work-info-dashboard">
      <div class="work-info-summary">
        <article><span>Arbeits-Skillpunkte</span><strong>${state.workSkillPoints}</strong><small>Nur durch abgeschlossene Arbeit</small></article>
        <article><span>Automatisch</span><strong>${stats.automatic}</strong><small>abgeschlossene Schichten</small></article>
        <article><span>Manuell</span><strong>${stats.manual}</strong><small>verkaufte Ergebnisse</small></article>
      </div>
      <div class="work-type-stats">
        <span>Mine <b>${stats.manualByType.mine || 0}</b></span>
        <span>Elektro <b>${stats.manualByType.electrical || 0}</b></span>
        <span>Bau <b>${stats.manualByType.construction || 0}</b></span>
      </div>
      <div class="work-skill-tree">
        ${["time", "automatic", "manual"].map((branch) => {
          const info = workSkillBranchInfo(branch);
          const points = Math.round(state.workSkillTree[branch] || 0);
          return `<article class="work-skill-branch ${branch}">
            <span class="work-skill-icon">${info.icon}</span>
            <h3>${info.title}</h3>
            <strong>${points}/100</strong>
            <div class="work-skill-progress"><i style="width:${points}%"></i></div>
            <p>${info.text}</p>
            <small>${info.detail}</small>
            <button class="mini-button gold" data-work-skill-upgrade="${branch}" ${state.workSkillPoints <= 0 || points >= 100 ? "disabled" : ""}>1 Punkt investieren</button>
          </article>`;
        }).join("")}
      </div>
    </section>`;
}

function openWorkInfoDialog() {
  clearDialogDynamic();
  els.dialogTitle.textContent = "Arbeitsinfo & Skillbaum";
  els.dialogText.textContent = "Dieser Skillbaum ist vollständig getrennt vom normalen Charakter-Skillbaum. Jede abgeschlossene automatische oder manuelle Arbeit gibt genau einen Arbeits-Skillpunkt.";
  const panel = document.createElement("div");
  panel.innerHTML = workInfoHtml();
  setDialogBack(openWorkHubDialog, "Arbeitshelfer");
  els.dialog.append(...panel.children);
  els.dialog.querySelectorAll("[data-work-skill-upgrade]").forEach((button) => button.addEventListener("click", () => upgradeWorkSkill(button.dataset.workSkillUpgrade)));
  if (!els.dialog.open) els.dialog.showModal();
}

function upgradeWorkSkill(branch) {
  const tree = ensureWorkProgressState();
  if (!(branch in tree) || state.workSkillPoints <= 0 || tree[branch] >= 100) return;
  state.workSkillPoints -= 1;
  tree[branch] += 1;
  addFeed(`${workSkillBranchInfo(branch).title} auf ${tree[branch]}/100 verbessert.`);
  save();
  openWorkInfoDialog();
  renderJobs();
}

function companySkillLevel() {
  return Math.max(0, Math.min(10, Math.floor(Number(state?.skills?.Unternehmertum || 0))));
}

function automaticJobUnlockStatus(job) {
  const level = companySkillLevel();
  const required = Math.max(0, Math.min(10, Number(job?.companySkill || 0)));
  return {
    level,
    required,
    unlocked: level >= required,
    text: required <= 0
      ? `Einstiegsarbeit · Unternehmen ${level}/10`
      : `Benötigt Unternehmen ${required}/10 · aktuell ${level}/10`
  };
}

function work(job) {
  const unlock = automaticJobUnlockStatus(job);
  if (!unlock.unlocked) return addFeed(`${job.name} ist noch gesperrt. Erhöhe Unternehmen im Skillbaum auf ${unlock.required}/10.`);
  if (state.workedDay === state.day) return addFeed("Du hast heute schon 8 Stunden gearbeitet. Morgen wieder.");
  if (!canWorkAtCurrentPlace()) return openReturnHomeChoice("Arbeiten geht nur in deiner Wohnung, der Notunterkunft oder in einem gebuchten Hotelzimmer.");
  if (state.energy < job.energy) return addFeed("Du bist zu müde für diese Schicht.");
  state.energy -= job.energy;
  state.job = job.name;
  state.pendingSalary = 0;
  state.workDaysThisMonth += 1;
  state.totalWorkDays = (state.totalWorkDays || 0) + 1;
  state.workedDay = state.day;
  const adjustedPay = automaticWorkPay(job);
  payoutFromTreasury(adjustedPay);
  recordIncome("salary", adjustedPay);
  state.salaryPayouts = (state.salaryPayouts || 0) + 1;
  grantWorkSkillPoint("automatic");
  improveSkill(job.skill, Math.random() > 0.55 ? 1 : 0);
  improveCredit(0.5);
  addXp(28, "Arbeit");
  addFeed(`8 Stunden gearbeitet. Lohn direkt ausgezahlt: ${euro.format(adjustedPay)}. +1 Arbeits-Skillpunkt.`);
  save();
  render();
}


/* Eigener Shop, Gefahrensystem und gemeinsamer Online-Markt · 2026-07-21 */
const PLAYER_SHOP_CREATE_COST = 100000;
const PLAYER_SHOP_STORAGE_TIERS = [
  { level: 0, capacity: 0, upgradeCost: 0, label: "Kein Warenlager" },
  { level: 1, capacity: 500, upgradeCost: 100000, label: "Lager Stufe 1" },
  { level: 2, capacity: 1000, upgradeCost: 200000, label: "Lager Stufe 2" },
  { level: 3, capacity: 5000, upgradeCost: 1000000, label: "Lager Stufe 3" }
];
const PLAYER_SHOP_WHOLESALE_MARKETS = ["beverages", "snacks", "groceries", "pharmacy"];
const PLAYER_SHOP_WHOLESALE_ICONS = {
  beverages: "🥤",
  snacks: "🥪",
  groceries: "🛒",
  pharmacy: "💊"
};
const playerShopEuroExact = new Intl.NumberFormat("de-DE", { style: "currency", currency: "EUR", minimumFractionDigits: 2, maximumFractionDigits: 2 });

function playerShopStorageTier(level = ensurePlayerShopState().storageLevel) {
  return PLAYER_SHOP_STORAGE_TIERS.find((entry) => entry.level === Number(level)) || PLAYER_SHOP_STORAGE_TIERS[0];
}

function playerShopStorageUsed(shop = ensurePlayerShopState()) {
  const stored = (shop.wholesaleStock || []).reduce((sum, entry) => sum + Math.max(0, Math.floor(Number(entry.quantity || 0))), 0);
  const listed = (shop.listings || []).filter((entry) => entry.itemKind === "shopstock").reduce((sum, entry) => sum + Math.max(0, Math.floor(Number(entry.quantity || 0))), 0);
  return stored + listed;
}

function playerShopStorageFree(shop = ensurePlayerShopState()) {
  return Math.max(0, playerShopStorageTier(shop.storageLevel).capacity - playerShopStorageUsed(shop));
}

function playerShopWholesaleCatalog() {
  const seen = new Set();
  const result = [];
  PLAYER_SHOP_WHOLESALE_MARKETS.forEach((marketKey) => {
    (shopMarketCatalog[marketKey] || []).forEach((item) => {
      if (!item?.name || !Number(item.price) || !item.effect || seen.has(item.name)) return;
      seen.add(item.name);
      result.push({
        id: `wholesale:${marketKey}:${item.name}`,
        marketKey,
        name: item.name,
        retailPrice: Math.max(.01, Number(item.price)),
        effect: { ...(item.effect || {}) },
        text: item.text || "Großhandelsware für deinen eigenen Shop.",
        icon: PLAYER_SHOP_WHOLESALE_ICONS[marketKey] || "📦"
      });
    });
  });
  return result;
}

function playerShopWholesaleUnitPrice(retailPrice, quantity) {
  const qty = Math.max(20, Math.min(100, Math.floor(Number(quantity || 20))));
  const progress = (qty - 20) / 80;
  const factorAt20 = 1 / 3;
  const factorAt100 = 1 / 15;
  const factor = factorAt20 - (factorAt20 - factorAt100) * progress;
  return Math.max(.05, Math.round(Math.max(.01, Number(retailPrice || 1)) * factor * 100) / 100);
}

function playerShopWholesaleMaxSellPrice(retailPrice) {
  return Math.max(1, Math.floor(Math.max(1, Number(retailPrice || 1)) * (2 / 3)));
}

function playerShopWholesaleStockEntry(item, quantity, unitCost) {
  return {
    id: playerShopId("stock"),
    itemName: item.name,
    quantity: Math.max(1, Math.floor(Number(quantity || 1))),
    unitCost: Math.max(.01, Math.round(Number(unitCost || 0) * 100) / 100),
    retailPrice: Math.max(.01, Number(item.retailPrice || 1)),
    maxSellPrice: playerShopWholesaleMaxSellPrice(item.retailPrice),
    icon: item.icon || "📦",
    text: item.text || "Ware aus dem Großhandel.",
    effect: { ...(item.effect || {}) }
  };
}

function createPlayerShopState() {
  return {
    created: false,
    name: "",
    danger: 8,
    reputation: 50,
    listings: [],
    storageLevel: 0,
    wholesaleStock: [],
    stats: { totalSales: 0, aiSales: 0, onlineSales: 0, legalSales: 0, illegalSales: 0, revenue: 0 },
    lastAiCycleAt: Date.now(),
    processedOnlineOrders: [],
    onlineEnabled: true
  };
}

function normalizePlayerShopSave(value, ownerState = state) {
  const base = createPlayerShopState();
  const shop = value && typeof value === "object" ? value : {};
  shop.created = Boolean(shop.created);
  shop.name = String(shop.name || `${ownerState?.lastName || ownerState?.firstName || "KL"} Shop`).trim().slice(0, 40);
  shop.danger = clamp(Number(shop.danger ?? base.danger), 0, 100);
  shop.reputation = clamp(Number(shop.reputation ?? base.reputation), 0, 100);
  shop.listings = Array.isArray(shop.listings) ? shop.listings.filter((listing) => listing && listing.id && listing.itemName && Number(listing.quantity) > 0).map((listing) => ({
    ...listing,
    id: String(listing.id),
    itemName: String(listing.itemName).slice(0, 100),
    itemKind: String(listing.itemKind || "item"),
    quantity: Math.max(1, Math.floor(Number(listing.quantity || 1))),
    price: Math.max(1, Math.round(Number(listing.price || 1))),
    illegal: Boolean(listing.illegal),
    soldQuantity: Math.max(0, Math.floor(Number(listing.soldQuantity || 0))),
    vehicleMeta: listing.vehicleMeta && typeof listing.vehicleMeta === "object" ? { ...listing.vehicleMeta } : null,
    propertyData: listing.propertyData && typeof listing.propertyData === "object" ? { ...listing.propertyData } : null,
    createdAtMs: Number(listing.createdAtMs || Date.now())
  })) : [];
  shop.storageLevel = Math.max(0, Math.min(3, Math.floor(Number(shop.storageLevel || 0))));
  shop.wholesaleStock = Array.isArray(shop.wholesaleStock) ? shop.wholesaleStock.filter((entry) => entry && entry.itemName && Number(entry.quantity) > 0).map((entry) => ({
    id: String(entry.id || playerShopId("stock")),
    itemName: String(entry.itemName).slice(0, 100),
    quantity: Math.max(1, Math.floor(Number(entry.quantity || 1))),
    unitCost: Math.max(.01, Math.round(Number(entry.unitCost || .01) * 100) / 100),
    retailPrice: Math.max(.01, Number(entry.retailPrice || 1)),
    maxSellPrice: Math.max(1, Math.floor(Number(entry.maxSellPrice || playerShopWholesaleMaxSellPrice(entry.retailPrice || 1)))),
    icon: String(entry.icon || "📦").slice(0, 8),
    text: String(entry.text || "Ware aus dem Großhandel.").slice(0, 240),
    effect: entry.effect && typeof entry.effect === "object" ? { ...entry.effect } : {}
  })) : [];
  shop.stats = { ...base.stats, ...(shop.stats || {}) };
  Object.keys(base.stats).forEach((key) => shop.stats[key] = Math.max(0, Number(shop.stats[key] || 0)));
  shop.lastAiCycleAt = Number(shop.lastAiCycleAt || Date.now());
  shop.processedOnlineOrders = Array.isArray(shop.processedOnlineOrders) ? [...new Set(shop.processedOnlineOrders.map(String))].slice(-250) : [];
  shop.onlineEnabled = shop.onlineEnabled !== false;
  return shop;
}

function ensurePlayerShopState() {
  state.playerShop = normalizePlayerShopSave(state.playerShop, state);
  return state.playerShop;
}

function playerShopId(prefix = "shop") {
  const random = globalThis.crypto?.randomUUID?.() || `${Date.now()}-${Math.random().toString(36).slice(2, 11)}`;
  return `${prefix}-${random}`;
}

function playerShopSellerName() {
  const full = `${state.firstName || ""} ${state.lastName || ""}`.trim();
  return full || "LifeBuilder-Spieler";
}

function playerShopForbiddenItem(name = "") {
  const value = String(name || "").trim().toLowerCase();
  if (/handyguthaben|guthaben(?:karte)?|prepaid|sim(?:[- .]|$)|datenpaket/i.test(value)) return false;
  return /(?:smartphone|(^|\s)handy(?:\s|$)|basic phone|gaming[- ]?pc|high[- ]?end gaming|computer|laptop|rucksack|backpack|reisepass|führerschein|fuehrerschein|bauplanung|bauteam|baugrundstück|baugrundstueck|grundstück|grundstueck|build[- ]?plot|land parcel)/i.test(value);
}

function playerShopIllegalName(name = "") {
  return /waffe|munition|kokain|drogen|hehler|schwarzmarkt|beute|gestohlen|illegal/i.test(String(name));
}

function playerShopSuggestedPrice(entry) {
  if (entry.itemKind === "property") return Math.max(1000, Math.round(Number(entry.propertyValue || entry.price || 1000)));
  if (entry.itemKind === "vehicle") return Math.max(1, Math.round(Number(entry.vehicleValue || vehicleValue(entry.itemName) || entry.price || 500)));
  if (entry.illegal) return Math.max(1, Math.round(Number(entry.sellMin || entry.price || 100)));
  if (entry.wholesale || entry.itemKind === "shopstock") {
    const maxPrice = Math.max(1, Number(entry.maxSellPrice || playerShopWholesaleMaxSellPrice(entry.retailPrice || 1)));
    const marginPrice = Math.ceil(Math.max(1, Number(entry.unitCost || .01) * 2));
    return Math.max(1, Math.min(maxPrice, marginPrice));
  }
  const base = itemBasePrice(entry.itemName || entry.name) || inventorySellValue(entry.itemName || entry.name) * 2;
  return Math.max(1, Math.round(base || 25));
}

function playerShopPropertyBlocked(property) {
  if (!property?.id || state.rentedProperties?.[property.id]) return true;
  const label = `${property.id} ${property.name || ""}`;
  if (propertyType(property) === "garage") return true;
  return /baugrund|grundstück|grundstueck|build[- ]?plot|land parcel|stellplatz/i.test(label);
}

function playerShopEntryCategory(entry) {
  if (entry.illegal || entry.itemKind === "blackmarket") return "hot";
  if (entry.itemKind === "property") return "properties";
  if (entry.itemKind === "vehicle") return "vehicles";
  if (["sim", "credit"].includes(entry.itemKind) || /sim|guthaben|prepaid|datenpaket/i.test(entry.itemName || "")) return "mobile";
  const name=String(entry.itemName||"").toLowerCase();
  if (/wasser|drink|cola|saft|kaffee|tee|getränk|trinken|limonade/i.test(name)) return "drinks";
  if (/essen|salat|sandwich|nudel|pizza|snack|brot|mahlzeit|lebensmittel/i.test(name)) return "food";
  if (/medizin|tablette|vitamin|erste-hilfe|verband|schmerz/i.test(name)) return "health";
  return "other";
}

function playerShopStockCategories() {
  return [["all","Alle","🧺"],["food","Essen","🍽️"],["drinks","Getränke","🥤"],["health","Medizin","💊"],["mobile","SIM & Guthaben","📶"],["vehicles","Fahrzeuge & Boote","🚗"],["properties","Immobilien","🏠"],["hot","Heiße Ware","☠️"],["other","Sonstiges","📦"]];
}

function playerShopAiEligibleListing(listing) {
  if (!listing || listing.illegal || Number(listing.price || 0) > 5000) return false;
  if (["property","vehicle","device","backpack","blackmarket"].includes(listing.itemKind)) return false;
  return playerShopWholesaleCatalog().some((item) => itemMatchesName(item.name, listing.itemName));
}

function playerShopSellableEntries() {
  const inventory = inventoryWorkbenchEntries().filter((entry) => entry.kind !== "blackmarket").map((entry) => ({
    sourceId: entry.id,
    itemName: entry.name,
    itemKind: entry.kind,
    quantity: Math.max(1, Number(entry.count || 1)),
    icon: entry.icon || "📦",
    text: entry.text || "Gegenstand aus deinem Inventar.",
    illegal: playerShopIllegalName(entry.name),
    effect: entry.kind === "consumable" ? { ...(state.consumables?.[entry.name]?.effect || {}) } : null,
    consumableText: entry.kind === "consumable" ? String(state.consumables?.[entry.name]?.text || entry.text || "") : "",
    vehicleValue: entry.kind === "vehicle" ? vehicleValue(entry.name) : 0,
    forbidden: playerShopForbiddenItem(entry.name)
  }));
  const black = (state.blackMarketGoods || []).map((entry,index) => ({
    sourceId: `black:${entry.inventoryId || entry.boughtAt || entry.boughtAtDay || index}`,
    blackIndex:index,
    blackInventoryId:entry.inventoryId || "",
    itemName:entry.name,
    itemKind:"blackmarket",
    quantity:1,
    icon:"☠️",
    text:`Heiße Ware vom Bahnhof · möglicher Shopwert ${euro.format(entry.sellMin || 0)} bis ${euro.format(entry.sellMax || 0)}. Verkauf ausschließlich über deinen Shop.`,
    illegal:true,
    sellMin:entry.sellMin,
    sellMax:entry.sellMax,
    blackData:{...entry},
    forbidden:false
  }));
  const shopStock=(ensurePlayerShopState().wholesaleStock||[]).map((entry)=>({
    sourceId:`shopstock:${entry.id}`,
    shopStockId:entry.id,
    itemName:entry.itemName,
    itemKind:"shopstock",
    quantity:Math.max(1,Number(entry.quantity||1)),
    icon:entry.icon||"📦",
    text:`${entry.text||"Großhandelsware."} Einkauf ${playerShopEuroExact.format(entry.unitCost||0)} · maximaler Shoppreis ${euro.format(entry.maxSellPrice||1)}.`,
    illegal:false,
    effect:{...(entry.effect||{})},
    consumableText:entry.text||"Ware aus deinem Shoplager.",
    wholesale:true,
    unitCost:Number(entry.unitCost||0),
    retailPrice:Number(entry.retailPrice||1),
    maxSellPrice:Number(entry.maxSellPrice||1),
    shopStockData:{...entry},
    forbidden:false
  }));
  const properties=(state.properties||[]).map((id)=>findProperty(id)).filter((property)=>property&&!playerShopPropertyBlocked(property)).map((property)=>({
    sourceId:`property:${property.id}`,
    propertyId:property.id,
    itemName:property.name,
    itemKind:"property",
    quantity:1,
    icon:propertyType(property)==="island"?"🏝️":propertyType(property)==="villa"?"🏛️":"🏠",
    text:`${property.city||state.homeCity||"Deutschland"} · aktueller Immobilienwert ${euro.format(propertyMarketValue(property))}. Räume und Ausbau werden übertragen.`,
    illegal:false,
    propertyValue:propertyMarketValue(property),
    forbidden:false
  }));
  return [...shopStock,...inventory,...properties,...black].filter((entry)=>!entry.forbidden).map((entry)=>({...entry,shopCategory:playerShopEntryCategory(entry)}));
}

function reservePlayerShopStock(entry, quantity) {
  const count=Math.max(1,Math.min(Math.floor(Number(quantity||1)),Math.floor(Number(entry.quantity||1))));
  if (entry.itemKind === "shopstock") {
    const shop=ensurePlayerShopState();
    const stock=shop.wholesaleStock.find((item)=>item.id===entry.shopStockId);
    if (!stock || Number(stock.quantity||0)<count) return null;
    stock.quantity-=count;
    if (stock.quantity<=0) shop.wholesaleStock=shop.wholesaleStock.filter((item)=>item.id!==stock.id);
    return {quantity:count,effect:{...(stock.effect||entry.effect||{})},consumableText:stock.text||entry.consumableText||entry.text||"",shopStockData:{...stock,quantity:count},unitCost:Number(stock.unitCost||entry.unitCost||0),retailPrice:Number(stock.retailPrice||entry.retailPrice||1),maxSellPrice:Number(stock.maxSellPrice||entry.maxSellPrice||1)};
  }
  if (entry.itemKind === "property") {
    const property=findProperty(entry.propertyId);
    if (!property || playerShopPropertyBlocked(property)) return null;
    const id=property.id;
    const propertyData={originalId:id,property:JSON.parse(JSON.stringify(property)),customProperty:JSON.parse(JSON.stringify((state.customProperties||[]).find((item)=>item.id===id)||null)),meta:JSON.parse(JSON.stringify(state.propertyMeta?.[id]||{})),rooms:JSON.parse(JSON.stringify(state.propertyRooms?.[id]||[])),wasActiveHome:state.activeHomePropertyId===id};
    state.properties=(state.properties||[]).filter((value)=>value!==id);
    state.customProperties=(state.customProperties||[]).filter((item)=>item.id!==id);
    delete state.propertyMeta?.[id]; delete state.propertyRooms?.[id]; delete state.rentedProperties?.[id];
    if (property.garageSlots) state.garages=Math.max(0,Number(state.garages||0)-Number(property.garageSlots||0));
    if (propertyData.wasActiveHome) { state.activeHomePropertyId=currentAccessibleHomeProperty()?.id||""; state.homeDashboardActive=!!state.activeHomePropertyId||isEmergencyShelterAvailable(); }
    return {quantity:1,propertyData};
  }
  if (entry.itemKind === "consumable") {
    const owned=state.consumables?.[entry.itemName];
    if (!owned || Number(owned.count||0)<count) return null;
    owned.count-=count; if (owned.count<=0) delete state.consumables[entry.itemName];
    return {quantity:count,effect:{...(owned.effect||entry.effect||{})},consumableText:owned.text||entry.consumableText||entry.text||""};
  }
  if (entry.itemKind === "blackmarket") {
    const index=(state.blackMarketGoods||[]).findIndex((item,idx)=>entry.blackInventoryId?item.inventoryId===entry.blackInventoryId:idx===entry.blackIndex);
    const current=state.blackMarketGoods?.[index]; if (!current) return null;
    state.blackMarketGoods.splice(index,1); return {quantity:1,blackData:{...current}};
  }
  const ownedName=(state.items||[]).find((name)=>itemMatchesName(name,entry.itemName));
  if (!ownedName || inventoryItemCount(ownedName)<count) return null;
  const extra={}; if (vehicleItems().some((vehicle)=>itemMatchesName(vehicle,ownedName))) extra.vehicleMeta={...(state.vehicleMeta?.[ownedName]||{})};
  if (!consumeInventoryItem(ownedName,count)) return null;
  if (extra.vehicleMeta && inventoryItemCount(ownedName)<=0) delete state.vehicleMeta?.[ownedName];
  return {quantity:count,ownedName,...extra};
}

function returnPlayerShopStock(listing, quantity = listing?.quantity || 1) {
  if (!listing) return;
  const count=Math.max(1,Math.floor(Number(quantity||1)));
  if (listing.itemKind === "shopstock") {
    const shop=ensurePlayerShopState(), data=listing.shopStockData||{};
    const existing=shop.wholesaleStock.find((entry)=>entry.itemName===listing.itemName&&Math.abs(Number(entry.unitCost||0)-Number(listing.unitCost||data.unitCost||0))<.001);
    if (existing) existing.quantity+=count; else shop.wholesaleStock.push({id:String(data.id||playerShopId("stock")),itemName:listing.itemName,quantity:count,unitCost:Number(listing.unitCost||data.unitCost||0),retailPrice:Number(listing.retailPrice||data.retailPrice||1),maxSellPrice:Number(listing.maxSellPrice||data.maxSellPrice||1),icon:listing.icon||data.icon||"📦",text:listing.consumableText||listing.text||data.text||"Ware aus dem Großhandel.",effect:{...(listing.effect||data.effect||{})}});
    return;
  }
  if (listing.itemKind === "property") {
    const data=listing.propertyData||{};
    const base=JSON.parse(JSON.stringify(data.customProperty||data.property||{name:listing.itemName,city:state.homeCity,eur:listing.price}));
    let id=String(data.originalId||base.id||playerShopId("property")); if ((state.properties||[]).includes(id)) id=playerShopId("property"); base.id=id;
    state.properties||=[]; state.properties.push(id);
    if (!(realEstateItems||[]).some((entry)=>entry.id===id)) { state.customProperties||=[]; state.customProperties.push(base); }
    state.propertyMeta||={}; state.propertyMeta[id]={...(data.meta||{}),eur:Number(data.meta?.eur||data.property?.eur||listing.price||1000)};
    state.propertyRooms||={}; if (Array.isArray(data.rooms)&&data.rooms.length) state.propertyRooms[id]=JSON.parse(JSON.stringify(data.rooms));
    if (base.garageSlots) state.garages=Number(state.garages||0)+Number(base.garageSlots||0);
    if (data.wasActiveHome) { state.activeHomePropertyId=id; state.homeDashboardActive=true; }
    return;
  }
  if (listing.itemKind === "consumable") {
    state.consumables||={}; const current=state.consumables[listing.itemName]||{count:0,effect:listing.effect||{},text:listing.consumableText||listing.text||""}; current.count+=count; current.effect=listing.effect||current.effect||{}; current.text=listing.consumableText||current.text||listing.text||""; state.consumables[listing.itemName]=current; return;
  }
  if (listing.itemKind === "blackmarket") { state.blackMarketGoods||=[]; for(let i=0;i<count;i+=1) state.blackMarketGoods.push({...(listing.blackData||{name:listing.itemName,sellMin:listing.price,sellMax:Math.round(listing.price*1.4)}),inventoryId:playerShopId("hot"),boughtAt:Date.now(),boughtAtDay:state.day}); return; }
  state.items||=[]; for(let i=0;i<count;i+=1) state.items.push(listing.ownedName||listing.itemName);
  if (listing.vehicleMeta) { state.vehicleMeta||={}; state.vehicleMeta[listing.ownedName||listing.itemName]={...listing.vehicleMeta}; }
}

function grantPlayerShopPurchasedItem(listing, quantity = 1) {
  const count=Math.max(1,Math.floor(Number(quantity||1)));
  if (listing.itemKind === "property") {
    const data=listing.propertyData||{}, base=JSON.parse(JSON.stringify(data.property||{name:listing.itemName,city:state.homeCity,eur:listing.price})), id=playerShopId("online-property");
    base.id=id; base.name=base.name||listing.itemName; base.eur=Number(data.meta?.eur||base.eur||listing.price||1000);
    state.customProperties||=[]; state.customProperties.push(base); state.properties||=[]; state.properties.push(id); state.propertyMeta||={}; state.propertyMeta[id]={...(data.meta||{}),boughtAt:Date.now(),purchasePrice:Number(listing.price||0),eur:base.eur}; state.propertyRooms||={}; if(Array.isArray(data.rooms)&&data.rooms.length) state.propertyRooms[id]=JSON.parse(JSON.stringify(data.rooms)); if(base.garageSlots) state.garages=Number(state.garages||0)+Number(base.garageSlots||0); return;
  }
  if (listing.itemKind === "consumable" || listing.itemKind === "shopstock") { state.consumables||={}; const current=state.consumables[listing.itemName]||{count:0,effect:listing.effect||{},text:listing.consumableText||listing.text||"Online-Marktplatz"}; current.count+=count; current.effect=listing.effect||current.effect||{}; current.text=listing.consumableText||current.text||listing.text||"Online-Marktplatz"; state.consumables[listing.itemName]=current; return; }
  if (listing.itemKind === "blackmarket") { state.blackMarketGoods||=[]; for(let i=0;i<count;i+=1) state.blackMarketGoods.push({...(listing.blackData||{}),inventoryId:playerShopId("hot"),name:listing.itemName,price:Math.max(1,Math.round(Number(listing.price||1)*.7)),sellMin:Math.max(1,Math.round(Number(listing.price||1)*.85)),sellMax:Math.max(2,Math.round(Number(listing.price||1)*1.35)),boughtAt:Date.now(),boughtAtDay:state.day}); return; }
  state.items||=[]; for(let i=0;i<count;i+=1) state.items.push(listing.itemName); if(listing.itemKind==="vehicle"&&listing.vehicleMeta){state.vehicleMeta||={};state.vehicleMeta[listing.itemName]={...listing.vehicleMeta};}
}

function playerShopListingCapacityNeeded(listing, quantity = 1) {
  if (["blackmarket","property","vehicle"].includes(listing.itemKind)) return 0;
  if (["device","backpack"].includes(listing.itemKind)) return 0;
  return Math.max(1,Number(quantity||1));
}

function playerShopSaleDangerDelta(illegal, itemName = "") {
  if (illegal) return randomInt(16, 24);
  if (/essen|salat|sandwich|wasser|drink|vitamin|medizin|geschenk|blume|spielzeug/i.test(itemName)) return -randomInt(7, 11);
  return -randomInt(3, 7);
}

function applyPlayerShopSaleResult(listing, quantity, channel = "ai") {
  const shop=ensurePlayerShopState();
  const managed=shop.listings.find((entry)=>entry.id===listing?.id)||listing;
  if (!managed) return 0;
  const available=Math.max(0,Math.floor(Number(managed.quantity||0))), requested=Math.max(1,Math.floor(Number(quantity||1))), count=Math.min(available,requested);
  if (count<=0) return 0;
  const revenue=Math.max(1,Math.round(Number(managed.price||1)*count));
  state.bank+=revenue; recordIncome(managed.illegal?"other":"business",revenue); shop.stats.totalSales+=count; shop.stats[channel==="online"?"onlineSales":"aiSales"]+=count; shop.stats[managed.illegal?"illegalSales":"legalSales"]+=count; shop.stats.revenue+=revenue; shop.danger=clamp(shop.danger+playerShopSaleDangerDelta(managed.illegal,managed.itemName),0,100); shop.reputation=clamp(shop.reputation+(managed.illegal?-1:1.5),0,100); managed.quantity=Math.max(0,available-count); managed.soldQuantity=Math.max(0,Number(managed.soldQuantity||0))+count; if(managed.quantity<=0) shop.listings=shop.listings.filter((entry)=>entry.id!==managed.id); addFeed(`${managed.itemName} im eigenen Shop verkauft (${channel==="online"?"Online-Spieler":"lokale Laufkundschaft"}): ${euro.format(revenue)}. Restbestand ${managed.quantity}. Gefahr ${Math.round(shop.danger)}%.`); return revenue;
}

function maybeRunPlayerShopRaid(listing) {
  const shop = ensurePlayerShopState();
  if (!listing?.illegal || shop.danger < 78) return false;
  const risk = Math.min(.42, .08 + (shop.danger - 78) / 100);
  if (Math.random() >= risk) return false;
  const fine = randomInt(600, 4200);
  shop.listings = shop.listings.filter((entry) => entry.id !== listing.id);
  shop.danger = clamp(shop.danger - randomInt(25, 42), 0, 100);
  state.debt += fine;
  addFeed(`Kontrolle im eigenen Shop: ${listing.itemName} wurde beschlagnahmt. Strafe ${euro.format(fine)}. Gefahr fällt auf ${Math.round(shop.danger)}%.`);
  deletePlayerShopListingOnline(listing).catch(() => {});
  return true;
}

function maybeRunPlayerShopAiCycle(force = false) {
  const shop=ensurePlayerShopState(); if(!shop.created||!shop.listings.length) return false;
  const now=Date.now(), interval=35000, elapsed=now-Number(shop.lastAiCycleAt||now); if(!force&&elapsed<interval) return false; const cycles=force?1:Math.max(1,Math.min(6,Math.floor(elapsed/interval))); shop.lastAiCycleAt=now; let changed=false;
  for(let i=0;i<cycles;i+=1){const candidates=shop.listings.filter(playerShopAiEligibleListing); if(!candidates.length) break; const listing=candidates[randomInt(0,candidates.length-1)]; const reference=Math.max(1,playerShopSuggestedPrice({...listing,name:listing.itemName})); const priceFactor=Math.max(.08,Math.min(1.15,reference/Math.max(1,listing.price))); const trustFactor=.35+shop.reputation/140; const dangerFactor=Math.max(.3,1-shop.danger/125); const chance=Math.min(.82,.2*priceFactor*trustFactor*dangerFactor+.02); if(Math.random()>chance) continue; const qty=Math.min(Number(listing.quantity||1),Math.random()<.16?2:1); if(applyPlayerShopSaleResult(listing,qty,"ai")<=0) continue; syncPlayerShopListingQuantityOnline(listing).catch(()=>{}); changed=true;}
  if(changed){save();render();} return changed;
}

function stopPlayerShopRuntime() {
  if (playerShopTimer) {
    clearInterval(playerShopTimer);
    playerShopTimer = null;
  }
  if (playerShopOnlineUnsubscribe) {
    try { playerShopOnlineUnsubscribe(); } catch {}
    playerShopOnlineUnsubscribe = null;
  }
}

function startPlayerShopRuntime() {
  stopPlayerShopRuntime();
  playerShopTimer = setInterval(() => {
    if (!els.dialog?.open || !els.dialog.classList.contains("player-shop-dialog")) return stopPlayerShopRuntime();
    const sold = maybeRunPlayerShopAiCycle();
    if (sold && els.dialog?.open) {
      const currentView = els.dialog.querySelector("[data-player-shop-view]")?.dataset.playerShopView || "overview";
      openPlayerShopDialog(currentView, { preserveScroll: true });
    }
  }, 5000);
}

function playerShopDangerLabel(value) {
  if (value < 25) return "Unauffällig";
  if (value < 55) return "Beobachtet";
  if (value < 78) return "Riskant";
  return "Kontrollgefahr";
}

function playerShopOnlineListingPayload(listing) {
  return {
    ownerUid: "",
    sellerName: playerShopSellerName(),
    shopName: ensurePlayerShopState().name,
    itemName: String(listing.itemName || "Artikel").slice(0, 100),
    itemKind: String(listing.itemKind || "item").slice(0, 30),
    quantity: Math.max(1, Math.floor(Number(listing.quantity || 1))),
    price: Math.max(1, Math.round(Number(listing.price || 1))),
    illegal: Boolean(listing.illegal),
    icon: String(listing.icon || "📦").slice(0, 8),
    text: String(listing.text || "").slice(0, 240),
    effect: listing.effect || {},
    consumableText: String(listing.consumableText || "").slice(0, 240),
    blackData: listing.illegal ? {
      name: String(listing.blackData?.name || listing.itemName || "Ware").slice(0, 100),
      sellMin: Math.max(0, Math.round(Number(listing.blackData?.sellMin || listing.price || 0))),
      sellMax: Math.max(0, Math.round(Number(listing.blackData?.sellMax || listing.price || 0)))
    } : {},
    vehicleMeta: listing.itemKind === "vehicle" && listing.vehicleMeta ? JSON.parse(JSON.stringify(listing.vehicleMeta)) : {},
    propertyData: listing.itemKind === "property" && listing.propertyData ? JSON.parse(JSON.stringify(listing.propertyData)) : {},
    status: "active",
    createdAtMs: Number(listing.createdAtMs || Date.now()),
    updatedAtMs: Date.now()
  };
}

async function publishPlayerShopListingOnline(listing) {
  if (!ensurePlayerShopState().onlineEnabled || !navigator.onLine) return false;
  try {
    const fb = await getFirebasePhoneRuntime();
    const uid = fb.auth.currentUser?.uid;
    if (!uid) return false;
    const payload = playerShopOnlineListingPayload(listing);
    payload.ownerUid = uid;
    await fb.setDoc(fb.doc(fb.db, "playerShopListings", listing.id), payload);
    listing.onlinePublished = true;
    listing.onlineId = listing.id;
    playerShopOnlineStatus = "online";
    save();
    return true;
  } catch (error) {
    console.warn("Shop-Angebot konnte nicht online gestellt werden", error);
    playerShopOnlineStatus = "error";
    return false;
  }
}

async function deletePlayerShopListingOnline(listing) {
  if (!listing?.onlineId && !listing?.onlinePublished) return;
  try {
    const fb = await getFirebasePhoneRuntime();
    await fb.deleteDoc(fb.doc(fb.db, "playerShopListings", listing.onlineId || listing.id));
  } catch (error) {
    console.warn("Online-Angebot konnte nicht entfernt werden", error);
  }
}

async function syncPlayerShopListingQuantityOnline(listing) {
  if (!listing?.onlineId && !listing?.onlinePublished) return;
  try {
    const fb = await getFirebasePhoneRuntime();
    const ref = fb.doc(fb.db, "playerShopListings", listing.onlineId || listing.id);
    if (Number(listing.quantity || 0) <= 0) await fb.deleteDoc(ref);
    else await fb.updateDoc(ref, { quantity: Math.max(1, Math.floor(Number(listing.quantity))), updatedAtMs: Date.now() });
  } catch (error) {
    console.warn("Online-Bestand konnte nicht aktualisiert werden", error);
  }
}

async function subscribePlayerShopOnlineListings() {
  if (!navigator.onLine) {
    playerShopOnlineStatus = "offline";
    playerShopOnlineListings = [];
    return;
  }
  try {
    const fb = await getFirebasePhoneRuntime();
    const query = fb.query(fb.collection(fb.db, "playerShopListings"), fb.where("status", "==", "active"), fb.limit(80));
    if (playerShopOnlineUnsubscribe) playerShopOnlineUnsubscribe();
    playerShopOnlineUnsubscribe = fb.onSnapshot(query, (snapshot) => {
      playerShopOnlineListings = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() })).filter((entry) => Number(entry.quantity || 0) > 0);
      playerShopOnlineStatus = "online";
      if (els.dialog?.open && els.dialog.classList.contains("player-shop-dialog") && els.dialog.querySelector('[data-player-shop-view="online"]')) {
        openPlayerShopDialog("online", { preserveScroll: true, skipSubscribe: true });
      }
    }, (error) => {
      console.warn("Online-Shop-Abonnement fehlgeschlagen", error);
      playerShopOnlineStatus = "error";
    });
    await processPlayerShopOnlineOrders();
  } catch (error) {
    console.warn("Online-Markt nicht verfügbar", error);
    playerShopOnlineStatus = "error";
  }
}

async function processPlayerShopOnlineOrders() {
  try {
    const fb = await getFirebasePhoneRuntime();
    const uid = fb.auth.currentUser?.uid;
    if (!uid) return 0;
    const shop = ensurePlayerShopState();
    const query = fb.query(fb.collection(fb.db, "playerShopOrders"), fb.where("sellerUid", "==", uid), fb.limit(50));
    const snapshot = await fb.getDocs(query);
    let credited = 0;
    for (const orderDoc of snapshot.docs) {
      if (shop.processedOnlineOrders.includes(orderDoc.id)) continue;
      const order = orderDoc.data();
      if (order.status !== "paid") continue;
      let claimed = false;
      await fb.runTransaction(fb.db, async (transaction) => {
        const latest = await transaction.get(orderDoc.ref);
        if (!latest.exists() || latest.data()?.status !== "paid" || latest.data()?.sellerUid !== uid) return;
        transaction.update(orderDoc.ref, { status: "claimed", sellerClaimedAtMs: Date.now() });
        claimed = true;
      });
      if (!claimed) continue;
      const localListing = shop.listings.find((listing) => listing.id === order.listingId) || {
        id: order.listingId,
        itemName: order.itemName,
        itemKind: order.itemKind,
        price: order.price,
        quantity: order.quantity,
        illegal: order.illegal
      };
      applyPlayerShopSaleResult(localListing, Math.max(1, Number(order.quantity || 1)), "online");
      shop.processedOnlineOrders.push(orderDoc.id);
      credited += Number(order.total || order.price || 0);
    }
    shop.processedOnlineOrders = shop.processedOnlineOrders.slice(-250);
    if (credited > 0) {
      save();
      render();
    }
    return credited;
  } catch (error) {
    console.warn("Online-Shop-Auszahlungen konnten nicht abgeholt werden", error);
    return 0;
  }
}

async function buyPlayerShopOnlineListing(listingId) {
  const listing = playerShopOnlineListings.find((entry) => entry.id === listingId);
  if (!listing) return addFeed("Dieses Online-Angebot ist nicht mehr verfügbar.");
  const price = Math.max(1, Math.round(Number(listing.price || 1)));
  if (!canAfford(price)) return addFeed(`Für ${listing.itemName} brauchst du ${euro.format(price)}.`);
  const capacityNeed = playerShopListingCapacityNeeded(listing, 1);
  if (capacityNeed > 0 && inventoryUsed() + capacityNeed > inventoryCapacity()) return addFeed("Dein Inventar ist voll. Schaffe zuerst Platz.");
  try {
    const fb = await getFirebasePhoneRuntime();
    const uid = fb.auth.currentUser?.uid;
    if (!uid) throw new Error("Nicht angemeldet");
    if (listing.ownerUid === uid) return addFeed("Dein eigenes Online-Angebot kannst du nicht kaufen.");
    const listingRef = fb.doc(fb.db, "playerShopListings", listingId);
    const orderRef = fb.doc(fb.collection(fb.db, "playerShopOrders"));
    await fb.runTransaction(fb.db, async (transaction) => {
      const latest = await transaction.get(listingRef);
      if (!latest.exists()) throw new Error("Angebot wurde bereits entfernt");
      const data = latest.data();
      const quantity = Math.floor(Number(data.quantity || 0));
      if (data.status !== "active" || quantity < 1) throw new Error("Angebot ist ausverkauft");
      if (Math.round(Number(data.price || 0)) !== price) throw new Error("Preis wurde geändert");
      transaction.update(listingRef, { quantity: quantity - 1, status: quantity - 1 <= 0 ? "soldout" : "active", updatedAtMs: Date.now() });
      transaction.set(orderRef, {
        listingId,
        sellerUid: data.ownerUid,
        buyerUid: uid,
        itemName: data.itemName,
        itemKind: data.itemKind,
        quantity: 1,
        price,
        total: price,
        illegal: Boolean(data.illegal),
        status: "paid",
        createdAtMs: Date.now()
      });
    });
    debitPlayer(price, "auto");
    grantPlayerShopPurchasedItem(listing, 1);
    if (listing.illegal) {
      const shop = ensurePlayerShopState();
      shop.danger = clamp(shop.danger + randomInt(4, 8), 0, 100);
    }
    addFeed(`${listing.itemName} von ${listing.shopName || listing.sellerName || "Online-Shop"} für ${euro.format(price)} gekauft.`);
    save();
    render();
    openPlayerShopDialog("online", { preserveScroll: true });
  } catch (error) {
    addFeed(`Online-Kauf fehlgeschlagen: ${error?.message || "Angebot nicht verfügbar"}.`);
  }
}

function upgradePlayerShopStorage() {
  const shop = ensurePlayerShopState();
  if (!shop.created) return addFeed("Eröffne zuerst deinen Shop.");
  const next = PLAYER_SHOP_STORAGE_TIERS.find((entry) => entry.level === shop.storageLevel + 1);
  if (!next) return addFeed("Dein Shoplager ist bereits vollständig ausgebaut.");
  if (!canAfford(next.upgradeCost)) return addFeed(`Für ${next.label} brauchst du ${euro.format(next.upgradeCost)}.`);
  pay(next.upgradeCost, false, { target: "treasury", taxRate: .19, awardXp: false });
  shop.storageLevel = next.level;
  addFeed(`${next.label} gekauft: ${next.capacity.toLocaleString("de-DE")} Artikel Lagerkapazität.`);
  save();
  render();
  openPlayerShopDialog("wholesale", { preserveScroll: true });
}

function buyPlayerShopWholesale(itemName, quantity) {
  const shop = ensurePlayerShopState();
  if (!shop.created) return addFeed("Eröffne zuerst deinen Shop.");
  const tier = playerShopStorageTier(shop.storageLevel);
  if (!tier.capacity) return addFeed("Kaufe zuerst Lager Stufe 1, bevor du Großhandelsware bestellst.");
  const item = playerShopWholesaleCatalog().find((entry) => entry.name === itemName);
  if (!item) return addFeed("Diese Großhandelsware ist nicht mehr verfügbar.");
  const qty = Math.max(20, Math.min(100, Math.floor(Number(quantity || 20))));
  if (playerShopStorageFree(shop) < qty) return addFeed(`Im Shoplager fehlen ${qty - playerShopStorageFree(shop)} freie Plätze.`);
  const unitCost = playerShopWholesaleUnitPrice(item.retailPrice, qty);
  const total = Math.round(unitCost * qty * 100) / 100;
  if (!canAfford(total)) return addFeed(`Für ${qty}x ${item.name} brauchst du ${playerShopEuroExact.format(total)}.`);
  pay(total, false, { target: "treasury", taxRate: .19, awardXp: false });
  const existing = shop.wholesaleStock.find((entry) => entry.itemName === item.name);
  if (existing) {
    const oldQty = Math.max(0, Number(existing.quantity || 0));
    const combinedQty = oldQty + qty;
    existing.unitCost = Math.round((((oldQty * Number(existing.unitCost || 0)) + (qty * unitCost)) / combinedQty) * 100) / 100;
    existing.quantity = combinedQty;
    existing.retailPrice = item.retailPrice;
    existing.maxSellPrice = playerShopWholesaleMaxSellPrice(item.retailPrice);
    existing.effect = { ...(item.effect || {}) };
    existing.text = item.text;
    existing.icon = item.icon;
  } else {
    shop.wholesaleStock.push(playerShopWholesaleStockEntry(item, qty, unitCost));
  }
  addFeed(`${qty}x ${item.name} für ${playerShopEuroExact.format(unitCost)} pro Stück bestellt. Gesamt ${playerShopEuroExact.format(total)}.`);
  save();
  render();
  openPlayerShopDialog("wholesale", { preserveScroll: true });
}

