function refreshFinancePhone(appId = "invest") {
  const phone = ownedPhoneItem();
  if (phone && els.dialog?.open && els.dialog.querySelector(".device-shell")) {
    openDeviceInterface(phone, appId, false);
    return true;
  }
  return false;
}

function tradingPositionQuote(position) {
  const offer = tradingCallOffers.find((entry) => entry.id === position.offerId) || tradingCallOffers[0];
  const amount = Math.max(0, Number(position.amount) || 0);
  const ticks = Math.max(0, Math.floor((Date.now() - Number(position.startedAt || Date.now())) / MARKET_TICK_MS));
  const seed = stringSeed(`${position.id}:${position.offerId}:${position.startedAt}`);
  const wave = Math.sin((seed + ticks * 7.17) * 0.071) + Math.sin((seed + ticks * 2.83) * 0.039) * 0.55;
  const direction = Number(position.direction) || (seed % 2 ? 1 : -1);
  const trend = direction * Math.min(0.16, ticks * 0.0065);
  const spread = Math.max(Math.abs(offer.minReturn || -0.1), Math.abs(offer.maxReturn || 0.15));
  const rate = clamp((wave * spread * 0.46) + trend, offer.minReturn, offer.maxReturn);
  const value = Math.max(0, Math.round(amount * (1 + rate) * 100) / 100);
  return {
    ...position,
    value,
    result: Math.round((value - amount) * 100) / 100,
    rate: Math.round(rate * 1000) / 10,
    elapsedTicks: ticks
  };
}

function tradingPositionRows() {
  state.tradingPositions ||= [];
  return state.tradingPositions.map(tradingPositionQuote);
}

function runTradingCall(offer, options = {}) {
  if (!state.tradingEnabled) return addFeed("Trading Call ist noch nicht freigeschaltet.");
  const amount = Math.round(Number(prompt(`Wie viel Euro in ${offer.name} anlegen?`, "1000")) * 100) / 100;
  if (!amount || amount <= 0) return;
  const paid = options.keepDevice
    ? spendPhoneCredit(amount, `${offer.name} Einsatz`, { target: "treasury", taxRate: 0.01 })
    : pay(amount, false, { method: "card", target: "treasury", taxRate: 0.01 });
  if (!paid) return addFeed(options.keepDevice ? "Nicht genug Handy-Guthaben für diesen Trading Call." : "Nicht genug Geld auf deinem Konto.");
  state.tradingPositions ||= [];
  const id = `trade-position-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
  state.tradingPositions.unshift({
    id,
    offerId: offer.id,
    name: offer.name,
    amount,
    startedAt: Date.now(),
    direction: Math.random() > offer.risk ? 1 : -1,
    source: options.keepDevice ? "phone" : "bank"
  });
  state.tradingPositions = state.tradingPositions.slice(0, 24);
  addFeed(`${offer.name}: ${euro.format(amount)} eingesetzt. Die Position läuft jetzt und kann im Trading verkauft werden.`);
  save();
  if (options.keepDevice && refreshFinancePhone("trading")) return;
  render();
}

function sellTradingPosition(id, options = {}) {
  state.tradingPositions ||= [];
  const index = state.tradingPositions.findIndex((position) => position.id === id);
  if (index < 0) return addFeed("Diese Trading-Position wurde bereits verkauft.");
  const row = tradingPositionQuote(state.tradingPositions[index]);
  if (!confirm(`${row.name} für ${euro.format(row.value)} verkaufen?`)) return;
  const usePhoneCredit = options.keepDevice || row.source === "phone";
  if (usePhoneCredit) {
    state.publicTreasury = Math.max(0, (state.publicTreasury || 0) - row.value);
    addPhoneCredit(row.value, "Trading-Verkauf");
  } else {
    payoutFromTreasury(row.value);
  }
  state.tradingPositions.splice(index, 1);
  state.tradingHistory ||= [];
  state.tradingHistory.unshift({
    id: `trade-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
    name: row.name,
    amount: row.amount,
    payout: row.value,
    result: row.result,
    rate: row.rate,
    direction: row.result >= 0 ? "verkauft mit Gewinn" : "verkauft mit Verlust",
    day: state.day || 1,
    at: Date.now(),
    settled: true
  });
  state.tradingHistory = state.tradingHistory.slice(0, 20);
  recordIncome("trading", Math.max(0, row.result));
  improveSkill("Finanzen", row.result >= 0 ? 1 : 0);
  addFeed(`${row.name} verkauft: ${euro.format(row.value)} ausgezahlt (${row.result >= 0 ? "+" : "-"}${euro.format(Math.abs(row.result))}).`);
  save();
  if (options.keepDevice && refreshFinancePhone("trading")) return;
  render();
}

function removeTradingHistoryEntry(id, item = ownedPhoneItem()) {
  state.tradingHistory ||= [];
  state.tradingHistory = state.tradingHistory.filter((entry) => entry.id !== id);
  save();
  if (item && els.dialog?.open && els.dialog.querySelector(".device-shell")) {
    refreshDeviceApp("trading", item);
    return;
  }
  render();
}

function createMarketEntries(group) {
  const names = marketCatalog[group.type] || [];
  return names.map((name, index) => {
    const points = marketHistoryPoints(group.type, name, index);
    const change = Math.round(((points.at(-1) - points[0]) / points[0]) * 1000) / 10;
    return {
      id: marketAssetId(group.type, name),
      name,
      group: group.type,
      price: points.at(-1),
      riskLabel: group.type === "etf" ? "niedrig" : group.type === "stocks" ? "mittel" : "hoch",
      change,
      points
    };
  });
}

function marketAssetId(group, name) {
  return `${group}:${name}`;
}

function stringSeed(text) {
  return String(text).split("").reduce((sum, char, index) => sum + char.charCodeAt(0) * (index + 17), 0);
}

function marketVolatility(group) {
  if (group === "crypto") return 0.095;
  if (group === "stocks") return 0.045;
  return 0.018;
}

function marketBasePrice(group, name, index = 0) {
  return marketBasePrices[marketAssetId(group, name)] || (group === "crypto" ? 25 + index * 11 : group === "stocks" ? 80 + index * 8 : 45 + index * 3);
}

const MARKET_TICK_MS = 15 * 1000;

function currentMarketHour() {
  return Math.floor(Date.now() / MARKET_TICK_MS);
}

function currentMarketPrice(group, name, index = 0, hourOffset = 0) {
  const base = marketBasePrice(group, name, index);
  const seed = stringSeed(`${group}:${name}`);
  const step = currentMarketHour() + hourOffset;
  const volatility = marketVolatility(group);
  const wave = Math.sin((seed + step * 11.37) * 0.071) + Math.sin((seed + step * 3.19) * 0.037) * 0.62;
  const rareMove = Math.sin((seed + step * 0.91) * 0.113) * volatility * 0.45;
  const movement = clamp(wave * volatility + rareMove, -volatility * 2.2, volatility * 2.2);
  const price = Math.max(base * 0.08, base * (1 + movement));
  return Math.round(price * 100) / 100;
}

function marketHistoryPoints(group, name, index = 0) {
  return Array.from({ length: 18 }, (_, step) => currentMarketPrice(group, name, index, step - 17));
}

function formatMarketPrice(value) {
  const digits = value < 10 ? 2 : value < 100 ? 1 : 0;
  return new Intl.NumberFormat("de-DE", { style: "currency", currency: "EUR", minimumFractionDigits: digits, maximumFractionDigits: digits }).format(value);
}

function marketChart(points) {
  const max = Math.max(...points);
  const min = Math.min(...points);
  const spread = Math.max(1, max - min);
  const path = points.map((point, index) => {
    const x = Math.round(index * (100 / Math.max(1, points.length - 1)));
    const y = Math.round(34 - ((point - min) / spread) * 28);
    return `${x},${y}`;
  }).join(" ");
  return `<svg class="mini-chart" viewBox="0 0 100 38" aria-hidden="true"><polyline points="${path}"></polyline></svg>`;
}

function portfolioRows() {
  state.portfolio ||= [];
  return state.portfolio.map((position) => {
    const catalog = marketCatalog[position.group] || [];
    const index = Math.max(0, catalog.indexOf(position.name));
    const price = currentMarketPrice(position.group, position.name, index);
    const value = Math.round((position.units || 0) * price * 100) / 100;
    const invested = position.invested || 0;
    return {
      ...position,
      price,
      value,
      invested,
      result: Math.round((value - invested) * 100) / 100,
      resultPercent: invested > 0 ? Math.round(((value - invested) / invested) * 1000) / 10 : 0
    };
  });
}

function portfolioValue() {
  return portfolioRows().reduce((sum, row) => sum + row.value, 0);
}

function portfolioTypeLabel(type) {
  if (type === "etf") return "ETF";
  if (type === "stocks") return "Aktie";
  if (type === "crypto") return "Krypto";
  return "Anlage";
}

function renderPortfolioSection() {
  const rows = portfolioRows();
  if (!rows.length) {
    return `
      <div class="shop-section">
        <h3>Depot</h3>
        <p class="muted">Noch keine ETFs, Aktien oder Krypto gekauft. Öffne einen Markt und kaufe eine Position, dann erscheint sie hier.</p>
      </div>
    `;
  }
  const total = rows.reduce((sum, row) => sum + row.value, 0);
  const invested = rows.reduce((sum, row) => sum + row.invested, 0);
  const result = total - invested;
  return `
    <div class="shop-section">
      <h3>Depot · ${euro.format(total)}</h3>
      <p class="muted">Investiert: ${euro.format(invested)} · Ergebnis: ${result >= 0 ? "+" : ""}${euro.format(result)}</p>
      ${rows.map((row) => `
        <article class="item-card market-card">
          <div>
            <h3>${row.name}</h3>
            <p>${portfolioTypeLabel(row.group)} · Stück/Coins: ${(row.units || 0).toLocaleString("de-DE", { maximumFractionDigits: 6 })}</p>
            <p>Kurs: ${formatMarketPrice(row.price)} · Wert: ${euro.format(row.value)} · ${row.result >= 0 ? "+" : ""}${euro.format(row.result)} (${row.resultPercent >= 0 ? "+" : ""}${row.resultPercent}%)</p>
          </div>
          <button class="mini-button" data-kind="portfolio-sell" data-index="${row.id}">Verkaufen</button>
        </article>
      `).join("")}
    </div>
  `;
}

function buyMarketAsset(asset, options = {}) {
  if (!state.exchangeEnabled) return addFeed("Aktiviere zuerst die Börse in der Bank-App.");
  if (!state.tradingEnabled) return addFeed("Trading ist noch nicht freigeschaltet. Aktiviere Trading in der Bank-App.");
  const amount = Number(prompt(`Wie viel Euro in ${asset.name} investieren?`, String(Math.max(10, Math.round(asset.price)))));
  if (!amount || amount <= 0) return;
  const paid = options.keepDevice
    ? spendPhoneCredit(amount, `${asset.name} Kauf`, { target: "treasury", taxRate: 0.01 })
    : pay(amount, false, { method: "card", target: "treasury", taxRate: 0.01 });
  if (!paid) return addFeed(options.keepDevice ? "Nicht genug Handy-Guthaben für diesen Kauf." : "Nicht genug Geld auf deinem Konto.");
  const units = amount / asset.price;
  state.portfolio ||= [];
  const existing = state.portfolio.find((position) => position.id === asset.id);
  if (existing) {
    existing.units += units;
    existing.invested += amount;
    existing.avgPrice = existing.invested / existing.units;
    existing.lastBuyPrice = asset.price;
    existing.updatedAt = Date.now();
  } else {
    state.portfolio.push({
      id: asset.id,
      group: asset.group,
      name: asset.name,
      units,
      invested: amount,
      avgPrice: asset.price,
      lastBuyPrice: asset.price,
      boughtAt: Date.now(),
      updatedAt: Date.now()
    });
  }
  improveSkill("Finanzen", Math.random() > 0.65 ? 1 : 0);
  addFeed(`${asset.name}: ${euro.format(amount)} gekauft. Die Position liegt jetzt in deinem Depot.`, { purchase: { name: asset.name, total: amount, method: "card", icon: "📈" } });
  save();
  if (options.keepDevice && refreshFinancePhone("invest")) return;
  els.dialog.close();
  render();
}

function sellPortfolioAsset(id, options = {}) {
  if (!state.exchangeEnabled) return addFeed("Aktiviere zuerst die Börse in der Bank-App.");
  if (!state.tradingEnabled) return addFeed("Verkaufen geht erst, wenn Trading in der Bank-App freigeschaltet wurde.");
  state.portfolio ||= [];
  const index = state.portfolio.findIndex((position) => position.id === id);
  if (index < 0) return;
  const row = portfolioRows().find((position) => position.id === id);
  if (!row) return;
  if (!confirm(`${row.name} für ${euro.format(row.value)} verkaufen?`)) return;
  if (options.keepDevice) {
    state.publicTreasury = Math.max(0, (state.publicTreasury || 0) - row.value);
    addPhoneCredit(row.value, "Börsenverkauf");
  } else {
    payoutFromTreasury(row.value);
  }
  recordIncome("exchange", row.value);
  state.portfolio.splice(index, 1);
  improveSkill("Finanzen", 1);
  addFeed(`${row.name} verkauft: ${euro.format(row.value)} ausgezahlt.`);
  save();
  if (options.keepDevice && refreshFinancePhone(options.appId || "invest")) return;
  render();
}

function invest(item) {
  if (!pay(item.price)) return addFeed("Nicht genug Geld für diese Investition.");
  const swing = Math.random() < item.risk ? 1 + Math.random() * 0.18 : 1 - Math.random() * 0.22;
  const result = Math.round(item.price * swing);
  payoutFromTreasury(result);
  improveSkill("Finanzen", Math.random() > 0.65 ? 1 : 0);
  addFeed(`${item.name}: Einsatz ${euro.format(item.price)}, aktueller Wert ${euro.format(result)}.`);
  save();
  render();
}

function renderMap() {
  if (!els.cityMap) return;
  els.locationLabel.textContent = `Lokale Karte ${state.worldLocation} · ${localPlaceName()}`;
  const roads = routes.map(([fromId, toId]) => {
    const from = mapPlaces.find((place) => place.id === fromId);
    const to = mapPlaces.find((place) => place.id === toId);
    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const length = Math.sqrt(dx * dx + dy * dy);
    const angle = Math.atan2(dy, dx) * 180 / Math.PI;
    return `<i class="map-road" style="left:${from.x}%;top:${from.y}%;width:${length}%;transform:rotate(${angle}deg)"></i>`;
  }).join("");
  const pins = mapPlaces.map((place) => `
    <button class="map-pin ${place.id === state.location ? "current" : ""}" data-place="${place.id}" style="left:${place.x}%;top:${place.y}%">
      ${place.icon}<span>${localPlaceName(place)}</span>
    </button>
  `).join("");
  els.cityMap.innerHTML = roads + pins;
  els.cityMap.querySelectorAll(".map-pin").forEach((pin) => pin.addEventListener("click", () => openLocalTravelChoice(pin.dataset.place)));

  if (state.localTravel) {
    const left = Math.max(0, Math.ceil((state.localTravel.arrivesAt - Date.now()) / 1000));
    const target = mapPlaces.find((place) => place.id === state.localTravel.placeId)?.name || "Ziel";
    els.routeList.innerHTML = `<article class="item-card"><div><h3>Unterwegs nach ${target}</h3><p>${state.localTravel.mode}. Ankunft in ${left} Sekunden.</p></div><button disabled>Fahrt</button></article>`;
    return;
  }
  if (state.worldTravel) {
    const left = Math.max(0, state.worldTravel.arrivesAt - Date.now());
    els.routeList.innerHTML = `<article class="item-card"><div><h3>Sie sind gerade unterwegs nach ${state.worldTravel.place?.name || "Ziel"}</h3><p>Ankunft in ${formatRemainingMs(left)}. Du kannst Spiele, Charakter, Bank und andere Bereiche nutzen, aber die lokale Karte erst nach Ankunft.</p></div><button disabled>Fernreise</button></article>`;
    return;
  }

  const placeActions = localPlaceActionsHtml();
  els.routeList.innerHTML = placeActions;
  bindLocalPlaceActions();
}

