function hasBlackBusinessLicense(id) {
  return !!state?.blackBusiness?.licenses?.[id];
}

function buyBlackBusinessLicense(id, source = "Schwarze Ecke") {
  const license = blackBusinessLicenses[id];
  if (!license) return;
  state.blackBusiness ||= createBlackBusinessState();
  state.blackBusiness.licenses ||= {};
  if (state.blackBusiness.licenses[id]) return addFeed(`${license.name} besitzt du bereits.`);
  if (!pay(license.price, false, { target: "treasury", taxRate: 0 })) return addFeed(`${license.name} kostet ${euro.format(license.price)}.`);
  state.blackBusiness.licenses[id] = Date.now();
  state.blackBusiness.message = `${license.name} freigeschaltet.`;
  addFeed(`${license.name} gekauft (${source}): ${euro.format(license.price)}.`, { purchase: { name: license.name, total: license.price, method: "auto" } });
  save();
  render();
}

