function buyStationBlackMarketOffer(offer) {
  if (!offer) return;
  if (inventoryUsed()+1>inventoryCapacity()) return addFeed("Dein Inventar ist voll. Schaffe zuerst einen freien Platz oder nutze einen größeren Rucksack.");
  if (!pay(offer.price,false,{taxRate:0,target:"treasury"})) return addFeed(`Für ${offer.name} brauchst du ${euro.format(offer.price)}.`);
  state.blackMarketGoods||=[]; state.blackMarketGoods.push({...offer,inventoryId:playerShopId("hot"),boughtAtDay:state.day,boughtAt:Date.now()}); const shop=ensurePlayerShopState(); shop.danger=clamp(shop.danger+Math.max(1,Math.round(Number(offer.heat||.1)*8)),0,100); improveSkill("Straßenwissen",1); addFeed(`${offer.name} gekauft und ins Inventar gelegt. Verkauf nur über deinen eigenen Shop.`,{purchase:{name:offer.name,total:offer.price,method:"auto"}}); save(); render(); openStationHotGoodsDialog();
}

function openBlackCornerSellDialog() {
  if (!hasBlackBusinessLicense("fence")) return addFeed("Du brauchst zuerst die Hehler-Lizenz. Du findest sie bei „Heiße Ware“ am Hauptbahnhof.");
  const dirty=state.dirtyMoney||0; completeBlackBusinessTimers(); clearDialogDynamic(); els.dialogTitle.textContent="Schwarze Ecke · Verwaltung"; els.dialogText.textContent="Hier verwaltest du Lizenzen und Schwarzgeld. Heiße Ware kann hier nicht mehr verkauft werden; dafür ist ausschließlich dein eigener Shop vorgesehen.";
  const list=document.createElement("div"); list.className="market-list"; const licenseHtml=Object.entries(blackBusinessLicenses).filter(([id])=>id!=="fence").map(([id,license])=>card(license.name,`${license.text} Preis: ${euro.format(license.price)}.`,hasBlackBusinessLicense(id)?"Aktiv":"Kaufen",id,hasBlackBusinessLicense(id)||!canAfford(license.price),"black-license")).join(""); const pendingHtml=(state.blackBusiness?.pendingSales||[]).length?(state.blackBusiness.pendingSales||[]).map((sale,index)=>card("Alter laufender Verkauf",`${sale.name}: fertig in ${formatRemainingMs(Math.max(0,sale.readyAt-Date.now()))}. Neue Ware läuft nur noch über den Shop.`,"Warten",index,true,"black-pending")).join(""):""; const launderHtml=dirty>0?card("Schwarzgeld waschen",`Offen: ${euro.format(dirty)}. Verlust ${hasBlackBusinessLicense("trust")?"3 bis 5":"3 bis 8"}%. Polizeirisiko: 10%.`,hasBlackBusinessLicense("laundering")?"Waschen":"Lizenz fehlt","launder",!hasBlackBusinessLicense("laundering"),"black-launder"):`<article class="item-card"><div><h3>Kein Schwarzgeld</h3><p>Illegale Shop-Einnahmen erscheinen hier.</p></div><button disabled>Sauber</button></article>`; const hint=`<article class="item-card"><div><h3>Heiße Ware verkaufen</h3><p>Arbeit → Eigener Shop → Ware einstellen → Heiße Ware.</p></div><button class="mini-button" data-open-player-shop-hot>Zum Shop</button></article>`; list.innerHTML=licenseHtml+launderHtml+pendingHtml+hint; const close=document.createElement("button"); close.className="mini-button"; close.textContent="Schließen"; close.onclick=()=>els.dialog.close(); els.dialog.append(list,close); list.querySelector('button[data-kind="black-launder"]')?.addEventListener("click",launderDirtyMoney); list.querySelectorAll('button[data-kind="black-license"]').forEach((button)=>button.addEventListener("click",()=>{buyBlackBusinessLicense(button.dataset.index,"Schwarze Ecke");openBlackCornerSellDialog();})); list.querySelector("[data-open-player-shop-hot]")?.addEventListener("click",()=>{playerShopStockFilter="hot";openPlayerShopDialog("stock");}); if(!els.dialog.open) els.dialog.showModal();
}

function launderDirtyMoney() {
  if (!hasBlackBusinessLicense("laundering")) return addFeed("Du brauchst zuerst die Schwarzgeld-Wasch-Lizenz in der Schwarzen Ecke.");
  const dirty = state.dirtyMoney || 0;
  if (dirty <= 0) return addFeed("Du hast kein Schwarzgeld zum Waschen.");
  const amount = Math.min(dirty, Math.round(Number(prompt("Wie viel Schwarzgeld möchtest du waschen?", String(Math.floor(dirty))))));
  if (!amount || amount <= 0) return;
  state.dirtyMoney = Math.max(0, dirty - amount);
  if (Math.random() < 0.1) {
    const fine = randomInt(1000, 11000);
    applyCriminalFine("Geldwäsche", `${euro.format(amount)} Schwarzgeld wurde eingezogen.`, fine, hour);
    els.dialog.close();
    save();
    render();
    return;
  }
  const feeRate = randomInt(3, hasBlackBusinessLicense("trust") ? 5 : 8) / 100;
  const clean = Math.round(amount * (1 - feeRate));
  state.cash += clean;
  recordIncome("sales", clean);
  improveSkill("Straßenwissen", 1);
  addXp(16, "Geldwäsche");
  addFeed(`${euro.format(amount)} gewaschen. Sauber erhalten: ${euro.format(clean)}.`);
  els.dialog.close();
  save();
  render();
}

function sellBlackMarketGood(index) {
  if (!hasBlackBusinessLicense("fence")) return addFeed("Du brauchst zuerst die Hehler-Lizenz.");
  state.blackMarketGoods ||= [];
  const item = state.blackMarketGoods[index];
  if (!item) return addFeed("Diese Ware ist nicht mehr vorhanden.");
  const risk = Math.max(0, 0.2 - (clamp(state.policeBribe ?? 0, 0, 100) / 100) * 0.2);
  if (Math.random() < risk) {
    const fine = randomInt(1000, 11000);
    state.blackMarketGoods.splice(index, 1);
    applyCriminalFine("Schwarzmarkt-Verkauf", `Beim Verkauf von ${item.name} erwischt. Die Ware wurde eingezogen.`, fine, hour);
    els.dialog.close();
    save();
    render();
    return;
  }
  const amount = randomInt(item.sellMin, item.sellMax);
  state.blackMarketGoods.splice(index, 1);
  if (!hasBlackBusinessLicense("dealer")) {
    state.blackBusiness ||= createBlackBusinessState();
    state.blackBusiness.pendingSales ||= [];
    state.blackBusiness.pendingSales.push({ name: item.name, amount, dirty: true, readyAt: Date.now() + randomInt(60, 180) * 1000 });
    addFeed(`${item.name}: Käufer gesucht. Verkauf dauert 1 bis 3 Minuten.`);
    els.dialog.close();
    save();
    render();
    return;
  }
  completeBlackSale(item.name, amount, { dirty: true });
  els.dialog.close();
  save();
  render();
}

function completeBlackSale(name, amount, options = {}) {
  if (options.dirty) {
    addDirtyBusinessMoney(amount, name);
    improveSkill("Straßenwissen", 1);
    addXp(12, "Schwarzes Business");
    addFeed(`${name} verkauft: ${euro.format(amount)} Schwarzgeld erhalten.`);
    return;
  }
  state.cash += amount;
  recordIncome("sales", amount);
  improveSkill("Straßenwissen", 1);
  addXp(12, "Schwarze Ecke");
  addFeed(`${name} verkauft: ${euro.format(amount)} bar erhalten.`);
}

function completeBlackBusinessTimers() {
  if (!state?.blackBusiness?.pendingSales?.length) return 0;
  const now = Date.now();
  const ready = state.blackBusiness.pendingSales.filter((sale) => sale.readyAt <= now);
  state.blackBusiness.pendingSales = state.blackBusiness.pendingSales.filter((sale) => sale.readyAt > now);
  ready.forEach((sale) => completeBlackSale(sale.name, sale.amount, { dirty: !!sale.dirty }));
  if (ready.length) save();
  return ready.length;
}

function settleBlackBusinessStaffCosts() {
  const black = state.blackBusiness;
  if (!black) return;
  const count = (black.staff?.length || 0) + (black.courierStaff?.length || 0);
  if (!count) return;
  const total = count * 1000;
  if (state.cash + state.bank >= total && pay(total, false, { target: "treasury", taxRate: 0 })) {
    black.message = `Mitarbeiter bezahlt: ${euro.format(total)}.`;
    addFeed(`Schwarzes Business: Mitarbeiter bezahlt (${euro.format(total)}).`);
  } else {
    black.staffBlockedUntil = 0;
    black.message = "Mitarbeiterlohn offen. Aufträge bleiben verfügbar, aber die Crew ist unzufrieden.";
    addFeed("Schwarzes Business: Mitarbeiterlohn konnte nicht bezahlt werden. Aufträge bleiben ohne Zeitsperre verfügbar.");
  }
}

function applyCriminalFine(title, text, fine, banMs = hour) {
  state.debt = (state.debt || 0) + fine;
  state.unpaidFines = (state.unpaidFines || 0) + fine;
  state.stationBanUntil = Math.max(state.stationBanUntil || 0, Date.now() + banMs);
  state.credit = clamp((state.credit || 0) - 8);
  state.criminalRecord ||= [];
  state.criminalRecord.unshift({
    title,
    text,
    fine,
    day: state.day,
    at: Date.now(),
    banUntil: state.stationBanUntil
  });
  state.criminalRecord = state.criminalRecord.slice(0, 80);
  addFeed(`${title}: ${text} Bußgeld ${euro.format(fine)} und 1 Stunde Bahnhofsverbot.`);
}

function randomInt(min, max) {
  return Math.floor(min + Math.random() * (max - min + 1));
}

function repairCarAtWorkshop() {
  const damagedVehicle = (state.items || []).find((item) => vehicleItems().includes(item) && state.vehicleMeta?.[item]?.damaged);
  if (!state.carDamaged && !damagedVehicle) return addFeed("Dein Auto braucht gerade keine Reparatur.");
  const cost = 650;
  if (!pay(cost)) return addFeed(`Die Reparatur kostet ${euro.format(cost)}.`);
  state.carDamaged = false;
  if (damagedVehicle && state.vehicleMeta?.[damagedVehicle]) state.vehicleMeta[damagedVehicle].damaged = false;
  improveSkill("Handwerk", 1);
  addFeed(`Auto repariert: ${euro.format(cost)} bezahlt.`);
  save();
  render();
}

function renderGames() {
  if (!els.gameLibrary) return;
  els.gameLibrary.classList.add("games-hub");
  els.gameLibrary.innerHTML = games.map((game, index) => {
    const lock = gameRequirement(game);
    const displayName = `${game.icon || "🎮"} ${game.name}`;
    if (game.id === "snake") {
      resetSnakeDayIfNeeded();
      const records = state.snake?.records || { easy: state.snake?.record || 0, medium: 0, hard: 0 };
      const text = `${game.text} Rekorde: Easy ${records.easy || 0}, Mittel ${records.medium || 0}, Schwer ${records.hard || 0}.${lock.text}`;
      return card(displayName, text, lock.locked ? "Gesperrt" : "Spielen", index, lock.locked, "snake");
    }
    if (game.id === "war") {
      resetWarDayIfNeeded();
      return card(displayName, `${game.text} Siege: ${state.war?.wins || 0}.${lock.text}`, lock.locked ? "Gesperrt" : "Spielen", index, lock.locked, "war");
    }
    if (game.id === "kingdom") {
      resetKingdomDayIfNeeded();
      return card(displayName, `${game.text} Reines Strategiespiel ohne Geldgewinn.${lock.text}`, lock.locked ? "Gesperrt" : "Spielen", index, lock.locked, "kingdom");
    }
    if (game.id === "strong") {
      return card(displayName, `${game.text}${lock.text}`, lock.locked ? "Gesperrt" : "Öffnen", index, lock.locked, "strong");
    }
    if (game.id === "survival") {
      return card(displayName, `${game.text} Steuerung: WASD, Klick-Ziel, I Inventar, M Karte, Mausrad-Zoom.${lock.text}`, lock.locked ? "Gesperrt" : "Öffnen", index, lock.locked, "survival");
    }
    if (game.id === "racer") {
      resetRacerDayIfNeeded();
      return card(displayName, `${game.text} Siege: ${state.racer?.wins || 0}.${lock.text}`, lock.locked ? "Gesperrt" : "Spielen", index, lock.locked, "racer");
    }
    if (game.id === "iconman") {
      const icon = state.iconman?.skin || "🟡";
      const text = `${game.text} Münzen: ${state.iconman?.coins || 0}. Rekord: ${state.iconman?.record || 0}. Bestes Level: ${state.iconman?.bestLevel || 1}.${lock.text}`;
      return card(`${icon} ${game.name}`, text, lock.locked ? "Gesperrt" : "Öffnen", index, lock.locked, "iconman");
    }
    const disabled = !isReady("game");
    return card(displayName, `${game.text} Belohnung: ${euro.format(game.reward)}. Cooldown: ${waitText("game")}.${lock.text}`, disabled || lock.locked ? "Warten" : "Spielen", index, disabled || lock.locked);
  }).join("");
  els.gameLibrary.querySelectorAll("button:not(:disabled)").forEach((button) => button.addEventListener("click", () => {
    const game = games[Number(button.dataset.index)];
    if (game.id === "snake") return openSnakeGame();
    if (game.id === "war") return openWarGame();
    if (game.id === "kingdom") return openKingdomModeSelect();
    if (game.id === "strong") return openStrongGame();
    if (game.id === "survival") return openSurvivalGame();
    if (game.id === "racer") return openRacerGame();
    if (game.id === "iconman") return openIconManGame();
    playMiniGame(game);
  }));
}

function gameRequirement(game) {
  const id = game?.id || "";
  if (["iconman", "snake", "racer"].includes(id)) {
    const ok = !!ownedPhoneItem();
    return { locked: !ok, text: ok ? " Gerät: Smartphone." : " Benötigt: Smartphone." };
  }
  if (id === "war") {
    const ok = state.items.includes("Laptop gebraucht") || ownsAnyComputerAtLeast("Laptop gebraucht");
    return { locked: !ok, text: ok ? " Gerät: Laptop." : " Benötigt: Laptop gebraucht." };
  }
  if (["kingdom", "strong", "survival"].includes(id)) {
    const ok = ownsAnyComputerAtLeast("Gaming-PC");
    return { locked: !ok, text: ok ? " Gerät: Gaming-PC." : " Benötigt: Gaming-PC." };
  }
  return { locked: false, text: "" };
}

function playMiniGame(game) {
  if (!isReady("game")) return addFeed(`Mini-Games sind erst in ${waitText("game")} wieder möglich.`);
  setCooldown("game");
  addXp(25, game.name);
  improveSkill(game.skill, Math.random() > 0.7 ? 1 : 0);
  addFeed(`${game.name}: gespielt. Games geben kein echtes Geld mehr, nur Fortschritt und Spaß.`);
  save();
  render();
}

function renderInventory() {
  if (!els.inventoryList) return;
  els.inventoryList.innerHTML = inventoryCardsHtml(true, "main");
  bindInventoryActions(els.inventoryList);
}

function inventoryCategoryDefinitions() {
  return [
    ["all", "Alle"],
    ["drinks", "Getränke"],
    ["food", "Essen"],
    ["medicine", "Medizin"],
    ["electronics", "Elektro"],
    ["computer", "Computer"],
    ["documents", "Dokumente"],
    ["vehicles", "Fahrzeuge"],
    ["backpacks", "Rucksäcke"],
    ["household", "Haushalt"],
    ["misc", "Sonstiges"]
  ];
}

function inventoryCategoryFor(name, kind = "item") {
  const text = String(name || "").toLowerCase();
  if (kind === "vehicle" || kind === "vehicles" || vehicleItems().includes(name)) return "vehicles";
  if (["führerschein", "reisepass"].includes(text)) return "documents";
  if (/wasser|cola|sprite|eistee|saft|schorle|drink|kaffee|kokoswasser|elektrolyte/.test(text)) return "drinks";
  if (/chips|schoko|gummi|sandwich|croissant|salat|futter|protein|snack|einkauf|meal|essen/.test(text)) return "food";
  if (/vitamin|magnesium|tablette|medizin|arznei|erste-hilfe|hilfe-set|erkältung/.test(text)) return "medicine";
  if (/laptop|computer|gaming-pc|pc|tablet/.test(text)) return "computer";
  if (/phone|smartphone|sim|powerbank|batterie/.test(text)) return "electronics";
  if (/rucksack|backpack/.test(text)) return "backpacks";
  if (/müll|reinigung|werkzeug|lampe|bett|sofa|schrank|küche|regal|stuhl|heimkino|light|möbel/.test(text)) return "household";
  return "misc";
}

function inventoryCategoryMatches(name, kind = "item") {
  const active = state.inventoryCategory || "all";
  return active === "all" || inventoryCategoryFor(name, kind) === active;
}

function inventoryCategoryNavHtml() {
  const active = state.inventoryCategory || "all";
  return `
    <div class="inventory-category-grid">
      ${inventoryCategoryDefinitions().map(([id, label]) => `
        <button class="mini-button ${active === id ? "gold" : ""}" type="button" data-inventory-category="${id}">${label}</button>
      `).join("")}
    </div>
  `;
}

function inventoryCardsHtml(withActions = true, source = "main") {
  const cards = [];
  cards.push(`<div class="meta-strip"><span>Inventar: ${inventoryUsed()}/${inventoryCapacity()}</span><span>Rucksackbonus: ${state.backpackSlots || 0}</span></div>`);
  cards.push(inventoryNeedsStatusHtml());
  cards.push(inventoryCategoryNavHtml());
  Object.entries(state.consumables || {}).forEach(([name, entry]) => {
    if (!entry?.count) return;
    if (!inventoryCategoryMatches(name, "consumable")) return;
    cards.push(`
      <article class="item-card">
        <div>
          <h3>${name} (${entry.count}x)</h3>
          <p>${entry.text || "Verbrauchsartikel im Inventar."}${itemIdBadge(name)}</p>
        </div>
        ${withActions ? `<div class="inventory-actions"><button data-use-consumable="${name}">Benutzen</button><button class="mini-button" data-sell-consumable="${name}">Verkaufen ${euro.format(inventorySellValue(name))}</button></div>` : "<button disabled>Besitz</button>"}
      </article>
    `);
  });
  if (state.items.includes("Führerschein") && inventoryCategoryMatches("Führerschein", "document")) cards.push(`
    <article class="item-card">
      <div><h3>Führerschein Klasse B</h3><p>Gültig dauerhaft. Verkauf bringt ${euro.format(inventorySellValue("Führerschein"))}.${itemIdBadge("Führerschein")}</p></div>
      ${withActions ? `<button class="mini-button" data-sell-item="Führerschein">Verkaufen</button>` : "<button disabled>Besitz</button>"}
    </article>
  `);
  if (state.items.includes("Reisepass") && inventoryCategoryMatches("Reisepass", "document")) cards.push(`
    <article class="item-card">
      <div><h3>Reisepass</h3><p>Noch ${state.passportTrips || 0} Fernreisen gültig. Verkauf bringt ${euro.format(inventorySellValue("Reisepass"))}.${itemIdBadge("Reisepass")}</p></div>
      ${withActions ? `<button class="mini-button" data-sell-item="Reisepass">Verkaufen</button>` : "<button disabled>Besitz</button>"}
    </article>
  `);
  vehicleItems().forEach((item) => {
    if (!state.items.includes(item)) return;
    if (!inventoryCategoryMatches(item, "vehicle")) return;
    const value = vehicleValue(item);
    cards.push(`
      <article class="item-card">
        <div>
          <h3>${item}</h3>
          <p>Fahrzeug im Besitz. Schätzwert: ${euro.format(value)}. Sofortverkauf bringt etwa die Hälfte oder weniger.${itemIdBadge(item)}</p>
        </div>
        <div class="inventory-actions">
          <button data-vehicle-sell="${item}">Sofort ${euro.format(quickVehicleSaleValue(item))}</button>
          <button data-vehicle-list="${item}">Anbieten</button>
        </div>
      </article>
    `);
  });
  (state.vehicleSaleOffers || []).forEach((offer) => {
    if (!inventoryCategoryMatches(offer.item, "vehicle")) return;
    cards.push(`
      <article class="item-card">
        <div>
          <h3>Inserat: ${offer.item}</h3>
          <p>Angeboten für ${euro.format(offer.ask)}. Chance pro Versuch: ${Math.round(offer.chance * 100)} Prozent.</p>
        </div>
        <button data-vehicle-offer="${offer.item}">Prüfen</button>
      </article>
    `);
  });
  ownedDeviceItems().forEach((item) => {
    if (!inventoryCategoryMatches(item, "device")) return;
    cards.push(`
      <article class="item-card">
        <div>
          <h3>${item}</h3>
          <p>${deviceDescription(item)}${itemIdBadge(item)}</p>
        </div>
        ${withActions ? `<div class="inventory-actions"><button data-use-device="${item}">Benutzen</button>${inventoryProtectedTopTierItem(item) ? `<button class="mini-button" disabled>Dauergerät</button>` : `<button class="mini-button" data-sell-item="${item}">Verkaufen ${euro.format(inventorySellValue(item))}</button>`}</div>` : "<button disabled>Besitz</button>"}
      </article>
    `);
  });
  const activeBackpackEntry = [...shopMarketCatalog.backpacks].reverse().find((entry) => Number(state.backpackSlots || 0) >= Number(entry.backpackSlots || 0));
  shopMarketCatalog.backpacks.forEach((entry) => {
    const item = entry.item || entry.name;
    if (!stateHasItemNamed(item) || !inventoryCategoryMatches(item, "backpack")) return;
    const active = !!activeBackpackEntry && itemMatchesName(activeBackpackEntry.item || activeBackpackEntry.name, item);
    const totalCapacity = Math.min(500, 8 + Number(entry.backpackSlots || 0));
    cards.push(`
      <article class="item-card inventory-backpack-card ${active ? "is-active" : ""}">
        <div>
          <h3>🎒 ${item}</h3>
          <p>${active ? "Aktuell ausgerüstet" : "Rucksack im Besitz"} · ${entry.backpackSlots || 0} Zusatzplätze · insgesamt ${totalCapacity} Inventarplätze.${itemIdBadge(item)}</p>
        </div>
        <button disabled>${active ? "Aktiv" : "Besitz"}</button>
      </article>
    `);
  });
  const hiddenItems = new Set([
    "Führerschein",
    "Reisepass",
    ...vehicleItems(),
    ...ownedDeviceItems(),
    ...shopMarketCatalog.clothing.map((item) => item.item || item.name),
    ...shopMarketCatalog.backpacks.map((item) => item.item || item.name)
  ]);
  const normalItems = (state.items || []).filter((item) => !hiddenItems.has(item));
  const normalCounts = normalItems.reduce((map, item) => {
    map[item] = (map[item] || 0) + 1;
    return map;
  }, {});
  Object.entries(normalCounts).forEach(([item, count]) => {
    if (!inventoryCategoryMatches(item, "item")) return;
    const canInstallSim = isSimTariffName(item);
    const creditCard = phoneCreditCardByName(item);
    const canUsePowerbank = item === "Powerbank";
    cards.push(`
      <article class="item-card">
        <div>
          <h3>${count > 1 ? `${item} (${count}x)` : item}</h3>
          <p>Gegenstand im Rucksack. Verkauf bringt ${euro.format(inventorySellValue(item))}.${canInstallSim ? " Kann ins Handy eingelegt werden." : ""}${creditCard ? ` Lädt ${euro.format(creditCard.credit)} Handy-Guthaben auf.` : ""}${canUsePowerbank ? " Kann dein Handy unterwegs laden." : ""}${itemIdBadge(item)}</p>
        </div>
        ${withActions ? `<div class="inventory-actions">${canInstallSim ? `<button data-install-sim="${item}">Einlegen</button>` : ""}${creditCard ? `<button data-redeem-phone-credit="${item}">Einlösen</button>` : ""}${canUsePowerbank ? `<button data-use-powerbank>Benutzen</button>` : ""}<button class="mini-button" data-sell-item="${item}">Verkaufen ${euro.format(inventorySellValue(item))}</button></div>` : "<button disabled>Besitz</button>"}
      </article>
    `);
  });
  if (state.garages && inventoryCategoryMatches("Garagenplätze", "vehicles")) cards.push(staticInventoryCard("Garagenplätze", `${state.garages} zusätzliche Stellplätze gekauft. Gesamt: ${vehicleCapacity()}.`));
  const hasRealItems = cards.length > 2;
  return hasRealItems
    ? cards.join("")
    : `${cards.join("")}<article class="item-card"><div><h3>${state.inventoryCategory === "all" ? "Inventar leer" : "Kategorie leer"}</h3><p>Kaufe passende Gegenstände oder wähle eine andere Kategorie. Immobilien sind im Immobilienbereich.</p></div><button disabled>Leer</button></article>`;
}

function inventoryEntryById(id) {
  return inventoryWorkbenchEntries().find((entry) => entry.id === id) || null;
}

function inventoryMaximumUseAmount(entry) {
  if (!entry) return 1;
  return entry.kind === "consumable" ? Math.max(1, Number(entry.count) || 1) : 1;
}

function inventoryUseUntilFullAmount(entry) {
  if (!entry || entry.kind !== "consumable") return 1;
  const stored = state.consumables?.[entry.name];
  const effect = stored?.effect || {};
  const candidates = [
    ["hunger", Number(effect.hunger) || 0],
    ["thirst", Number(effect.thirst) || 0],
    ["energy", Number(effect.energy) || 0],
    ["health", Number(effect.health) || 0]
  ].filter(([, value]) => value > 0).sort((a, b) => b[1] - a[1]);
  if (!candidates.length) return 1;
  const [stat, value] = candidates[0];
  const current = stat === "health" ? Number(state.health ?? 100) : Number(state[stat] ?? 0);
  const needed = Math.max(0, 100 - current);
  if (needed <= 0) return 0;
  return Math.max(1, Math.min(inventoryMaximumUseAmount(entry), Math.ceil(needed / value)));
}

function useInventoryWorkbenchEntry(entry, amount = 1) {
  if (!entry) return;
  if (entry.kind === "consumable") return useConsumableAmount(entry.name, amount);
  if (entry.kind === "device") {
    openDeviceInterface(entry.name);
    queuePurchaseConfirmation({ kind: "use", title: "Benutzt", name: entry.name, icon: "📱" });
    return;
  }
  if (entry.kind === "sim") return installSimCard(entry.name);
  if (entry.kind === "credit") return redeemPhoneCreditCard(entry.name);
  if (entry.kind === "powerbank") return usePowerbank();
  addFeed(`${entry.name} kann nicht direkt auf den Charakter angewendet werden.`);
}

function closeInventoryUseChoice(root = els.dialog) {
  root?.querySelector?.("[data-inventory-use-choice]")?.remove();
}

function openInventoryUseChoice(entry, root = els.dialog) {
  if (!entry) return;
  const maximum = inventoryMaximumUseAmount(entry);
  if (entry.kind !== "consumable" || maximum <= 1) return useInventoryWorkbenchEntry(entry, 1);
  const fillAmount = inventoryUseUntilFullAmount(entry);
  closeInventoryUseChoice(root);
  const overlay = document.createElement("div");
  overlay.className = "inventory-use-choice-overlay";
  overlay.dataset.inventoryUseChoice = "true";
  overlay.innerHTML = `
    <div class="inventory-use-choice-card" role="dialog" aria-modal="true" aria-label="Menge benutzen">
      <span class="inventory-use-choice-icon">${entry.icon}</span>
      <h3>${escapeHtml(entry.name)}</h3>
      <p>${maximum} Stück vorhanden. Wähle, wie viel du auf den Charakter anwenden möchtest.</p>
      <button class="primary-button" type="button" data-inventory-use-one>1 benutzen</button>
      <button class="mini-button gold" type="button" data-inventory-use-fill ${fillAmount < 1 ? "disabled" : ""}>${fillAmount > 1 ? `Mehr benutzen · bis voll (${fillAmount}x)` : fillAmount === 1 ? "Bis voll (1x)" : "Passender Wert ist bereits voll"}</button>
      <button class="mini-button" type="button" data-inventory-use-cancel>Abbrechen</button>
    </div>`;
  root.appendChild(overlay);
  overlay.querySelector("[data-inventory-use-one]")?.addEventListener("click", () => { closeInventoryUseChoice(root); useInventoryWorkbenchEntry(entry, 1); });
  overlay.querySelector("[data-inventory-use-fill]")?.addEventListener("click", () => { closeInventoryUseChoice(root); useInventoryWorkbenchEntry(entry, fillAmount); });
  overlay.querySelector("[data-inventory-use-cancel]")?.addEventListener("click", () => closeInventoryUseChoice(root));
  overlay.addEventListener("click", (event) => { if (event.target === overlay) closeInventoryUseChoice(root); });
}

function stopInventoryDesktopAmountSelection(root) {
  if (inventoryDesktopWheelHandler) document.removeEventListener("wheel", inventoryDesktopWheelHandler, true);
  inventoryDesktopWheelHandler = null;
  root?.querySelector?.("[data-inventory-drag-amount]")?.remove();
  const label = root?.querySelector?.(".inventory-drop-label");
  if (label) label.textContent = "Zum Benutzen auf den Charakter ziehen";
}

function beginInventoryDesktopAmountSelection(root, entry) {
  stopInventoryDesktopAmountSelection(root);
  inventoryUiDragAmount = 1;
  const maximum = inventoryMaximumUseAmount(entry);
  if (maximum <= 1) return;
  const indicator = document.createElement("div");
  indicator.className = "inventory-drag-amount-indicator";
  indicator.dataset.inventoryDragAmount = "true";
  root.appendChild(indicator);
  const update = () => {
    indicator.textContent = `Menge ${inventoryUiDragAmount}x · Mausrad hoch/runter`;
    const label = root.querySelector(".inventory-drop-label");
    if (label) label.textContent = `${inventoryUiDragAmount}x auf den Charakter ziehen`;
  };
  inventoryDesktopWheelHandler = (event) => {
    if (!inventoryUiDrag || inventoryUiDrag.id !== entry.id) return;
    event.preventDefault();
    const direction = event.deltaY < 0 ? 1 : -1;
    inventoryUiDragAmount = Math.max(1, Math.min(maximum, inventoryUiDragAmount + direction));
    update();
  };
  document.addEventListener("wheel", inventoryDesktopWheelHandler, { capture: true, passive: false });
  update();
}

function sellInventoryWorkbenchEntry(entry) {
  if (!entry) return;
  if (entry.protected || inventoryProtectedTopTierItem(entry.name)) return addFeed(`${entry.name} ist die letzte Geräte-Stufe und bleibt dauerhaft in deinem Besitz.`);
  if (entry.kind === "consumable") return sellConsumable(entry.name);
  return sellInventoryItem(entry.name);
}

function inventorySearchTextMatches(text, query) {
  const normalizedQuery = inventorySearchKey(query);
  if (!normalizedQuery) return true;
  const normalizedText = inventorySearchKey(text);
  if (normalizedText.includes(normalizedQuery)) return true;
  const hayTokens = normalizedText.split(" ").filter(Boolean);
  const originalTokens = normalizedQuery.split(" ").filter(Boolean);
  return originalTokens.every((token) => {
    const candidates = new Set([token]);
    const aliases = inventoryGeneralSearchAliases[token];
    if (aliases) inventorySearchKey(aliases).split(" ").filter(Boolean).forEach((alias) => candidates.add(alias));
    return [...candidates].some((candidate) => hayTokens.some((hay) => {
      if (hay === candidate) return true;
      if (candidate.length < 3 || hay.length < 3) return false;
      return hay.includes(candidate);
    }));
  });
}

function applyInventorySearchFilter(root, value = "") {
  inventoryUiSearch = String(value || "");
  const query = inventorySearchKey(inventoryUiSearch);
  let visible = 0;
  root.querySelectorAll("[data-inventory-entry]").forEach((slot) => {
    const entry = inventoryEntryById(slot.dataset.inventoryEntry);
    const searchable = entry ? inventoryEntrySearchText(entry) : (slot.getAttribute("data-inventory-search-text") || "");
    const show = inventorySearchTextMatches(searchable, query);
    slot.hidden = !show;
    if (show) visible += 1;
  });
  root.querySelectorAll(".inventory-slot.empty").forEach((slot) => { slot.hidden = !!query; });
  const empty = root.querySelector("[data-inventory-search-empty]");
  if (empty) empty.hidden = visible > 0 || !query;
}

function closeInventoryInlineActions(root, exceptSlot = null) {
  root?.querySelectorAll("[data-inventory-entry]").forEach((slot) => {
    if (slot === exceptSlot) return;
    slot.classList.remove("selected", "actions-open");
    const actions = slot.querySelector("[data-inventory-slot-actions]");
    if (actions) actions.hidden = true;
  });
}

function renderInventorySelectedDetail(root, entry) {
  if (!root || !entry) return;
  const slot = [...root.querySelectorAll("[data-inventory-entry]")].find((element) => element.dataset.inventoryEntry === entry.id);
  if (!slot) return;
  inventoryUiSelected = entry.id;
  closeInventoryInlineActions(root, slot);
  slot.classList.add("selected", "actions-open");
  const actions = slot.querySelector("[data-inventory-slot-actions]");
  if (actions) actions.hidden = false;
}

function toggleInventoryInlineActions(root, slot, entry) {
  if (!root || !slot || !entry) return;
  const actions = slot.querySelector("[data-inventory-slot-actions]");
  const wasOpen = !!actions && !actions.hidden;
  closeInventoryInlineActions(root);
  if (!wasOpen) renderInventorySelectedDetail(root, entry);
  else inventoryUiSelected = "";
}

function clearInventoryDragHighlights(root) {
  root?.querySelectorAll(".drag-sort-target,.touch-dragging").forEach((element) => element.classList.remove("drag-sort-target", "touch-dragging"));
  root?.querySelector("[data-inventory-dropzone]")?.classList.remove("drag-ready", "drag-over");
  root?.classList.remove("inventory-touch-sorting");
}

function confirmInventoryContextSale(entry) {
  if (!entry) return;
  if (entry.kind === "vehicle") {
    renderInventorySelectedDetail(els.dialog, entry);
    return;
  }
  if (!entry.canSell) {
    addFeed(entry.protected ? `${entry.name} ist ein Dauergerät und nicht verkäuflich.` : `${entry.name} kann nicht verkauft werden.`);
    return;
  }
  const value = inventorySellValue(entry.name);
  if (window.confirm(`${entry.name} für ${euro.format(value)} verkaufen?`)) sellInventoryWorkbenchEntry(entry);
}

function startInventoryTouchSort(root, slot, entry, event) {
  if (!entry || !event || event.pointerType === "mouse") return;
  if (event.target?.closest?.("[data-inventory-slot-actions]")) return;
  if (inventoryTouchDrag) return;
  const drag = {
    root, slot, entry, pointerId: event.pointerId,
    startX: event.clientX, startY: event.clientY, x: event.clientX, y: event.clientY,
    started: false, targetPosition: -1, overCharacter: false, timer: 0, scrollFrame: 0,
    scrollContainer: root.querySelector(".character-hub-content") || root.closest?.(".character-hub-content") || els.dialog
  };
  const cleanup = () => {
    clearTimeout(drag.timer);
    if (drag.scrollFrame) cancelAnimationFrame(drag.scrollFrame);
    document.removeEventListener("pointermove", onMove, true);
    document.removeEventListener("pointerup", onEnd, true);
    document.removeEventListener("pointercancel", onCancel, true);
    clearInventoryDragHighlights(root);
    if (inventoryTouchDrag === drag) inventoryTouchDrag = null;
  };
  const updateTarget = () => {
    root.querySelectorAll(".drag-sort-target").forEach((element) => element.classList.remove("drag-sort-target"));
    const element = document.elementFromPoint(drag.x, drag.y);
    const targetSlot = element?.closest?.("[data-inventory-position]");
    const dropzone = element?.closest?.("[data-inventory-dropzone]");
    drag.targetPosition = targetSlot ? Number(targetSlot.dataset.inventoryPosition) : -1;
    drag.overCharacter = !!dropzone;
    if (targetSlot && drag.targetPosition !== Number(slot.dataset.inventoryPosition)) targetSlot.classList.add("drag-sort-target");
    dropzone?.classList.add("drag-over");
    if (!dropzone) root.querySelector("[data-inventory-dropzone]")?.classList.remove("drag-over");
  };
  const autoScroll = () => {
    if (!drag.started || !drag.scrollContainer) return;
    const scroller = drag.scrollContainer;
    const rect = scroller.getBoundingClientRect();
    const edge = Math.max(54, Math.min(92, rect.height * 0.22));
    let speed = 0;
    if (drag.y < rect.top + edge) {
      speed = -Math.ceil(4 + ((rect.top + edge - drag.y) / edge) * 20);
    } else if (drag.y > rect.bottom - edge) {
      speed = Math.ceil(4 + ((drag.y - (rect.bottom - edge)) / edge) * 20);
    }
    if (speed) {
      const before = scroller.scrollTop;
      scroller.scrollTop += speed;
      if (scroller.scrollTop !== before) updateTarget();
    }
    drag.scrollFrame = requestAnimationFrame(autoScroll);
  };
  const begin = () => {
    drag.started = true;
    inventoryIgnoreClickUntil = Date.now() + 900;
    closeInventoryInlineActions(root);
    slot.classList.add("touch-dragging");
    root.classList.add("inventory-touch-sorting");
    root.querySelector("[data-inventory-dropzone]")?.classList.add("drag-ready");
    if (navigator.vibrate) navigator.vibrate(18);
    updateTarget();
    drag.scrollFrame = requestAnimationFrame(autoScroll);
  };
  const onMove = (moveEvent) => {
    if (moveEvent.pointerId !== drag.pointerId) return;
    drag.x = moveEvent.clientX;
    drag.y = moveEvent.clientY;
    if (!drag.started) {
      if (Math.hypot(drag.x - drag.startX, drag.y - drag.startY) > 12) cleanup();
      return;
    }
    moveEvent.preventDefault();
    updateTarget();
  };
  const onEnd = (upEvent) => {
    if (upEvent.pointerId !== drag.pointerId) return;
    if (drag.started) {
      upEvent.preventDefault();
      if (drag.overCharacter) openInventoryUseChoice(entry, root);
      else if (drag.targetPosition >= 0 && drag.targetPosition !== Number(slot.dataset.inventoryPosition)) moveInventoryEntryToSlot(entry.id, drag.targetPosition);
    }
    cleanup();
  };
  const onCancel = (cancelEvent) => {
    if (cancelEvent.pointerId === drag.pointerId) cleanup();
  };
  drag.timer = window.setTimeout(begin, 430);
  inventoryTouchDrag = drag;
  document.addEventListener("pointermove", onMove, { capture: true, passive: false });
  document.addEventListener("pointerup", onEnd, { capture: true, passive: false });
  document.addEventListener("pointercancel", onCancel, true);
}

function bindInventoryWorkbench(root) {
  const search = root.querySelector("[data-inventory-search]");
  if (search) {
    search.addEventListener("input", () => applyInventorySearchFilter(root, search.value));
    search.addEventListener("search", () => applyInventorySearchFilter(root, search.value));
    applyInventorySearchFilter(root, search.value);
  }

  root.querySelectorAll("[data-inventory-slot-actions] button").forEach((button) => {
    button.addEventListener("pointerdown", (event) => event.stopPropagation());
    button.addEventListener("dragstart", (event) => event.preventDefault());
  });
  root.querySelectorAll("[data-inventory-inline-use]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      useInventoryWorkbenchEntry(inventoryEntryById(button.dataset.inventoryInlineUse));
    });
  });
  root.querySelectorAll("[data-inventory-inline-sell]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      confirmInventoryContextSale(inventoryEntryById(button.dataset.inventoryInlineSell));
    });
  });
  root.querySelectorAll("[data-inventory-inline-vehicle-sell]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      sellVehicleNow(button.dataset.inventoryInlineVehicleSell);
    });
  });
  root.querySelectorAll("[data-inventory-inline-vehicle-list]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      listVehicleForSale(button.dataset.inventoryInlineVehicleList);
    });
  });

  root.querySelectorAll("[data-inventory-entry]").forEach((slot) => {
    const getEntry = () => inventoryEntryById(slot.dataset.inventoryEntry);
    slot.addEventListener("click", (event) => {
      if (event.target?.closest?.("[data-inventory-slot-actions]")) return;
      if (Date.now() < inventoryIgnoreClickUntil) { event.preventDefault(); return; }
      toggleInventoryInlineActions(root, slot, getEntry());
    });
    slot.addEventListener("keydown", (event) => {
      if (!["Enter", " "].includes(event.key) || event.target?.closest?.("[data-inventory-slot-actions]")) return;
      event.preventDefault();
      toggleInventoryInlineActions(root, slot, getEntry());
    });
    slot.addEventListener("dblclick", (event) => {
      if (event.target?.closest?.("[data-inventory-slot-actions]")) return;
      useInventoryWorkbenchEntry(getEntry(), 1);
    });
    slot.addEventListener("contextmenu", (event) => {
      event.preventDefault();
      const entry = getEntry();
      renderInventorySelectedDetail(root, entry);
      confirmInventoryContextSale(entry);
    });
    slot.addEventListener("pointerdown", (event) => startInventoryTouchSort(root, slot, getEntry(), event));
    slot.addEventListener("dragstart", (event) => {
      if (event.target?.closest?.("[data-inventory-slot-actions]")) return event.preventDefault();
      const entry = getEntry();
      if (!entry) return event.preventDefault();
      inventoryUiDrag = entry;
      inventoryUiDragAmount = 1;
      inventoryIgnoreClickUntil = Date.now() + 500;
      closeInventoryInlineActions(root);
      event.dataTransfer?.setData("text/plain", entry.id);
      event.dataTransfer?.setDragImage(slot, 30, 30);
      if (event.dataTransfer) event.dataTransfer.effectAllowed = "move";
      root.querySelector("[data-inventory-dropzone]")?.classList.add("drag-ready");
      beginInventoryDesktopAmountSelection(root, entry);
    });
    slot.addEventListener("dragend", () => {
      inventoryUiDrag = null;
      inventoryUiDragAmount = 1;
      stopInventoryDesktopAmountSelection(root);
      clearInventoryDragHighlights(root);
    });
  });

  root.querySelectorAll("[data-inventory-position]").forEach((slot) => {
    slot.addEventListener("dragover", (event) => {
      if (!inventoryUiDrag || inventoryUiDrag.id === slot.dataset.inventoryEntry) return;
      event.preventDefault();
      if (event.dataTransfer) event.dataTransfer.dropEffect = "move";
      root.querySelectorAll(".drag-sort-target").forEach((element) => element.classList.remove("drag-sort-target"));
      slot.classList.add("drag-sort-target");
    });
    slot.addEventListener("dragleave", () => slot.classList.remove("drag-sort-target"));
    slot.addEventListener("drop", (event) => {
      if (!inventoryUiDrag) return;
      event.preventDefault();
      event.stopPropagation();
      const sourceId = event.dataTransfer?.getData("text/plain") || inventoryUiDrag.id;
      const targetPosition = Number(slot.dataset.inventoryPosition);
      stopInventoryDesktopAmountSelection(root);
      clearInventoryDragHighlights(root);
      inventoryUiDrag = null;
      inventoryUiDragAmount = 1;
      moveInventoryEntryToSlot(sourceId, targetPosition);
    });
  });

  root.addEventListener("click", (event) => {
    if (!event.target?.closest?.("[data-inventory-entry]")) {
      closeInventoryInlineActions(root);
      inventoryUiSelected = "";
    }
  });

  const dropzone = root.querySelector("[data-inventory-dropzone]");
  if (dropzone) {
    dropzone.addEventListener("dragover", (event) => { event.preventDefault(); dropzone.classList.add("drag-over"); });
    dropzone.addEventListener("dragleave", () => dropzone.classList.remove("drag-over"));
    dropzone.addEventListener("drop", (event) => {
      event.preventDefault();
      event.stopPropagation();
      dropzone.classList.remove("drag-over", "drag-ready");
      const id = event.dataTransfer?.getData("text/plain") || inventoryUiDrag?.id;
      const entry = inventoryEntryById(id);
      const amount = inventoryUiDragAmount || 1;
      stopInventoryDesktopAmountSelection(root);
      useInventoryWorkbenchEntry(entry, amount);
      inventoryUiDrag = null;
      inventoryUiDragAmount = 1;
    });
  }

}

function bindInventoryActions(root) {
  if (root.querySelector(".inventory-game-layout")) {
    bindInventoryWorkbench(root);
    return;
  }
  root.querySelectorAll("[data-inventory-detail-use]").forEach((button) => {
    button.addEventListener("click", () => useInventoryWorkbenchEntry(inventoryEntryById(button.dataset.inventoryDetailUse)));
  });
  root.querySelectorAll("[data-inventory-detail-sell]").forEach((button) => {
    button.addEventListener("click", () => sellInventoryWorkbenchEntry(inventoryEntryById(button.dataset.inventoryDetailSell)));
  });
  root.querySelectorAll("[data-inventory-category]").forEach((button) => {
    button.addEventListener("click", () => {
      state.inventoryCategory = button.dataset.inventoryCategory || "all";
      save();
      refreshAfterStateChange("inventory");
    });
  });
  root.querySelectorAll("[data-vehicle-sell]").forEach((button) => {
    button.addEventListener("click", () => sellVehicleNow(button.dataset.vehicleSell));
  });
  root.querySelectorAll("[data-vehicle-list]").forEach((button) => {
    button.addEventListener("click", () => listVehicleForSale(button.dataset.vehicleList));
  });
  root.querySelectorAll("[data-vehicle-offer]").forEach((button) => {
    button.addEventListener("click", () => retryVehicleOffer(button.dataset.vehicleOffer));
  });
  root.querySelectorAll("[data-use-consumable]").forEach((button) => {
    button.addEventListener("click", () => useConsumable(button.dataset.useConsumable));
  });
  root.querySelectorAll("[data-sell-consumable]").forEach((button) => {
    button.addEventListener("click", () => sellConsumable(button.dataset.sellConsumable));
  });
  root.querySelectorAll("[data-use-device]").forEach((button) => {
    button.addEventListener("click", () => {
      const item = button.dataset.useDevice;
      openDeviceInterface(item);
      queuePurchaseConfirmation({ kind: "use", title: "Benutzt", name: item, icon: "📱" });
    });
  });
  root.querySelectorAll("[data-sell-item]").forEach((button) => {
    button.addEventListener("click", () => sellInventoryItem(button.dataset.sellItem));
  });
  root.querySelectorAll("[data-install-sim]").forEach((button) => {
    button.addEventListener("click", () => installSimCard(button.dataset.installSim));
  });
  root.querySelectorAll("[data-redeem-phone-credit]").forEach((button) => {
    button.addEventListener("click", () => redeemPhoneCreditCard(button.dataset.redeemPhoneCredit));
  });
  root.querySelectorAll("[data-use-powerbank]").forEach((button) => {
    button.addEventListener("click", usePowerbank);
  });
}

function findShopCatalogEntry(name) {
  return findCatalogItemByName(name)?.entry || null;
}

function itemBasePrice(name) {
  const tariff = simTariffByName(name);
  const creditCard = phoneCreditCardByName(name);
  return tariff?.price || creditCard?.price || {
    "Führerschein": 3200,
    "Reisepass": 70,
    "Prepaid-Karte": 15,
    "City-SIM Datenpaket": 25,
    "Powerbank": 39,
    "Müllbeutel": 3,
    "Reinigungsmittel": 5,
    "Erste-Hilfe-Set": 22
  }[name] || 0;
}

function inventorySellValue(name) {
  if (/wasser/i.test(name)) return 0;
  const entry = findShopCatalogEntry(name);
  const price = entry?.price || itemBasePrice(name);
  return Math.max(0, Math.round((price || 0) * 0.5));
}

function sellConsumable(name) {
  const entry = state.consumables?.[name];
  if (!entry?.count) return;
  const value = inventorySellValue(name);
  entry.count -= 1;
  if (entry.count <= 0) delete state.consumables[name];
  if (value > 0) {
    payoutFromTreasury(value);
    recordIncome("sales", value);
  }
  addFeed(`${name} verkauft: ${euro.format(value)} erhalten.`, { purchase: { kind: "sell", title: "Verkauft", name, total: value, method: "Konto" } });
  save();
  refreshAfterStateChange("inventory");
}

function sellInventoryItem(name) {
  const ownedName = (state.items || []).find((owned) => owned === name || itemMatchesName(owned, name));
  if (!ownedName) return addFeed("Dieser Gegenstand ist nicht mehr im Inventar.");
  if (inventoryProtectedTopTierItem(ownedName)) return addFeed(`${ownedName} ist die letzte Geräte-Stufe und kann nicht verkauft werden.`);
  if (!consumeInventoryItem(ownedName, 1)) return addFeed("Dieser Gegenstand ist nicht mehr im Inventar.");
  if (itemMatchesName(ownedName, "Reisepass")) state.passportTrips = 0;
  if (state.phoneSim === ownedName && isSimTariffName(ownedName)) state.phoneSim = "";
  const value = inventorySellValue(ownedName);
  if (value > 0) {
    payoutFromTreasury(value);
    recordIncome("sales", value);
  }
  addFeed(`${ownedName} verkauft: ${euro.format(value)} erhalten.`, { purchase: { kind: "sell", title: "Verkauft", name: ownedName, total: value, method: "Konto" } });
  save();
  refreshAfterStateChange("inventory");
}

function installSimCard(name) {
  if (!phoneItems().some((phone) => state.items.includes(phone))) return addFeed("Du brauchst zuerst ein Handy, bevor du eine SIM-Karte benutzen kannst.");
  if (!isSimTariffName(name)) return;
  if (!consumeInventoryItem(name, 1)) return addFeed("Diese SIM-Karte ist nicht mehr im Inventar.");
  if (state.phoneSim && isSimTariffName(state.phoneSim) && state.phoneSim !== name) {
    state.items.push(state.phoneSim);
  }
  state.phoneSim = name;
  ensurePhoneIdentity();
  addFeed(`${name} ins Handy eingelegt. Guthaben: ${euro.format(state.phoneCredit || 0)}.`, { purchase: { kind: "use", title: "SIM eingelegt", name, icon: "📶" } });
  save();
  refreshAfterStateChange("inventory");
}

function redeemPhoneCreditCard(name) {
  const card = phoneCreditCardByName(name);
  if (!card) return;
  if (!ownedPhoneItem()) return addFeed("Du brauchst zuerst ein Handy, um Guthaben aufzuladen.");
  if (!consumeInventoryItem(name, 1)) return addFeed("Diese Guthabenkarte ist nicht mehr im Inventar.");
  state.phoneCredit = Math.round(((state.phoneCredit || 0) + card.credit) * 100) / 100;
  addFeed(`${name} eingelöst. Neues Handy-Guthaben: ${euro.format(state.phoneCredit)}.`, { purchase: { kind: "use", title: "Guthabenkarte eingelöst", name, icon: "💳" } });
  save();
  refreshAfterStateChange("inventory");
  updatePhoneShortcut();
}

function usePowerbank() {
  if (!ownedPhoneItem()) return addFeed("Du brauchst zuerst ein Handy.");
  if (!consumeInventoryItem("Powerbank", 1)) return addFeed("Du hast keine Powerbank im Inventar.");
  state.phoneBattery = 100;
  addFeed("Powerbank benutzt. Dein Handy-Akku ist wieder bei 100 Prozent.", { purchase: { kind: "use", title: "Benutzt", name: "Powerbank", icon: "🔋" } });
  save();
  refreshAfterStateChange("inventory");
  updatePhoneShortcut();
}

function useConsumableAmount(name, requestedAmount = 1) {
  const entry = state.consumables?.[name];
  if (!entry?.count) return 0;
  const amount = Math.max(1, Math.min(Number(entry.count) || 1, Math.floor(Number(requestedAmount) || 1)));
  const effect = entry.effect || {};
  state.hunger = clamp(state.hunger + (effect.hunger || 0) * amount);
  state.thirst = clamp(state.thirst + (effect.thirst || 0) * amount);
  state.energy = clamp(state.energy + (effect.energy || 0) * amount);
  state.health = clamp((state.health ?? 100) + (effect.health || 0) * amount);
  if (effect.illness && state.illness !== "severe") state.illness = "healthy";
  if (effect.illness && state.illness === "severe" && state.health >= 70) state.illness = "sick";
  if ((state.health ?? 100) >= 96 && state.illness !== "severe") state.illness = "healthy";
  entry.count -= amount;
  if (entry.count <= 0) delete state.consumables[name];
  addFeed(`${name}${amount > 1 ? ` ${amount}x` : ""} benutzt.`, { purchase: { kind: "use", title: amount > 1 ? `${amount}x benutzt` : "Benutzt", name, icon: "✓" } });
  save();
  refreshAfterStateChange("inventory");
  return amount;
}

function useConsumable(name) {
  return useConsumableAmount(name, 1);
}

let firebasePhoneRuntime = null;
let firebasePhoneRuntimePromise = null;
let phoneSmsUnsubscribe = null;
let phoneSmsListeningTo = "";
let phoneIncomingUnsubscribe = null;
let activePhonePeer = null;
let activeLocalPhoneStream = null;

function normalizePhoneNumber(value) {
  const digits = String(value || "").replace(/\D/g, "");
  if (!digits) return "";
  if (digits.startsWith("49555") && digits.length >= 11) return digits.slice(0, 11);
  if (digits.startsWith("555") && digits.length >= 9) return `49${digits.slice(0, 9)}`;
  if (digits.length === 6) return `49555${digits}`;
  return digits;
}

function prettyPhoneNumber(value) {
  const number = normalizePhoneNumber(value);
  if (!number) return "keine Nummer";
  if (number.startsWith("49555") && number.length === 11) return `+49 555 ${number.slice(5)}`;
  return `+${number}`;
}

function createPhoneNumber() {
  let tail = "";
  for (let i = 0; i < 6; i += 1) tail += String(Math.floor(Math.random() * 10));
  return `49555${tail}`;
}

function ensurePhoneIdentity() {
  if (!state.phoneSim) return "";
  if (!state.phoneNumber) {
    state.phoneNumber = createPhoneNumber();
    save();
  }
  return state.phoneNumber;
}

function contactNameFor(number) {
  const normalized = normalizePhoneNumber(number);
  return state.phoneContacts?.find((contact) => normalizePhoneNumber(contact.number) === normalized)?.name || prettyPhoneNumber(normalized);
}

function conversationIdFor(a, b) {
  return [normalizePhoneNumber(a), normalizePhoneNumber(b)].sort().join("_");
}

async function loadFirebasePhoneRuntime() {
  if (firebasePhoneRuntime) return firebasePhoneRuntime;
  if (firebasePhoneRuntimePromise) return firebasePhoneRuntimePromise;
  firebasePhoneRuntimePromise = (async () => {
    const [appMod, authMod, dbMod, storageMod] = await Promise.all([
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-app.js"),
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-auth.js"),
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-firestore.js"),
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-storage.js")
    ]);
    const app = appMod.getApps().length ? appMod.getApp() : appMod.initializeApp(firebasePhoneConfig);
    const auth = authMod.getAuth(app);
    if (!auth.currentUser) {
      if (window.LifeBuilderOnline?.requireUser) {
        const user = await window.LifeBuilderOnline.requireUser(auth, authMod);
        if (!user || !auth.currentUser) throw new Error("Bitte zuerst mit deinem LifeBuilder-Account anmelden.");
      } else {
        throw new Error("Bitte zuerst mit deinem LifeBuilder-Account anmelden.");
      }
    }
    const db = dbMod.getFirestore(app, FIRESTORE_DATABASE_ID);
    const storage = storageMod.getStorage(app);
    firebasePhoneRuntime = { ...dbMod, ...storageMod, auth, db, storage };
    return firebasePhoneRuntime;
  })().catch((error) => {
    firebasePhoneRuntimePromise = null;
    addFeed(`Firebase Telefon/SMS konnte nicht starten: ${error.message || error}`);
    throw error;
  });
  return firebasePhoneRuntimePromise;
}

function sharedSystemAccountsPayload() {
  return {
    publicTreasury: Math.round((state?.publicTreasury || 0) * 100) / 100,
    taxAccount: Math.round((state?.taxAccount || 0) * 100) / 100,
    casinoAccount: Math.round((state?.casinoAccount || 0) * 100) / 100
  };
}

function applySharedSystemAccounts(data) {
  if (!state || !data) return;
  let changed = false;
  systemAccountsRemoteApplying = true;
  systemAccountKeys.forEach((key) => {
    const next = Number(data[key]);
    if (!Number.isFinite(next)) return;
    const rounded = Math.max(0, Math.round(next * 100) / 100);
    if (state[key] !== rounded) {
      state[key] = rounded;
      changed = true;
    }
  });
  if (changed) {
    saveSlots[selectedSlot] = state;
    localStorage.setItem(SAVE_SLOTS_KEY, JSON.stringify(saveSlots));
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    render();
  }
  systemAccountsRemoteApplying = false;
}

async function pushSharedSystemAccounts() {
  if (!ENABLE_SHARED_SYSTEM_ACCOUNTS || !state) return;
  const payload = sharedSystemAccountsPayload();
  const payloadKey = JSON.stringify(payload);
  if (payloadKey === lastSystemAccountsPayload) return;
  try {
    const fb = await loadFirebasePhoneRuntime();
    await fb.setDoc(fb.doc(fb.db, ...SHARED_SYSTEM_ACCOUNTS_PATH), {
      ...payload,
      updatedAtMs: Date.now(),
      updatedBy: state.phoneNumber || `slot-${selectedSlot + 1}`
    }, { merge: true });
    lastSystemAccountsPayload = payloadKey;
  } catch (error) {
    console.warn("Shared system accounts sync failed", error);
  }
}

function scheduleSystemAccountsSync() {
  if (!ENABLE_SHARED_SYSTEM_ACCOUNTS || !state || systemAccountsRemoteApplying) return;
  clearTimeout(systemAccountsPushTimer);
  systemAccountsPushTimer = setTimeout(pushSharedSystemAccounts, 900);
}

async function initSharedSystemAccountsSync() {
  if (!ENABLE_SHARED_SYSTEM_ACCOUNTS || !state || systemAccountsInitStarted) return;
  systemAccountsInitStarted = true;
  try {
    const fb = await loadFirebasePhoneRuntime();
    const docRef = fb.doc(fb.db, ...SHARED_SYSTEM_ACCOUNTS_PATH);
    systemAccountsUnsubscribe?.();
    systemAccountsUnsubscribe = fb.onSnapshot(docRef, async (snapshot) => {
      if (snapshot.exists()) {
        applySharedSystemAccounts(snapshot.data());
        lastSystemAccountsPayload = JSON.stringify(sharedSystemAccountsPayload());
        return;
      }
      await pushSharedSystemAccounts();
    }, (error) => {
      addFeed(`Globale Konten laufen lokal weiter: ${error.message || error}`);
    });
  } catch (error) {
    systemAccountsInitStarted = false;
    console.warn("Shared system accounts listener failed", error);
  }
}

async function registerPhoneOnline() {
  const fb = await loadFirebasePhoneRuntime();
  const ownerUid = fb.auth.currentUser?.uid;
  if (!ownerUid) throw new Error("Firebase-Anmeldung fehlt.");

  for (let attempt = 0; attempt < 6; attempt += 1) {
    const number = ensurePhoneIdentity();
    if (!number) return null;
    const phoneRef = fb.doc(fb.db, "phones", number);
    const existing = await fb.getDoc(phoneRef);
    if (existing.exists() && existing.data()?.ownerUid !== ownerUid) {
      state.phoneNumber = createPhoneNumber();
      save();
      continue;
    }
    await fb.setDoc(phoneRef, {
      number,
      ownerUid,
      displayName: `${state.firstName || ""} ${state.lastName || ""}`.trim() || state.name || "LifeBuilder",
      slot: activeSlot,
      updatedAt: fb.serverTimestamp()
    }, { merge: true });
    return { number, ownerUid };
  }
  throw new Error("Es konnte keine freie Telefonnummer erstellt werden.");
}

async function lookupPhoneRegistration(fb, rawNumber) {
  const number = normalizePhoneNumber(rawNumber);
  if (!number) return null;
  const snapshot = await fb.getDoc(fb.doc(fb.db, "phones", number));
  if (!snapshot.exists()) return null;
  const data = snapshot.data();
  if (!data?.ownerUid || data.number !== number) return null;
  return data;
}

async function ensurePhoneConversation(fb, from, to, senderUid, recipientUid) {
  const conversationId = conversationIdFor(from, to);
  const conversationRef = fb.doc(fb.db, "phoneConversations", conversationId);
  const existing = await fb.getDoc(conversationRef);
  if (!existing.exists()) {
    await fb.setDoc(conversationRef, {
      phoneNumbers: [normalizePhoneNumber(from), normalizePhoneNumber(to)],
      participantUids: [...new Set([senderUid, recipientUid])],
      createdAt: fb.serverTimestamp(),
      createdAtMs: Date.now()
    });
  }
  return { conversationId, conversationRef };
}

function addPhoneContact(name, rawNumber) {
  const number = normalizePhoneNumber(rawNumber);
  const label = String(name || "").trim();
  if (!label || !number) return addFeed("Kontakt braucht Name und Telefonnummer.");
  state.phoneContacts ||= [];
  const existing = state.phoneContacts.find((contact) => normalizePhoneNumber(contact.number) === number);
  if (existing) existing.name = label;
  else state.phoneContacts.push({ name: label, number, createdAt: Date.now() });
  save();
  addFeed(`Kontakt gespeichert: ${label} (${prettyPhoneNumber(number)}).`);
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

function deletePhoneContact(number) {
  const normalized = normalizePhoneNumber(number);
  state.phoneContacts = (state.phoneContacts || []).filter((contact) => normalizePhoneNumber(contact.number) !== normalized);
  if (state.phoneActiveContact === normalized) state.phoneActiveContact = "";
  save();
  addFeed("Kontakt gelöscht.");
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

async function sendFirebaseSms(rawNumber, text) {
  const from = ensurePhoneIdentity();
  const to = normalizePhoneNumber(rawNumber);
  const message = String(text || "").trim();
  if (!from) return addFeed("Lege zuerst eine SIM-Karte ein.");
  if (!to) return addFeed("Bitte gültige Telefonnummer eingeben.");
  if (!message) return addFeed("SMS ist leer.");
  if (message.length > 2000) return addFeed("Die SMS ist zu lang.");

  const fb = await loadFirebasePhoneRuntime();
  const sender = await registerPhoneOnline();
  const recipient = await lookupPhoneRegistration(fb, to);
  if (!sender || !recipient) return addFeed("Diese Telefonnummer ist aktuell nicht bei Sim.KL registriert.");

  if (!chargePhoneCommunication("sms")) {
    save();
    return openDeviceInterface(ownedPhoneItem(), "sms", false);
  }
  save();
  const onlineFrom = sender.number;
  const { conversationId } = await ensurePhoneConversation(fb, onlineFrom, to, sender.ownerUid, recipient.ownerUid);
  await fb.addDoc(fb.collection(fb.db, "phoneConversations", conversationId, "messages"), {
    from: onlineFrom,
    to,
    senderUid: sender.ownerUid,
    recipientUid: recipient.ownerUid,
    text: message,
    createdAt: fb.serverTimestamp(),
    createdAtMs: Date.now()
  });
  state.phoneActiveContact = to;
  save();
  addFeed(`SMS an ${contactNameFor(to)} gesendet.`);
  openDeviceInterface(ownedPhoneItem(), "sms", false);
}

function cachedMessagesFor(number) {
  const own = ensurePhoneIdentity();
  const id = own && number ? conversationIdFor(own, number) : "";
  return id ? (state.phoneMessages?.[id] || []) : [];
}

async function startSmsListener(number) {
  const own = ensurePhoneIdentity();
  const other = normalizePhoneNumber(number);
  if (!own || !other) return;
  const fb = await loadFirebasePhoneRuntime();
  const ownRegistration = await registerPhoneOnline();
  const otherRegistration = await lookupPhoneRegistration(fb, other);
  if (!ownRegistration || !otherRegistration) return;
  const onlineOwn = ownRegistration.number;
  const listenKey = conversationIdFor(onlineOwn, other);
  if (phoneSmsListeningTo === listenKey && phoneSmsUnsubscribe) return;
  await ensurePhoneConversation(fb, onlineOwn, other, ownRegistration.ownerUid, otherRegistration.ownerUid);
  const conversationId = listenKey;
  if (phoneSmsUnsubscribe) phoneSmsUnsubscribe();
  phoneSmsListeningTo = listenKey;
  const q = fb.query(fb.collection(fb.db, "phoneConversations", conversationId, "messages"), fb.orderBy("createdAtMs", "asc"), fb.limit(80));
  phoneSmsUnsubscribe = fb.onSnapshot(q, (snapshot) => {
    state.phoneMessages ||= {};
    state.phoneMessages[conversationId] = snapshot.docs.map((docSnap) => ({ id: docSnap.id, ...docSnap.data() }));
    save();
    if (els.dialog?.open && els.dialog.querySelector(".device-shell") && state.phoneActiveContact === other) refreshDeviceApp("sms");
  }, (error) => addFeed(`SMS-Verbindung getrennt: ${error.message || error}`));
}

async function startIncomingCallListener() {
  const own = ensurePhoneIdentity();
  if (!own || phoneIncomingUnsubscribe) return;
  const fb = await loadFirebasePhoneRuntime();
  const registration = await registerPhoneOnline();
  if (!registration) return;
  const q = fb.query(fb.collection(fb.db, "phoneCalls"), fb.where("calleeUid", "==", registration.ownerUid), fb.limit(20));
  phoneIncomingUnsubscribe = fb.onSnapshot(q, (snapshot) => {
    const calls = snapshot.docs
      .map((docSnap) => ({ id: docSnap.id, ...docSnap.data() }))
      .filter((call) => call.status === "ringing");
    state.phoneIncomingCalls = calls.map((call) => ({ id: call.id, caller: call.caller, createdAtMs: call.createdAtMs || Date.now() }));
    if (calls.length) {
      state.phoneCallStatus = `Eingehender Anruf von ${contactNameFor(calls[0].caller)}.`;
      save();
      if (els.dialog?.open && els.dialog.querySelector(".device-shell")) refreshDeviceApp("phone");
    }
  });
}

function phoneRealtimeStatus() {
  if (!state.phoneSim) return "Lege zuerst eine SIM-Karte ein.";
  if (!state.phoneNumber) return "Nummer wird beim ersten Online-Start erstellt.";
  return `Deine Nummer: ${prettyPhoneNumber(state.phoneNumber)}.`;
}

async function startFirebaseCall(rawNumber) {
  const caller = ensurePhoneIdentity();
  const callee = normalizePhoneNumber(rawNumber);
  if (!caller) return addFeed("Lege zuerst eine SIM-Karte ein.");
  if (!callee) return addFeed("Bitte gültige Telefonnummer eingeben.");

  const fb = await loadFirebasePhoneRuntime();
  const callerRegistration = await registerPhoneOnline();
  const calleeRegistration = await lookupPhoneRegistration(fb, callee);
  if (!callerRegistration || !calleeRegistration) return addFeed("Diese Telefonnummer ist aktuell nicht bei Sim.KL registriert.");
  const onlineCaller = callerRegistration.number;

  if (!chargePhoneCommunication("call")) {
    save();
    return openDeviceInterface(ownedPhoneItem(), "phone", false);
  }
  const tariff = activeSimTariff();
  if (Math.random() >= (tariff?.callChance || 0)) {
    state.phoneCallStatus = `Anruf zu ${contactNameFor(callee)} abgebrochen. Die Gebühr wurde berechnet; erneutes Anrufen kostet erneut.`;
    addFeed(state.phoneCallStatus);
    save();
    return openDeviceInterface(ownedPhoneItem(), "phone", false);
  }
  save();
  if (!navigator.mediaDevices?.getUserMedia || !window.RTCPeerConnection) {
    return addFeed("Dieser Browser unterstützt WebRTC/Mikrofon hier nicht.");
  }
  activeLocalPhoneStream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
  activePhonePeer = new RTCPeerConnection({ iceServers: [{ urls: "stun:stun.l.google.com:19302" }] });
  activeLocalPhoneStream.getTracks().forEach((track) => activePhonePeer.addTrack(track, activeLocalPhoneStream));
  activePhonePeer.ontrack = (event) => {
    let audio = document.querySelector("[data-phone-remote-audio]");
    if (!audio) {
      audio = document.createElement("audio");
      audio.dataset.phoneRemoteAudio = "1";
      audio.autoplay = true;
      document.body.appendChild(audio);
    }
    audio.srcObject = event.streams[0];
  };
  const callRef = fb.doc(fb.collection(fb.db, "phoneCalls"));
  const callerCandidates = fb.collection(callRef, "callerCandidates");
  const queuedCallerCandidates = [];
  let callDocumentCreated = false;
  activePhonePeer.onicecandidate = (event) => {
    if (!event.candidate) return;
    const candidate = event.candidate.toJSON();
    if (!callDocumentCreated) {
      queuedCallerCandidates.push(candidate);
      return;
    }
    fb.addDoc(callerCandidates, candidate).catch((error) => console.warn("ICE candidate failed", error));
  };
  const offer = await activePhonePeer.createOffer();
  await activePhonePeer.setLocalDescription(offer);
  await fb.setDoc(callRef, {
    caller: onlineCaller,
    callee,
    callerUid: callerRegistration.ownerUid,
    calleeUid: calleeRegistration.ownerUid,
    participantUids: [...new Set([callerRegistration.ownerUid, calleeRegistration.ownerUid])],
    status: "ringing",
    offer: { type: offer.type, sdp: offer.sdp },
    createdAtMs: Date.now(),
    createdAt: fb.serverTimestamp()
  });
  callDocumentCreated = true;
  await Promise.all(queuedCallerCandidates.splice(0).map((candidate) => fb.addDoc(callerCandidates, candidate)));
  fb.onSnapshot(callRef, async (snapshot) => {
    const data = snapshot.data();
    if (!activePhonePeer || !data?.answer || activePhonePeer.currentRemoteDescription) return;
    await activePhonePeer.setRemoteDescription(new RTCSessionDescription(data.answer));
  });
  fb.onSnapshot(fb.collection(callRef, "calleeCandidates"), (snapshot) => {
    snapshot.docChanges().forEach((change) => {
      if (change.type === "added" && activePhonePeer) activePhonePeer.addIceCandidate(new RTCIceCandidate(change.doc.data()));
    });
  });
  state.phoneCallStatus = `Rufe ${contactNameFor(callee)} an. Warte auf Annahme.`;
  save();
  addFeed(state.phoneCallStatus);
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

async function answerFirebaseCall(callId) {
  await registerPhoneOnline();
  const fb = await loadFirebasePhoneRuntime();
  if (!navigator.mediaDevices?.getUserMedia || !window.RTCPeerConnection) {
    return addFeed("Dieser Browser unterstützt WebRTC/Mikrofon hier nicht.");
  }
  const callRef = fb.doc(fb.db, "phoneCalls", callId);
  const callSnapshot = await fb.getDoc(callRef);
  const callData = callSnapshot.data();
  if (!callData?.offer) return addFeed("Anruf ist nicht mehr verfügbar.");
  if (callData.calleeUid !== fb.auth.currentUser?.uid) return addFeed("Dieser Anruf gehört nicht zu deiner Telefonnummer.");
  activeLocalPhoneStream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
  activePhonePeer = new RTCPeerConnection({ iceServers: [{ urls: "stun:stun.l.google.com:19302" }] });
  activeLocalPhoneStream.getTracks().forEach((track) => activePhonePeer.addTrack(track, activeLocalPhoneStream));
  activePhonePeer.ontrack = (event) => {
    let audio = document.querySelector("[data-phone-remote-audio]");
    if (!audio) {
      audio = document.createElement("audio");
      audio.dataset.phoneRemoteAudio = "1";
      audio.autoplay = true;
      document.body.appendChild(audio);
    }
    audio.srcObject = event.streams[0];
  };
  const calleeCandidates = fb.collection(callRef, "calleeCandidates");
  activePhonePeer.onicecandidate = (event) => {
    if (event.candidate) fb.addDoc(calleeCandidates, event.candidate.toJSON());
  };
  await activePhonePeer.setRemoteDescription(new RTCSessionDescription(callData.offer));
  const answer = await activePhonePeer.createAnswer();
  await activePhonePeer.setLocalDescription(answer);
  await fb.updateDoc(callRef, {
    status: "active",
    answer: { type: answer.type, sdp: answer.sdp },
    answeredAtMs: Date.now()
  });
  fb.onSnapshot(fb.collection(callRef, "callerCandidates"), (snapshot) => {
    snapshot.docChanges().forEach((change) => {
      if (change.type === "added" && activePhonePeer) activePhonePeer.addIceCandidate(new RTCIceCandidate(change.doc.data()));
    });
  });
  state.phoneCallStatus = `Anruf mit ${contactNameFor(callData.caller)} aktiv.`;
  state.phoneIncomingCalls = [];
  save();
  addFeed(state.phoneCallStatus);
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

async function rejectFirebaseCall(callId) {
  const fb = await loadFirebasePhoneRuntime();
  const callRef = fb.doc(fb.db, "phoneCalls", callId);
  const callSnapshot = await fb.getDoc(callRef);
  if (!callSnapshot.exists() || callSnapshot.data()?.calleeUid !== fb.auth.currentUser?.uid) {
    return addFeed("Dieser Anruf kann nicht abgelehnt werden.");
  }
  await fb.updateDoc(callRef, { status: "rejected", rejectedAtMs: Date.now() });
  state.phoneIncomingCalls = (state.phoneIncomingCalls || []).filter((call) => call.id !== callId);
  state.phoneCallStatus = "Anruf abgelehnt.";
  save();
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

function endFirebaseCall() {
  activePhonePeer?.close();
  activePhonePeer = null;
  activeLocalPhoneStream?.getTracks().forEach((track) => track.stop());
  activeLocalPhoneStream = null;
  state.phoneCallStatus = "Anruf beendet.";
  save();
  openDeviceInterface(ownedPhoneItem(), "phone", false);
}

function phoneItems() {
  return ["Basic Phone KL-1", "Smartphone", "Einsteiger-Smartphone", "Mittelklasse Smartphone", "Mittelklasse-Smartphone", "Pro Smartphone", "Ultra Smartphone"];
}

function simTariffByName(name) {
  if (name === "Prepaid-Karte") return simKlTariffs[0];
  if (name === "City-SIM Datenpaket") return simKlTariffs[2];
  return simKlTariffs.find((tariff) => tariff.name === name) || null;
}

function isSimTariffName(name) {
  return !!simTariffByName(name);
}

function phoneCreditCardByName(name) {
  return phoneCreditCards.find((card) => card.name === name) || null;
}

function activeSimTariff() {
  return simTariffByName(state.phoneSim);
}

function phoneCreditAmount() {
  return Math.max(0, Math.round((Number(state.phoneCredit) || 0) * 100) / 100);
}

function canAffordPhoneCredit(amount) {
  return phoneCreditAmount() >= Math.max(0, Number(amount) || 0);
}

function spendPhoneCredit(amount, label = "Handy-Zahlung", options = {}) {
  const value = Math.max(0, Math.round((Number(amount) || 0) * 100) / 100);
  if (value <= 0) return true;
  if (!canAffordPhoneCredit(value)) {
    addFeed(`${label}: Handy-Guthaben reicht nicht. Verfügbar ${euro.format(phoneCreditAmount())}, benötigt ${euro.format(value)}.`);
    return false;
  }
  state.phoneCredit = Math.round((phoneCreditAmount() - value) * 100) / 100;
  state.phoneCreditSpent = Math.round(((state.phoneCreditSpent || 0) + value) * 100) / 100;
  allocateOutgoingPayment(value, options.target || "treasury", options.taxRate ?? 0);
  return true;
}

function addPhoneCredit(amount, label = "Handy-Gutschrift") {
  const value = Math.max(0, Math.round((Number(amount) || 0) * 100) / 100);
  state.phoneCredit = Math.round((phoneCreditAmount() + value) * 100) / 100;
  if (value > 0) addFeed(`${label}: ${euro.format(value)}. Guthaben jetzt ${euro.format(state.phoneCredit)}.`);
}

function chargePhoneCommunication(kind) {
  const tariff = activeSimTariff();
  if (!tariff) {
    addFeed("Lege zuerst einen Sim.KL Tarif ein.");
    return false;
  }
  const cost = kind === "sms" ? tariff.smsCost : tariff.callCost;
  return spendPhoneCredit(cost, kind === "sms" ? "SMS" : "Anruf");
}

function phoneCreditSummaryHtml() {
  const tariff = activeSimTariff();
  const rate = tariff ? Math.round(tariff.callChance * 100) : 0;
  const costs = tariff?.unlimited
    ? "Telefon und SMS kostenlos"
    : tariff
      ? `SMS ${euro.format(tariff.smsCost)} · Anruf ${euro.format(tariff.callCost)}`
      : "Kein Tarif eingelegt";
  return `<div class="device-finance-summary phone-credit-summary"><b>Guthaben ${euro.format(phoneCreditAmount())}</b><small>${escapeHtml(activeSimName())} · ${costs}${tariff ? ` · Verbindung ${rate}%` : ""}</small></div>`;
}

function computerItems() {
  return ["Laptop gebraucht", "Office Laptop", "Creator Laptop", "Gaming-PC", "High-End Gaming-PC"];
}

function ownedDeviceItems() {
  const deviceNames = [...phoneItems(), ...computerItems()];
  return [...new Set((state.items || []).filter((owned) => deviceNames.some((name) => itemMatchesName(owned, name))))];
}

function deviceTier(item) {
  if (/basic phone|basic/i.test(item)) return 0;
  if (/mittelklasse|office/i.test(item)) return 2;
  if (/pro|creator|gaming-pc/i.test(item)) return 3;
  if (/ultra|high-end/i.test(item)) return 4;
  if (/smartphone$|einsteiger|gebraucht/i.test(item)) return 1;
  return phoneItems().includes(item) ? 1 : 2;
}

function deviceSpeedText(tier) {
  return [
    "Sehr einfach: Notizen und Shop laufen.",
    "Langsam: Online-Apps öffnen mit Wartezeit.",
    "Solide: Alltag, Bank und Online-Shops laufen gut.",
    "Schnell: Business, Trading und Multitasking laufen sauber.",
    "Ultra: alles sofort, höchste App-Leistung und volle Features."
  ][tier] || "Solide Leistung.";
}

function hasPhoneSim() {
  return !!activeSimTariff();
}

function hasDataSim() {
  const tariff = activeSimTariff();
  return !!tariff && simKlTariffs.indexOf(tariff) >= 2;
}

function activeSimName() {
  return activeSimTariff()?.name || "Keine SIM";
}

function normalizeFinderSave(value = {}, owner = state || {}) {
  const fallbackPreference = owner.gender === "female" ? "male" : "female";
  const finder = value && typeof value === "object" ? value : {};
  finder.preference = finder.preference === "male" ? "male" : finder.preference === "female" ? "female" : fallbackPreference;
  finder.preferenceSelected = !!finder.preferenceSelected;
  const migratedPlan = finder.plan || (finder.premium ? "plus" : "free");
  finder.plan = FINDER_PLANS[migratedPlan] ? migratedPlan : "free";
  finder.premium = finder.plan !== "free";
  finder.modFreePlan = !!finder.modFreePlan;
  finder.planPaidDay = Number(finder.planPaidDay || finder.premiumPaidDay || 0);
  finder.planHistory = Array.isArray(finder.planHistory) ? [...new Set(finder.planHistory.filter((id) => FINDER_PLANS[id]))] : [finder.plan];
  if (!finder.planHistory.includes(finder.plan)) finder.planHistory.push(finder.plan);
  finder.swipeDay = Number(finder.swipeDay || owner.day || 1);
  finder.swipesToday = Math.max(0, Number(finder.swipesToday || 0));
  finder.seenToday = Array.isArray(finder.seenToday) ? [...new Set(finder.seenToday)] : [];
  finder.passed = Array.isArray(finder.passed) ? [...new Set(finder.passed)] : [];
  finder.liked = Array.isArray(finder.liked) ? [...new Set(finder.liked)] : [];
  finder.favorites = Array.isArray(finder.favorites) ? [...new Set(finder.favorites)] : [];
  finder.favoriteReviewUsed = finder.favoriteReviewUsed && typeof finder.favoriteReviewUsed === "object" ? finder.favoriteReviewUsed : {};
  finder.matches = Array.isArray(finder.matches) ? [...new Set(finder.matches)] : [];
  finder.totalMatches = Math.max(finder.matches.length, Number(finder.totalMatches || 0));
  finder.lostMatches = Array.isArray(finder.lostMatches) ? [...new Set(finder.lostMatches)] : [];
  finder.freeMatchCooldownUntilDay = Math.max(0, Number(finder.freeMatchCooldownUntilDay || 0));
  finder.chats = finder.chats && typeof finder.chats === "object" ? finder.chats : {};
  finder.activeProfileId ||= "";
  finder.activeProfileSource = ["discover", "likes"].includes(finder.activeProfileSource) ? finder.activeProfileSource : "discover";
  finder.forcedProfileId ||= "";
  finder.lastPassedId ||= "";
  finder.rewindUsedDay = Number(finder.rewindUsedDay || 0);
  finder.view ||= "discover";
  finder.relationshipId ||= "";
  finder.pendingRelationshipId ||= "";
  if (finder.pendingRelationshipId === finder.relationshipId || !finder.matches.includes(finder.pendingRelationshipId)) finder.pendingRelationshipId = "";
  finder.blockedProfiles = Array.isArray(finder.blockedProfiles) ? [...new Set(finder.blockedProfiles)] : [];
  finder.relationshipStats = finder.relationshipStats && typeof finder.relationshipStats === "object" ? finder.relationshipStats : {};
  finder.relationshipStats.relationship = Math.max(0, Math.min(100, Number(finder.relationshipStats.relationship ?? 0)));
  finder.relationshipStats.mood = Math.max(0, Math.min(100, Number(finder.relationshipStats.mood ?? 0)));
  finder.relationshipStats.lastInteractionDay = Math.max(0, Number(finder.relationshipStats.lastInteractionDay || 0));
  finder.relationshipStats.neglectDays = Math.max(0, Number(finder.relationshipStats.neglectDays || 0));
  finder.relationshipStats.movedIn = !!finder.relationshipStats.movedIn;
  finder.relationshipStats.lastAction ||= "";
  finder.relationshipStats.history = Array.isArray(finder.relationshipStats.history) ? finder.relationshipStats.history.slice(0, 30) : [];
  finder.metProfiles = Array.isArray(finder.metProfiles) ? [...new Set(finder.metProfiles)] : [];
  finder.dateHistory = Array.isArray(finder.dateHistory) ? finder.dateHistory : [];
  finder.lastMeetingDay = Math.max(0, Number(finder.lastMeetingDay || 0));
  if (finder.swipeDay !== Number(owner.day || 1)) {
    finder.swipeDay = Number(owner.day || 1);
    finder.swipesToday = 0;
    finder.seenToday = [];
    finder.lastPassedId = "";
    finder.forcedProfileId = "";
  }
  Object.entries(finder.chats).forEach(([profileId, chat]) => {
    if (!chat || typeof chat !== "object") finder.chats[profileId] = { messages: [], interest: 0, meetingReady: false, meetingAccepted: false, dates: 0 };
    const current = finder.chats[profileId];
    current.messages = Array.isArray(current.messages) ? current.messages : [];
    current.interest = Math.max(0, Math.min(100, Number(current.interest || 0)));
    current.meetingReady = !!current.meetingReady;
    current.meetingAccepted = !!current.meetingAccepted;
    current.dates = Math.max(0, Number(current.dates || 0));
    current.lastDateDay = Math.max(0, Number(current.lastDateDay || 0));
    current.relationshipReady = !!current.relationshipReady;
    current.lost = !!current.lost;
  });
  return finder;
}

function ensureFinderState() {
  state.finder = normalizeFinderSave(state.finder, state);
  return state.finder;
}

function finderPlanConfig(planId = ensureFinderState().plan) {
  return FINDER_PLANS[planId] || FINDER_PLANS.free;
}

function finderPlanRank(planId = ensureFinderState().plan) {
  return Math.max(0, FINDER_PLAN_ORDER.indexOf(planId));
}

function finderProfileById(id) {
  return finderAllProfiles().find((profile) => profile.id === id) || null;
}

function finderRelationshipPartner() {
  const finder = ensureFinderState();
  return finder.relationshipId ? finderProfileById(finder.relationshipId) : null;
}

function finderRelationshipStats() {
  const finder = ensureFinderState();
  const stats = finder.relationshipStats;
  if (finder.relationshipId && stats.relationship <= 0 && stats.mood <= 0) {
    const chat = finderChatFor(finder.relationshipId);
    stats.relationship = Math.max(45, Math.min(65, Number(chat.interest || 50)));
    stats.mood = 78;
    stats.lastInteractionDay = Number(state.day || 1);
    stats.neglectDays = 0;
  }
  return stats;
}

function relationshipStatusLabel(value = finderRelationshipStats().relationship) {
  if (value >= 90) return "Sehr eng";
  if (value >= 75) return "Fest verbunden";
  if (value >= 55) return "Stabil";
  if (value >= 35) return "Angespannt";
  if (value >= 15) return "Kritisch";
  return "Kurz vor Trennung";
}

function partnerMoodLabel(value = finderRelationshipStats().mood) {
  if (value >= 85) return "Sehr glücklich";
  if (value >= 65) return "Zufrieden";
  if (value >= 45) return "Nachdenklich";
  if (value >= 25) return "Enttäuscht";
  return "Sehr unglücklich";
}

function finderPartnerInteractedToday() {
  const finder = ensureFinderState();
  return Number(finder.lastMeetingDay || 0) === Number(state.day || 1)
    || Number(finderRelationshipStats().lastInteractionDay || 0) === Number(state.day || 1);
}

function endFinderRelationshipPermanently(reason = "Die Beziehung ist zerbrochen", options = {}) {
  const finder = ensureFinderState();
  const profileId = finder.relationshipId;
  const profile = finderProfileById(profileId);
  if (!profileId || !profile) return false;
  const initiatedByPlayer = !!options.initiatedByPlayer;
  finder.relationshipId = "";
  finder.matches = finder.matches.filter((id) => id !== profileId);
  finder.liked = finder.liked.filter((id) => id !== profileId);
  finder.favorites = finder.favorites.filter((id) => id !== profileId);
  finder.passed = finder.passed.filter((id) => id !== profileId);
  if (!finder.lostMatches.includes(profileId)) finder.lostMatches.push(profileId);
  if (!finder.blockedProfiles.includes(profileId)) finder.blockedProfiles.push(profileId);
  delete finder.chats[profileId];
  finder.activeProfileId = "";
  finder.view = "matches";
  finder.relationshipStats = {
    relationship: 0, mood: 0, lastInteractionDay: 0, neglectDays: 0,
    movedIn: false, lastAction: "", history: []
  };
  addFeed(initiatedByPlayer
    ? `Du hast die Beziehung mit ${profile.name} beendet. Match, Chat, Dates und der gesamte Beziehungsfortschritt wurden gelöscht. Dieses Profil kann nicht erneut erscheinen.`
    : `${reason}: ${profile.name} hat die Beziehung beendet. Dieses Profil kann nicht erneut erscheinen.`);
  return true;
}

function settleFinderRelationshipAfterSleep() {
  const finder = ensureFinderState();
  if (!finder.relationshipId) return;
  const profile = finderRelationshipPartner();
  if (!profile) return endFinderRelationshipPermanently("Beziehungsprofil nicht mehr verfügbar");
  const stats = finderRelationshipStats();
  const completedDay = Math.max(1, Number(state.day || 1) - 1);
  const cared = Number(stats.lastInteractionDay || 0) === completedDay;
  if (cared) {
    stats.neglectDays = 0;
    stats.mood = clamp(stats.mood - 1, 0, 100);
  } else {
    stats.neglectDays += 1;
    stats.relationship = clamp(stats.relationship - (stats.movedIn ? 7 : 6), 0, 100);
    stats.mood = clamp(stats.mood - (stats.movedIn ? 10 : 8), 0, 100);
    addFeed(`${profile.name} fühlt sich vernachlässigt: Beziehung ${Math.round(stats.relationship)}%, Stimmung ${Math.round(stats.mood)}%.`);
  }
  if (stats.neglectDays >= 5 || stats.relationship <= 5 || stats.mood <= 3) {
    endFinderRelationshipPermanently(`${profile.name} wurde zu lange vernachlässigt`);
  }
}

function partnerActionDefinitions() {
  return [
    { id: "talk", name: "In Ruhe reden", text: "Zeit nehmen, zuhören und den Tag besprechen.", cost: 0, relationship: 3, mood: 5, icon: "💬" },
    { id: "cook", name: "Gemeinsam kochen", text: "Zusammen essen und den Alltag teilen.", cost: 60, relationship: 4, mood: 7, icon: "🍲" },
    { id: "gift", name: "Kleine Überraschung", text: "Eine persönliche Aufmerksamkeit mitbringen.", cost: 250, relationship: 6, mood: 9, icon: "🎁" },
    { id: "outing", name: "Gemeinsamer Ausflug", text: "Einen besonderen Tag miteinander verbringen.", cost: 1000, relationship: 8, mood: 12, icon: "🌆" }
  ];
}

function finderRelationshipActionCount() {
  const actionNames = new Set(partnerActionDefinitions().map((entry) => entry.name));
  return (state?.finder?.relationshipStats?.history || []).filter((entry) => actionNames.has(entry?.action)).length;
}

function openPartnerCareDialog() {
  const profile = finderRelationshipPartner();
  if (!profile) return addFeed("Du bist aktuell in keiner festen Beziehung.");
  const stats = finderRelationshipStats();
  const chat = finderChatFor(profile.id);
  clearDialogDynamic();
  els.dialogTitle.textContent = `${profile.name} · Beziehung`;
  els.dialogText.textContent = `${profile.gender === "female" ? "Deine Freundin" : "Dein Freund"}${stats.movedIn ? " wohnt bei dir" : ` lebt in ${profile.city}`}. Kümmere dich regelmäßig um die Beziehung. Pro Spieltag zählt eine gemeinsame Aktivität.`;
  const panel = document.createElement("div");
  panel.className = "partner-care-panel";
  panel.innerHTML = `
    <section class="partner-care-hero">
      ${finderProfileAvatarHtml(profile, "partner-care plain")}
      <div><h3>${escapeHtml(profile.name)}, ${profile.age}</h3><p>${escapeHtml(profile.job)} · ${escapeHtml(profile.city)}</p><span>${stats.movedIn ? "Zusammenwohnend" : "Eigener Wohnort"}</span></div>
    </section>
    <section class="partner-meter-grid">
      <article><div><span>Beziehung</span><b>${Math.round(stats.relationship)}%</b></div><progress max="100" value="${stats.relationship}"></progress><small>${relationshipStatusLabel(stats.relationship)}</small></article>
      <article><div><span>Ihre Stimmung</span><b>${Math.round(stats.mood)}%</b></div><progress max="100" value="${stats.mood}"></progress><small>${partnerMoodLabel(stats.mood)}</small></article>
    </section>
    <div class="partner-daily-note ${finderPartnerInteractedToday() ? "done" : ""}">${finderPartnerInteractedToday() ? `Heute schon Zeit miteinander verbracht: ${escapeHtml(stats.lastAction || "gemeinsame Aktivität")}.` : "Heute wurde noch nichts gemeinsam unternommen."}</div>
    <section class="partner-action-list">
      ${partnerActionDefinitions().map((action) => card(`${action.icon} ${action.name}`, `${action.text}${action.cost ? ` Kosten: ${euro.format(action.cost)}.` : " Kostenlos."}`, finderPartnerInteractedToday() ? "Heute erledigt" : "Machen", action.id, finderPartnerInteractedToday() || !canAfford(action.cost), "partner-action")).join("")}
    </section>
    <section class="partner-move-card">
      <div><b>Zusammenziehen</b><small>Benötigt mindestens 80% Beziehung, 65% Stimmung und drei gemeinsame Dates.</small></div>
      <button class="mini-button gold" data-partner-move ${stats.movedIn || stats.relationship < 80 || stats.mood < 65 || chat.dates < 3 || !hasAccessibleHome() ? "disabled" : ""}>${stats.movedIn ? "Wohnt bei dir" : "Einzug vorschlagen"}</button>
    </section>
    <section class="partner-breakup-card">
      <div><b>Beziehung beenden</b><small>Beim Trennen werden Match, Chat, Dates und sämtlicher Fortschritt mit ${escapeHtml(profile.name)} endgültig gelöscht.</small></div>
      <button class="mini-button danger" data-partner-breakup>Trennen</button>
    </section>
  `;
  els.dialog.append(panel);
  panel.querySelectorAll('button[data-kind="partner-action"]:not(:disabled)').forEach((button) => button.addEventListener("click", () => completePartnerAction(button.dataset.index)));
  panel.querySelector("[data-partner-move]:not(:disabled)")?.addEventListener("click", askPartnerToMoveIn);
  panel.querySelector("[data-partner-breakup]")?.addEventListener("click", () => showPartnerBreakupConfirmation(panel));
  if (!els.dialog.open) els.dialog.showModal();
}

function showPartnerBreakupConfirmation(panel) {
  const profile = finderRelationshipPartner();
  if (!profile || !panel) return;
  panel.querySelector(".partner-breakup-confirm")?.remove();
  const overlay = document.createElement("div");
  overlay.className = "partner-breakup-confirm";
  overlay.innerHTML = `
    <div class="partner-breakup-confirm-card">
      ${finderProfileAvatarHtml(profile, "mini plain")}
      <h4>Wirklich von ${escapeHtml(profile.name)} trennen?</h4>
      <p>Danach sind Match, Chat, Dates, Beziehung und Stimmung vollständig verloren. ${escapeHtml(profile.name)} kann anschließend nicht erneut gefunden werden.</p>
      <div class="partner-breakup-confirm-actions">
        <button class="mini-button" data-partner-breakup-cancel>Nein, zusammenbleiben</button>
        <button class="mini-button danger" data-partner-breakup-confirm>Ja, endgültig trennen</button>
      </div>
    </div>`;
  panel.append(overlay);
  overlay.querySelector("[data-partner-breakup-cancel]")?.addEventListener("click", () => overlay.remove());
  overlay.querySelector("[data-partner-breakup-confirm]")?.addEventListener("click", () => {
    const current = finderRelationshipPartner();
    if (!current) return overlay.remove();
    if (!endFinderRelationshipPermanently("Beziehung beendet", { initiatedByPlayer: true })) return;
    save();
    els.dialog.close();
    render();
  });
}

function completePartnerAction(actionId) {
  const profile = finderRelationshipPartner();
  const action = partnerActionDefinitions().find((entry) => entry.id === actionId);
  if (!profile || !action) return;
  if (finderPartnerInteractedToday()) return addFeed("Für heute habt ihr bereits eine gemeinsame Aktivität erledigt.");
  if (action.cost > 0 && !pay(action.cost, false, { target: "treasury", taxRate: 0.19 })) return addFeed(`Für ${action.name} brauchst du ${euro.format(action.cost)}.`);
  const stats = finderRelationshipStats();
  stats.relationship = clamp(stats.relationship + action.relationship, 0, 100);
  stats.mood = clamp(stats.mood + action.mood, 0, 100);
  stats.lastInteractionDay = Number(state.day || 1);
  ensureFinderState().lastMeetingDay = Number(state.day || 1);
  stats.neglectDays = 0;
  stats.lastAction = action.name;
  stats.history.unshift({ day: state.day, action: action.name, at: Date.now() });
  stats.history = stats.history.slice(0, 30);
  addFeed(`${action.name} mit ${profile.name}: Beziehung ${Math.round(stats.relationship)}%, Stimmung ${Math.round(stats.mood)}%.`, action.cost ? { purchase: { name: `${action.name} mit ${profile.name}`, total: action.cost, method: "Konto/Bargeld", icon: action.icon } } : undefined);
  save();
  render();
  openPartnerCareDialog();
}

function askPartnerToMoveIn() {
  const profile = finderRelationshipPartner();
  const stats = finderRelationshipStats();
  const chat = profile ? finderChatFor(profile.id) : null;
  if (!profile || !chat || stats.movedIn) return;
  if (stats.relationship < 80 || stats.mood < 65 || chat.dates < 3 || !hasAccessibleHome()) return addFeed("Für einen Einzug braucht ihr mehr Vertrauen, mindestens drei Dates und eine verfügbare Wohnung.");
  stats.movedIn = true;
  stats.relationship = clamp(stats.relationship + 5, 0, 100);
  stats.mood = clamp(stats.mood + 10, 0, 100);
  stats.lastInteractionDay = Number(state.day || 1);
  ensureFinderState().lastMeetingDay = Number(state.day || 1);
  stats.lastAction = "Zusammengezogen";
  stats.history.unshift({ day: state.day, action: "Zusammengezogen", at: Date.now() });
  stats.history = stats.history.slice(0, 30);
  chat.messages.push({ from: "them", text: "Ja, ich möchte zu dir ziehen. Lass uns gemeinsam ein Zuhause aufbauen. ❤️", at: Date.now() });
  addFeed(`${profile.name} ist bei dir eingezogen.`);
  save();
  render();
  openPartnerCareDialog();
}

function finderDailyLimit() {
  return finderPlanConfig().dailyLimit;
}

function finderMatchLimit() {
  return finderPlanConfig().matchLimit;
}

function finderRemainingProfiles() {
  const finder = ensureFinderState();
  return Math.max(0, finderDailyLimit() - finder.swipesToday);
}

function finderFreeCooldownDays() {
  const finder = ensureFinderState();
  if (finder.plan !== "free") return 0;
  return Math.max(0, finder.freeMatchCooldownUntilDay - Number(state.day || 1));
}

function finderProfilesForPreference() {
  const finder = ensureFinderState();
  const bots = finderProfiles.filter((profile) => profile.gender === finder.preference);
  const players = finderOnlineProfiles.filter((profile) => profile.gender === finder.preference && profile.online);
  if (!players.length) return bots;
  // Zuerst erscheinen immer wieder Bots. Nach jeweils drei Bots wird ein
  // echter Online-Spieler eingemischt, damit Spielerprofile nicht sofort,
  // aber zuverlässig innerhalb der täglichen Auswahl auftauchen.
  const mixed = [];
  let playerIndex = 0;
  bots.forEach((bot, index) => {
    mixed.push(bot);
    if ((index + 1) % 3 === 0 && playerIndex < players.length) mixed.push(players[playerIndex++]);
  });
  while (playerIndex < players.length) mixed.push(players[playerIndex++]);
  return mixed;
}

function finderCurrentProfile() {
  const finder = ensureFinderState();
  if (finder.swipesToday >= finderDailyLimit()) return null;
  if (finder.forcedProfileId) {
    const forced = finderProfileById(finder.forcedProfileId);
    finder.forcedProfileId = "";
    if (forced && forced.gender === finder.preference) return forced;
  }
  let pool = finderProfilesForPreference().filter((entry) => !finder.matches.includes(entry.id) && entry.id !== finder.relationshipId && !finder.blockedProfiles.includes(entry.id));
  let available = pool.filter((entry) => !finder.seenToday.includes(entry.id));
  if (!available.length) {
    finder.seenToday = [];
    available = pool;
  }
  if (finderPlanConfig().favorites) {
    const favored = available.find((entry) => finder.favorites.includes(entry.id));
    if (favored) return favored;
  }
  return available[0] || null;
}

function finderChatFor(profileId) {
  const finder = ensureFinderState();
  finder.chats[profileId] ||= { messages: [], interest: 0, meetingReady: false, meetingAccepted: false, dates: 0, lastDateDay: 0, relationshipReady: false, lost: false };
  return finder.chats[profileId];
}

function finderCanCreateMatch() {
  const finder = ensureFinderState();
  const plan = finderPlanConfig();
  if (finder.matches.length >= plan.matchLimit) return { ok: false, reason: `Dein ${plan.name}-Limit von ${plan.matchLimit} aktiven Matches ist erreicht.` };
  const cooldown = finderFreeCooldownDays();
  if (finder.plan === "free" && cooldown > 0) return { ok: false, reason: `Nach dem verlorenen Free-Match musst du noch ${cooldown} Spieltag${cooldown === 1 ? "" : "e"} schlafen.` };
  return { ok: true, reason: "" };
}

