function finsterDefaultState() {
  return { view: "feed", handle: "", displayName: "", bio: "", accountCreated: false, selectedPostId: "", selectedUserUid: "", activeConversationUid: "", likedPostIds: [], following: [], aiLikes: {}, aiComments: {}, aiMessages: {} };
}

/* Finsta.KL moderation: real-player feed and local profanity masking.
   The original sentence structure remains, only blocked words are replaced with asterisks. */
const finsterBlockedWordStems = [
  "arschloch","arsch","arschgeige","arschkriecher","arschficker","arschfotze",
  "wichser","wichs","wixer","wixxer","fick","ficken","gefickt","ficker","fickdich",
  "fotze","votze","muschi","möse","moese","schlampe","hure","hurensohn","hurentochter",
  "bastard","miststück","miststueck","drecksau","drecksschwein","schwein","sau",
  "idiot","idioten","vollidiot","trottel","depp","spast","spasti","spastiker",
  "behindert","mongo","mongoloid","opfer","lappen","loser","versager",
  "kacke","scheiße","scheisse","scheiss","shit","bullshit","mistkerl","dreckskerl",
  "pimmel","schwanz","penis","titten","brüste","brueste","nutte","prostituierte",
  "verpiss","verrecke","haltdeinmaul","fresse","maul",
  "neger","nigger","kanake","zigeuner","judensau","schwuchtel","transe",
  "missgeburt","fehlgeburt","krüppel","krueppel"
];
const finsterBlockedPhrases = [
  "halt die fresse","halt dein maul","sohn einer hure","du hurensohn","fick dich",
  "verpiss dich","leck mich","leck meinen","geh sterben","bring dich um"
];

function finsterNormalizeForFilter(value) {
  return String(value || "")
    .toLocaleLowerCase("de-DE")
    .replace(/[013457@$!]/g, (char) => ({ "0":"o","1":"i","3":"e","4":"a","5":"s","7":"t","@":"a","$":"s","!":"i" }[char] || char))
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

function finsterMaskToken(token) {
  return Array.from(String(token || "")).map((char) => /[\p{L}\p{N}]/u.test(char) ? "*" : char).join("");
}

function censorFinsterText(value, maxLength = 1000) {
  const source = String(value || "").trim().slice(0, maxLength);
  if (!source) return "";
  let result = source;
  for (const phrase of finsterBlockedPhrases) {
    const pattern = phrase.trim().split(/\s+/).map((part) => part.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("\\s+");
    result = result.replace(new RegExp(`\\b${pattern}\\b`, "giu"), (match) => finsterMaskToken(match));
  }
  result = result.replace(/[\p{L}\p{N}_-]+/gu, (token) => {
    const normalized = finsterNormalizeForFilter(token).replace(/[_-]+/g, "");
    const blocked = finsterBlockedWordStems.some((stem) => normalized === stem || normalized.startsWith(stem));
    return blocked ? finsterMaskToken(token) : token;
  });
  return result;
}

function ensureFinsterState() {
  state.finster = { ...finsterDefaultState(), ...(state.finster || {}) };
  state.finster.likedPostIds = Array.isArray(state.finster.likedPostIds) ? state.finster.likedPostIds : [];
  state.finster.following = Array.isArray(state.finster.following) ? state.finster.following : [];
  // Alte lokale KI-/Bot-Zustände aus früheren Versionen werden nicht mehr verwendet.
  if (String(state.finster.selectedUserUid || "").startsWith("ai-finster-")) state.finster.selectedUserUid = "";
  if (String(state.finster.activeConversationUid || "").startsWith("ai-finster-")) state.finster.activeConversationUid = "";
  state.finster.aiLikes = {};
  state.finster.aiComments = {};
  state.finster.aiMessages = {};
  return state.finster;
}

let finsterPostsCache = [];
let finsterUsersCache = [];
let finsterMessagesCache = [];
let finsterCommentsCache = new Map();
let finsterPostsUnsubscribe = null;
let finsterUsersUnsubscribe = null;
let finsterMessagesUnsubscribe = null;
let finsterRuntimeStarting = null;
let finsterUploadFile = null;
let finsterUploadPreviewUrl = "";

function finsterCurrentUid() {
  return firebasePhoneRuntime?.auth?.currentUser?.uid || "";
}

function finsterAiPosts() {
  // Deaktiviert: Finsta.KL zeigt ausschließlich Beiträge echter Online-Spieler.
  return [];
}

function finsterAllPosts() {
  // Nur echte Online-Beiträge. Keine automatisch erzeugten KI-/Bot-Posts mehr im Feed.
  return [...finsterPostsCache].sort((a, b) => Number(b.createdAtMs || 0) - Number(a.createdAtMs || 0));
}

function finsterProfileByUid(uid) {
  if (!uid) return null;
  return finsterUsersCache.find((entry) => entry.uid === uid) || null;
}

function finsterTimeText(timestamp) {
  const diff = Math.max(0, Date.now() - Number(timestamp || Date.now()));
  if (diff < 60000) return "gerade eben";
  if (diff < hour) return `vor ${Math.floor(diff / minute)} Min.`;
  if (diff < 24 * hour) return `vor ${Math.floor(diff / hour)} Std.`;
  return `vor ${Math.floor(diff / (24 * hour))} Tagen`;
}

function finsterAvatarHtml(profile, size = "normal") {
  const name = profile?.displayName || profile?.handle || "F";
  const initials = name.split(/\s+/).map((part) => part[0]).join("").slice(0, 2).toUpperCase();
  const hue = profile?.avatarHue ?? Math.abs(stringSeed(profile?.uid || name)) % 360;
  return `<span class="finster-avatar ${size}" style="--avatar-hue:${hue}">${escapeHtml(initials)}</span>`;
}

async function ensureFinsterRealtime() {
  if (finsterRuntimeStarting) return finsterRuntimeStarting;
  finsterRuntimeStarting = (async () => {
    const fb = await loadFirebasePhoneRuntime();
    const uid = fb.auth.currentUser?.uid;
    if (!uid) throw new Error("Firebase-Anmeldung fehlt.");
    if (!finsterPostsUnsubscribe) {
      const queryPosts = fb.query(fb.collection(fb.db, "finsterPosts"), fb.orderBy("createdAtMs", "desc"), fb.limit(60));
      finsterPostsUnsubscribe = fb.onSnapshot(queryPosts, (snapshot) => {
        finsterPostsCache = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data(), ai: false }));
        refreshFinsterIfVisible();
      }, (error) => console.warn("Finster posts", error));
    }
    if (!finsterUsersUnsubscribe) {
      const queryUsers = fb.query(fb.collection(fb.db, "finsterUsers"), fb.limit(100));
      finsterUsersUnsubscribe = fb.onSnapshot(queryUsers, (snapshot) => {
        finsterUsersCache = snapshot.docs.map((doc) => ({ uid: doc.id, ...doc.data(), ai: false }));
        const mine = finsterUsersCache.find((entry) => entry.uid === uid);
        if (mine) {
          const finster = ensureFinsterState();
          finster.accountCreated = true;
          finster.handle = mine.handle || finster.handle;
          finster.displayName = mine.displayName || finster.displayName;
          finster.bio = mine.bio || finster.bio;
          save();
        }
        refreshFinsterIfVisible();
      }, (error) => console.warn("Finster users", error));
    }
    if (!finsterMessagesUnsubscribe) {
      const queryMessages = fb.query(fb.collection(fb.db, "finsterMessages"), fb.where("participantUids", "array-contains", uid), fb.limit(250));
      finsterMessagesUnsubscribe = fb.onSnapshot(queryMessages, (snapshot) => {
        finsterMessagesCache = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() })).sort((a, b) => Number(a.createdAtMs || 0) - Number(b.createdAtMs || 0));
        refreshFinsterIfVisible();
      }, (error) => console.warn("Finster messages", error));
    }
    return fb;
  })().finally(() => { finsterRuntimeStarting = null; });
  return finsterRuntimeStarting;
}

function stopFinsterRealtime() {
  [finsterPostsUnsubscribe, finsterUsersUnsubscribe, finsterMessagesUnsubscribe].forEach((unsubscribe) => {
    if (typeof unsubscribe === "function") unsubscribe();
  });
  finsterPostsUnsubscribe = null;
  finsterUsersUnsubscribe = null;
  finsterMessagesUnsubscribe = null;
}

function refreshFinsterIfVisible() {
  if (!els.dialog?.open || !els.dialog.querySelector(".finster-app")) return;
  const active = document.activeElement;
  if (active?.matches?.("input, textarea")) return;
  const item = ownedPhoneItem();
  if (item) refreshDeviceApp("finster", item);
}

