function finsterNavHtml(view) {
  return `<nav class="finster-nav">
    ${[["feed","⌂","Feed"],["explore","⌕","Entdecken"],["create","＋","Posten"],["messages","✉","Nachrichten"],["profile","●","Profil"]].map(([id, icon, label]) => `<button class="${view === id ? "active" : ""}" data-finster-view="${id}"><span>${icon}</span><small>${label}</small></button>`).join("")}
  </nav>`;
}

function finsterPostCardHtml(post) {
  const finster = ensureFinsterState();
  const liked = finster.likedPostIds.includes(post.id);
  const profile = finsterProfileByUid(post.ownerUid) || post;
  const localLikes = post.ai ? Number(finster.aiLikes[post.id] || 0) : 0;
  const localComments = post.ai ? (finster.aiComments[post.id] || []).length : 0;
  return `<article class="finster-post" data-finster-post-card="${post.id}">
    <header>
      <button data-finster-open-user="${post.ownerUid}">${finsterAvatarHtml(profile, "small")}</button>
      <div><strong>@${escapeHtml(post.handle || profile.handle || "finster")}</strong><small>${escapeHtml(profile.city || "LifeBuilder")} · ${finsterTimeText(post.createdAtMs)}</small></div>
      ${post.ownerUid === finsterCurrentUid() ? `<button class="finster-more" data-finster-delete-post="${post.id}" title="Beitrag löschen">•••</button>` : ""}
    </header>
    <button class="finster-image-button" data-finster-open-post="${post.id}"><img src="${escapeHtml(post.imageUrl || "")}" loading="lazy" alt="Beitrag von ${escapeHtml(post.displayName || post.handle || "Finster")}"></button>
    <div class="finster-post-actions">
      <button class="${liked ? "liked" : ""}" data-finster-like="${post.id}">${liked ? "♥" : "♡"}</button>
      <button data-finster-open-post="${post.id}">◯</button>
      <button data-finster-message-user="${post.ownerUid}" ${post.ownerUid === finsterCurrentUid() ? "disabled" : ""}>➤</button>
    </div>
    <strong class="finster-like-count">${Number(post.likeCount || 0) + localLikes} Likes</strong>
    <p><b>@${escapeHtml(post.handle || profile.handle || "finster")}</b> ${escapeHtml(censorFinsterText(post.caption || "", 1000))}</p>
    <button class="finster-comments-link" data-finster-open-post="${post.id}">${Number(post.commentCount || 0) + localComments} Kommentare ansehen</button>
  </article>`;
}

function finsterFeedHtml() {
  const posts = finsterAllPosts();
  return `<section class="finster-feed">${posts.length ? posts.map(finsterPostCardHtml).join("") : `<div class="finster-empty"><b>Noch keine Beiträge</b><p>Erstelle den ersten Post.</p></div>`}</section>`;
}

function finsterExploreHtml() {
  const own = finsterCurrentUid();
  const profiles = finsterUsersCache.filter((profile) => profile.uid !== own);
  return `<section class="finster-explore"><div class="finster-search"><span>⌕</span><input data-finster-search placeholder="Accounts oder Orte suchen"></div><div class="finster-user-grid" data-finster-user-grid>${profiles.map((profile) => `<article data-finster-user-card="${escapeHtml(`${profile.handle} ${profile.displayName} ${profile.city || ""}`.toLowerCase())}">${finsterAvatarHtml(profile)}<div><strong>${escapeHtml(profile.displayName)}</strong><small>@${escapeHtml(profile.handle)} · ${escapeHtml(profile.city || "LifeBuilder")}</small><p>${escapeHtml(profile.bio || "Finsta.KL-Profil")}</p></div><button class="mini-button" data-finster-open-user="${profile.uid}">Profil</button></article>`).join("")}</div></section>`;
}

function finsterCreateHtml() {
  return `<section class="finster-create">
    <div class="finster-upload-preview" data-finster-upload-preview>${finsterUploadPreviewUrl ? `<img src="${finsterUploadPreviewUrl}" alt="Vorschau">` : `<span>▧</span><p>Wähle ein Bild bis 8 MB.</p>`}</div>
    <label class="finster-file-button">Bild auswählen<input type="file" data-finster-file accept="image/jpeg,image/png,image/webp,image/gif"></label>
    <textarea data-finster-caption maxlength="1000" placeholder="Schreibe eine Bildunterschrift..."></textarea>
    <button class="primary-button" data-finster-publish ${finsterUploadFile ? "" : "disabled"}>Beitrag veröffentlichen</button>
    <small data-finster-upload-status>JPG, PNG, WEBP oder GIF. Upload über Firebase Storage.</small>
  </section>`;
}

function finsterCommentsFor(postId) {
  if (postId.startsWith("ai-post-")) return ensureFinsterState().aiComments[postId] || [];
  return finsterCommentsCache.get(postId) || [];
}

function finsterPostDetailHtml(postId) {
  const post = finsterAllPosts().find((entry) => entry.id === postId);
  if (!post) return `<div class="finster-empty"><b>Beitrag nicht gefunden</b><button class="mini-button" data-finster-view="feed">Zurück zum Feed</button></div>`;
  const comments = finsterCommentsFor(postId);
  return `<section class="finster-post-detail"><button class="mini-button" data-finster-view="feed">← Feed</button>${finsterPostCardHtml(post)}<div class="finster-comment-list">${comments.length ? comments.map((comment) => `<article>${finsterAvatarHtml(comment, "tiny")}<p><b>@${escapeHtml(comment.handle || "spieler")}</b> ${escapeHtml(censorFinsterText(comment.text || "", 500))}<small>${finsterTimeText(comment.createdAtMs)}</small></p></article>`).join("") : `<p>Noch keine Kommentare.</p>`}</div><div class="finster-comment-compose"><input data-finster-comment-input maxlength="500" placeholder="Kommentar schreiben..."><button data-finster-comment-send="${postId}">Senden</button></div></section>`;
}

function finsterUserProfileHtml(uid) {
  const profile = finsterProfileByUid(uid);
  if (!profile) return `<div class="finster-empty"><b>Profil nicht gefunden</b></div>`;
  const finster = ensureFinsterState();
  const following = finster.following.includes(uid);
  const posts = finsterAllPosts().filter((post) => post.ownerUid === uid);
  return `<section class="finster-profile-view"><button class="mini-button" data-finster-view="explore">← Zurück</button><header>${finsterAvatarHtml(profile, "large")}<div><h3>${escapeHtml(profile.displayName)}</h3><strong>@${escapeHtml(profile.handle)}</strong><small>${escapeHtml(profile.city || "LifeBuilder")}</small></div></header><p>${escapeHtml(profile.bio || "Noch kein Profiltext.")}</p><div class="finster-profile-actions">${uid !== finsterCurrentUid() ? `<button class="mini-button ${following ? "active" : "gold"}" data-finster-follow="${uid}">${following ? "Gefolgt" : "Folgen"}</button><button class="mini-button" data-finster-message-user="${uid}">Nachricht</button>` : ""}</div><div class="finster-profile-grid">${posts.map((post) => `<button data-finster-open-post="${post.id}"><img src="${escapeHtml(post.imageUrl)}" loading="lazy" alt="Beitrag"></button>`).join("") || `<p>Noch keine Beiträge.</p>`}</div></section>`;
}

function finsterConversationMessages(uid) {
  const own = finsterCurrentUid();
  if (uid.startsWith("ai-finster-")) return ensureFinsterState().aiMessages[uid] || [];
  return finsterMessagesCache.filter((message) => message.participantUids?.includes(own) && message.participantUids?.includes(uid));
}

function finsterMessagesHtml() {
  const finster = ensureFinsterState();
  const activeUid = finster.activeConversationUid;
  const own = finsterCurrentUid();
  const realPartners = [...new Set(finsterMessagesCache.flatMap((message) => message.participantUids || []).filter((uid) => uid && uid !== own))].map(finsterProfileByUid).filter(Boolean);
  const partners = realPartners;
  if (activeUid) {
    const profile = finsterProfileByUid(activeUid);
    const messages = finsterConversationMessages(activeUid);
    return `<section class="finster-chat"><header><button data-finster-close-chat>←</button>${finsterAvatarHtml(profile, "small")}<div><strong>${escapeHtml(profile?.displayName || "Chat")}</strong><small>@${escapeHtml(profile?.handle || "finster")}</small></div></header><div class="finster-chat-thread" data-finster-chat-thread>${messages.map((message) => `<p class="${message.senderUid === own || message.from === "me" ? "mine" : "theirs"}"><span>${escapeHtml(censorFinsterText(message.text || "", 800))}</span><small>${finsterTimeText(message.createdAtMs || message.at)}</small></p>`).join("") || `<p class="system"><span>Noch keine Nachrichten. Schreib Hallo.</span></p>`}</div><div class="finster-chat-compose"><textarea data-finster-message-input maxlength="800" placeholder="Nachricht..."></textarea><button data-finster-send-message="${activeUid}">Senden</button></div></section>`;
  }
  return `<section class="finster-inbox"><h3>Nachrichten</h3>${partners.map((profile) => `<button data-finster-message-user="${profile.uid}">${finsterAvatarHtml(profile, "small")}<div><strong>${escapeHtml(profile.displayName)}</strong><small>@${escapeHtml(profile.handle)}</small></div><span>›</span></button>`).join("") || `<div class="finster-empty"><p>Noch keine Chats. Öffne ein Profil und schreibe eine Nachricht.</p></div>`}</section>`;
}

function finsterOwnProfileHtml() {
  const finster = ensureFinsterState();
  const ownUid = finsterCurrentUid();
  const own = finsterProfileByUid(ownUid) || { uid: ownUid, handle: finster.handle, displayName: finster.displayName, bio: finster.bio, city: state.worldLocation || state.homeCity };
  const posts = finsterAllPosts().filter((post) => post.ownerUid === ownUid);
  return `<section class="finster-own-profile"><header>${finsterAvatarHtml(own, "large")}<div><h3>${escapeHtml(own.displayName || "Finsta-Profil")}</h3><strong>@${escapeHtml(own.handle || "profil")}</strong></div></header><div class="finster-own-stats"><span><b>${posts.length}</b> Beiträge</span><span><b>${finster.following.length}</b> Gefolgt</span><span><b>${finster.likedPostIds.length}</b> Likes</span></div><p>${escapeHtml(own.bio || "Noch kein Profiltext.")}</p><button class="mini-button" data-finster-edit-profile>Profil bearbeiten</button><div class="finster-profile-grid">${posts.map((post) => `<button data-finster-open-post="${post.id}"><img src="${escapeHtml(post.imageUrl)}" loading="lazy" alt="Eigener Beitrag"></button>`).join("") || `<p>Du hast noch nichts gepostet.</p>`}</div></section>`;
}


function finstaConnectionOnline() {
  return navigator.onLine !== false && (!!firebasePhoneRuntime?.auth?.currentUser || !!window.LifeBuilderOnline?.getUser?.());
}

function finsterAppHtml() {
  const finster = ensureFinsterState();
  ensureFinsterRealtime().catch((error) => console.warn("Finster runtime", error));
  if (!finster.accountCreated) return `<div class="finster-app">${finsterAccountCreateHtml()}</div>`;
  let body = finsterFeedHtml();
  if (finster.view === "explore") body = finsterExploreHtml();
  if (finster.view === "create") body = finsterCreateHtml();
  if (finster.view === "messages") body = finsterMessagesHtml();
  if (finster.view === "profile") body = finsterOwnProfileHtml();
  if (finster.view === "post") body = finsterPostDetailHtml(finster.selectedPostId);
  if (finster.view === "user") body = finsterUserProfileHtml(finster.selectedUserUid);
  const online = finstaConnectionOnline();
  return `<div class="finster-app"><div class="finster-topbar"><b>Finsta.KL</b><span class="${online ? "online" : "offline"}">${online ? "Online" : "Offline"}</span></div><div class="finster-content">${body}</div>${finsterNavHtml(["post","user"].includes(finster.view) ? "" : finster.view)}</div>`;
}

async function createFinsterAccount(shell, item) {
  const handle = String(shell.querySelector("[data-finster-handle]")?.value || "").trim().toLowerCase().replace(/[^a-z0-9._-]/g, "").slice(0, 24);
  const displayName = censorFinsterText(shell.querySelector("[data-finster-display-name]")?.value || "", 40);
  const bio = censorFinsterText(shell.querySelector("[data-finster-bio]")?.value || "", 180);
  if (handle.length < 3) return addFeed("Der Finster-Benutzername braucht mindestens drei Zeichen.");
  if (!displayName) return addFeed("Bitte einen Anzeigenamen eingeben.");
  try {
    const fb = await ensureFinsterRealtime();
    const uid = fb.auth.currentUser.uid;
    const handleRef = fb.doc(fb.db, "finsterHandles", handle);
    const userRef = fb.doc(fb.db, "finsterUsers", uid);
    await fb.runTransaction(fb.db, async (transaction) => {
      const handleDoc = await transaction.get(handleRef);
      if (handleDoc.exists() && handleDoc.data().uid !== uid) throw new Error("Dieser Benutzername ist schon vergeben.");
      transaction.set(handleRef, { uid, handle, createdAtMs: Date.now() });
      transaction.set(userRef, { uid, handle, displayName, bio, city: state.worldLocation || state.homeCity, avatarHue: Math.abs(stringSeed(uid)) % 360, createdAtMs: Date.now(), updatedAtMs: Date.now() }, { merge: true });
    });
    const finster = ensureFinsterState();
    Object.assign(finster, { handle, displayName, bio, accountCreated: true, view: "feed" });
    save();
    addFeed(`Finsta.KL-Konto @${handle} erstellt.`);
    refreshDeviceApp("finster", item);
  } catch (error) {
    addFeed(`Finster-Konto konnte nicht erstellt werden: ${error.message || error}`);
  }
}

function selectFinsterFile(file, shell) {
  if (!file) return;
  if (!/^image\/(jpeg|png|webp|gif)$/.test(file.type) || file.size > 8 * 1024 * 1024) return addFeed("Bitte ein Bild im Format JPG, PNG, WEBP oder GIF bis 8 MB wählen.");
  if (finsterUploadPreviewUrl) URL.revokeObjectURL(finsterUploadPreviewUrl);
  finsterUploadFile = file;
  finsterUploadPreviewUrl = URL.createObjectURL(file);
  const preview = shell.querySelector("[data-finster-upload-preview]");
  if (preview) preview.innerHTML = `<img src="${finsterUploadPreviewUrl}" alt="Vorschau">`;
  const publish = shell.querySelector("[data-finster-publish]");
  if (publish) publish.disabled = false;
}

async function publishFinsterPost(shell, item) {
  const file = finsterUploadFile;
  const caption = censorFinsterText(shell.querySelector("[data-finster-caption]")?.value || "", 1000);
  const status = shell.querySelector("[data-finster-upload-status]");
  if (!file) return addFeed("Wähle zuerst ein Bild.");
  try {
    const fb = await ensureFinsterRealtime();
    const uid = fb.auth.currentUser.uid;
    const finster = ensureFinsterState();
    const postRef = fb.doc(fb.collection(fb.db, "finsterPosts"));
    const safeExt = (file.name.split(".").pop() || "jpg").toLowerCase().replace(/[^a-z0-9]/g, "").slice(0, 5) || "jpg";
    const storageRef = fb.ref(fb.storage, `finster/${uid}/${postRef.id}.${safeExt}`);
    if (status) status.textContent = "Upload startet...";
    const task = fb.uploadBytesResumable(storageRef, file, { contentType: file.type, customMetadata: { ownerUid: uid, postId: postRef.id } });
    await new Promise((resolve, reject) => task.on("state_changed", (snapshot) => {
      if (status) status.textContent = `Upload ${Math.round(snapshot.bytesTransferred / snapshot.totalBytes * 100)} %`;
    }, reject, resolve));
    const imageUrl = await fb.getDownloadURL(storageRef);
    await fb.setDoc(postRef, { ownerUid: uid, handle: finster.handle, displayName: finster.displayName, caption, imageUrl, storagePath: storageRef.fullPath, createdAtMs: Date.now(), likeCount: 0, commentCount: 0 });
    finsterUploadFile = null;
    if (finsterUploadPreviewUrl) URL.revokeObjectURL(finsterUploadPreviewUrl);
    finsterUploadPreviewUrl = "";
    finster.view = "feed";
    save();
    addFeed("Finsta.KL-Beitrag veröffentlicht.");
    queuePurchaseConfirmation({ kind: "use", title: "Veröffentlicht", name: "Finsta.KL-Beitrag", icon: "▧" });
    refreshDeviceApp("finster", item);
  } catch (error) {
    if (status) status.textContent = `Fehler: ${error.message || error}`;
    addFeed(`Beitrag konnte nicht veröffentlicht werden: ${error.message || error}`);
  }
}

async function toggleFinsterLike(postId, item) {
  const finster = ensureFinsterState();
  const post = finsterAllPosts().find((entry) => entry.id === postId);
  if (!post) return;
  const liked = finster.likedPostIds.includes(postId);
  if (post.ai) {
    finster.aiLikes[postId] = Math.max(0, Number(finster.aiLikes[postId] || 0) + (liked ? -1 : 1));
  } else {
    try {
      const fb = await ensureFinsterRealtime();
      const uid = fb.auth.currentUser.uid;
      const postRef = fb.doc(fb.db, "finsterPosts", postId);
      const likeRef = fb.doc(fb.db, "finsterPosts", postId, "likes", uid);
      await fb.runTransaction(fb.db, async (transaction) => {
        const [postDoc, likeDoc] = await Promise.all([transaction.get(postRef), transaction.get(likeRef)]);
        if (!postDoc.exists()) throw new Error("Beitrag existiert nicht mehr.");
        const count = Math.max(0, Number(postDoc.data().likeCount || 0));
        if (likeDoc.exists()) {
          transaction.delete(likeRef);
          transaction.update(postRef, { likeCount: Math.max(0, count - 1) });
        } else {
          transaction.set(likeRef, { ownerUid: uid, createdAtMs: Date.now() });
          transaction.update(postRef, { likeCount: count + 1 });
        }
      });
    } catch (error) {
      return addFeed(`Like fehlgeschlagen: ${error.message || error}`);
    }
  }
  finster.likedPostIds = liked ? finster.likedPostIds.filter((id) => id !== postId) : [...finster.likedPostIds, postId];
  save();
  refreshDeviceApp("finster", item);
}

async function loadFinsterComments(postId, item) {
  const finster = ensureFinsterState();
  finster.selectedPostId = postId;
  finster.view = "post";
  if (!postId.startsWith("ai-post-")) {
    try {
      const fb = await ensureFinsterRealtime();
      const queryComments = fb.query(fb.collection(fb.db, "finsterPosts", postId, "comments"), fb.orderBy("createdAtMs", "asc"), fb.limit(100));
      const snapshot = await fb.getDocs(queryComments);
      finsterCommentsCache.set(postId, snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    } catch (error) {
      console.warn("Finster comments", error);
    }
  }
  save();
  refreshDeviceApp("finster", item);
}

async function sendFinsterComment(postId, textValue, item) {
  const clean = censorFinsterText(textValue, 500);
  if (!clean) return;
  const finster = ensureFinsterState();
  if (postId.startsWith("ai-post-")) {
    finster.aiComments[postId] ||= [];
    finster.aiComments[postId].push({ ownerUid: "me", handle: finster.handle, displayName: finster.displayName, text: clean, createdAtMs: Date.now() });
  } else {
    try {
      const fb = await ensureFinsterRealtime();
      const uid = fb.auth.currentUser.uid;
      const postRef = fb.doc(fb.db, "finsterPosts", postId);
      await fb.addDoc(fb.collection(postRef, "comments"), { ownerUid: uid, handle: finster.handle, displayName: finster.displayName, text: clean, createdAtMs: Date.now() });
      await fb.runTransaction(fb.db, async (transaction) => {
        const postDoc = await transaction.get(postRef);
        if (postDoc.exists()) transaction.update(postRef, { commentCount: Math.max(0, Number(postDoc.data().commentCount || 0)) + 1 });
      });
      const cached = finsterCommentsCache.get(postId) || [];
      cached.push({ ownerUid: uid, handle: finster.handle, displayName: finster.displayName, text: clean, createdAtMs: Date.now() });
      finsterCommentsCache.set(postId, cached);
    } catch (error) {
      return addFeed(`Kommentar fehlgeschlagen: ${error.message || error}`);
    }
  }
  save();
  refreshDeviceApp("finster", item);
}

async function deleteFinsterPost(postId, item) {
  const post = finsterPostsCache.find((entry) => entry.id === postId);
  if (!post || post.ownerUid !== finsterCurrentUid()) return;
  try {
    const fb = await ensureFinsterRealtime();
    await fb.deleteDoc(fb.doc(fb.db, "finsterPosts", postId));
    if (post.storagePath) await fb.deleteObject(fb.ref(fb.storage, post.storagePath)).catch(() => {});
    addFeed("Finsta.KL-Beitrag gelöscht.");
    refreshDeviceApp("finster", item);
  } catch (error) {
    addFeed(`Beitrag konnte nicht gelöscht werden: ${error.message || error}`);
  }
}

function finsterAiReply(profile, text) {
  const lower = String(text || "").toLowerCase();
  if (/hallo|hey|hi|moin/.test(lower)) return `Hey 😊 Schön, dass du schreibst. Wie läuft dein Tag?`;
  if (/bild|foto|post/.test(lower)) return `Danke! Das Bild ist in ${profile.city} entstanden. Ich hatte richtig Glück mit dem Licht.`;
  if (/wie geht|alles gut/.test(lower)) return "Ganz gut, etwas viel los, aber ich freue mich über die Nachricht.";
  if (/treffen|kaffee/.test(lower)) return "Erst mal ein bisschen schreiben, aber ein Kaffee klingt grundsätzlich gut.";
  return ["Klingt interessant. Erzähl mehr.", "Das sehe ich ähnlich 😊", "Was begeistert dich daran am meisten?", "Guter Punkt. Darüber habe ich noch nicht so nachgedacht."][Math.abs(stringSeed(`${profile.uid}:${text}`)) % 4];
}

async function sendFinsterMessage(uid, textValue, item) {
  const clean = censorFinsterText(textValue, 800);
  const profile = finsterProfileByUid(uid);
  if (!clean || !profile) return;
  const finster = ensureFinsterState();
  if (uid.startsWith("ai-finster-")) {
    finster.aiMessages[uid] ||= [];
    finster.aiMessages[uid].push({ from: "me", senderUid: finsterCurrentUid(), text: clean, createdAtMs: Date.now() });
    const reply = finsterAiReply(profile, clean);
    setTimeout(() => {
      if (!state) return;
      ensureFinsterState().aiMessages[uid].push({ from: "them", senderUid: uid, text: reply, createdAtMs: Date.now() });
      save();
      refreshFinsterIfVisible();
    }, 700);
  } else {
    try {
      const fb = await ensureFinsterRealtime();
      const own = fb.auth.currentUser.uid;
      const participantUids = [own, uid].sort();
      await fb.addDoc(fb.collection(fb.db, "finsterMessages"), { senderUid: own, recipientUid: uid, participantUids, text: clean, createdAtMs: Date.now() });
    } catch (error) {
      return addFeed(`Nachricht fehlgeschlagen: ${error.message || error}`);
    }
  }
  save();
  refreshDeviceApp("finster", item);
}

async function updateFinsterProfile(shell, item) {
  const finster = ensureFinsterState();
  const displayName = censorFinsterText(prompt("Anzeigename", finster.displayName || state.firstName || "") || "", 40);
  if (!displayName) return;
  const bio = censorFinsterText(prompt("Profiltext", finster.bio || "") ?? finster.bio, 180);
  try {
    const fb = await ensureFinsterRealtime();
    await fb.updateDoc(fb.doc(fb.db, "finsterUsers", fb.auth.currentUser.uid), { displayName, bio, city: state.worldLocation || state.homeCity, updatedAtMs: Date.now() });
    finster.displayName = displayName;
    finster.bio = bio;
    save();
    refreshDeviceApp("finster", item);
  } catch (error) {
    addFeed(`Profil konnte nicht gespeichert werden: ${error.message || error}`);
  }
}

function bindFinsterDeviceActions(shell, item) {
  const finsterHostScreen = shell?.closest?.(".device-screen") || shell?.querySelector?.(".device-screen");
  if (finsterHostScreen) {
    finsterHostScreen.classList.add("finster-host-screen");
    finsterHostScreen.scrollTop = 0;
  }
  const finsterContent = shell?.querySelector?.(".finster-content");
  if (finsterContent && !finsterContent.dataset.finsterScrollBound) {
    finsterContent.dataset.finsterScrollBound = "1";
    finsterContent.addEventListener("touchmove", () => {}, { passive: true });
    finsterContent.addEventListener("wheel", (event) => {
      if (Math.abs(event.deltaY) < 1 || finsterContent.scrollHeight <= finsterContent.clientHeight + 1) return;
      finsterContent.scrollTop += event.deltaY;
      if (event.cancelable) event.preventDefault();
    }, { passive: false });
  }
  ensureFinsterRealtime().catch((error) => addFeed(`Finsta.KL Firebase: ${error.message || error}`));
  shell.querySelector("[data-finster-create-account]")?.addEventListener("click", () => createFinsterAccount(shell, item));
  shell.querySelectorAll("[data-finster-view]").forEach((button) => button.addEventListener("click", () => {
    const finster = ensureFinsterState();
    finster.view = button.dataset.finsterView || "feed";
    finster.selectedPostId = "";
    finster.selectedUserUid = "";
    if (finster.view !== "messages") finster.activeConversationUid = "";
    save();
    refreshDeviceApp("finster", item);
  }));
  shell.querySelector("[data-finster-file]")?.addEventListener("change", (event) => selectFinsterFile(event.target.files?.[0], shell));
  shell.querySelector("[data-finster-publish]")?.addEventListener("click", () => publishFinsterPost(shell, item));
  shell.querySelectorAll("[data-finster-like]").forEach((button) => button.addEventListener("click", () => toggleFinsterLike(button.dataset.finsterLike, item)));
  shell.querySelectorAll("[data-finster-open-post]").forEach((button) => button.addEventListener("click", () => loadFinsterComments(button.dataset.finsterOpenPost, item)));
  shell.querySelectorAll("[data-finster-open-user]").forEach((button) => button.addEventListener("click", () => {
    const finster = ensureFinsterState();
    finster.selectedUserUid = button.dataset.finsterOpenUser;
    finster.view = "user";
    save();
    refreshDeviceApp("finster", item);
  }));
  shell.querySelectorAll("[data-finster-message-user]").forEach((button) => button.addEventListener("click", () => {
    const finster = ensureFinsterState();
    finster.activeConversationUid = button.dataset.finsterMessageUser;
    finster.view = "messages";
    save();
    refreshDeviceApp("finster", item);
  }));
  shell.querySelector("[data-finster-close-chat]")?.addEventListener("click", () => {
    ensureFinsterState().activeConversationUid = "";
    save();
    refreshDeviceApp("finster", item);
  });
  shell.querySelectorAll("[data-finster-follow]").forEach((button) => button.addEventListener("click", () => {
    const finster = ensureFinsterState();
    const uid = button.dataset.finsterFollow;
    finster.following = finster.following.includes(uid) ? finster.following.filter((id) => id !== uid) : [...finster.following, uid];
    save();
    refreshDeviceApp("finster", item);
  }));
  shell.querySelector("[data-finster-comment-send]")?.addEventListener("click", (event) => sendFinsterComment(event.currentTarget.dataset.finsterCommentSend, shell.querySelector("[data-finster-comment-input]")?.value, item));
  shell.querySelector("[data-finster-comment-input]")?.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      shell.querySelector("[data-finster-comment-send]")?.click();
    }
  });
  shell.querySelector("[data-finster-send-message]")?.addEventListener("click", (event) => sendFinsterMessage(event.currentTarget.dataset.finsterSendMessage, shell.querySelector("[data-finster-message-input]")?.value, item));
  shell.querySelector("[data-finster-message-input]")?.addEventListener("keydown", (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      shell.querySelector("[data-finster-send-message]")?.click();
    }
  });
  shell.querySelectorAll("[data-finster-delete-post]").forEach((button) => button.addEventListener("click", () => deleteFinsterPost(button.dataset.finsterDeletePost, item)));
  shell.querySelector("[data-finster-edit-profile]")?.addEventListener("click", () => updateFinsterProfile(shell, item));
  shell.querySelector("[data-finster-search]")?.addEventListener("input", (event) => {
    const query = event.currentTarget.value.trim().toLowerCase();
    shell.querySelectorAll("[data-finster-user-card]").forEach((card) => card.hidden = query && !card.dataset.finsterUserCard.includes(query));
  });
  const thread = shell.querySelector("[data-finster-chat-thread]");
  if (thread) requestAnimationFrame(() => { thread.scrollTop = thread.scrollHeight; });
}

const phoneAppStoreCatalog = [
  {
    id: "finder",
    label: "Finder.KL",
    icon: "♥",
    minTier: 3,
    status: "available",
    description: "Profile entdecken, Match-Likes senden, chatten, reisen und Beziehungen aufbauen. Benötigt ein Pro-Smartphone."
  },
  {
    id: "finster",
    label: "Finsta.KL",
    icon: "f",
    minTier: 1,
    status: "available",
    description: "Firebase-Social-App mit Profilen, Live-Feed, Bildern, Likes, Kommentaren und Nachrichten."
  },
  {
    id: "onlinecasino",
    label: "Casino",
    icon: "●",
    minTier: 2,
    status: "locked",
    description: "Die Casino-App wird noch gemeinsam überarbeitet und ist deshalb derzeit gesperrt."
  }
];

function installedPhoneApps() {
  state.installedPhoneApps = Array.isArray(state.installedPhoneApps)
    ? [...new Set(state.installedPhoneApps.filter((id) => phoneAppStoreCatalog.some((app) => app.id === id && app.status === "available")))]
    : [];
  return state.installedPhoneApps;
}

function isPhoneAppInstalled(appId) {
  return installedPhoneApps().includes(appId);
}

function appStoreRequirementText(app, item) {
  if (app.status === "locked") return "Gesperrt";
  const tier = deviceTier(item);
  if (tier < app.minTier) return app.minTier >= 3 ? "Pro-Smartphone benötigt" : "Besseres Smartphone benötigt";
  return isPhoneAppInstalled(app.id) ? "Installiert" : "Bereit zum Download";
}

function phoneAppStoreHtml(item) {
  const tier = deviceTier(item);
  return `
    <div class="phone-app-store">
      <div class="device-finance-summary app-store-head">
        <span class="app-store-logo">A</span>
        <div>
          <b>Life App Store</b>
          <small>Apps herunterladen, verwalten und wieder entfernen. App-Daten bleiben bei einer Deinstallation gespeichert.</small>
        </div>
      </div>
      <div class="app-store-list">
        ${phoneAppStoreCatalog.map((app) => {
          const installed = isPhoneAppInstalled(app.id);
          const unavailable = app.status === "locked" || tier < app.minTier;
          const action = installed ? "uninstall" : "install";
          const buttonText = app.status === "locked"
            ? "Gesperrt"
            : tier < app.minTier
              ? "Nicht kompatibel"
              : installed
                ? "Deinstallieren"
                : "Laden";
          return `
            <article class="app-store-card ${app.status === "locked" ? "locked" : ""}">
              <span class="app-store-icon app-${app.id}">${app.icon}</span>
              <div>
                <strong>${escapeHtml(app.label)}</strong>
                <small>${escapeHtml(app.description)}</small>
                <i>${escapeHtml(appStoreRequirementText(app, item))}</i>
              </div>
              <button class="mini-button ${installed ? "danger" : "gold"}" data-appstore-${action}="${app.id}" ${unavailable && !installed ? "disabled" : ""}>${buttonText}</button>
            </article>
          `;
        }).join("")}
      </div>
      <p class="device-hint">Finder.KL und Finsta.KL erscheinen nach dem Download als eigene Apps unten im Handy. Die Casino-App bleibt bis zum nächsten Ausbau gesperrt.</p>
    </div>
  `;
}

function installPhoneApp(appId, item) {
  const app = phoneAppStoreCatalog.find((entry) => entry.id === appId);
  if (!app || app.status !== "available") return addFeed("Diese App ist derzeit gesperrt.");
  if (deviceTier(item) < app.minTier) return addFeed(`${app.label} benötigt ein Pro-Smartphone.`);
  if (isPhoneAppInstalled(appId)) return;
  state.installedPhoneApps.push(appId);
  addFeed(`${app.label} wurde installiert.`);
  queuePurchaseConfirmation({ kind: "use", title: "App installiert", name: app.label, icon: "⬇️" });
  save();
  openDeviceInterface(item, "appstore", false);
}

function uninstallPhoneApp(appId, item) {
  const app = phoneAppStoreCatalog.find((entry) => entry.id === appId);
  if (!app || !isPhoneAppInstalled(appId)) return;
  state.installedPhoneApps = installedPhoneApps().filter((id) => id !== appId);
  if (appId === "finster") stopFinsterRealtime();
  if (appId === "finder") {
    const finder = state.finder = normalizeFinderSave(state.finder, state);
    finder.plan = "free";
    finder.premium = false;
    finder.modFreePlan = false;
    finder.planPaidDay = 0;
    finder.view = "discover";
    finder.activeProfileId = "";
  }
  addFeed(`${app.label} wurde deinstalliert. Gespeicherte Profile und Chats bleiben erhalten.`);
  queuePurchaseConfirmation({ kind: "use", title: "App deinstalliert", name: app.label, icon: "🗑️" });
  save();
  openDeviceInterface(item, "appstore", false);
}

function deviceAppsFor(item) {
  const tier = deviceTier(item);
  const phoneDevice = phoneItems().includes(item);
  const requiredDeviceLabel = (min) => min >= 3 ? "Pro-Smartphone" : min >= 2 ? "Mittelklasse-Smartphone" : "Einsteiger-Smartphone";
  // Feste System-Apps bleiben zuerst. Der App Store sitzt bewusst am Ende
  // der letzten System-App-Reihe; heruntergeladene Apps folgen erst darunter.
  const apps = [
    { id: "notes", min: 0, label: "Notizen", icon: "i", text: "Schreibe und speichere kleine Notizen direkt auf deinem Handy." },
    { id: "phone", min: 1, sim: true, label: "Telefon", icon: "☎", text: "Anrufe, Kontakte und spätere Sprachfunktionen. Für echte Online-Anrufe brauchen wir WebRTC/Firebase-Signaling." },
    { id: "sms", min: 1, sim: true, label: "SMS", icon: "✉", text: "SMS und Nachrichten. Mit Firebase können echte Spieler-Nachrichten zwischen dir und deinem Bruder synchron laufen." },
    { id: "bank", min: 1, data: true, label: "Bank", icon: "€", text: `Konto ${euro.format(state.bank)} · Bar ${euro.format(state.cash)} · Schulden ${euro.format(state.debt)}.` },
    { id: "shop", min: 0, label: "Shop", icon: "□", text: "Basis-Shop, Kleidung, Geräte und Verbrauchsartikel sind erreichbar." },
    { id: "world", min: 1, data: true, label: "Stadtkarte", icon: "⌖", text: `Aktuell: ${state.worldLocation || state.homeCity}. Fernreisen starten am Flughafen der lokalen Karte.` },
    { id: "games", min: 1, data: true, label: "Games", icon: "▶", text: "Snake.KL, War Map, Kingdom Duel, Strong.KL, Survival.kl und weitere Spiele." },
    { id: "business", min: 2, minLevel: 5, data: true, phoneCredit: true, label: "Business", icon: "B", text: "Business, Charakter-Info und riskante Geschäfte laufen hier." },
    { id: "trading", min: 2, minLevel: 5, data: true, phoneCredit: true, label: "Trading", icon: "T", text: "Trading Calls: Einsätze und Auszahlungen laufen über Handy-Guthaben." },
    { id: "invest", min: 2, minLevel: 5, data: true, phoneCredit: true, label: "Börse", icon: "↗", text: `Portfolio: ${portfolioValueText()}. ETF-Weltmarkt, Aktien und Krypto sind hier.` },
    ...(phoneDevice ? [{ id: "appstore", min: 1, data: true, layoutClass: "device-appstore-anchor", label: "App Store", icon: "A", text: "Neue Apps herunterladen, installierte Apps verwalten und Apps wieder deinstallieren." }] : [])
  ];
  if (phoneDevice && isPhoneAppInstalled("finder")) {
    apps.push({ id: "finder", min: 3, data: true, layoutClass: "device-downloaded-app", label: "Finder.KL", icon: "♥", text: "Free, Plus, Gold oder Platinum: Profile entdecken, Match-Likes senden, chatten, reisen und Beziehungen aufbauen." });
  }
  if (phoneDevice && isPhoneAppInstalled("finster")) {
    apps.push({ id: "finster", min: 1, data: true, layoutClass: "device-downloaded-app", label: "Finsta.KL", icon: "f", text: "Bilder posten, Live-Feed ansehen, liken, kommentieren und anderen LifeBuilder-Spielern schreiben." });
  }
  return apps.map((app) => {
    const missingTier = tier < app.min;
    const missingLevel = (state.level || 0) < (app.minLevel || 0);
    const missingSim = app.sim && !hasPhoneSim();
    const missingData = app.data && !hasPhoneSim();
    const missingCredit = app.phoneCredit && phoneCreditAmount() <= 0;
    const slowData = app.data && tier >= 2 && !hasDataSim();
    return {
      ...app,
      levelLocked: missingLevel,
      // Ein leeres Handy-Guthaben sperrt bereits freigeschaltete Apps nicht mehr.
      // Kostenpflichtige Aktionen prüfen ihr Guthaben weiterhin direkt über spendPhoneCredit().
      locked: missingTier || missingLevel || missingSim || missingData,
      lockText: missingLevel
        ? `${app.label} wird ab Level ${app.minLevel} freigeschaltet. Aktuell bist du Level ${state.level || 0}.`
        : missingTier
        ? `Dafür brauchen Sie mindestens ein ${requiredDeviceLabel(app.min)}.`
        : missingSim
          ? "Benötigt eine SIM-Karte."
          : missingData
            ? "Benötigt eine SIM-Karte für Online-Apps."
            : missingCredit
              ? "0 € Handy-Guthaben: Die App bleibt geöffnet. Anschauen und Verwalten ist möglich; kostenpflichtige Aktionen benötigen neues Guthaben."
            : slowData
              ? ""
              : ""
    };
  });
}

function deviceDescription(item) {
  const tier = deviceTier(item);
  if (phoneItems().includes(item)) return `${deviceSpeedText(tier)} ${tier === 0 ? "Basic Phone: nur Notizen." : "Apps werden je nach Smartphone-Stufe und SIM freigeschaltet."}`;
  return `${deviceSpeedText(tier)} Computer im Tablet-Look mit stärkerem Arbeits- und Business-Fokus.`;
}

function deviceBackAsset(item) {
  const tier = deviceTier(item);
  if (tier <= 0) return "assets/phone-basic.avif";
  if (tier === 1) return "assets/phone-entry.avif";
  if (tier === 2) return "assets/phone-mid.avif";
  return "";
}

function deviceBackFallback(item) {
  const tier = deviceTier(item);
  if (tier >= 4) return { label: "ULTRA", sub: "KL HyperGlass", cls: "ultra" };
  return { label: "PRO", sub: "Titan Business", cls: "pro" };
}

let lastDeviceAppTap = { id: "", at: 0 };
let deviceInfoTimer = null;
let lastPhoneChargeAt = 0;
let pendingDeviceScrollTop = null;

function phoneNotesArray() {
  state.phoneNotesList ||= [];
  if (!state.phoneNotesList.length && (state.phoneNotes || "").trim()) {
    state.phoneNotesList.push({ id: `note-${Date.now()}`, text: String(state.phoneNotes).trim(), createdAt: Date.now(), updatedAt: Date.now() });
    state.phoneNotes = "";
  }
  return state.phoneNotesList;
}

function savePhoneNote(text) {
  const clean = String(text || "").trim();
  if (!clean) return addFeed("Schreibe zuerst eine Notiz.");
  const notes = phoneNotesArray();
  const editing = notes.find((note) => note.id === state.phoneEditingNoteId);
  if (editing) {
    editing.text = clean;
    editing.updatedAt = Date.now();
    addFeed("Notiz bearbeitet.");
  } else {
    notes.unshift({ id: `note-${Date.now()}-${Math.round(Math.random() * 9999)}`, text: clean, createdAt: Date.now(), updatedAt: Date.now() });
    addFeed("Notiz gespeichert.");
  }
  state.phoneEditingNoteId = "";
  state.phoneNotes = "";
}

function phoneNotesViewHtml() {
  const notes = phoneNotesArray();
  const editing = notes.find((note) => note.id === state.phoneEditingNoteId);
  return `
    <label class="device-notes">
      <span>${editing ? "Notiz bearbeiten" : "Neue Notiz"}</span>
      <textarea data-device-notes maxlength="1200" placeholder="Schreib dir etwas auf...">${escapeHtml(editing?.text || "")}</textarea>
    </label>
    <div class="device-note-actions">
      <button class="mini-button gold" data-device-save-notes>${editing ? "Änderung speichern" : "Notiz speichern"}</button>
      ${editing ? `<button class="mini-button" data-device-note-cancel>Abbrechen</button>` : ""}
    </div>
    <div class="device-notes-list">
      ${notes.length ? notes.map((note) => `
        <article class="device-note-card">
          <p>${escapeHtml(note.text)}</p>
          <small>${new Date(note.updatedAt || note.createdAt || Date.now()).toLocaleString("de-DE", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" })}</small>
          <div>
            <button class="mini-button" data-device-note-edit="${note.id}">Bearbeiten</button>
            <button class="mini-button" data-device-note-delete="${note.id}">Löschen</button>
          </div>
        </article>
      `).join("") : `<p class="device-hint">Noch keine gespeicherten Notizen.</p>`}
    </div>
  `;
}

function deviceNotificationText(item, appId = "home") {
  const notesCount = phoneNotesArray().length;
  const messages = [
    { title: "Info", text: `SIM: ${activeSimName()} · Guthaben ${euro.format(phoneCreditAmount())} · ${deviceSpeedText(deviceTier(item))}` },
    { title: "Notizen", text: notesCount ? "Du hast eine gespeicherte Notiz." : "Keine neuen Notizen." },
    { title: "Telefon", text: "Keine verpassten Anrufe." },
    { title: "SMS", text: "Keine neuen SMS." },
    { title: "Bank", text: state.onlineBanking ? `Konto ${euro.format(state.bank)} · Schulden ${euro.format(state.debt)}.` : "Online-Banking noch nicht beantragt." },
    { title: "Shop", text: `Inventar ${inventoryUsed()}/${inventoryCapacity()} belegt.` },
    { title: "Stadtkarte", text: `${state.worldLocation || state.homeCity} · ${localPlaceName()}.` },
    { title: "Games", text: "Spielstände und Rekorde bereit." }
  ];
  const index = Math.floor(Date.now() / 5000) % messages.length;
  if (appId !== "home") return messages.find((entry) => entry.title.toLowerCase().includes(appId)) || messages[index];
  return messages[index];
}

function openDeviceAppDirect(item, appId) {
  if (appId === "business" && (state.level || 0) < 5) {
    addFeed(`Business wird ab Level 5 freigeschaltet. Aktuell bist du Level ${state.level || 0}.`);
    return openDeviceInterface(item, "business", false);
  }
  if (appId === "notes" || appId === "phone" || appId === "sms" || appId === "business" || appId === "finder" || appId === "finster" || appId === "appstore") return openDeviceInterface(item, appId);
  if (appId === "bank") {
    if (!state.onlineBanking) return openDeviceInterface(item, appId);
    els.dialog.close();
    switchMainTab("bank");
    render();
    return;
  }
  if (appId === "shop") {
    els.dialog.close();
    switchMainTab("shop");
    render();
    return;
  }
  if (appId === "games") {
    els.dialog.close();
    switchMainTab("games");
    render();
    return;
  }
  if (appId === "world") {
    els.dialog.close();
    switchMainTab("world");
    render();
    return;
  }
  if (appId === "invest" || appId === "trading") {
    return openDeviceInterface(item, appId, false);
  }
  openDeviceInterface(item, appId);
}

function isAtHomeForCharging() {
  const atOwnHome = state?.location === "home" && (state.worldLocation || state.homeCity) === state.homeCity;
  return atOwnHome || isHotelDashboardAvailable();
}

function updatePhoneBattery(activeUse = false) {
  state.phoneBattery ??= 100;
  if (!isAtHomeForCharging() && activeUse) state.phoneBattery = clamp(state.phoneBattery - 0.25, 1, 100);
}

let passiveSaveTimer = null;

function schedulePassiveSave(delay = 2500) {
  if (passiveSaveTimer) return;
  passiveSaveTimer = setTimeout(() => {
    passiveSaveTimer = null;
    if (state) save();
  }, delay);
}

function tickPhoneCharging() {
  if (!state) return;
  state.phoneBattery ??= 100;
  if (!isAtHomeForCharging() || state.phoneBattery >= 100) return;
  const now = Date.now();
  if (!lastPhoneChargeAt) lastPhoneChargeAt = now;
  if (now - lastPhoneChargeAt < 5000) return;
  const steps = Math.floor((now - lastPhoneChargeAt) / 5000);
  state.phoneBattery = clamp(state.phoneBattery + steps, 0, 100);
  lastPhoneChargeAt += steps * 5000;
  schedulePassiveSave(30000);
}

function resetPhoneChargeTimerIfAway() {
  if (!isAtHomeForCharging()) lastPhoneChargeAt = 0;
}

