function refreshDeviceApp(appId, item = ownedPhoneItem()) {
  if (item && els.dialog?.open && els.dialog.querySelector(".device-shell")) {
    pendingDeviceScrollTop = els.dialog.querySelector(".device-screen")?.scrollTop ?? null;
    openDeviceInterface(item, appId, false);
    return true;
  }
  return false;
}

function onlineCasinoScale() {
  const base = Math.max(...casinoLevelConfigs[0].slotChips);
  const current = Math.max(...casinoLevelConfig().slotChips);
  return Math.max(1, current / base);
}

function onlineCasinoScaledCents(cents) {
  return Math.max(1, Math.round((cents || 0) * onlineCasinoScale()));
}

