function onlineCasinoSpin(item) {
  const stake = state.onlineCasinoStakeCents || casinoLevelConfig().slotChips[0];
  if (!takeWallet(stake)) {
    state.onlineCasinoMessage = `Nicht genug Chips für ${formatCents(stake)}.`;
    save();
    return refreshDeviceApp("onlinecasino", item);
  }
  const symbols = ["🍒", "🔔", "💎", "7️⃣", "👑", "⭐"];
  const reels = Array.from({ length: 3 }, () => symbols[Math.floor(Math.random() * symbols.length)]);
  const counts = reels.reduce((map, symbol) => ({ ...map, [symbol]: (map[symbol] || 0) + 1 }), {});
  const max = Math.max(...Object.values(counts));
  let win = 0;
  if (max === 3) win = Math.round(stake * (2.4 + (state.casinoLevel || 0) * 0.35) * casinoPayoutFactor());
  else if (max === 2 && Math.random() > casinoHouseCutChance()) win = Math.round(stake * 0.55 * casinoPayoutFactor());
  state.onlineCasinoReels = reels;
  state.onlineCasinoRiskCents = win;
  if (win > 0) {
    ensureCasinoHouseBankroll();
    state.onlineCasinoMessage = `Treffer: ${formatCents(win)}. Nimm den Gewinn oder riskiere ihn.`;
  } else {
    state.onlineCasinoMessage = "Kein Treffer. Einsatz verloren.";
  }
  save();
  refreshDeviceApp("onlinecasino", item);
}

function onlineCasinoDepositPrompt(item) {
  const amount = Math.round(Number(prompt("Wie viele Euro möchtest du online in Chips kaufen?", String(casinoDepositAmounts()[0] || 50))));
  if (!amount || amount <= 0) return;
  if (!spendPhoneCredit(amount, "Online-Casino Chips", { target: "casino", taxRate: 0 })) return addFeed(`Du brauchst ${euro.format(amount)} Handy-Guthaben.`);
  addWallet(amount * 100);
  state.onlineCasinoMessage = `${euro.format(amount)} online in Chips gekauft.`;
  queuePurchaseConfirmation({ kind: "deposit", name: "Online-Casino Chips", total: amount, method: "Handy-Guthaben", icon: "🎰" });
  save();
  refreshDeviceApp("onlinecasino", item);
}

function onlineCasinoWithdrawPrompt(item) {
  const amount = Math.round(Number(prompt("Wie viele Euro möchtest du online auszahlen?", String(Math.floor(walletCents() / 100)))));
  if (!amount || amount <= 0) return;
  const cents = Math.min(walletCents(), amount * 100);
  if (cents <= 0) return addFeed("Dein Casino-Wallet ist leer.");
  ensureCasinoHouseBankroll();
  addWallet(-cents);
  state.casinoAccount = Math.max(0, (state.casinoAccount || 0) - cents / 100);
  state.casinoDailyProfit = (state.casinoDailyProfit || 0) - cents / 100;
  addPhoneCredit(cents / 100, "Online-Casino Auszahlung");
  recordIncome("casino", cents / 100);
  state.onlineCasinoMessage = `${formatCents(cents)} online ausgezahlt.`;
  queuePurchaseConfirmation({ kind: "withdraw", name: "Online-Casino Auszahlung", total: cents / 100, method: "Handy-Guthaben", icon: "💸" });
  save();
  refreshDeviceApp("onlinecasino", item);
}

function buyOnlineCasinoUpgrade(item) {
  const next = nextCasinoLevel();
  if (next == null) return addFeed("Casino ist bereits auf der höchsten Stufe.");
  const config = casinoLevelConfigs[next];
  if (!spendPhoneCredit(config.cost, `Online-Casino ${config.name}`, { target: "casino", taxRate: 0.19 })) return addFeed(`Für ${config.name} brauchst du ${euro.format(config.cost)} Handy-Guthaben.`);
  state.casinoLevel = next;
  state.onlineCasinoStakeCents = casinoLevelConfig().slotChips[0];
  state.onlineCasinoRiskCents = 0;
  state.onlineCasinoMessage = `${config.name} online freigeschaltet. Gewinne und Einsätze skalieren mit.`;
  queuePurchaseConfirmation({ name: `Online-Casino ${config.name}`, total: config.cost, method: "Handy-Guthaben", icon: "🎰" });
  save();
  refreshDeviceApp("onlinecasino", item);
}

function downgradeOnlineCasinoLevel(item) {
  const previous = previousCasinoLevel();
  if (previous == null) return addFeed("Du bist bereits auf Stufe 0.");
  state.casinoLevel = previous;
  state.onlineCasinoStakeCents = casinoLevelConfig().slotChips[0];
  state.onlineCasinoRiskCents = 0;
  state.onlineCasinoMessage = `${casinoLevelConfig().name} aktiv.`;
  save();
  refreshDeviceApp("onlinecasino", item);
}

function playOnlineCasinoRisk(type, item) {
  const risk = state.onlineCasinoRiskCents || 0;
  if (risk <= 0) return;
  if (type === "take") {
    ensureCasinoHouseBankroll();
    payoutFromCasino(risk);
    state.onlineCasinoRiskCents = 0;
    state.onlineCasinoMessage = `${formatCents(risk)} genommen.`;
    save();
    return refreshDeviceApp("onlinecasino", item);
  }
  const chance = type === "ladder" ? 0.43 : 0.47;
  if (Math.random() < chance) {
    const factor = type === "ladder" ? 1.8 : 1.65;
    state.onlineCasinoRiskCents = Math.round(risk * factor);
    state.onlineCasinoMessage = `Risiko gewonnen: jetzt ${formatCents(state.onlineCasinoRiskCents)}.`;
  } else {
    state.onlineCasinoRiskCents = 0;
    state.onlineCasinoMessage = "Risiko verloren.";
  }
  save();
  refreshDeviceApp("onlinecasino", item);
}

