function staffCardHtml(worker, index, type) {
  const roles = type === "courier" ? ["Fahren", "Übergabe", "Absicherung"] : ["Besorgen", "Sortieren", "Verkaufen"];
  return `
    <article class="staff-card">
      <strong>${escapeHtml(worker.name)}</strong>
      <small>Rolle: ${escapeHtml(worker.role || roles[index % roles.length])}</small>
      <div class="staff-role-actions">${roles.map((role) => `<button class="mini-button" data-black-staff-role="${type}:${index}:${role}">${role}</button>`).join("")}<button class="mini-button danger" data-black-staff-fire="${type}:${index}">Entlassen</button></div>
    </article>
  `;
}

function addDirtyBusinessMoney(amount, label) {
  state.dirtyMoney = (state.dirtyMoney || 0) + amount;
  state.illegalEarnings = (state.illegalEarnings || 0) + amount;
  state.blackBusiness.message = `${label}: ${euro.format(amount)} Schwarzgeld.`;
}

function businessRiskHit(baseRisk, title) {
  const bribe = clamp(state.policeBribe ?? 0, 0, 100) / 100;
  const risk = Math.max(0, baseRisk * (1 - bribe));
  if (Math.random() >= risk) return false;
  const fine = randomInt(1000, 11000);
  applyCriminalFine(title, "Geschäft aufgeflogen. Ware und Einsatz wurden eingezogen.", fine, hour);
  return true;
}

function buyBlackWeapon(id, item) {
  if (!hasBlackBusinessLicense("fence")) return addFeed("Waffenbusiness ist gesperrt.");
  const model = blackWeaponCatalog.find((entry) => entry.id === id);
  if (!model) return;
  if (blackWeaponStorageCapacity() <= 0) return addFeed("Du brauchst zuerst mindestens ein Lager auf der Business Map.");
  if (blackWeaponStorageFree() <= 0) return addFeed(`Deine Lager sind voll (${blackWeaponStorageUsed()}/${blackWeaponStorageCapacity()}).`);
  if (!spendPhoneCredit(model.price, model.name, { target: "treasury", taxRate: 0 })) return addFeed(`${model.name} kostet ${euro.format(model.price)} Handy-Guthaben.`);
  state.blackBusiness.weapons ||= [];
  state.blackBusiness.weapons.push({ ...model, uid: `weapon-${Date.now()}-${Math.round(Math.random() * 9999)}`, mods: [] });
  state.blackBusiness.message = `${model.name} eingekauft.`;
  addFeed(`${model.name} ins Waffenlager gelegt.`, { purchase: { name: model.name, total: model.price, method: "Handy-Guthaben", icon: "📦" } });
  save();
  refreshBusinessContext(item, businessMapActiveLocation || "weapons");
}

function openBlackWeaponSelectDialog(index, phoneItem) {
  const weapon = state.blackBusiness?.weapons?.[index];
  if (!weapon) return addFeed("Diese Ware ist nicht mehr vorhanden.");
  const matches = (state.blackBusiness.weapons || [])
    .map((entry, entryIndex) => ({ entry, entryIndex }))
    .filter(({ entry }) => (entry.id || entry.name) === (weapon.id || weapon.name));
  if (matches.length <= 1) return openBlackWeaponModDialog(index, phoneItem);
  clearDialogDynamic();
  els.dialogTitle.textContent = `${weapon.name} auswählen`;
  els.dialogText.textContent = "Du hast mehrere gleiche Waffen. Wähle, welche du anpassen möchtest.";
  const list = document.createElement("div");
  list.className = "market-list";
  list.innerHTML = matches.map(({ entry, entryIndex }, shownIndex) => `
    <article class="weapon-select-card">
      ${weaponPreviewHtml(entry, "small")}
      <div>
        <strong>${escapeHtml(entry.name)} #${shownIndex + 1}</strong>
        <small>Wert ${euro.format(blackWeaponValue(entry))} · Mods ${(entry.mods || []).length}${weaponGroupsComplete(entry) ? " · voll ausgebaut" : ""}</small>
      </div>
      <button class="mini-button gold" data-black-weapon-pick="${entryIndex}">Anpassen</button>
    </article>
  `).join("");
  setDialogBack(() => returnToBusinessContext(phoneItem, "weapons"), "Business Map");
  els.dialog.append(list);
  list.querySelectorAll("[data-black-weapon-pick]").forEach((button) => {
    button.addEventListener("click", () => openBlackWeaponModDialog(Number(button.dataset.blackWeaponPick), phoneItem));
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function openBlackWeaponModDialog(index, phoneItem) {
  const weapon = state.blackBusiness?.weapons?.[index];
  if (!weapon) return addFeed("Diese Ware ist nicht mehr vorhanden.");
  clearDialogDynamic();
  els.dialogTitle.textContent = weapon.name;
  els.dialogText.textContent = `Aktueller Wert: ${euro.format(blackWeaponValue(weapon))}. Pro Gruppe ist nur ein Teil möglich. Kaufpreis plus 3% erhöht den Wert, Vollausbau bringt 10%.`;
  const list = document.createElement("div");
  list.className = "market-list";
  const groups = ["Visier", "Dämpfer", "Magazin", "Griff", "Finish"];
  list.innerHTML = `
    <article class="weapon-mod-overview">
      ${weaponPreviewHtml(weapon)}
      <div>
        <strong>${escapeHtml(weapon.name)}</strong>
        <small>${groups.map((group) => `${blackWeaponGroupLabel(group)}: ${weaponModForGroup(weapon, group)?.name || "frei"}`).join(" · ")}</small>
      </div>
    </article>
    ${groups.map((group) => {
      const used = weaponModForGroup(weapon, group);
      return card(blackWeaponGroupLabel(group), used ? `Verbaut: ${used.name}.` : `${blackWeaponModsForGroup(group).length} Optionen verfügbar.`, "Öffnen", group, false, "black-weapon-group-open");
    }).join("")}
  `;
  setDialogBack(() => returnToBusinessContext(phoneItem, "weapons"), "Business Map");
  els.dialog.append(list);
  list.querySelectorAll('button[data-kind="black-weapon-group-open"]').forEach((button) => {
    button.addEventListener("click", () => openBlackWeaponGroupDialog(index, button.dataset.index, phoneItem));
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function openBlackWeaponGroupDialog(index, group, phoneItem) {
  const weapon = state.blackBusiness?.weapons?.[index];
  if (!weapon) return addFeed("Diese Ware ist nicht mehr vorhanden.");
  clearDialogDynamic();
  const used = weaponModForGroup(weapon, group);
  els.dialogTitle.textContent = `${blackWeaponGroupLabel(group)} · ${weapon.name}`;
  els.dialogText.textContent = used
    ? `Schon verbaut: ${used.name}. Pro Kategorie kann nur ein Teil eingebaut werden.`
    : "Wähle ein Teil. Es wird direkt bezahlt und an diese einzelne Waffe gebaut.";
  const list = document.createElement("div");
  list.className = "market-list weapon-mod-market";
  list.innerHTML = `
    ${weaponPreviewHtml(weapon)}
    ${blackWeaponModsForGroup(group).map((mod, modIndex) => {
      const label = mod.group === "Finish" && mod.color ? `<span class="finish-swatch" style="--finish-color:${escapeHtml(mod.color)}"></span>${escapeHtml(mod.name)}` : escapeHtml(mod.name);
      return `
        <article class="device-finance-card">
          <div>
            <strong>${label}</strong>
            <small>Kosten ${euro.format(mod.price)} · Wertsteigerung ca. ${euro.format(Math.round(mod.price * 1.03))}</small>
          </div>
          <button class="mini-button gold" data-black-weapon-mod-buy="${modIndex}" ${used || !canAffordPhoneCredit(mod.price) ? "disabled" : ""}>${used ? "Belegt" : "Einbauen"}</button>
        </article>
      `;
    }).join("")}
  `;
  setDialogBack(() => openBlackWeaponModDialog(index, phoneItem));
  els.dialog.append(list);
  list.querySelectorAll("[data-black-weapon-mod-buy]").forEach((button) => {
    button.addEventListener("click", () => {
      if (weaponModForGroup(weapon, group)) return addFeed(`${blackWeaponGroupLabel(group)} ist schon belegt.`);
      const mod = blackWeaponModsForGroup(group)[Number(button.dataset.blackWeaponModBuy)];
      if (!mod || !spendPhoneCredit(mod.price, `${weapon.name}: ${mod.name}`, { target: "treasury", taxRate: 0 })) return addFeed("Nicht genug Handy-Guthaben für diesen Einbau.");
      weapon.mods ||= [];
      weapon.mods.push(mod);
      state.blackBusiness.message = `${mod.group} verbaut: ${mod.name}.`;
      addFeed(`${weapon.name}: ${mod.name} eingebaut.`, { purchase: { name: `${weapon.name} · ${mod.name}`, total: mod.price, method: "Handy-Guthaben", icon: "🔧" } });
      save();
      openBlackWeaponModDialog(index, phoneItem);
    });
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function sellBlackWeapon(index, item) {
  const weapon = state.blackBusiness?.weapons?.[index];
  if (!weapon) return addFeed("Diese Ware ist nicht mehr vorhanden.");
  if (businessRiskHit(0.18, "Waffenbusiness")) {
    state.blackBusiness.weapons.splice(index, 1);
    save();
    refreshBusinessContext(item, businessMapActiveLocation || "sell");
    return;
  }
  const amount = blackWeaponValue(weapon);
  state.blackBusiness.weapons.splice(index, 1);
  if (!hasBlackBusinessLicense("dealer")) {
    state.blackBusiness.pendingSales ||= [];
    state.blackBusiness.pendingSales.push({ name: weapon.name, amount, dirty: true, readyAt: Date.now() + randomInt(60, 180) * 1000 });
    state.blackBusiness.message = `${weapon.name}: Verkauf läuft.`;
    addFeed(`${weapon.name}: Verkauf dauert 1 bis 3 Minuten.`);
  } else {
    addDirtyBusinessMoney(amount, weapon.name);
    addFeed(`${weapon.name}: ${euro.format(amount)} Schwarzgeld erhalten.`);
  }
  improveSkill("Straßenwissen", 1);
  save();
  refreshBusinessContext(item, businessMapActiveLocation || "sell");
}

function hireBlackStaff(type, item) {
  if (!hasBlackBusinessLicense("hiring")) return addFeed("Du brauchst die Anheuern-Lizenz.");
  const cost = 2500;
  if (!spendPhoneCredit(cost, "Mitarbeiter anheuern", { target: "treasury", taxRate: 0 })) return addFeed(`Mitarbeiter anheuern kostet ${euro.format(cost)} Handy-Guthaben.`);
  const pool = type === "courier" ? "courierStaff" : "staff";
  state.blackBusiness[pool] ||= [];
  const names = ["K. Nord", "M. Schatten", "R. Nacht", "T. Grau", "L. Kante", "S. Kurier", "A. Still"];
  state.blackBusiness[pool].push({ name: names[(state.blackBusiness[pool].length + randomInt(0, names.length - 1)) % names.length], role: type === "courier" ? "Fahren" : ["Besorgen", "Sortieren", "Verkaufen"][state.blackBusiness[pool].length % 3], hiredAt: Date.now() });
  state.blackBusiness.message = "Mitarbeiter angeheuert.";
  save();
  refreshBusinessContext(item, businessMapActiveLocation || (type === "courier" ? "courier" : "stolen"));
}

function setBlackStaffRole(payload, item) {
  const [type, indexText, role] = String(payload || "").split(":");
  const pool = type === "courier" ? "courierStaff" : "staff";
  const worker = state.blackBusiness?.[pool]?.[Number(indexText)];
  if (!worker) return;
  worker.role = role;
  state.blackBusiness.message = `${worker.name}: ${role}.`;
  save();
  refreshBusinessContext(item, businessMapActiveLocation || (type === "courier" ? "courier" : "stolen"));
}

function fireBlackStaff(payload, item) {
  const [type, indexText] = String(payload || "").split(":");
  const pool = type === "courier" ? "courierStaff" : "staff";
  const index = Number(indexText);
  const worker = state.blackBusiness?.[pool]?.[index];
  if (!worker) return addFeed("Dieser Mitarbeiter ist nicht mehr vorhanden.");
  if (!confirm(`${worker.name} wirklich entlassen?`)) return;
  state.blackBusiness[pool].splice(index, 1);
  state.blackBusiness.message = `${worker.name} wurde entlassen.`;
  addFeed(`${worker.name} wurde aus dem ${type === "courier" ? "Kurierdienst" : "Hehler-Team"} entlassen.`);
  save();
  refreshBusinessContext(item, businessMapActiveLocation || (type === "courier" ? "courier" : "stolen"));
}

function runHehlerAction(id, item) {
  const target = heistTargets.find((entry) => entry.id === id);
  if (!target) return;
  if (!hasBlackBusinessLicense("hiring")) return addFeed("Du brauchst die Anheuern-Lizenz.");
  const black = state.blackBusiness ||= createBlackBusinessState();
  black.staffBlockedUntil = 0;
  black.heistLastDay ||= {};
  black.heistRuns ||= {};
  const cooldown = heistCooldownStatus(target);
  if (!cooldown.ready) return addFeed(`${target.name} ist noch nicht bereit. ${cooldown.text}.`);
  if ((black.staff || []).length < target.need) return addFeed(`${target.name} braucht ${target.need} Mitarbeiter.`);
  if (!spendPhoneCredit(target.cost, `${target.name} Vorbereitung`, { target: "treasury", taxRate: 0 })) return addFeed(`${target.name} kostet ${euro.format(target.cost)} Handy-Guthaben.`);
  black.heistLastDay[target.id] = Number(state.day || 1);
  black.heistRuns[target.id] = Math.max(0, Number(black.heistRuns[target.id] || 0)) + 1;
  if (businessRiskHit(target.risk, target.name)) {
    black.message = `${target.name}: Einsatz verloren. ${target.cooldownDays === 1 ? "Morgen" : `Nach ${target.cooldownDays} Schlaf-Tagen`} wieder verfügbar.`;
    save();
    updateBusinessMapStatusStrip();
    return refreshBusinessContext(item, "stolen");
  }
  const amount = randomInt(target.min, target.max);
  addDirtyBusinessMoney(amount, target.name);
  addFeed(`${target.name}: ${euro.format(amount)} Schwarzgeld erhalten.`, {
    purchase: { kind: "withdraw", title: "Hehler-Auftrag abgeschlossen", name: target.name, total: amount, method: "Schwarzgeld", icon: "🕶️" }
  });
  addXp(target.xp, target.name);
  improveSkill("Straßenwissen", 1);
  save();
  updateBusinessMapStatusStrip();
  refreshBusinessContext(item, "stolen");
}
function runCourierAction(id, item) {
  const run = courierRuns.find((entry) => entry.id === id);
  if (!run) return;
  if (!hasBlackBusinessLicense("hiring")) return addFeed("Du brauchst die Anheuern-Lizenz.");
  const black = state.blackBusiness ||= createBlackBusinessState();
  black.courierLastDay ||= {};
  black.courierRuns ||= {};
  const cooldown = courierCooldownStatus(run);
  if (!cooldown.ready) return addFeed(`${run.name} ist noch nicht bereit. ${cooldown.text}.`);
  if ((black.courierStaff || []).length < run.need) return addFeed(`${run.name} braucht ${run.need} Fahrer.`);
  if (!spendPhoneCredit(run.cost, `${run.name} Vorbereitung`, { target: "treasury", taxRate: 0 })) return addFeed(`${run.name} kostet ${euro.format(run.cost)} Handy-Guthaben.`);
  // Der Versuch zählt sofort. Auch ein gescheiterter Auftrag kann nicht endlos neu gestartet werden.
  black.courierLastDay[run.id] = Number(state.day || 1);
  black.courierRuns[run.id] = Math.max(0, Number(black.courierRuns[run.id] || 0)) + 1;
  if (businessRiskHit(run.risk, run.name)) {
    black.message = `${run.name}: Einsatz verloren. ${run.cooldownDays === 1 ? "Morgen" : `Nach ${run.cooldownDays} Schlaf-Tagen`} wieder verfügbar.`;
    save();
    updateBusinessMapStatusStrip();
    return refreshBusinessContext(item, "courier");
  }
  addDirtyBusinessMoney(run.reward, run.name);
  addFeed(`${run.name}: ${euro.format(run.reward)} Schwarzgeld.`, {
    purchase: { kind: "withdraw", title: "Kurier-Auftrag abgeschlossen", name: run.name, total: run.reward, method: "Schwarzgeld", icon: "🚚" }
  });
  improveSkill("Straßenwissen", 1);
  save();
  updateBusinessMapStatusStrip();
  refreshBusinessContext(item, "courier");
}

function bribePolicePrompt(item) {
  const missing = 100 - clamp(state.policeBribe ?? 100, 0, 100);
  if (missing <= 0) return addFeed("Polizei-Schmierung ist bereits bei 100%.");
  const percent = Math.min(missing, Math.max(0, Math.round(Number(prompt("Wie viele Prozent wiederherstellen?", String(Math.min(10, missing)))))));
  if (!percent) return;
  const costPerPercent = randomInt(100, 1000);
  const cost = percent * costPerPercent;
  if (!spendPhoneCredit(cost, "Cops schmieren", { target: "treasury", taxRate: 0 })) return addFeed(`Cops schmieren kostet diesmal ${euro.format(cost)} Handy-Guthaben.`);
  state.policeBribe = clamp((state.policeBribe || 0) + percent, 0, 100);
  addFeed(`Polizei geschmiert: +${percent}% für ${euro.format(cost)}.`);
  save();
  refreshBusinessContext(item, "bribe");
}

