function realEstateCategories() {
  return [
    { id: "garage", name: "Garagen", text: "Kleine, mittlere und große Garagen für mehr Fahrzeugplätze.", filter: (item) => item.garageSlots || item.name.toLowerCase().includes("garage") },
    { id: "flat-all", name: "Wohnungsangebote", text: "Alle kleinen, mittleren und großen Wohnungen sowie Penthouses in einer Liste.", filter: (item) => ["apartment", "penthouse"].includes(propertyType(item)) },
    { id: "house", name: "Häuser", text: "Reihenhäuser, Stadthäuser und Eigenheime.", filter: (item) => propertyType(item) === "house" },
    { id: "villa", name: "Villen", text: "Große Luxusimmobilien mit vielen Räumen und Garagen.", filter: (item) => propertyType(item) === "villa" },
    { id: "island", name: "Inseln", text: "Endgame-Luxusobjekte wie private Inseln.", filter: (item) => item.name.toLowerCase().includes("insel") || item.name.toLowerCase().includes("island") }
  ];
}

function propertyMarketValue(property) {
  const meta = state.propertyMeta?.[property.id] || {};
  const base = meta.eur || property.eur || meta.purchasePrice || 0;
  const days = Math.max(0, (state.day || 1) - 1);
  const wave = Math.sin((days + (meta.valueSeed || 0) * 31) / 9) * 0.055;
  const trend = ((meta.valueSeed || 0) * 0.035) + ((meta.upgrades || 0) * 0.018);
  return Math.max(1000, Math.round(base * (1 + wave + trend)));
}

function seededUnit(seed) {
  const x = Math.sin(seed * 999.91) * 10000;
  return x - Math.floor(x);
}

function realEstateMarketFactor(item) {
  const day = state?.day || 1;
  const seed = Array.from(String(item.id || item.name)).reduce((sum, char) => sum + char.charCodeAt(0), 0);
  const wave = (seededUnit(seed + day * 17) - .5) * .08;
  const premium = propertyType(item) === "island" ? .04 : propertyType(item) === "villa" ? .025 : 0;
  return clamp(1 + wave + premium, .92, 1.12);
}

function realEstateOfferPrice(item) {
  if (item.repeatable) return item.eur || item.price || 0;
  const type = propertyType(item);
  const minByType = { garage: 6000, apartment: 25000, penthouse: 180000, house: 160000, villa: 1200000, island: 25000000 };
  const base = item.eur || item.price || 0;
  return Math.max(minByType[type] || 1000, Math.round(base * realEstateMarketFactor(item) / 1000) * 1000);
}

function dailyRealEstateOffers() {
  const day = state?.day || 1;
  const offers = realEstateItems.filter((item) => {
    if (item.repeatable || item.garageSlots) return true;
    const seed = Array.from(String(item.id || item.name)).reduce((sum, char) => sum + char.charCodeAt(0), 0);
    return seededUnit(seed + day * 31) > .13;
  });
  return offers.length >= 300 ? offers : realEstateItems.slice(0, Math.max(300, Math.min(realEstateItems.length, 320)));
}

function formatDateTime(timestamp) {
  if (!timestamp) return "Noch nicht";
  return new Date(timestamp).toLocaleDateString("de-DE", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function openPropertyInfoDialog() {
  clearDialogDynamic();
  els.dialogTitle.textContent = "Immobilieninformationen";
  els.dialogText.textContent = "Jede Immobilie mit Wertentwicklung, Kaufdaten, Vermietung und Mieteinnahmen.";
  const list = document.createElement("div");
  list.className = "market-list property-info-list";
  const ids = state.properties || [];
  list.innerHTML = ids.length ? ids.map((id) => {
    const property = findProperty(id);
    if (!property) return "";
    const meta = state.propertyMeta?.[id] || {};
    const currentValue = propertyMarketValue(property);
    const purchase = meta.purchasePrice || meta.baseValue || property.eur || 0;
    const diff = currentValue - purchase;
    const rented = state.rentedProperties?.[id];
    return `
      <article class="item-card property-info-card">
        <div>
          <h3>${property.name}</h3>
          <p>${property.city} · Kauf: ${formatDateTime(meta.boughtAt)} · ${rented ? `Vermietet seit ${formatDateTime(meta.rentedAt)}` : "Nicht vermietet"}</p>
          <p>Wert: ${euro.format(currentValue)} · ${diff >= 0 ? "Gestiegen" : "Gesunken"} um ${euro.format(Math.abs(diff))}</p>
          <p>Miete bisher: ${euro.format(meta.rentEarned || 0)}${rented ? ` · Monatsmiete: ${euro.format(rented.monthlyRent || (rented.rent || 0) * 30)} · Pro Schlaf: ${euro.format(rented.sleepPayout || rented.weeklyRent || (rented.rent || 0) * 7)}` : ""}</p>
        </div>
        ${rented
          ? `<button class="mini-button" data-property-rental-manage="${id}">Vermietung bearbeiten</button>`
          : `<div class="inventory-actions property-sale-actions"><button disabled>${diff >= 0 ? "▲" : "▼"}</button><button class="mini-button danger" data-property-sell="${id}">Verkaufen</button></div>`}
      </article>
    `;
  }).join("") : `<article class="item-card"><div><h3>Keine Immobilien</h3><p>Noch keine eigenen Immobilien vorhanden.</p></div><button disabled>Leer</button></article>`;
  const close = document.createElement("button");
  close.className = "mini-button";
  close.textContent = "Schließen";
  close.onclick = () => els.dialog.close();
  els.dialog.append(list, close);
  list.querySelectorAll("[data-property-rental-manage]").forEach((button) => {
    button.addEventListener("click", () => {
      const property = findProperty(button.dataset.propertyRentalManage);
      if (property) openRentalManagement(property);
    });
  });
  list.querySelectorAll("[data-property-sell]").forEach((button) => {
    button.addEventListener("click", () => {
      const property = findProperty(button.dataset.propertySell);
      if (property) sellOwnedProperty(property);
    });
  });
  if (!els.dialog.open) els.dialog.showModal();
}

function openRealEstateCategory(category) {
  const owned = new Set(state.properties || []);
  const entries = dailyRealEstateOffers().filter(category.filter);
  clearDialogDynamic();
  els.dialogTitle.textContent = category.name;
  els.dialogText.textContent = `${category.text} ${entries.length} Angebote.`;
  const list = document.createElement("div");
  list.className = "market-list realestate-category-list";
  list.innerHTML = entries.map((item, index) => {
    const bought = owned.has(item.id) && !item.repeatable;
    const label = bought ? "Besitzt du" : item.bidOnly ? "Bieten" : "Kaufen";
    return card(item.name, `${item.city} · ${item.text} Preis heute: ${realEstatePriceText(item)}.`, label, index, bought, "realestate-buy");
  }).join("") || card("Keine Angebote", "In dieser Kategorie gibt es aktuell nichts.", "Leer", 0, true);
  const close = document.createElement("button");
  close.className = "mini-button";
  close.textContent = "Schließen";
  close.onclick = () => els.dialog.close();
  els.dialog.append(list, close);
  list.querySelectorAll('button[data-kind="realestate-buy"]:not(:disabled)').forEach((button) => {
    button.addEventListener("click", () => {
      const item = entries[Number(button.dataset.index)];
      els.dialog.close();
      buyRealEstate(item);
    });
  });
  els.dialog.showModal();
}

function propertyProfile(property) {
  const value = property?.eur || property?.price || 50000;
  const sqm = property.sqm || Math.max(24, Math.round(Math.sqrt(value / 85) * 8));
  const floors = property.floors || (value >= 2500000 ? 4 : value >= 900000 ? 3 : value >= 260000 ? 2 : 1);
  const type = propertyType(property);
  let rooms = property.rooms || Math.max(1, Math.min(24, Math.round(sqm / 24)));
  let garages = property.garageSlots || (value >= 1800000 ? 4 : value >= 650000 ? 2 : value >= 220000 ? 1 : 0);
  if (type === "apartment" && value < 100000) {
    rooms = Math.max(1, Math.min(4, property.rooms || Math.round(sqm / 32)));
    garages = 0;
  }
  return { sqm, floors, rooms, garages, type };
}

function propertyType(property) {
  if (property?.isTenantRental) return "apartment";
  const name = `${property?.name || ""}`.toLowerCase();
  const value = property?.eur || property?.price || 0;
  if (property?.garageSlots && value < 50000 || name.includes("garage")) return "garage";
  if (name.includes("insel") || name.includes("island")) return "island";
  if (name.includes("villa") || value >= 1200000) return "villa";
  if (name.includes("haus") || name.includes("eigenheim") || value >= 260000) return "house";
  if (name.includes("penthouse")) return "penthouse";
  return "apartment";
}

function propertyTypeLabel(type) {
  return { garage: "Garage", villa: "Villa", house: "Haus", penthouse: "Penthouse", apartment: "Wohnung", island: "Insel" }[type] || "Immobilie";
}

function defaultResidentialRoomNames(count) {
  if (count <= 1) return ["Wohn-/Schlafzimmer"];
  const names = ["Wohnzimmer", "Schlafzimmer", "Kinderzimmer", "Büro", "Gästezimmer", "Hobbyraum", "Esszimmer", "Ankleidezimmer", "Fitnessraum", "Aufenthaltsraum"];
  return names.slice(0, Math.max(1, Math.min(10, count)));
}

function propertyRoomLayout(property) {
  const profile = propertyProfile(property);
  const residential = defaultResidentialRoomNames(profile.rooms).map((name, index) => ({ key: `living-${index}`, name, fixed: false, kind: "living" }));
  const storageName = property?.storageType || (["house", "villa", "island"].includes(profile.type) ? "Keller" : "Keller/Box");
  return [
    ...residential,
    { key: "kitchen", name: "Küche", fixed: true, kind: "kitchen" },
    { key: "bathroom", name: "Bad", fixed: true, kind: "bathroom" },
    { key: "storage", name: storageName, fixed: true, kind: "storage" }
  ];
}

function propertyRoomDefinition(property, index) {
  return propertyRoomLayout(property)[index] || { key: `room-${index}`, name: `Raum ${index + 1}`, fixed: false, kind: "living" };
}

function propertyVisualHtml(property, profile) {
  const floors = Array.from({ length: Math.min(profile.floors, 4) }, (_, floor) => `<span>${floor === 0 ? "Erdgeschoss" : `${floor + 1}. Etage`}</span>`).join("");
  const layout = propertyRoomLayout(property);
  const rooms = layout.map((definition, index) => `<button class="${definition.fixed ? "fixed-room" : "living-room"}" data-property-room="${index}"><span>${propertyRoomName(index, property)}</span><small>${definition.fixed ? "Nebenraum" : `Wohnraum ${index + 1}`}</small></button>`).join("");
  return `
    <div class="property-visual ${profile.type}">
      <div class="property-building">
        <i class="roof"></i>
        <i class="tower left"></i>
        <i class="tower right"></i>
        <div class="floors">${floors}</div>
        <i class="door"></i>
        <i class="garage-door"></i>
      </div>
      <div class="property-room-map">${rooms}</div>
    </div>
  `;
}

function propertyRooms(id, count) {
  state.propertyRooms ||= {};
  state.propertyRooms[id] ||= {};
  for (let i = 0; i < Math.min(count, 16); i += 1) {
    state.propertyRooms[id][i] ||= { furniture: [], cleaned: false, customName: "", description: "" };
    state.propertyRooms[id][i].furniture = normalizeRoomFurniture(state.propertyRooms[id][i].furniture);
    state.propertyRooms[id][i].customName ||= "";
    state.propertyRooms[id][i].description ||= "";
  }
  return state.propertyRooms[id];
}

function normalizeRoomFurniture(furniture = []) {
  return (furniture || []).map((entry) => {
    if (typeof entry === "object" && entry?.name) return entry;
    const item = furnitureCatalog.find((candidate) => candidate.name === entry);
    return {
      id: `${Date.now()}-${Math.random().toString(16).slice(2)}`,
      name: String(entry || "Möbelstück"),
      group: item?.group || "Sonstiges",
      price: item?.price || 0,
      boughtAt: state?.day || 1
    };
  });
}

function roomFurnitureText(room) {
  const furniture = normalizeRoomFurniture(room?.furniture || []);
  return furniture.length ? furniture.map((item) => item.name).join(", ") : "";
}

function enterProperty(id) {
  const property = findProperty(id);
  if (!property) return;
  if (!isTenantRentalProperty(property) && state.rentedProperties?.[property.id]) {
    addFeed(`${property.name} ist vermietet und kann während der Vermietung nicht betreten werden.`);
    return openRentalManagement(property);
  }
  state.activeHomePropertyId = property.id;
  state.homeDashboardActive = true;
  state.location = "home";
  state.worldLocation = state.homeCity || state.worldLocation;
  const profile = propertyProfile(property);
  const layout = propertyRoomLayout(property);
  clearDialogDynamic();
  propertyRooms(property.id, layout.length);
  const meta = state.propertyMeta?.[property.id] || {};
  const rentalText = isTenantRentalProperty(property) ? ` · Tagesmiete ${euro.format(state.tenantLease?.dailyRent || property.dailyRent || 0)}` : ` · Wert: ${euro.format(property.eur || property.price || 0)}`;
  els.dialogTitle.textContent = isTenantRentalProperty(property) ? "Mietwohnung betreten" : `${propertyTypeLabel(profile.type)} betreten`;
  els.dialogText.textContent = `${property.city} · ${property.district ? `${property.district} · ` : ""}ca. ${profile.sqm} m² · ${profile.rooms} Wohnräume plus Küche, Bad und ${property.storageType || "Keller/Box"} · ${profile.floors} Etage(n)${rentalText}.${meta.customDescription ? ` ${meta.customDescription}` : ""}`;
  const list = document.createElement("div");
  list.className = "market-list property-room-list";
  list.innerHTML = propertyVisualHtml(property, profile);

  const describe = document.createElement("button");
  describe.className = "mini-button";
  describe.textContent = meta.customDescription ? "Wohnungstext bearbeiten" : "Wohnung beschreiben";
  describe.onclick = () => openPropertyDescriptionEditor(property.id);

  const contract = document.createElement("button");
  contract.className = "mini-button gold property-rent-button";
  if (isTenantRentalProperty(property)) {
    contract.textContent = "Mietvertrag bearbeiten";
    contract.onclick = openTenantLeaseManagement;
  } else {
    contract.textContent = state.rentedProperties?.[property.id] ? "Vermietung bearbeiten" : "Weitervermieten";
    contract.onclick = () => state.rentedProperties?.[property.id] ? openRentalManagement(property) : toggleRentProperty(property);
  }

  const sellProperty = document.createElement("button");
  sellProperty.className = "mini-button danger";
  sellProperty.textContent = "Immobilie verkaufen";
  sellProperty.hidden = isTenantRentalProperty(property);
  sellProperty.onclick = () => sellOwnedProperty(property);

  const exit = document.createElement("button");
  exit.className = "mini-button gold";
  exit.textContent = "Ausgang";
  exit.onclick = exitHomeToWorldMap;
  const close = document.createElement("button");
  close.className = "mini-button";
  close.textContent = "Schließen";
  close.onclick = () => els.dialog.close();
  const actions = document.createElement("div");
  actions.className = "property-home-actions";
  actions.append(describe, contract, sellProperty, exit, close);
  els.dialog.append(list, actions);
  list.querySelectorAll("[data-property-room]").forEach((button) => {
    button.addEventListener("click", () => openPropertyRoom(property.id, Number(button.dataset.propertyRoom)));
  });
  if (!els.dialog.open) els.dialog.showModal();
  save();
}

function openEmergencyShelterDialog(hasRentedHomes = false) {
  const available = isEmergencyShelterAvailable();
  const daysLeft = emergencyShelterDaysLeft();
  state.activeHomePropertyId = "";
  state.homeDashboardActive = available;
  state.location = "home";
  state.worldLocation = state.homeCity || state.worldLocation;
  if (available) switchMainTab("overview");
  else if (["overview", "work"].includes(activeTabId())) switchMainTab("world");
  updateHomeDashboardVisibility();
  clearDialogDynamic();
  els.dialogTitle.textContent = "Notunterkunft";
  els.dialogText.textContent = available
    ? `${hasRentedHomes ? "Alle eigenen Wohnungen sind vermietet." : "Du hast noch keine freie Wohnung."} Die Notunterkunft ist insgesamt ${EMERGENCY_SHELTER_FREE_DAYS} Spieltage kostenlos nutzbar.`
    : "Deine kostenlose Zeit in der Notunterkunft ist abgelaufen. Miete eine Wohnung, damit Heute, Arbeit und Schlafen wieder verfügbar werden.";
  const notice = document.createElement("div");
  notice.className = `emergency-shelter-card ${available ? "" : "expired"}`;
  notice.innerHTML = `
    <strong>${available ? "Minimale Unterkunft" : "Kostenlose Zeit abgelaufen"}</strong>
    <span>${available ? `Noch ${daysLeft} Spieltag${daysLeft === 1 ? "" : "e"} verfügbar. Keine Räume, Möbel oder Ausbauten.` : "Nur Mietwohnung auswählen oder die Unterkunft verlassen."}</span>
    <div class="shelter-day-meter"><i style="width:${Math.max(0, Math.min(100, daysLeft / EMERGENCY_SHELTER_FREE_DAYS * 100))}%"></i></div>
  `;
  const exit = document.createElement("button");
  exit.className = "mini-button";
  exit.textContent = "Ausgang";
  exit.onclick = exitHomeToWorldMap;
  const rental = document.createElement("button");
  rental.className = "mini-button gold";
  rental.textContent = "Mietwohnung";
  rental.onclick = openTenantRentalMarket;
  const actions = document.createElement("div");
  actions.className = "emergency-shelter-actions";
  actions.append(exit, rental);
  els.dialog.append(notice, actions);
  if (!els.dialog.open) els.dialog.showModal();
  save();
}

function openHomePropertyDialog() {
  const residential = ownedResidentialProperties();
  const homeProperty = currentAccessibleHomeProperty();
  if (homeProperty) {
    state.activeHomePropertyId = homeProperty.id;
    state.homeDashboardActive = true;
    switchMainTab("overview");
    updateHomeDashboardVisibility();
    enterProperty(homeProperty.id);
    return;
  }
  openEmergencyShelterDialog(residential.length > 0);
}

function propertyRoomName(index, property = null) {
  const target = property || null;
  const definition = target ? propertyRoomDefinition(target, index) : { name: `Raum ${index + 1}`, fixed: false };
  if (!target || definition.fixed) return definition.name;
  const room = state?.propertyRooms?.[target.id]?.[index];
  return String(room?.customName || definition.name).trim() || definition.name;
}

function openPropertyDescriptionEditor(propertyId) {
  const property = findProperty(propertyId);
  if (!property) return;
  state.propertyMeta ||= {};
  state.propertyMeta[propertyId] ||= {};
  clearDialogDynamic();
  els.dialogTitle.textContent = "Wohnung beschreiben";
  els.dialogText.textContent = "Dieser Text erscheint beim Betreten der Wohnung. Räume kannst du separat benennen und beschreiben.";
  const editor = document.createElement("div");
  editor.className = "property-editor-card";
  editor.innerHTML = `<label>Beschreibung<textarea data-property-description maxlength="280" placeholder="Zum Beispiel: Modern eingerichtet, ruhige Lage und viel Platz.">${escapeHtml(state.propertyMeta[propertyId].customDescription || "")}</textarea></label><small data-property-description-count></small>`;
  const saveButton = document.createElement("button");
  saveButton.className = "primary-button";
  saveButton.textContent = "Beschreibung speichern";
  saveButton.onclick = () => {
    const value = editor.querySelector("[data-property-description]").value.trim();
    state.propertyMeta[propertyId].customDescription = value;
    addFeed(`${property.name}: Wohnungsbeschreibung gespeichert.`);
    save();
    enterProperty(propertyId);
  };
  setDialogBack(() => enterProperty(propertyId), "Wohnung");
  els.dialog.append(editor, saveButton);
  const textarea = editor.querySelector("textarea");
  const count = editor.querySelector("[data-property-description-count]");
  const update = () => { count.textContent = `${textarea.value.length}/280 Zeichen`; };
  textarea.addEventListener("input", update);
  update();
}

function openPropertyRoomEditor(propertyId, roomIndex) {
  const property = findProperty(propertyId);
  if (!property) return;
  const definition = propertyRoomDefinition(property, roomIndex);
  if (definition.fixed) return addFeed(`${definition.name} ist ein fester Nebenraum und kann nicht umbenannt oder beschrieben werden.`);
  const room = propertyRooms(propertyId, propertyRoomLayout(property).length)[roomIndex];
  clearDialogDynamic();
  els.dialogTitle.textContent = "Wohnraum bearbeiten";
  els.dialogText.textContent = "Passe Name und Beschreibung dieses Wohnraums an.";
  const editor = document.createElement("div");
  editor.className = "property-editor-card";
  editor.innerHTML = `
    <label>Raumname<input data-room-custom-name maxlength="42" value="${escapeHtml(room.customName || definition.name)}"></label>
    <label>Beschreibung<textarea data-room-description maxlength="220" placeholder="Wie nutzt du diesen Raum?">${escapeHtml(room.description || "")}</textarea></label>
  `;
  const saveButton = document.createElement("button");
  saveButton.className = "primary-button";
  saveButton.textContent = "Raum speichern";
  saveButton.onclick = () => {
    room.customName = editor.querySelector("[data-room-custom-name]").value.trim().slice(0, 42) || definition.name;
    room.description = editor.querySelector("[data-room-description]").value.trim().slice(0, 220);
    addFeed(`${room.customName} wurde angepasst.`);
    save();
    openPropertyRoom(propertyId, roomIndex);
  };
  setDialogBack(() => openPropertyRoom(propertyId, roomIndex), "Raum");
  els.dialog.append(editor, saveButton);
}

function tenantRentalTierMeta(tier) {
  return {
    small: { name: "Kleine Wohnungen", text: "20 Angebote · 1 bis 2 Wohnräume · 100 bis 211 Euro pro Tag", icon: "🏠" },
    medium: { name: "Mittlere Wohnungen", text: "30 Angebote · 3 bis 5 Wohnräume · 409 bis 998 Euro pro Tag", icon: "🏢" },
    large: { name: "Große Wohnungen", text: "25 Angebote · 6 bis 10 Wohnräume · 2.015 bis 3.995 Euro pro Tag", icon: "🏙" }
  }[tier];
}

function openTenantRentalMarket() {
  clearDialogDynamic();
  els.dialogTitle.textContent = "Mietwohnungen";
  els.dialogText.textContent = `Mietwohnungen sind auch vor Level 2 verfügbar. Die Tagesmiete wird bei jedem Schlafen bezahlt. Aktueller Ort: ${state.homeCity}.`;
  const list = document.createElement("div");
  list.className = "rental-tier-grid";
  list.innerHTML = ["small", "medium", "large"].map((tier) => {
    const meta = tenantRentalTierMeta(tier);
    const offers = tenantRentalOffers.filter((offer) => offer.tier === tier);
    const min = Math.min(...offers.map((offer) => offer.dailyRent));
    const max = Math.max(...offers.map((offer) => offer.dailyRent));
    return `<button data-rental-tier="${tier}"><b>${meta.icon}</b><strong>${meta.name}</strong><span>${meta.text}</span><small>${euro.format(min)} bis ${euro.format(max)}/Tag</small></button>`;
  }).join("");
  setDialogBack(() => openEmergencyShelterDialog(ownedResidentialProperties().length > 0), "Notunterkunft");
  els.dialog.append(list);
  list.querySelectorAll("[data-rental-tier]").forEach((button) => button.addEventListener("click", () => openTenantRentalCategory(button.dataset.rentalTier)));
  if (!els.dialog.open) els.dialog.showModal();
}

function openTenantRentalCategory(tier) {
  const meta = tenantRentalTierMeta(tier);
  const offers = tenantRentalOffers.filter((offer) => offer.tier === tier);
  clearDialogDynamic();
  els.dialogTitle.textContent = meta?.name || "Mietwohnungen";
  els.dialogText.textContent = `${offers.length} Angebote in ${state.homeCity}. Küche, Bad und Keller/Box zählen nicht zu den angegebenen Wohnräumen.`;
  const list = document.createElement("div");
  list.className = "market-list tenant-rental-list";
  list.innerHTML = offers.map((offer) => `
    <article class="item-card tenant-rental-card">
      <div class="tenant-rental-copy"><small>${escapeHtml(offer.district)} · ca. ${offer.sqm} m²</small><h3>${escapeHtml(offer.name)}</h3><p>${offer.rooms} Wohnraum${offer.rooms === 1 ? "" : "e"} + Küche, Bad und ${escapeHtml(offer.storageType)} · ${offer.floors} Etage(n).</p><strong>${euro.format(offer.dailyRent)}/Tag</strong></div>
      <button class="mini-button gold" data-tenant-offer="${offer.id}">Ansehen</button>
    </article>
  `).join("");
  setDialogBack(openTenantRentalMarket, "Mietwohnungen");
  els.dialog.append(list);
  list.querySelectorAll("[data-tenant-offer]").forEach((button) => button.addEventListener("click", () => openTenantRentalOffer(button.dataset.tenantOffer)));
}

function openTenantRentalOffer(offerId) {
  const offer = tenantRentalOfferById(offerId);
  if (!offer) return;
  const preview = { ...offer, city: state.homeCity, isTenantRental: true };
  clearDialogDynamic();
  els.dialogTitle.textContent = offer.name;
  els.dialogText.textContent = `${state.homeCity} · ${offer.district} · ${offer.sqm} m² · ${offer.rooms} Wohnräume plus Küche, Bad und ${offer.storageType}.`;
  const detail = document.createElement("div");
  detail.className = "tenant-rental-detail";
  detail.innerHTML = `${propertyVisualHtml(preview, propertyProfile(preview))}<div class="tenant-rental-price"><span>Tagesmiete</span><b>${euro.format(offer.dailyRent)}</b><small>Erste Tagesmiete sofort, danach bei jedem Schlafen.</small></div>`;
  const rent = document.createElement("button");
  rent.className = "primary-button";
  rent.textContent = state.tenantLease ? `Mietwohnung wechseln · ${euro.format(offer.dailyRent)}` : `Jetzt mieten · ${euro.format(offer.dailyRent)}`;
  rent.onclick = () => startTenantLease(offer.id);
  setDialogBack(() => openTenantRentalCategory(offer.tier), "Angebote");
  els.dialog.append(detail, rent);
}

function startTenantLease(offerId) {
  const offer = tenantRentalOfferById(offerId);
  if (!offer) return;
  if (!canAfford(offer.dailyRent)) return addFeed(`Für die erste Tagesmiete brauchst du ${euro.format(offer.dailyRent)}.`);
  if (state.tenantLease && !confirm(`Deinen bisherigen Mietvertrag beenden und ${offer.name} mieten?`)) return;
  debitPlayer(offer.dailyRent, "auto");
  allocateOutgoingPayment(offer.dailyRent, "treasury", 0.19);
  const property = {
    id: offer.id,
    name: offer.name,
    city: state.homeCity,
    district: offer.district,
    eur: Math.round(offer.dailyRent * 365 * 8),
    rooms: offer.rooms,
    sqm: offer.sqm,
    floors: offer.floors,
    storageType: offer.storageType,
    isTenantRental: true,
    rentalTier: offer.tier
  };
  state.tenantLease = {
    active: true,
    offerId: offer.id,
    dailyRent: offer.dailyRent,
    startedDay: state.day || 1,
    lastPaidDay: state.day || 1,
    paidDays: 1,
    totalPaid: offer.dailyRent,
    property
  };
  state.activeHomePropertyId = property.id;
  state.location = "home";
  state.worldLocation = state.homeCity;
  state.homeDashboardActive = true;
  propertyRooms(property.id, propertyRoomLayout(property).length);
  addFeed(`${offer.name} gemietet. Erste Tagesmiete: ${euro.format(offer.dailyRent)}.`, { purchase: { name: `${offer.name} · Tagesmiete`, total: offer.dailyRent, method: "auto", icon: "🏠" } });
  save();
  render();
  enterProperty(property.id);
}

function settleTenantRentAfterSleep() {
  const lease = state?.tenantLease;
  if (!lease || lease.active === false) return;
  if (Number(lease.lastPaidDay || 0) >= Number(state.day || 1)) return;
  const rent = Math.max(0, Math.round(Number(lease.dailyRent || 0)));
  if (rent <= 0) return;
  if (canAfford(rent)) {
    debitPlayer(rent, "auto");
    allocateOutgoingPayment(rent, "treasury", 0.19);
    lease.lastPaidDay = state.day || 1;
    lease.paidDays = Math.max(1, Number(lease.paidDays || 0)) + 1;
    lease.totalPaid = Math.max(0, Number(lease.totalPaid || 0)) + rent;
    addFeed(`${lease.property?.name || "Mietwohnung"}: ${euro.format(rent)} Tagesmiete bezahlt.`, { purchase: { name: "Tagesmiete bezahlt", total: rent, method: "auto", icon: "🏠" } });
    return;
  }
  const name = lease.property?.name || "Mietwohnung";
  state.tenantLease = null;
  state.activeHomePropertyId = "";
  state.homeDashboardActive = isEmergencyShelterAvailable();
  addFeed(`${name}: Mietvertrag beendet, weil die Tagesmiete von ${euro.format(rent)} nicht bezahlt werden konnte.`);
}

function openTenantLeaseManagement() {
  const lease = state?.tenantLease;
  const property = activeTenantRentalProperty();
  if (!lease || !property) return openTenantRentalMarket();
  clearDialogDynamic();
  els.dialogTitle.textContent = "Mietvertrag bearbeiten";
  els.dialogText.textContent = `${property.name} in ${property.city} · ${property.district}.`;
  const list = document.createElement("div");
  list.className = "market-list rental-management-list";
  list.innerHTML = `
    <article class="item-card"><div><h3>Aktiver Mietvertrag</h3><p>${euro.format(lease.dailyRent)}/Tag · ${lease.paidDays || 1} bezahlte Tage · Insgesamt ${euro.format(lease.totalPaid || lease.dailyRent)}.</p></div><button disabled>Aktiv</button></article>
    <article class="item-card"><div><h3>Wohnung</h3><p>${property.rooms} Wohnräume plus Küche, Bad und ${property.storageType}. Räume und Wohnungstext können angepasst werden.</p></div><button data-tenant-enter>Betreten</button></article>
  `;
  const market = document.createElement("button");
  market.className = "mini-button gold";
  market.textContent = "Andere Mietwohnung suchen";
  market.onclick = openTenantRentalMarket;
  const stop = document.createElement("button");
  stop.className = "mini-button danger";
  stop.textContent = "Mietvertrag beenden";
  stop.onclick = () => {
    if (!confirm("Mietvertrag wirklich beenden? Bereits bezahlte Tagesmieten werden nicht erstattet.")) return;
    const name = property.name;
    state.tenantLease = null;
    state.activeHomePropertyId = "";
    state.homeDashboardActive = isEmergencyShelterAvailable();
    addFeed(`${name}: Mietvertrag beendet.`);
    save();
    render();
    openEmergencyShelterDialog(ownedResidentialProperties().length > 0);
  };
  setDialogBack(() => enterProperty(property.id), "Wohnung");
  els.dialog.append(list, market, stop);
  list.querySelector("[data-tenant-enter]")?.addEventListener("click", () => enterProperty(property.id));
}

