function refreshCasinoPanelStable(options = {}) {
  const area = state?.casinoArea || "";
  const fallback = options.fallback !== false;
  if (!area || !isCasinoTabActive() || state?.casinoWalk) {
    if (fallback) render();
    return false;
  }
  const panel = els.casinoList?.querySelector(".casino-world-panel");
  const scroller = panel?.querySelector(".casino-world-panel-scroll");
  if (!panel || !scroller) {
    if (fallback) render();
    return false;
  }

  const scrollTop = scroller.scrollTop;
  scroller.classList.add("casino-stable-refresh");
  scroller.innerHTML = casinoLocationPanelBodyHtml(area);
  bindCasinoPanelEvents(scroller);
  if (els.casinoWalletValue) els.casinoWalletValue.textContent = formatWalletCents(walletCents());
  const title = panel.querySelector(".casino-world-panel-head h3");
  if (title) title.textContent = casinoLocationTitle(area);
  updateCasinoPassiveUi();

  const restore = () => {
    scroller.scrollTop = Math.min(scrollTop, Math.max(0, scroller.scrollHeight - scroller.clientHeight));
    scroller.classList.remove("casino-stable-refresh");
  };
  restore();
  requestAnimationFrame(restore);
  return true;
}

