function casinoWithdraw(amountCents = walletCents()) {
  const amount = Math.min(walletCents(), Math.max(0, Math.round(amountCents)));
  if (amount <= 0) return addFeed("Dein Casino-Wallet ist leer.");
  state.casinoAccount = Math.max(0, (state.casinoAccount || 0) - amount / 100);
  state.casinoDailyProfit = (state.casinoDailyProfit || 0) - amount / 100;
  state.bank += Math.floor(amount / 100);
  state.cash += (amount % 100) / 100;
  recordIncome("casino", amount / 100);
  addWallet(-amount);
  addFeed(`${formatCents(amount)} aus dem Casino-Wallet ausgezahlt.`, { purchase: { kind: "withdraw", name: "Casino-Auszahlung", total: amount / 100, method: "Auf Bankkonto", icon: "💸" } });
  save();
  refreshCasinoPanelStable();
}

