function bindCasinoEvents() {
  const mapStage = els.casinoList.querySelector("[data-casino-map-stage]");
  mapStage?.addEventListener("click", (event) => {
    if (event.target.closest("[data-casino-area]")) return;
    const rect = mapStage.getBoundingClientRect();
    if (!rect.width || !rect.height) return;
    const position = {
      x: ((event.clientX - rect.left) / rect.width) * 100,
      y: ((event.clientY - rect.top) / rect.height) * 100
    };
    walkToCasinoRoad(position);
  });

  els.casinoList.querySelectorAll("[data-casino-area]").forEach((button) => button.addEventListener("click", (event) => {
    event.stopPropagation();
    walkToCasinoArea(button.dataset.casinoArea);
  }));

  bindCasinoPanelEvents(els.casinoList);
}

