function makeDeck(deckCount = 1) {
  const deck = [];
  for (let i = 0; i < deckCount; i++) {
    cardSuits.forEach((suit) => cardRanks.forEach((rank) => deck.push({ rank, suit })));
  }
  for (let i = deck.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [deck[i], deck[j]] = [deck[j], deck[i]];
  }
  return deck;
}

function cardValue(card) {
  if (card.rank === "A") return 11;
  if (["J", "Q", "K"].includes(card.rank)) return 10;
  return Number(card.rank);
}

function handValue(hand) {
  let value = hand.reduce((sum, card) => sum + cardValue(card), 0);
  let aces = hand.filter((card) => card.rank === "A").length;
  while (value > 21 && aces > 0) {
    value -= 10;
    aces -= 1;
  }
  return value;
}

function cardHtml(card, hidden = false) {
  if (hidden) return `<span class="play-card hidden-card">?</span>`;
  const red = card.suit === "♥" || card.suit === "♦";
  return `<span class="play-card ${red ? "red" : ""}"><b>${card.rank}</b><small>${card.suit}</small></span>`;
}

function highLowView() {
  const game = state.highlow || createHighLowState();
  const active = game.stage === "guess" || game.stage === "won";
  const maxBet = highLowMaxBetCents();
  const dailyLimit = highLowDailyLimitCents();
  const dailyLeft = Math.max(0, dailyLimit - (state.highlowDailyCents || 0));
  const canStart = game.betCents > 0 && !active && game.betCents <= dailyLeft;
  const canAdd = !active && game.betCents < maxBet && game.betCents < dailyLeft;
  const canCollect = active && Number(game.wins || 0) > 0 && game.riskCents > 0;
  const visibleAmount = game.betCents || game.riskCents || 0;
  const currentCard = game.playCard || game.currentCard;
  const nextRound = Math.min(3, Number(game.roundsPlayed || 0) + 1);
  return `
    <section class="casino-table casino-pro-game highlow-table">
      <div class="casino-game-banner highlow"><span>🃏</span><div><small>3-RUNDEN-RISIKO</small><h3>High or Lower</h3><p>Treffe dreimal oder sichere deinen Gewinn nach dem ersten richtigen Tipp.</p></div></div>
      <div class="casino-round-track">${[1,2,3].map((round) => `<i class="${round <= Number(game.wins || 0) ? "done" : round === nextRound && active ? "active" : ""}">${round}</i>`).join("")}</div>
      <div class="casino-kpi-row"><span><small>Fester Einsatz</small><b>${formatCents(game.betCents)}</b></span><span><small>Aktueller Gewinn</small><b>${formatCents(game.riskCents)}</b></span><span><small>Heute frei</small><b>${formatCents(dailyLeft)}</b></span></div>
      <div class="highlow-layout pro">
        <div class="highlow-card-zone pro"><div><small>AKTUELLE KARTE</small>${currentCard ? highLowCardHtml(currentCard) : `<span class="play-card hidden-card">?</span>`}</div><span class="highlow-versus">VS</span><div><small>${game.nextCard ? "GEZOGEN" : "NÄCHSTE KARTE"}</small>${game.nextCard ? highLowCardHtml(game.nextCard) : `<span class="play-card hidden-card">?</span>`}</div></div>
        <div class="highlow-stack pro"><div class="highlow-stack-head"><strong>Chip-Stapel</strong><span>${formatCents(visibleAmount)}</span></div>${highLowChipStack(visibleAmount)}</div>
      </div>
      ${highLowDrawnCards(game.history || [])}
      <p class="casino-result">${game.message || "Setze Chips und starte die Runde."}</p>
      <div class="casino-actions">
        <button class="mini-button gold" data-highlow-add ${canAdd ? "" : "disabled"}>+ Aktiven Chip setzen</button>
        <button class="primary-button" data-highlow-start ${canStart ? "" : "disabled"}>Runde starten</button>
      </div>
      ${active ? `<div class="casino-choice-grid"><button data-highlow-choice="high"><span>⬆</span><b>Higher</b></button><button data-highlow-choice="equal"><span>=</span><b>Gleich</b></button><button data-highlow-choice="low"><span>⬇</span><b>Lower</b></button></div><button class="primary-button casino-collect" data-highlow-collect ${canCollect ? "" : "disabled"}>Gewinn nehmen · ${canCollect ? formatCents(game.riskCents) : "erst nach Treffer"}</button>` : ""}
      ${highLowHistory(game.history || [])}
    </section>
  `;
}

function highLowChipStack(amount) {
  const rowCap = Math.max(100000, Math.ceil(highLowMaxBetCents() / 5));
  return `
    <div class="highlow-chip-stack">
      ${Array.from({ length: 5 }, (_, index) => {
        const rowValue = Math.max(0, Math.min(rowCap, amount - index * rowCap));
        const chipCount = Math.ceil((rowValue / rowCap) * 10);
        return `
          <div class="highlow-stack-row ${rowValue >= rowCap ? "full" : ""}">
            <span>${formatCents((index + 1) * rowCap)}</span>
            <div>${Array.from({ length: 10 }, (_, chipIndex) => `<i class="${chipIndex < chipCount ? "filled" : ""}"></i>`).join("")}</div>
          </div>
        `;
      }).join("")}
    </div>
  `;
}

function highLowHistory(history) {
  if (!history.length) return "";
  return `
    <div class="highlow-history">
      ${history.slice(0, 8).map((entry) => `
        <span class="${entry.win ? "win" : "loss"}">
          ${entry.choice === "high" ? "H" : entry.choice === "low" ? "L" : "="} · ${entry.from.rank}${entry.from.suit} → ${entry.to.rank}${entry.to.suit}
        </span>
      `).join("")}
    </div>
  `;
}

function highLowDrawnCards(history) {
  if (!history.length) return "";
  return `
    <div class="highlow-drawn">
      <small>Gezogene Karten</small>
      <div class="card-row">${history.slice(0, 10).map((entry) => highLowCardHtml(entry.to)).join("")}</div>
    </div>
  `;
}

function highLowCardHtml(card) {
  const red = card.color === "red";
  return `<span class="play-card highlow-card ${red ? "red" : ""}"><b>${card.rank}</b><small>${card.suit}</small></span>`;
}

function highLowMaxBetCents() {
  return casinoLevelConfig().highLowMax;
}

function highLowDailyLimitCents() {
  return casinoLevelConfig().highLowDaily;
}

function drawHighLowCard() {
  const rankIndex = Math.floor(Math.random() * cardRanks.length);
  const suit = cardSuits[Math.floor(Math.random() * cardSuits.length)];
  return {
    rank: cardRanks[rankIndex],
    suit,
    value: rankIndex + 1,
    color: suit === "♥" || suit === "♦" ? "red" : "black"
  };
}

function addHighLowChip() {
  const game = state.highlow ||= createHighLowState();
  if (game.stage === "guess" || game.stage === "won") return casinoMessage("High or Lower läuft bereits. Nimm den Gewinn oder spiele weiter.");
  const chips = casinoLevelConfig().highLowChips;
  const chip = chips.includes(state.casinoChipCents) ? state.casinoChipCents : chips[0];
  const maxBet = highLowMaxBetCents();
  if (game.betCents + chip > maxBet) return casinoMessage(`Maximaler High-or-Lower-Einsatz pro Runde ist ${formatCents(maxBet)}.`);
  const dailyLeft = Math.max(0, highLowDailyLimitCents() - (state.highlowDailyCents || 0));
  if (game.betCents + chip > dailyLeft) return casinoMessage(`Mit diesem Chip würdest du dein Tageslimit überschreiten. Heute sind noch ${formatCents(dailyLeft)} frei.`);
  if (!takeWallet(chip)) return casinoMessage("Nicht genug Casino-Guthaben für diesen Chip.");
  game.betCents += chip;
  game.message = `${formatCents(chip)} fest gesetzt. Gesamteinsatz: ${formatCents(game.betCents)}. Eine Rücknahme ist nicht möglich.`;
  state.casinoMessage = "";
  playCasinoSound("chip");
  save();
  refreshCasinoPanelStable();
}

function clearHighLowBet() {
  const game = state.highlow ||= createHighLowState();
  if (game.betCents > 0 || game.riskCents > 0) return casinoMessage("Gesetzte High-or-Lower-Chips sind fest und können nicht zurückgenommen werden.");
}

function startHighLow() {
  const game = state.highlow ||= createHighLowState();
  if (game.betCents <= 0) return casinoMessage("Setze erst Chips auf den High-or-Lower-Tisch.");
  const dailyLeft = Math.max(0, highLowDailyLimitCents() - (state.highlowDailyCents || 0));
  if (game.betCents > highLowMaxBetCents()) return casinoMessage(`Pro Runde sind maximal ${formatCents(highLowMaxBetCents())} erlaubt.`);
  if (game.betCents > dailyLeft) return casinoMessage(`Tageslimit erreicht. Du kannst heute nur noch ${formatCents(dailyLeft)} setzen. Nach dem Schlafen ist es wieder frei.`);
  state.highlowDailyCents = (state.highlowDailyCents || 0) + game.betCents;
  game.riskCents = game.betCents;
  game.betCents = 0;
  game.currentCard = drawHighLowCard();
  game.playCard = game.currentCard;
  game.nextCard = null;
  game.stage = "guess";
  game.roundsPlayed = 0;
  game.wins = 0;
  game.message = `Startkarte ${game.currentCard.rank}${game.currentCard.suit}. Spielzug 1 von 3: Higher, Lower oder Gleich?`;
  game.history = [];
  state.casinoMessage = "";
  playCasinoSound("deal");
  save();
  refreshCasinoPanelStable();
}

function guessHighLow(choice) {
  const game = state.highlow ||= createHighLowState();
  if (!game.riskCents || !(game.playCard || game.currentCard)) return;
  const from = game.playCard || game.currentCard;
  const to = drawHighLowCard();
  const win = choice === "high" ? to.value > from.value : choice === "low" ? to.value < from.value : to.value === from.value;
  game.nextCard = to;
  game.history = [{ choice, from, to, win }, ...(game.history || [])];
  if (!win) {
    game.riskCents = 0;
    game.betCents = 0;
    game.currentCard = from;
    game.playCard = null;
    game.stage = "bet";
    game.roundsPlayed = 0;
    game.wins = 0;
    game.message = `${to.rank}${to.suit}: falsch. Einsatz verloren. Setze neue Chips für ein neues 3-Runden-Spiel.`;
    playCasinoSound("lose");
    save();
    refreshCasinoPanelStable();
    return;
  }
  game.roundsPlayed = Math.min(3, Number(game.roundsPlayed || 0) + 1);
  game.wins = Math.min(3, Number(game.wins || 0) + 1);
  game.riskCents = Math.round(game.riskCents * 1.72);
  game.currentCard = from;
  game.playCard = to;
  game.stage = "won";
  triggerWinExplosion(game.riskCents);
  if (game.roundsPlayed >= 3) {
    const payout = game.riskCents;
    payoutFromCasino(payout);
    state.highlow = createHighLowState();
    state.highlow.message = `Drei Treffer geschafft. ${formatCents(payout)} wurden automatisch ins Casino-Wallet ausgezahlt. Setze neue Chips.`;
    addFeed(`High or Lower: Drei Treffer geschafft, ${formatCents(payout)} automatisch ausgezahlt.`, { purchase: { kind: "withdraw", title: "High-or-Lower-Gewinn", name: "3 Treffer · automatische Auszahlung", total: payout / 100, method: "Casino-Wallet", icon: "🃏" } });
    save();
    refreshCasinoPanelStable();
    return;
  }
  game.message = `Richtig: ${to.rank}${to.suit}. Treffer ${game.wins}/3 · Gewinn ${formatCents(game.riskCents)}. Jetzt nehmen oder Spielzug ${game.roundsPlayed + 1} riskieren.`;
  save();
  refreshCasinoPanelStable();
}

function collectHighLow() {
  const game = state.highlow ||= createHighLowState();
  if (!game.riskCents || Number(game.wins || 0) < 1) return casinoMessage("Du kannst den Einsatz erst nach mindestens einem richtigen Treffer nehmen.");
  const payout = game.riskCents;
  const hits = Math.max(1, Number(game.wins || 0));
  payoutFromCasino(payout);
  state.highlow = createHighLowState();
  state.highlow.message = `Gewinn nach ${hits} Treffer${hits === 1 ? "" : "n"} genommen: ${formatCents(payout)}. Setze neue Chips.`;
  addFeed(`High or Lower: ${formatCents(payout)} nach ${hits} Treffer${hits === 1 ? "" : "n"} ausgezahlt.`, { purchase: { kind: "withdraw", title: "High-or-Lower-Gewinn", name: `${hits} Treffer`, total: payout / 100, method: "Casino-Wallet", icon: "🃏" } });
  save();
  refreshCasinoPanelStable();
}

function pokerView() {
  const game = state.poker || createPokerState();
  const playing = game.status === "playing";
  const done = game.status === "done";
  const playerEval = game.player?.length && game.community?.length >= 3 ? evaluatePokerCards([...(game.player || []), ...(game.community || [])]) : null;
  const dealerEval = done && game.dealer?.length ? evaluatePokerCards([...(game.dealer || []), ...(game.community || [])]) : null;
  const community = Array.from({ length: 5 }, (_, index) => game.community?.[index] ? cardHtml(game.community[index]) : `<span class="play-card poker-empty-card">${index < 3 ? "F" : index === 3 ? "T" : "R"}</span>`).join("");
  const opponentCards = (game.dealer || []).map((card) => cardHtml(card, !done)).join("") || `<span class="play-card hidden-card">?</span><span class="play-card hidden-card">?</span>`;
  const actionLabel = game.pendingCallCents > 0 ? `Mitgehen · ${formatCents(game.pendingCallCents)}` : "Check / nächste Straße";
  return `
    <section class="casino-table casino-pro-game poker-table">
      <div class="casino-game-banner poker"><span>♣️</span><div><small>HEADS-UP TEXAS HOLD’EM</small><h3>Poker</h3><p>Zwei Handkarten, fünf Gemeinschaftskarten und echte Poker-Kombinationen.</p></div></div>
      <div class="casino-kpi-row"><span><small>Pot</small><b>${formatCents(game.potCents || 0)}</b></span><span><small>Street</small><b>${pokerStreetLabel(game.street)}</b></span><span><small>Grund-Einsatz</small><b>${formatCents(game.baseBetCents || state.casinoChipCents)}</b></span></div>
      <div class="poker-felt">
        <div class="poker-seat dealer"><div><small>CASINO-BANK</small><b>${done && dealerEval ? dealerEval.label : game.dealerAction || "bereit"}</b></div><div class="card-row">${opponentCards}</div></div>
        <div class="poker-community"><small>BOARD</small><div class="card-row">${community}</div></div>
        <div class="poker-pot"><span>CHIPS</span><b>${formatCents(game.potCents || 0)}</b></div>
        <div class="poker-seat player"><div><small>DEINE HAND</small><b>${playerEval ? playerEval.label : "noch offen"}</b></div><div class="card-row">${(game.player || []).map((card) => cardHtml(card)).join("") || `<span class="play-card hidden-card">?</span><span class="play-card hidden-card">?</span>`}</div></div>
      </div>
      <p class="casino-result">${game.message}</p>
      ${!playing ? `<button class="primary-button" data-poker-start>${done ? "Neue Poker-Hand" : "Poker-Hand starten"} · ${formatCents(state.casinoChipCents)}</button>` : `<div class="casino-actions poker-actions"><button class="primary-button" data-poker-check>${actionLabel}</button><button class="mini-button gold" data-poker-raise ${game.pendingCallCents > 0 || walletCents() < state.casinoChipCents ? "disabled" : ""}>Erhöhen +${formatCents(state.casinoChipCents)}</button><button class="mini-button danger" data-poker-fold>Aussteigen</button></div>`}
      ${game.history?.length ? `<div class="poker-history">${game.history.slice(0,5).map((entry) => `<span class="${entry.result}"><b>${entry.result === "win" ? "Sieg" : entry.result === "tie" ? "Split" : "Niederlage"}</b><small>${escapeHtml(entry.hand || "")}</small></span>`).join("")}</div>` : ""}
    </section>
  `;
}

function pokerStreetLabel(street) {
  return { idle: "Start", preflop: "Pre-Flop", flop: "Flop", turn: "Turn", river: "River", showdown: "Showdown" }[street] || "Start";
}

function startPoker() {
  const bet = state.casinoChipCents;
  if (!takeWallet(bet)) return casinoMessage("Nicht genug Casino-Guthaben für diese Poker-Hand.");
  const deck = makeDeck(1);
  state.poker = {
    ...createPokerState(),
    status: "playing",
    street: "preflop",
    deck,
    player: [deck.pop(), deck.pop()],
    dealer: [deck.pop(), deck.pop()],
    community: [],
    potCents: bet * 2,
    baseBetCents: bet,
    playerContribution: bet,
    dealerContribution: bet,
    message: "Pre-Flop: Checke, erhöhe oder steige aus.",
    history: state.poker?.history || []
  };
  playCasinoSound("spin");
  save();
  refreshCasinoPanelStable();
}

function pokerCheckCall() {
  const game = state.poker;
  if (!game || game.status !== "playing") return;
  if (game.pendingCallCents > 0) {
    const call = game.pendingCallCents;
    if (!takeWallet(call)) return casinoMessage(`Zum Mitgehen fehlen ${formatCents(call)}.`);
    game.playerContribution += call;
    game.potCents += call;
    game.pendingCallCents = 0;
    game.message = `Du gehst ${formatCents(call)} mit.`;
  } else {
    game.message = "Du checkst.";
  }
  pokerAdvanceStreet();
}

function pokerRaise() {
  const game = state.poker;
  if (!game || game.status !== "playing" || game.pendingCallCents > 0) return;
  const raise = state.casinoChipCents;
  if (!takeWallet(raise)) return casinoMessage("Nicht genug Casino-Guthaben zum Erhöhen.");
  game.playerContribution += raise;
  game.potCents += raise;
  const strength = pokerAiStrength(game);
  const foldChance = Math.max(.05, .38 - strength * .3);
  if (Math.random() < foldChance) {
    game.dealerAction = "Bank steigt aus";
    pokerFinish("win", `Die Casino-Bank steigt nach deiner Erhöhung aus. Pot ${formatCents(game.potCents)}.`);
    return;
  }
  game.dealerContribution += raise;
  game.potCents += raise;
  game.dealerAction = `Bank geht ${formatCents(raise)} mit`;
  game.message = `Erhöhung auf ${formatCents(raise)} – die Bank geht mit.`;
  pokerAdvanceStreet();
}

function pokerFold() {
  const game = state.poker;
  if (!game || game.status !== "playing") return;
  game.dealerAction = "Bank gewinnt";
  pokerFinish("loss", `Du steigst aus. Dein Einsatz von ${formatCents(game.playerContribution)} bleibt im Pot.`);
}

function pokerAdvanceStreet() {
  const game = state.poker;
  if (!game || game.status !== "playing") return;
  if (game.street === "preflop") {
    game.community.push(game.deck.pop(), game.deck.pop(), game.deck.pop());
    game.street = "flop";
  } else if (game.street === "flop") {
    game.community.push(game.deck.pop());
    game.street = "turn";
  } else if (game.street === "turn") {
    game.community.push(game.deck.pop());
    game.street = "river";
  } else {
    pokerShowdown();
    return;
  }
  game.dealerAction = "Bank checkt";
  const strength = pokerAiStrength(game);
  const raiseChance = .1 + strength * .32;
  if (Math.random() < raiseChance && walletCents() >= game.baseBetCents) {
    const raise = game.baseBetCents;
    game.dealerContribution += raise;
    game.potCents += raise;
    game.pendingCallCents = raise;
    game.dealerAction = `Bank erhöht ${formatCents(raise)}`;
    game.message = `${pokerStreetLabel(game.street)}: Die Casino-Bank erhöht. Mitgehen oder aussteigen?`;
  } else {
    game.message = `${pokerStreetLabel(game.street)} liegt. Du bist dran.`;
  }
  save();
  refreshCasinoPanelStable();
}

function pokerShowdown() {
  const game = state.poker;
  game.street = "showdown";
  const player = evaluatePokerCards([...game.player, ...game.community]);
  const dealer = evaluatePokerCards([...game.dealer, ...game.community]);
  const comparison = comparePokerScores(player.score, dealer.score);
  if (comparison > 0) pokerFinish("win", `Showdown: ${player.label} schlägt ${dealer.label}.`);
  else if (comparison === 0) pokerFinish("tie", `Split Pot: Beide halten ${player.label}.`);
  else pokerFinish("loss", `Showdown verloren: ${dealer.label} schlägt ${player.label}.`);
}

function pokerFinish(result, message) {
  const game = state.poker;
  if (!game) return;
  let payout = 0;
  if (result === "win") payout = game.potCents;
  else if (result === "tie") payout = game.playerContribution;
  if (payout > 0) {
    payoutFromCasino(payout);
    if (result === "win") triggerWinExplosion(payout);
  }
  const hand = game.player?.length && game.community?.length >= 3 ? evaluatePokerCards([...game.player, ...game.community]).label : "Ausgestiegen";
  game.status = "done";
  game.street = "showdown";
  game.pendingCallCents = 0;
  game.message = `${message}${payout ? ` Auszahlung ${formatCents(payout)}.` : ""}`;
  game.lastResult = result;
  game.history ||= [];
  game.history.unshift({ result, hand, pot: game.potCents, at: Date.now() });
  game.history = game.history.slice(0, 10);
  playCasinoSound(result === "win" ? "win" : result === "tie" ? "click" : "lose");
  save();
  refreshCasinoPanelStable();
}

function pokerAiStrength(game) {
  const cards = [...(game.dealer || []), ...(game.community || [])];
  if (cards.length >= 5) return Math.min(1, evaluatePokerCards(cards).score[0] / 8 + .08);
  const values = (game.dealer || []).map((card) => pokerRankValue(card.rank)).sort((a,b) => b-a);
  let strength = ((values[0] || 2) + (values[1] || 2)) / 28;
  if (values[0] === values[1]) strength += .25;
  if (game.dealer?.[0]?.suit === game.dealer?.[1]?.suit) strength += .08;
  return Math.max(0, Math.min(1, strength));
}

function pokerRankValue(rank) {
  return ({ A:14, K:13, Q:12, J:11 }[rank] || Number(rank) || 0);
}

function evaluatePokerCards(cards) {
  const clean = (cards || []).filter(Boolean);
  if (clean.length < 5) return { label: "Noch keine fertige Hand", score: [-1] };
  let best = null;
  for (let a=0; a<clean.length-4; a++) for (let b=a+1; b<clean.length-3; b++) for (let c=b+1; c<clean.length-2; c++) for (let d=c+1; d<clean.length-1; d++) for (let e=d+1; e<clean.length; e++) {
    const current = evaluatePokerFive([clean[a],clean[b],clean[c],clean[d],clean[e]]);
    if (!best || comparePokerScores(current.score, best.score) > 0) best = current;
  }
  return best;
}

function evaluatePokerFive(cards) {
  const values = cards.map((card) => pokerRankValue(card.rank)).sort((a,b) => b-a);
  const groups = [...values.reduce((map,value) => map.set(value,(map.get(value)||0)+1),new Map()).entries()].sort((a,b) => b[1]-a[1] || b[0]-a[0]);
  const flush = cards.every((card) => card.suit === cards[0].suit);
  const unique = [...new Set(values)];
  if (unique[0] === 14) unique.push(1);
  let straightHigh = 0;
  for (let i=0; i<=unique.length-5; i++) if (unique[i]-unique[i+4] === 4) { straightHigh=unique[i]; break; }
  if (flush && straightHigh) return { label: straightHigh === 14 ? "Royal Flush" : "Straight Flush", score:[8,straightHigh] };
  if (groups[0][1] === 4) return { label:"Vierling", score:[7,groups[0][0],groups[1][0]] };
  if (groups[0][1] === 3 && groups[1]?.[1] === 2) return { label:"Full House", score:[6,groups[0][0],groups[1][0]] };
  if (flush) return { label:"Flush", score:[5,...values] };
  if (straightHigh) return { label:"Straight", score:[4,straightHigh] };
  if (groups[0][1] === 3) return { label:"Drilling", score:[3,groups[0][0],...groups.filter(g=>g[1]===1).map(g=>g[0]).sort((a,b)=>b-a)] };
  const pairs = groups.filter(g=>g[1]===2).map(g=>g[0]).sort((a,b)=>b-a);
  if (pairs.length >= 2) return { label:"Zwei Paare", score:[2,pairs[0],pairs[1],groups.find(g=>g[1]===1)?.[0]||0] };
  if (pairs.length === 1) return { label:"Ein Paar", score:[1,pairs[0],...groups.filter(g=>g[1]===1).map(g=>g[0]).sort((a,b)=>b-a)] };
  return { label:`High Card ${pokerRankLabel(values[0])}`, score:[0,...values] };
}

function comparePokerScores(a = [], b = []) {
  for (let i=0; i<Math.max(a.length,b.length); i++) {
    const diff=(a[i]||0)-(b[i]||0);
    if (diff) return diff;
  }
  return 0;
}

function pokerRankLabel(value) {
  return ({14:"Ass",13:"König",12:"Dame",11:"Bube"}[value] || String(value));
}

function blackjackView() {
  const game = state.blackjack;
  const stakeLocked = game?.status === "playing";
  const deckCount = stakeLocked ? game.deckCount : (state.blackjackDecks || 1);
  const deckButtons = `<details class="blackjack-deck-dropdown" ${stakeLocked ? "data-locked" : ""}><summary><span><small>Deckanzahl</small><b>${deckCount} Deck${deckCount > 1 ? "s" : ""}</b></span><em>${stakeLocked ? "🔒 Fest" : "▾ Ändern"}</em></summary><div>${[1, 2, 3, 4].map((count) => `<button class="casino-deck-option ${deckCount === count ? "active" : ""}" data-bj-decks="${count}" ${stakeLocked ? "disabled" : ""}><b>${count}</b><small>Deck${count > 1 ? "s" : ""}</small><em>Einsatz ${formatCents(state.casinoChipCents * count)}</em></button>`).join("")}</div></details>`;
  if (!game) return `
    <section class="casino-table casino-pro-game blackjack-table">
      <div class="casino-game-banner blackjack"><span>♠️</span><div><small>CASINO CLASSIC</small><h3>Blackjack</h3><p>Komme so nah wie möglich an 21, ohne sie zu überschreiten.</p></div></div>
      <div class="blackjack-rules"><span>Blackjack zahlt 3:2</span><span>Bank zieht bis 17</span><span>Doppeln möglich</span><span>Aufgeben: 50 % zurück</span></div>
      ${deckButtons}
      <div class="blackjack-felt-preview"><div class="blackjack-deck-rack">${Array.from({length:deckCount},(_,i)=>`<span>DECK ${i+1}</span>`).join("")}</div><div class="blackjack-seat">Einsatz ${formatCents(state.casinoChipCents * deckCount)}</div></div>
      <button class="primary-button" data-blackjack-new>Blackjack-Runde starten</button>
    </section>`;
  const finished = game.status !== "playing";
  const playerValue = handValue(game.player);
  const dealerValue = finished ? handValue(game.dealer) : "?";
  const dealerCards = game.dealer.map((card,index)=>cardHtml(card,!finished&&index===1)).join("");
  const canDouble = !finished && game.player.length === 2 && walletCents() >= game.betCents;
  const canSurrender = !finished && game.player.length === 2;
  return `
    <section class="casino-table casino-pro-game blackjack-table active-hand">
      <div class="casino-game-banner blackjack"><span>♠️</span><div><small>${game.deckCount} DECK${game.deckCount>1?"S":""} · EINSATZ ${formatCents(game.betCents)}</small><h3>Blackjack</h3><p>${finished ? "Runde beendet – starte direkt die nächste Hand." : "Deine Entscheidung: Karte, Stand, Doppeln oder Aufgeben."}</p></div></div>
      ${deckButtons}
      <div class="blackjack-pro-felt">
        <div class="blackjack-score dealer"><small>BANK</small><b>${dealerValue}</b></div><div class="hand-zone dealer-zone"><div class="card-row">${dealerCards}</div></div>
        <div class="blackjack-table-logo">LB<br><small>BLACKJACK</small></div>
        <div class="hand-zone player-hand"><div class="card-row">${game.player.map(card=>cardHtml(card)).join("")}</div></div><div class="blackjack-score player"><small>DU</small><b>${playerValue}</b></div>
      </div>
      <p class="casino-result">${game.message}</p>
      <div class="casino-actions blackjack-actions">${!finished ? `<button class="primary-button" data-blackjack-hit>Karte</button><button class="mini-button" data-blackjack-stand>Stand</button>${canDouble?`<button class="mini-button gold" data-blackjack-double>Doppeln</button>`:""}${canSurrender?`<button class="mini-button danger" data-blackjack-surrender>Aufgeben</button>`:""}`:`<button class="primary-button" data-blackjack-new>Neue Runde</button>`}</div>
    </section>`;
}

function startBlackjack() {
  const deckCount = state.blackjackDecks || 1;
  const bet = state.casinoChipCents * deckCount;
  if (!takeWallet(bet)) return casinoMessage(`Nicht genug Casino-Guthaben. Zahle erst oben mit +${euro.format(casinoDepositAmounts()[0])} ein oder wähle einen kleineren Chip.`);
  state.casinoMessage = "";
  playCasinoSound("spin");
  const deck = makeDeck(deckCount);
  const game = {
    deck,
    deckCount,
    player: [deck.pop(), deck.pop()],
    dealer: [deck.pop(), deck.pop()],
    betCents: bet,
    status: "playing",
    message: "Du bist dran."
  };
  state.blackjack = game;
  if (handValue(game.player) === 21) finishBlackjack();
  save();
  refreshCasinoPanelStable();
}

function blackjackSurrender() {
  const game = state.blackjack;
  if (!game || game.status !== "playing" || game.player.length !== 2) return;
  const refund = Math.floor(game.betCents / 2);
  if (refund > 0) payoutFromCasino(refund);
  game.status = "done";
  game.message = `Aufgegeben. ${formatCents(refund)} wurden zurückgezahlt.`;
  playCasinoSound("lose");
  save();
  refreshCasinoPanelStable();
}

function blackjackDouble() {
  const game = state.blackjack;
  if (!game || game.status !== "playing" || game.player.length !== 2) return;
  if (!takeWallet(game.betCents)) return casinoMessage("Nicht genug Casino-Guthaben zum Doppeln.");
  game.betCents *= 2;
  game.player.push(game.deck.pop());
  game.message = "Einsatz verdoppelt. Eine Karte gezogen, jetzt steht die Hand.";
  blackjackStand();
}

function blackjackHit() {
  const game = state.blackjack;
  if (!game || game.status !== "playing") return;
  game.player.push(game.deck.pop());
  if (handValue(game.player) > 21) finishBlackjack();
  else game.message = "Karte gezogen. Noch eine oder Stand?";
  save();
  refreshCasinoPanelStable();
}

function blackjackStand() {
  const game = state.blackjack;
  if (!game || game.status !== "playing") return;
  while (handValue(game.dealer) < 18) game.dealer.push(game.deck.pop());
  finishBlackjack();
  save();
  refreshCasinoPanelStable();
}

function finishBlackjack() {
  const game = state.blackjack;
  const player = handValue(game.player);
  while (player <= 21 && handValue(game.dealer) < 18) game.dealer.push(game.deck.pop());
  const dealer = handValue(game.dealer);
  let payout = 0;
  if (player > 21) {
    game.message = `Überkauft: ${player}. Einsatz verloren.`;
  } else if (game.player.length === 2 && player === 21) {
    payout = Math.round(game.betCents * 2.5);
    game.message = `Black Jack. Auszahlung ${formatCents(payout)}.`;
  } else if (dealer > 21 || player > dealer) {
    payout = Math.round(game.betCents * 2);
    game.message = `Gewonnen: ${player} gegen ${dealer}.`;
  } else if (player === dealer) {
    payout = game.betCents;
    game.message = `Push: ${player} gegen ${dealer}. Einsatz zurück.`;
  } else {
    game.message = `Verloren: ${player} gegen ${dealer}.`;
  }
  if (payout) {
    payoutFromCasino(payout);
    triggerWinExplosion(payout);
  }
  game.status = "done";
}

