/* ========================================================================== */
/* Tägliche Geschenke & tägliche Quests · Update 2026-07-21                  */
/* ========================================================================== */
(() => {
  if (window.__lifeBuilderDailyAppsInstalled) return;
  window.__lifeBuilderDailyAppsInstalled = true;

  const DAILY_GIFTS_APP_ID = "dailygifts";
  const DAILY_QUESTS_APP_ID = "dailyquests";
  const DAILY_APPS_VERSION = "2026-07-21-daily-apps-modcodes-2";
  const DAILY_METRIC_KEYS = ["moneySpent", "moneyEarned", "itemsUsed", "itemsSold", "casinoStake", "travels", "gameRounds"];
  let dailyRewardGrantInProgress = false;

  const dailyRewardConsumables = {
    "Mineralwasser 1L": { name: "Mineralwasser 1L", effect: { thirst: 34 }, text: "Mehr Inhalt, besser für längere Wege." },
    "Energy Drink": { name: "Energy Drink", effect: { energy: 18, thirst: 4 }, text: "Schneller Energiekick, landet im Inventar." },
    "Nudelsalat": { name: "Nudelsalat", effect: { hunger: 26 }, text: "Sättigender Snack aus der Kühlung." },
    "Sandwich": { name: "Sandwich", effect: { hunger: 18 }, text: "Ein schneller Snack für unterwegs." },
    "Cola": { name: "Cola", effect: { thirst: 16, energy: 4 }, text: "Süßes Getränk mit kleinem Energiebonus." },
    "Vitamine": { name: "Vitamine", effect: { health: 8, energy: 4 }, text: "Kleine Unterstützung für Gesundheit und Energie." },
    "Schmerztabletten": { name: "Schmerztabletten", effect: { energy: 6, health: 10 }, text: "Kleine Hilfe, wenn der Tag zu lang wird." }
  };

  function dailyDateKey(date = new Date()) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }

  function dailyMonthKey(date = new Date()) {
    return dailyDateKey(date).slice(0, 7);
  }

  function dailyDaysInMonth(date = new Date()) {
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  }

  function dailyMonthLabel(date = new Date()) {
    return date.toLocaleDateString("de-DE", { month: "long", year: "numeric" });
  }

  function dailyHash(text) {
    let hash = 2166136261;
    for (const char of String(text || "")) {
      hash ^= char.charCodeAt(0);
      hash = Math.imul(hash, 16777619);
    }
    return hash >>> 0;
  }

  function dailySeededIndex(seed, length) {
    if (!length) return 0;
    return dailyHash(seed) % length;
  }

  function dailyMetricDefaults() {
    return Object.fromEntries(DAILY_METRIC_KEYS.map((key) => [key, 0]));
  }

  function ensureDailyFeatureState() {
    if (!state) return null;
    state.dailyGiftMonths = state.dailyGiftMonths && typeof state.dailyGiftMonths === "object" ? state.dailyGiftMonths : {};
    state.monthlySpecialItemValues = state.monthlySpecialItemValues && typeof state.monthlySpecialItemValues === "object" ? state.monthlySpecialItemValues : {};
    state.dailyQuestMetrics = { ...dailyMetricDefaults(), ...(state.dailyQuestMetrics || {}) };
    DAILY_METRIC_KEYS.forEach((key) => state.dailyQuestMetrics[key] = Math.max(0, Number(state.dailyQuestMetrics[key] || 0)));
    state.dailyQuestSystem = state.dailyQuestSystem && typeof state.dailyQuestSystem === "object" ? state.dailyQuestSystem : {};
    return state;
  }

  function dailyGiftMonthState(date = new Date()) {
    ensureDailyFeatureState();
    const key = dailyMonthKey(date);
    const value = state.dailyGiftMonths[key] && typeof state.dailyGiftMonths[key] === "object" ? state.dailyGiftMonths[key] : {};
    value.checkedInDays = Array.isArray(value.checkedInDays) ? [...new Set(value.checkedInDays.map(Number).filter((day) => day >= 1 && day <= 31))].sort((a, b) => a - b) : [];
    value.claimedDays = Array.isArray(value.claimedDays) ? [...new Set(value.claimedDays.map(Number).filter((day) => day >= 1 && day <= 31))].sort((a, b) => a - b) : [];
    value.specialClaimed = Boolean(value.specialClaimed);
    value.lastOpenedAt = Number(value.lastOpenedAt || 0);
    state.dailyGiftMonths[key] = value;
    return value;
  }

  function dailySpecialReward(date = new Date()) {
    const monthKey = dailyMonthKey(date);
    const themes = [
      ["Neujahrs-Chronometer", "⌚"], ["Herz aus Rubin", "💎"], ["Frühlings-Tresor", "🌱"],
      ["Goldene Baukrone", "👑"], ["Smaragd-Kompass", "🧭"], ["Sommer-Sammlerkoffer", "🧳"],
      ["Diamant-Sonnenbrille", "🕶️"], ["Platin-Strandpass", "🏝️"], ["Herbst-Siegelring", "💍"],
      ["Nachtmarkt-Relikt", "🌙"], ["Kristall-Trophäe", "🏆"], ["Winter-Luxusbox", "🎁"]
    ];
    const [theme, icon] = themes[date.getMonth()] || themes[0];
    const level = Math.max(0, Number(state?.level || 0));
    const maxValue = level < 5 ? 150_000 : level < 10 ? 250_000 : level < 30 ? 500_000 : level < 80 ? 750_000 : 1_000_000;
    const steps = Math.max(1, Math.floor((maxValue - 50_000) / 50_000) + 1);
    const valueStep = dailyHash(`${monthKey}:special-value:${Math.floor(level / 5)}`) % steps;
    const value = Math.min(maxValue, 50_000 + valueStep * 50_000);
    const name = `Monatspreis ${monthKey} · ${theme}`;
    return { type: "special", icon, name, value, label: `${theme} · Wert ${euro.format(value)}` };
  }

  function dailyGiftRewardForDay(day, date = new Date()) {
    const days = dailyDaysInMonth(date);
    if (day === days) return dailySpecialReward(date);
    const monthKey = dailyMonthKey(date);
    const level = Math.max(0, Number(state?.level || 0));
    const scale = level < 5 ? 0.25 + level * 0.08 : level < 10 ? 0.7 : level < 30 ? 1 : level < 80 ? 2 : 3.5;
    const itemScale = level < 5 ? 0.55 : level < 10 ? 0.8 : level < 30 ? 1 : level < 80 ? 1.5 : 2;
    const scaled = (amount, minimum = 1) => Math.max(minimum, Math.round(amount * scale));
    const milestones = {
      7: { type: "money", icon: "💶", amount: scaled(5000, 500) },
      14: { type: "casino", icon: "🎰", amount: scaled(2500, 250) },
      21: { type: "money", icon: "💰", amount: scaled(10000, 1000) },
      28: { type: "casino", icon: "🎲", amount: scaled(5000, 500) }
    };
    if (milestones[day]) {
      const reward = milestones[day];
      reward.label = reward.type === "money" ? `${reward.amount.toLocaleString("de-DE")} €` : `${reward.amount.toLocaleString("de-DE")} Casino-Coins`;
      return reward;
    }
    const itemPool = [
      ["Mineralwasser 1L", 2], ["Energy Drink", 2], ["Nudelsalat", 2], ["Sandwich", 2],
      ["Cola", 3], ["Vitamine", 2], ["Schmerztabletten", 1], ["Mineralwasser 1L", 5]
    ];
    const moneyPool = [500, 1000, 1500, 2500, 5000];
    const casinoPool = [250, 500, 750, 1000, 1500];
    const selector = dailyHash(`${monthKey}:${day}:kind`) % 10;
    if (selector <= 5) {
      const [name, baseAmount] = itemPool[dailySeededIndex(`${monthKey}:${day}:item`, itemPool.length)];
      const amount = Math.max(1, Math.round(baseAmount * itemScale));
      const icon = /wasser|cola|drink/i.test(name) ? "🥤" : /tablette|vitamin/i.test(name) ? "💊" : "🍽️";
      return { type: "item", icon, name, amount, label: `${amount}× ${name}` };
    }
    if (selector <= 8) {
      const baseAmount = moneyPool[dailySeededIndex(`${monthKey}:${day}:money`, moneyPool.length)];
      const amount = scaled(baseAmount, 100);
      return { type: "money", icon: "💶", amount, label: `${amount.toLocaleString("de-DE")} €` };
    }
    const baseAmount = casinoPool[dailySeededIndex(`${monthKey}:${day}:casino`, casinoPool.length)];
    const amount = scaled(baseAmount, 50);
    return { type: "casino", icon: "🎰", amount, label: `${amount.toLocaleString("de-DE")} Casino-Coins` };
  }

  function dailyGiftRequiredInventory(reward) {
    if (!reward) return 0;
    if (reward.type === "item") return Math.max(1, Number(reward.amount || 1));
    if (reward.type === "special") return 1;
    return 0;
  }

  function dailyGiftCanFit(reward) {
    const needed = dailyGiftRequiredInventory(reward);
    return needed <= 0 || inventoryUsed() + needed <= inventoryCapacity();
  }

  function markDailyGiftCheckin() {
    if (!state || !isPhoneAppInstalled(DAILY_GIFTS_APP_ID)) return false;
    const now = new Date();
    const month = dailyGiftMonthState(now);
    const day = now.getDate();
    const changed = !month.checkedInDays.includes(day);
    if (changed) month.checkedInDays.push(day);
    month.checkedInDays.sort((a, b) => a - b);
    month.lastOpenedAt = Date.now();
    if (changed) {
      addFeed(`Tägliche Geschenke: Tag ${day} wurde als Login-Tag gespeichert.`);
      save();
    }
    return changed;
  }

  function dailyGiftPerfectAttendance(date = new Date()) {
    const month = dailyGiftMonthState(date);
    const days = dailyDaysInMonth(date);
    return Array.from({ length: days }, (_, index) => index + 1).every((day) => month.checkedInDays.includes(day));
  }

  function grantDailyReward(reward) {
    if (!reward) return false;
    if (!dailyGiftCanFit(reward)) {
      addFeed(`Inventar voll: Für ${reward.label} brauchst du ${dailyGiftRequiredInventory(reward)} freie Plätze.`);
      return false;
    }
    dailyRewardGrantInProgress = true;
    try {
      if (reward.type === "money") {
        const amount = Math.max(0, Number(reward.amount || 0));
        state.publicTreasury = Math.max(0, Number(state.publicTreasury || 0) - amount);
        state.bank = Number(state.bank || 0) + amount;
        recordIncome("other", amount);
      } else if (reward.type === "casino") {
        addWallet(Math.round(Math.max(0, Number(reward.amount || 0)) * 100));
      } else if (reward.type === "item") {
        const item = dailyRewardConsumables[reward.name] || { name: reward.name, effect: {}, text: "Tagesgeschenk." };
        addConsumable(item, Math.max(1, Number(reward.amount || 1)));
      } else if (reward.type === "special") {
        state.items ||= [];
        state.items.push(reward.name);
        state.monthlySpecialItemValues[reward.name] = Math.max(50_000, Math.min(1_000_000, Number(reward.value || 50_000)));
      }
      addXp(reward.type === "special" ? 250 : 15, reward.type === "special" ? "Monatspreis" : "Tagesgeschenk");
      return true;
    } finally {
      dailyRewardGrantInProgress = false;
    }
  }

  function claimDailyGift(day, item) {
    if (!state) return;
    const now = new Date();
    const days = dailyDaysInMonth(now);
    const today = now.getDate();
    const selectedDay = Math.max(1, Math.min(days, Math.floor(Number(day || today))));
    const month = dailyGiftMonthState(now);
    if (selectedDay > today) return addFeed("Dieses Geschenk wird erst an seinem Kalendertag freigeschaltet.");
    if (month.claimedDays.includes(selectedDay)) return addFeed("Dieses Tagesgeschenk wurde bereits abgeholt.");
    const reward = dailyGiftRewardForDay(selectedDay, now);
    if (reward.type === "special" && !dailyGiftPerfectAttendance(now)) {
      return addFeed("Der Monatspreis ist gesperrt, weil mindestens ein echter Login-Tag in diesem Monat fehlt.");
    }
    if (!grantDailyReward(reward)) return;
    month.claimedDays.push(selectedDay);
    month.claimedDays.sort((a, b) => a - b);
    if (reward.type === "special") month.specialClaimed = true;
    addFeed(`${reward.type === "special" ? "Monatspreis" : `Tagesgeschenk Tag ${selectedDay}`} abgeholt: ${reward.label}.`, {
      purchase: { kind: "use", title: reward.type === "special" ? "Monatspreis erhalten" : "Tagesgeschenk", name: reward.label, icon: reward.icon }
    });
    save();
    pendingDeviceScrollTop = document.querySelector(".device-screen")?.scrollTop ?? null;
    openDeviceInterface(item, DAILY_GIFTS_APP_ID, false);
  }

  function dailyGiftCardHtml(day, date = new Date()) {
    const month = dailyGiftMonthState(date);
    const reward = dailyGiftRewardForDay(day, date);
    const today = date.getDate();
    const claimed = month.claimedDays.includes(day);
    const checked = month.checkedInDays.includes(day);
    const future = day > today;
    const special = reward.type === "special";
    const perfect = dailyGiftPerfectAttendance(date);
    const buttonText = claimed ? "Geholt" : future ? "Später" : special && !perfect ? "Serie fehlt" : "Abholen";
    const statusClass = claimed ? "claimed" : future ? "future" : checked ? "checked" : "missed";
    return `
      <article class="daily-gift-card ${statusClass} ${special ? "special" : ""} ${day === today ? "today" : ""}">
        <header><b>Tag ${day}</b><span>${reward.icon}</span></header>
        <strong>${escapeHtml(reward.label)}</strong>
        <button class="mini-button ${!claimed && !future && (!special || perfect) ? "gold" : ""}" data-daily-gift-claim="${day}" ${claimed || future || (special && !perfect) ? "disabled" : ""}>${buttonText}</button>
      </article>`;
  }

  function dailyGiftsAppHtml() {
    if (!state) return `<p class="device-hint">Starte zuerst einen Spielstand.</p>`;
    const now = new Date();
    const month = dailyGiftMonthState(now);
    const days = dailyDaysInMonth(now);
    const today = now.getDate();
    const special = dailySpecialReward(now);
    const perfectSoFar = Array.from({ length: today }, (_, index) => index + 1).every((day) => month.checkedInDays.includes(day));
    const remaining = Math.max(0, days - month.checkedInDays.length);
    return `
      <div class="daily-app daily-gifts-app">
        <header class="daily-app-hero gifts">
          <span>🎁</span>
          <div><p class="eyebrow">${escapeHtml(dailyMonthLabel(now))}</p><h4>Tägliche Geschenke</h4><small>Jeder Spieler erhält diesen Monat denselben Kalender.</small></div>
        </header>
        <section class="daily-streak-panel ${perfectSoFar ? "active" : "broken"}">
          <div><small>LOGIN-SERIE</small><b>${month.checkedInDays.length}/${days} Tage</b></div>
          <p>${perfectSoFar ? `Perfekt bis heute. Noch ${remaining} Login-Tage bis zum seltenen Monatspreis.` : "Mindestens ein Login-Tag fehlt. Normale Geschenke kannst du nachholen, der seltene Monatspreis bleibt diesen Monat gesperrt."}</p>
          <strong>${special.icon} ${escapeHtml(special.name)} · ${euro.format(special.value)}</strong>
        </section>
        <div class="daily-gift-grid">${Array.from({ length: days }, (_, index) => dailyGiftCardHtml(index + 1, now)).join("")}</div>
      </div>`;
  }

  function dailyCurrentMetricValue(metric) {
    ensureDailyFeatureState();
    if (metric === "workDays") return Math.max(0, Number(state.totalWorkDays || 0));
    if (metric === "shopSales") return Math.max(0, Number(ensurePlayerShopState()?.stats?.totalSales || 0));
    if (metric === "businessRuns") return Math.max(0, Number(state.businessRuns || 0));
    return Math.max(0, Number(state.dailyQuestMetrics?.[metric] || 0));
  }

  function dailyQuestRewardForBand(band, seed) {
    const tables = {
      starter: [
        { money: 500, xp: 25 }, { money: 1000, xp: 30 }, { money: 1500, xp: 40, item: ["Mineralwasser 1L", 2] },
        { money: 750, xp: 30, casino: 250 }
      ],
      advanced: [
        { money: 3000, xp: 60 }, { money: 5000, xp: 75, casino: 750 }, { money: 7500, xp: 90, item: ["Energy Drink", 2] },
        { money: 10000, xp: 100 }
      ],
      expert: [
        { money: 25000, xp: 125 }, { money: 50000, xp: 150, casino: 2500 }, { money: 75000, xp: 175 }, { money: 100000, xp: 200 }
      ],
      elite: [
        { money: 250000, xp: 250 }, { money: 500000, xp: 300, casino: 10000 }, { money: 750000, xp: 350 }, { money: 1000000, xp: 400 }
      ]
    };
    const pool = tables[band] || tables.starter;
    const reward = { ...pool[dailySeededIndex(seed, pool.length)] };
    const level = Math.max(0, Number(state?.level || 0));
    const factor = band === "starter"
      ? Math.max(0.35, Math.min(1, 0.35 + level * 0.09))
      : band === "advanced"
        ? Math.max(0.8, Math.min(1.25, 0.8 + (level - 10) * 0.025))
        : band === "expert"
          ? Math.max(1, Math.min(1.7, 1 + (level - 30) * 0.014))
          : Math.max(1.25, Math.min(2.2, 1.25 + (level - 80) * 0.045));
    if (reward.money) reward.money = Math.max(100, Math.round(reward.money * factor));
    if (reward.casino) reward.casino = Math.max(50, Math.round(reward.casino * factor));
    if (reward.xp) reward.xp = Math.max(10, Math.round(reward.xp * Math.min(1.6, factor)));
    if (reward.item) reward.item = [reward.item[0], Math.max(1, Math.round(Number(reward.item[1] || 1) * Math.min(1.5, factor)))];
    return reward;
  }

  function dailyQuestPool(level = 1) {
    const lv = Math.max(1, Number(level || 1));
    if (lv < 10) {
      const pool = [
        { metric: "itemsUsed", target: 2, title: "Versorge deinen Charakter", text: "Benutze 2 Getränke, Essen- oder Medizinartikel." },
        { metric: "travels", target: 2, title: "Unterwegs in der Stadt", text: "Starte 2 Fahrten oder Wege auf der lokalen Karte." },
        { metric: "moneyEarned", target: 1000, title: "Erstes Tagesgeld", text: "Verdiene heute insgesamt 1.000 €." },
        { metric: "moneySpent", target: 500, title: "Kleiner Einkauf", text: "Gib heute 500 € aus." },
        { metric: "workDays", target: 1, title: "Arbeitstag", text: "Schließe 1 Arbeitseinsatz ab." },
        { metric: "gameRounds", target: 2, title: "Kurze Spielpause", text: "Starte 2 echte Spielrunden." }
      ];
      if (lv >= 2) pool.push({ metric: "casinoStake", target: 2500, title: "Casino-Einstieg", text: "Setze insgesamt 2.500 € im Casino ein." });
      return { band: "starter", pool };
    }
    if (lv < 30) return {
      band: "advanced",
      pool: [
        { metric: "itemsUsed", target: 5, title: "Tagesversorgung", text: "Benutze 5 Verbrauchsartikel." },
        { metric: "travels", target: 5, title: "Stadtrunde", text: "Starte 5 lokale Wege oder Fahrten." },
        { metric: "moneyEarned", target: 25000, title: "Guter Verdienst", text: "Verdiene heute 25.000 €." },
        { metric: "moneySpent", target: 15000, title: "Investiere in dein Leben", text: "Gib heute 15.000 € aus." },
        { metric: "itemsSold", target: 3, title: "Inventarhändler", text: "Verkaufe 3 Gegenstände oder Verbrauchsartikel." },
        { metric: "casinoStake", target: 200000, title: "Casino-Abend", text: "Setze insgesamt 200.000 € im Casino ein." },
        { metric: "workDays", target: 2, title: "Doppelschicht", text: "Schließe 2 Arbeitseinsätze ab." },
        { metric: "gameRounds", target: 3, title: "Drei Runden", text: "Starte 3 echte Spielrunden." },
        { metric: "businessRuns", target: 2, title: "Unternehmensarbeit", text: "Schließe 2 Business-Aufträge ab." }
      ]
    };
    if (lv < 80) return {
      band: "expert",
      pool: [
        { metric: "casinoStake", target: 1000000, title: "High-Roller I", text: "Setze insgesamt 1.000.000 € im Casino ein." },
        { metric: "casinoStake", target: 10000000, title: "High-Roller X", text: "Setze insgesamt 10.000.000 € im Casino ein." },
        { metric: "moneyEarned", target: 500000, title: "Großer Tagesgewinn", text: "Verdiene heute 500.000 €." },
        { metric: "moneySpent", target: 750000, title: "Große Investition", text: "Gib heute 750.000 € aus." },
        { metric: "shopSales", target: 8, title: "Shop-Verkaufsserie", text: "Verkaufe 8 Artikel über deinen eigenen Shop." },
        { metric: "workDays", target: 3, title: "Arbeitsmarathon", text: "Schließe 3 Arbeitseinsätze ab." },
        { metric: "gameRounds", target: 5, title: "Gaming-Session", text: "Starte 5 echte Spielrunden." },
        { metric: "businessRuns", target: 5, title: "Business-Tag", text: "Schließe 5 Unternehmensaufträge ab." }
      ]
    };
    return {
      band: "elite",
      pool: [
        { metric: "casinoStake", target: 10000000, title: "Casino-Millionär", text: "Setze insgesamt 10.000.000 € im Casino ein." },
        { metric: "casinoStake", target: 25000000, title: "Casino-Legende", text: "Setze insgesamt 25.000.000 € im Casino ein." },
        { metric: "moneyEarned", target: 5000000, title: "Elite-Einnahmen", text: "Verdiene heute 5.000.000 €." },
        { metric: "moneySpent", target: 10000000, title: "Luxus-Investition", text: "Gib heute 10.000.000 € aus." },
        { metric: "shopSales", target: 20, title: "Shop-Imperium", text: "Verkaufe 20 Artikel über deinen eigenen Shop." },
        { metric: "workDays", target: 5, title: "Fünf Einsätze", text: "Schließe 5 Arbeitseinsätze ab." },
        { metric: "gameRounds", target: 10, title: "Gaming-Marathon", text: "Starte 10 echte Spielrunden." },
        { metric: "businessRuns", target: 10, title: "Unternehmensboss", text: "Schließe 10 Unternehmensaufträge ab." }
      ]
    };
  }

  function createDailyQuests(dateKey = dailyDateKey()) {
    const level = Math.max(1, Number(state?.level || 1));
    const { band, pool } = dailyQuestPool(level);
    const path = String(state?.path || state?.careerPath || "allgemein");
    const firstIndex = dailySeededIndex(`${dateKey}:${band}:${path}:quest-1`, pool.length);
    let secondIndex = dailySeededIndex(`${dateKey}:${band}:${path}:quest-2`, pool.length);
    if (secondIndex === firstIndex) secondIndex = (secondIndex + 1) % pool.length;
    return [pool[firstIndex], pool[secondIndex]].map((definition, index) => ({
      id: `${dateKey}-${index + 1}-${definition.metric}-${definition.target}`,
      ...definition,
      baseline: dailyCurrentMetricValue(definition.metric),
      progress: 0,
      claimed: false,
      reward: dailyQuestRewardForBand(band, `${dateKey}:${band}:${index}:${definition.metric}`)
    }));
  }

  function ensureDailyQuestDay() {
    if (!state) return null;
    ensureDailyFeatureState();
    const dateKey = dailyDateKey();
    const system = state.dailyQuestSystem;
    if (system.dateKey !== dateKey || !Array.isArray(system.quests) || system.quests.length !== 2) {
      system.dateKey = dateKey;
      system.createdAt = Date.now();
      system.levelBandAtCreation = Math.max(1, Number(state.level || 1));
      system.quests = createDailyQuests(dateKey);
    }
    updateDailyQuestProgress(false);
    return system;
  }

  function updateDailyQuestProgress(markCompletion = true) {
    if (!state?.dailyQuestSystem?.quests?.length) return false;
    let changed = false;
    state.dailyQuestSystem.quests.forEach((quest) => {
      const next = Math.max(0, Math.min(Number(quest.target || 0), dailyCurrentMetricValue(quest.metric) - Number(quest.baseline || 0)));
      if (Number(quest.progress || 0) !== next) {
        quest.progress = next;
        changed = true;
      }
      const complete = next >= Number(quest.target || 0);
      if (markCompletion && complete && !quest.completedAt) {
        quest.completedAt = Date.now();
        addFeed(`Tägliche Quest abgeschlossen: ${quest.title}. Belohnung kann in der App abgeholt werden.`);
        changed = true;
      }
    });
    return changed;
  }

  function dailyQuestRewardText(reward = {}) {
    const parts = [];
    if (reward.money) parts.push(`${Number(reward.money).toLocaleString("de-DE")} €`);
    if (reward.casino) parts.push(`${Number(reward.casino).toLocaleString("de-DE")} Casino-Coins`);
    if (reward.xp) parts.push(`${Number(reward.xp).toLocaleString("de-DE")} EP`);
    if (reward.item) parts.push(`${reward.item[1]}× ${reward.item[0]}`);
    return parts.join(" · ") || "Fortschritt";
  }

  function dailyQuestProgressText(quest) {
    const progress = Math.max(0, Number(quest.progress || 0));
    const target = Math.max(1, Number(quest.target || 1));
    const moneyMetrics = ["moneySpent", "moneyEarned", "casinoStake"].includes(quest.metric);
    return moneyMetrics ? `${euro.format(progress)} / ${euro.format(target)}` : `${Math.floor(progress).toLocaleString("de-DE")} / ${Math.floor(target).toLocaleString("de-DE")}`;
  }

  function dailyQuestsAppHtml() {
    if (!state) return `<p class="device-hint">Starte zuerst einen Spielstand.</p>`;
    const system = ensureDailyQuestDay();
    const quests = system?.quests || [];
    const done = quests.filter((quest) => Number(quest.progress || 0) >= Number(quest.target || 0)).length;
    const claimed = quests.filter((quest) => quest.claimed).length;
    const tomorrow = new Date();
    tomorrow.setHours(24, 0, 0, 0);
    const leftMs = Math.max(0, tomorrow.getTime() - Date.now());
    const hours = Math.floor(leftMs / 3_600_000);
    const minutes = Math.floor((leftMs % 3_600_000) / 60_000);
    return `
      <div class="daily-app daily-quests-app">
        <header class="daily-app-hero quests">
          <span>✓</span><div><p class="eyebrow">Level ${Math.max(1, Number(state.level || 1))}</p><h4>Tägliche Quests</h4><small>Zwei neue, levelgerechte Aufgaben pro echtem Kalendertag.</small></div>
        </header>
        <section class="daily-quest-summary"><div><small>FERTIG</small><b>${done}/2</b></div><div><small>ABGEHOLT</small><b>${claimed}/2</b></div><div><small>RESET</small><b>${hours}h ${minutes}m</b></div></section>
        <div class="daily-quest-list">
          ${quests.map((quest, index) => {
            const target = Math.max(1, Number(quest.target || 1));
            const progress = Math.max(0, Math.min(target, Number(quest.progress || 0)));
            const percent = Math.round(progress / target * 100);
            const complete = progress >= target;
            return `
              <article class="daily-quest-card ${complete ? "complete" : ""} ${quest.claimed ? "claimed" : ""}">
                <header><span>${index + 1}</span><div><h5>${escapeHtml(quest.title)}</h5><small>${escapeHtml(quest.text)}</small></div></header>
                <div class="daily-quest-progress"><i style="width:${percent}%"></i></div>
                <div class="daily-quest-meta"><b>${dailyQuestProgressText(quest)}</b><small>Belohnung: ${escapeHtml(dailyQuestRewardText(quest.reward))}</small></div>
                <button class="mini-button ${complete && !quest.claimed ? "gold" : ""}" data-daily-quest-claim="${escapeHtml(quest.id)}" ${!complete || quest.claimed ? "disabled" : ""}>${quest.claimed ? "Abgeholt" : complete ? "Belohnung abholen" : "Noch offen"}</button>
              </article>`;
          }).join("")}
        </div>
        <p class="device-hint">Die Aufgaben laufen nur bis Mitternacht. Danach werden zwei neue Quests passend zu deinem aktuellen Level erstellt.</p>
      </div>`;
  }

  function grantDailyQuestReward(quest) {
    if (!quest?.reward) return false;
    const reward = quest.reward;
    const inventoryNeed = reward.item ? Math.max(1, Number(reward.item[1] || 1)) : 0;
    if (inventoryNeed && inventoryUsed() + inventoryNeed > inventoryCapacity()) {
      addFeed(`Inventar voll: Für die Questbelohnung brauchst du ${inventoryNeed} freie Plätze.`);
      return false;
    }
    dailyRewardGrantInProgress = true;
    try {
      if (reward.money) {
        const amount = Math.max(0, Number(reward.money || 0));
        state.publicTreasury = Math.max(0, Number(state.publicTreasury || 0) - amount);
        state.bank = Number(state.bank || 0) + amount;
        recordIncome("other", amount);
      }
      if (reward.casino) addWallet(Math.round(Math.max(0, Number(reward.casino || 0)) * 100));
      if (reward.item) {
        const [name, amount] = reward.item;
        addConsumable(dailyRewardConsumables[name] || { name, effect: {}, text: "Questbelohnung." }, Math.max(1, Number(amount || 1)));
      }
      if (reward.xp) addXp(Math.max(0, Number(reward.xp || 0)), "Tägliche Quest");
      return true;
    } finally {
      dailyRewardGrantInProgress = false;
    }
  }

  function claimDailyQuest(questId, item) {
    const system = ensureDailyQuestDay();
    const quest = system?.quests?.find((entry) => entry.id === questId);
    if (!quest) return addFeed("Diese Quest gehört nicht mehr zum heutigen Tag.");
    updateDailyQuestProgress(false);
    if (quest.claimed) return addFeed("Diese Questbelohnung wurde bereits abgeholt.");
    if (Number(quest.progress || 0) < Number(quest.target || 0)) return addFeed("Diese Quest ist noch nicht abgeschlossen.");
    if (!grantDailyQuestReward(quest)) return;
    quest.claimed = true;
    quest.claimedAt = Date.now();
    addFeed(`Questbelohnung abgeholt: ${quest.title} · ${dailyQuestRewardText(quest.reward)}.`, {
      purchase: { kind: "use", title: "Questbelohnung", name: quest.title, icon: "✓" }
    });
    save();
    pendingDeviceScrollTop = document.querySelector(".device-screen")?.scrollTop ?? null;
    openDeviceInterface(item, DAILY_QUESTS_APP_ID, false);
  }

  function bumpDailyQuestMetric(key, amount = 1, saveNow = false) {
    if (!state || dailyRewardGrantInProgress || !DAILY_METRIC_KEYS.includes(key)) return;
    ensureDailyFeatureState();
    state.dailyQuestMetrics[key] = Math.max(0, Number(state.dailyQuestMetrics[key] || 0) + Math.max(0, Number(amount || 0)));
    if (state.dailyQuestSystem?.dateKey === dailyDateKey()) updateDailyQuestProgress(true);
    if (saveNow) save();
  }

  function bindDailyApps(shell, item, activeApp) {
    if (!shell) return;
    if (activeApp === DAILY_GIFTS_APP_ID) {
      shell.querySelectorAll("[data-daily-gift-claim]:not(:disabled)").forEach((button) => button.addEventListener("click", () => claimDailyGift(button.dataset.dailyGiftClaim, item)));
    }
    if (activeApp === DAILY_QUESTS_APP_ID) {
      shell.querySelectorAll("[data-daily-quest-claim]:not(:disabled)").forEach((button) => button.addEventListener("click", () => claimDailyQuest(button.dataset.dailyQuestClaim, item)));
      if (!window.__lifeBuilderDailyQuestDelegated) {
        window.__lifeBuilderDailyQuestDelegated = true;
        document.addEventListener("click", (event) => {
          const button = event.target.closest?.("[data-daily-quest-claim]");
          if (!button || button.disabled) return;
          event.preventDefault();
          event.stopImmediatePropagation();
          claimDailyQuest(button.dataset.dailyQuestClaim, ownedPhoneItem());
        }, true);
      }
    }
  }

  // App-Store-Einträge.
  if (!phoneAppStoreCatalog.some((app) => app.id === DAILY_GIFTS_APP_ID)) {
    phoneAppStoreCatalog.push({
      id: DAILY_GIFTS_APP_ID,
      label: "Tägliche Geschenke",
      icon: "🎁",
      minTier: 1,
      status: "available",
      description: "Jeden Kalendertag eine Belohnung. Eine perfekte Monatsserie schaltet einen einmaligen, wertvollen Monatspreis frei."
    });
  }
  if (!phoneAppStoreCatalog.some((app) => app.id === DAILY_QUESTS_APP_ID)) {
    phoneAppStoreCatalog.push({
      id: DAILY_QUESTS_APP_ID,
      label: "Tägliche Quests",
      icon: "✓",
      minTier: 1,
      status: "available",
      description: "Zwei neue Aufgaben pro Tag, automatisch an dein Charakterlevel angepasst, inklusive Fortschrittsanzeige und Belohnungen."
    });
  }

  const dailyBasePhoneAppStoreHtml = phoneAppStoreHtml;
  phoneAppStoreHtml = function dailyAppsPhoneAppStoreHtml(item) {
    return dailyBasePhoneAppStoreHtml(item).replace(
      /<p class="device-hint">Finder\.KL[\s\S]*?<\/p>/,
      `<p class="device-hint">Finder.KL, Finsta.KL, Event, Tägliche Geschenke und Tägliche Quests schließen nach dem Download direkt hinter dem App Store an. Die Casino-App bleibt bis zum nächsten Ausbau gesperrt.</p>`
    );
  };

  const dailyBaseDeviceAppsFor = deviceAppsFor;
  deviceAppsFor = function dailyAppsDeviceAppsFor(item) {
    const apps = dailyBaseDeviceAppsFor(item);
    if (!phoneItems().includes(item)) return apps;
    const tier = deviceTier(item);
    const appendDownloaded = (appId, label, icon, text) => {
      if (!isPhoneAppInstalled(appId) || apps.some((app) => app.id === appId)) return;
      apps.push({
        id: appId,
        min: 1,
        label,
        icon,
        text,
        layoutClass: "device-downloaded-app",
        locked: tier < 1,
        lockText: tier < 1 ? "Benötigt mindestens ein Einsteiger-Smartphone." : ""
      });
    };
    appendDownloaded(DAILY_GIFTS_APP_ID, "Tägliche Geschenke", "🎁", "Tägliche Belohnungen, Nachhol-Geschenke und ein seltener Monatspreis für eine perfekte Login-Serie.");
    appendDownloaded(DAILY_QUESTS_APP_ID, "Tägliche Quests", "✓", "Zwei levelgerechte Tagesaufgaben mit Live-Fortschritt und Belohnungen.");
    return apps;
  };

  const dailyBaseDeviceAppActions = deviceAppActions;
  deviceAppActions = function dailyAppsDeviceAppActions(appId, item) {
    if (appId === DAILY_GIFTS_APP_ID) return dailyGiftsAppHtml();
    if (appId === DAILY_QUESTS_APP_ID) return dailyQuestsAppHtml();
    return dailyBaseDeviceAppActions(appId, item);
  };

  const dailyBaseOpenDeviceAppDirect = openDeviceAppDirect;
  openDeviceAppDirect = function dailyAppsOpenDeviceAppDirect(item, appId) {
    if ([DAILY_GIFTS_APP_ID, DAILY_QUESTS_APP_ID].includes(appId)) return openDeviceInterface(item, appId);
    return dailyBaseOpenDeviceAppDirect(item, appId);
  };

  const dailyBaseOpenDeviceInterface = openDeviceInterface;
  openDeviceInterface = function dailyAppsOpenDeviceInterface(item, activeApp = "home", activeUse = true) {
    if (activeApp === DAILY_GIFTS_APP_ID) markDailyGiftCheckin();
    if (activeApp === DAILY_QUESTS_APP_ID) ensureDailyQuestDay();
    const result = dailyBaseOpenDeviceInterface(item, activeApp, activeUse);
    const shell = document.querySelector("#detailDialog .device-shell:last-of-type") || document.querySelector("#detailDialog .device-shell");
    bindDailyApps(shell, item, activeApp);
    return result;
  };

  // Spezial-Monatspreise besitzen einen echten Shopwert und können im eigenen Shop angeboten werden.
  const dailyBaseItemBasePrice = itemBasePrice;
  itemBasePrice = function dailyAppsItemBasePrice(name) {
    const specialValue = Number(state?.monthlySpecialItemValues?.[name] || 0);
    if (specialValue > 0) return specialValue;
    const specialMatch = String(name || "").match(/^Monatspreis\s+(\d{4}-\d{2})\s+·/i);
    if (specialMatch) {
      const valueStep = dailyHash(`${specialMatch[1]}:special-value`) % 20;
      return Math.min(1_000_000, 50_000 + valueStep * 50_000);
    }
    return dailyBaseItemBasePrice(name);
  };

  // Fortschritt aus den wichtigsten Spielsystemen erfassen.
  const dailyBasePay = pay;
  pay = function dailyAppsPay(price, preferCash = false, options = {}) {
    const paid = dailyBasePay(price, preferCash, options);
    if (paid) bumpDailyQuestMetric("moneySpent", Number(price || 0));
    return paid;
  };

  const dailyBasePayoutFromTreasury = payoutFromTreasury;
  payoutFromTreasury = function dailyAppsPayoutFromTreasury(amount) {
    const result = dailyBasePayoutFromTreasury(amount);
    bumpDailyQuestMetric("moneyEarned", Number(amount || 0));
    return result;
  };

  const dailyBaseTakeWallet = takeWallet;
  takeWallet = function dailyAppsTakeWallet(cents) {
    const paid = dailyBaseTakeWallet(cents);
    if (paid) bumpDailyQuestMetric("casinoStake", Number(cents || 0) / 100);
    return paid;
  };

  const dailyBaseUseConsumableAmount = useConsumableAmount;
  useConsumableAmount = function dailyAppsUseConsumableAmount(name, requestedAmount = 1) {
    const used = dailyBaseUseConsumableAmount(name, requestedAmount);
    if (used > 0) bumpDailyQuestMetric("itemsUsed", used, true);
    return used;
  };

  const dailyBaseSellConsumable = sellConsumable;
  sellConsumable = function dailyAppsSellConsumable(name) {
    const before = Number(state?.consumables?.[name]?.count || 0);
    const result = dailyBaseSellConsumable(name);
    const after = Number(state?.consumables?.[name]?.count || 0);
    if (after < before) bumpDailyQuestMetric("itemsSold", before - after, true);
    return result;
  };

  const dailyBaseSellInventoryItem = sellInventoryItem;
  sellInventoryItem = function dailyAppsSellInventoryItem(name) {
    const before = inventoryItemCount(name);
    const result = dailyBaseSellInventoryItem(name);
    const after = inventoryItemCount(name);
    if (after < before) bumpDailyQuestMetric("itemsSold", before - after, true);
    return result;
  };

  const dailyBaseBeginLocalTravel = beginLocalTravel;
  beginLocalTravel = function dailyAppsBeginLocalTravel(place, mode) {
    const previousArrival = Number(state?.localTravel?.arrivesAt || 0);
    const result = dailyBaseBeginLocalTravel(place, mode);
    if (Number(state?.localTravel?.arrivesAt || 0) > previousArrival) bumpDailyQuestMetric("travels", 1, true);
    return result;
  };

  function wrapDailyGameRound(functionName) {
    const original = window[functionName];
    if (typeof original !== "function") return;
    window[functionName] = function dailyGameRoundWrapper(...args) {
      bumpDailyQuestMetric("gameRounds", 1);
      const result = original.apply(this, args);
      save();
      return result;
    };
  }

  // Funktionsdeklarationen liegen im globalen Script-Scope, deshalb direkt neu zuweisen.
  const dailyGameRoundWrappers = [
    ["playMiniGame", playMiniGame], ["startIconManRound", startIconManRound], ["startSnakeDifficulty", startSnakeDifficulty],
    ["startWarColor", startWarColor], ["startKingdomGame", startKingdomGame], ["startRacerColor", startRacerColor],
    ["startSurvivalRun", startSurvivalRun]
  ];
  dailyGameRoundWrappers.forEach(([name, original]) => {
    if (typeof original !== "function") return;
    const wrapped = function (...args) {
      bumpDailyQuestMetric("gameRounds", 1);
      const result = original.apply(this, args);
      save();
      return result;
    };
    if (name === "playMiniGame") playMiniGame = wrapped;
    else if (name === "startIconManRound") startIconManRound = wrapped;
    else if (name === "startSnakeDifficulty") startSnakeDifficulty = wrapped;
    else if (name === "startWarColor") startWarColor = wrapped;
    else if (name === "startKingdomGame") startKingdomGame = wrapped;
    else if (name === "startRacerColor") startRacerColor = wrapped;
    else if (name === "startSurvivalRun") startSurvivalRun = wrapped;
  });

  const dailyBaseSave = save;
  save = function dailyAppsSave(...args) {
    if (state) {
      ensureDailyFeatureState();
      if (state.dailyQuestSystem?.dateKey === dailyDateKey()) updateDailyQuestProgress(true);
    }
    return dailyBaseSave.apply(this, args);
  };

  ensureDailyFeatureState();
  window.LifeBuilderDailyApps = {
    version: DAILY_APPS_VERSION,
    giftAppId: DAILY_GIFTS_APP_ID,
    questAppId: DAILY_QUESTS_APP_ID,
    getGiftPlan: () => Array.from({ length: dailyDaysInMonth() }, (_, index) => dailyGiftRewardForDay(index + 1)),
    getQuests: () => ensureDailyQuestDay()?.quests || [],
    refreshProgress: () => updateDailyQuestProgress(true)
  };
})();


/* iPhone/Safari: Scrollhöhe des Charakterdialogs sofort berechnen.
   content-visibility und neu eingesetztes HTML konnten die Scrollrange sonst erst Sekunden später melden. */
let mobileCharacterScrollObserver = null;
function stabilizeMobileCharacterScroll(section = "") {
  if (!window.matchMedia("(max-width: 700px)").matches || !els?.dialog) return;
  const dialog = els.dialog;
  const content = dialog.querySelector(".character-hub-content");
  if (!content) return;

  if (mobileCharacterScrollObserver) {
    try { mobileCharacterScrollObserver.disconnect(); } catch (_) {}
    mobileCharacterScrollObserver = null;
  }

  // Der neue Reiter beginnt oben. Bei refreshAfterStateChange stellt die bestehende
  // Scroll-Snapshot-Funktion direkt danach wieder die vorherige Position her.
  content.scrollTop = 0;
  dialog.scrollTop = 0;
  content.dataset.mobileCharacterSection = section || "overview";

  // Safari zu einer sofortigen vollständigen Layoutberechnung zwingen.
  void content.offsetHeight;
  void content.scrollHeight;
  content.style.setProperty("--mobile-scroll-height", `${content.scrollHeight}px`);

  const refreshRange = () => {
    if (!dialog.open || !content.isConnected) return;
    void content.offsetHeight;
    content.style.setProperty("--mobile-scroll-height", `${content.scrollHeight}px`);
  };

  requestAnimationFrame(refreshRange);

  // Dynamische SVGs/Karten können ihre endgültige Größe nach dem ersten Layout erhalten.
  // Der ResizeObserver aktualisiert nur die Scrollrange, ohne den Nutzer zurück nach oben zu setzen.
  if (typeof ResizeObserver !== "undefined") {
    mobileCharacterScrollObserver = new ResizeObserver(refreshRange);
    mobileCharacterScrollObserver.observe(content);
    if (content.firstElementChild) mobileCharacterScrollObserver.observe(content.firstElementChild);
    window.setTimeout(() => {
      try { mobileCharacterScrollObserver?.disconnect(); } catch (_) {}
      mobileCharacterScrollObserver = null;
    }, 1800);
  }

  content.addEventListener("touchstart", refreshRange, { passive: true, once: true });
}


/* Mobile dialog viewport fix: every newly opened shop/menu begins at its top. */
(() => {
  if (typeof HTMLDialogElement === "undefined" || HTMLDialogElement.prototype.__lifeBuilderMobileTopPatched) return;
  const proto = HTMLDialogElement.prototype;
  const originalShowModal = proto.showModal;
  proto.showModal = function lifeBuilderShowModalAtTop(...args) {
    const result = originalShowModal.apply(this, args);
    if (window.matchMedia("(max-width: 700px)").matches) {
      const dialog = this;
      requestAnimationFrame(() => {
        dialog.scrollTop = 0;
        dialog.querySelectorAll(".market-list,.item-list,.player-shop-body,.shop-stock-list,.dialog-scroll,.device-screen").forEach((node) => {
          node.scrollTop = 0;
        });
        const topAnchor = dialog.querySelector("h1,h2,.dialog-head,.market-head,.shop-head") || dialog.firstElementChild;
        if (topAnchor && typeof topAnchor.scrollIntoView === "function") {
          topAnchor.scrollIntoView({ block: "start", inline: "nearest", behavior: "instant" });
        }
        dialog.scrollTop = 0;
      });
    }
    return result;
  };
  proto.__lifeBuilderMobileTopPatched = true;
})();


/* Online-Mobile-Stabilitätsfix · 2026-07-22 */
(() => {
  // iOS: Pinch-, Doppel-Tipp- und Browserzoom vollständig deaktivieren.
  ["gesturestart", "gesturechange", "gestureend"].forEach((name) => {
    document.addEventListener(name, (event) => event.preventDefault(), { passive: false });
  });
  let lastTouchEnd = 0;
  document.addEventListener("touchend", (event) => {
    const now = Date.now();
    if (now - lastTouchEnd < 320) event.preventDefault();
    lastTouchEnd = now;
  }, { passive: false });
  document.addEventListener("dblclick", (event) => event.preventDefault(), { passive: false });

  // Schließen/Zurück bleibt auch über komplexen Shop-Inhalten anklickbar.
  document.addEventListener("click", (event) => {
    const close = event.target.closest?.("#closeDialog");
    if (close) {
      event.preventDefault();
      event.stopImmediatePropagation();
      clearDialogDynamic();
      if (els.dialog?.open) els.dialog.close();
      return;
    }
    const back = event.target.closest?.("#dialogBack:not([hidden])");
    if (back && typeof back.onclick === "function") {
      event.preventDefault();
      event.stopImmediatePropagation();
      back.onclick.call(back, event);
    }
  }, true);

  // Sobald ein echtes Dialog-/Spiel-Overlay offen ist, darf die Seite dahinter nicht scrollen.
  let lockedScrollY = 0;
  const overlayIsOpen = () => Boolean(
    document.querySelector("dialog[open], .snake-modal:not(.hidden), .business-map-overlay:not(.hidden), .online-auth-overlay.show")
  );
  const lockBackground = () => {
    if (document.body.classList.contains("life-overlay-locked")) return;
    lockedScrollY = window.scrollY || 0;
    document.documentElement.classList.add("life-overlay-locked");
    document.body.classList.add("life-overlay-locked");
    document.body.style.top = `-${lockedScrollY}px`;
  };
  const unlockBackground = () => {
    if (!document.body.classList.contains("life-overlay-locked")) return;
    document.documentElement.classList.remove("life-overlay-locked");
    document.body.classList.remove("life-overlay-locked");
    document.body.style.top = "";
    window.scrollTo(0, lockedScrollY);
  };
  const syncOverlayLock = () => overlayIsOpen() ? lockBackground() : unlockBackground();
  new MutationObserver(() => requestAnimationFrame(syncOverlayLock)).observe(document.body, {
    subtree: true, childList: true, attributes: true, attributeFilter: ["open", "class", "hidden"]
  });
  document.addEventListener("touchmove", (event) => {
    if (!overlayIsOpen()) return;
    const allowed = event.target.closest?.(
      "dialog[open],.character-hub-content,.wardrobe-list,.device-screen,.device-app-view,.casino-world-panel-scroll,.market-list,.dialog-scroll,.profile-info-scroll,.mood-info-panel,.work-helper-hub,.work-info-dashboard,.logistics-game,.iconman-menu,.racer-options-panel,.snake-game-shell,.snake-canvas,.racer-track"
    );
    if (!allowed) event.preventDefault();
  }, { passive: false, capture: true });
  document.addEventListener("close", () => setTimeout(syncOverlayLock, 0), true);
  document.addEventListener("cancel", () => setTimeout(syncOverlayLock, 0), true);
  window.addEventListener("pageshow", () => setTimeout(syncOverlayLock, 0));
  window.addEventListener("orientationchange", () => setTimeout(syncOverlayLock, 100));
})();
